**PRODUCTION PATTERN**:

```java
import java.net.*;
import java.io.*;
import java.time.Duration;
import java.util.*;
import java.util.concurrent.*;
import java.util.regex.Pattern;
import javax.net.ssl.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Counter;

public class ProductionWebhookService {

    private static final Logger logger = LoggerFactory.getLogger(ProductionWebhookService.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT.WEBHOOK");

    // Comprehensive blocked IP ranges including cloud metadata
    private static final List<IpRange> BLOCKED_RANGES = Arrays.asList(
        // IPv4 Private Ranges
        new IpRange("10.0.0.0", "10.255.255.255"),
        new IpRange("172.16.0.0", "172.31.255.255"),
        new IpRange("192.168.0.0", "192.168.255.255"),
        // Loopback
        new IpRange("127.0.0.0", "127.255.255.255"),
        // Link-local
        new IpRange("169.254.0.0", "169.254.255.255"),
        // AWS/GCP/Azure Metadata
        new IpRange("169.254.169.254", "169.254.169.254"),
        // GCP additional metadata
        new IpRange("metadata.google.internal"),
        // Multicast
        new IpRange("224.0.0.0", "239.255.255.255"),
        // Reserved
        new IpRange("0.0.0.0", "0.255.255.255"),
        new IpRange("240.0.0.0", "255.255.255.255")
    );

    // Blocked hostnames (case-insensitive)
    private static final Set<String> BLOCKED_HOSTNAMES = Set.of(
        "localhost",
        "metadata.google.internal",
        "metadata",
        "169.254.169.254",
        "instance-data",
        "kubernetes.default.svc"
    );

    // Allowed URL schemes
    private static final Set<String> ALLOWED_SCHEMES = Set.of("http", "https");

    // Allowed ports (prevent port scanning)
    private static final Set<Integer> ALLOWED_PORTS = Set.of(80, 443, 8080, 8443);

    private final Counter blockedRequests;
    private final Counter rebindingAttempts;
    private final ExecutorService dnsResolver;

    public ProductionWebhookService(MeterRegistry registry) {
        this.blockedRequests = registry.counter("webhook.blocked.total");
        this.rebindingAttempts = registry.counter("webhook.rebinding.attempts");
        this.dnsResolver = Executors.newFixedThreadPool(4);
    }

    public WebhookResult fetchWebhook(WebhookRequest request) {
        String requestId = UUID.randomUUID().toString();
        long startTime = System.currentTimeMillis();

        try {
            // Layer 1: URL Parsing and Scheme Validation
            URL url = validateAndParseUrl(request.getUrl(), requestId);

            // Layer 2: Hostname Blocklist Check
            validateHostname(url.getHost(), requestId);

            // Layer 3: DNS Resolution with Timeout and Pinning
            InetAddress pinnedAddress = resolveDNSWithValidation(
                url.getHost(), requestId, Duration.ofSeconds(2)
            );

            // Layer 4: Port Validation
            int port = resolvePort(url);
            validatePort(port, requestId);

            // Layer 5: Direct Socket Connection to Pinned IP
            Socket socket = createPinnedConnection(pinnedAddress, port, requestId);

            // Layer 6: Post-Connection IP Verification
            verifyConnectedAddress(socket, pinnedAddress, requestId);

            // Layer 7: Execute Request with Timeouts
            String response = executeRequest(socket, url, request, requestId);

            auditLogger.info("WEBHOOK_SUCCESS requestId={} url={} resolvedIP={} " +
                           "durationMs={} userId={}",
                           requestId, sanitizeUrl(request.getUrl()), 
                           pinnedAddress.getHostAddress(),
                           System.currentTimeMillis() - startTime,
                           request.getUserId());

            return WebhookResult.success(response, requestId);

        } catch (SecurityException e) {
            blockedRequests.increment();
            auditLogger.warn("WEBHOOK_BLOCKED requestId={} url={} reason={} userId={}",
                           requestId, sanitizeUrl(request.getUrl()), 
                           e.getMessage(), request.getUserId());
            return WebhookResult.blocked(e.getMessage(), requestId);

        } catch (Exception e) {
            logger.error("Webhook fetch failed - requestId={}", requestId, e);
            return WebhookResult.error("Internal error", requestId);
        }
    }

    private URL validateAndParseUrl(String urlString, String requestId) 
            throws SecurityException {
        try {
            URL url = new URL(urlString);

            if (!ALLOWED_SCHEMES.contains(url.getProtocol().toLowerCase())) {
                throw new SecurityException("Blocked URL scheme: " + url.getProtocol());
            }

            // Block URLs with credentials
            if (url.getUserInfo() != null) {
                throw new SecurityException("URLs with credentials not allowed");
            }

            return url;
        } catch (MalformedURLException e) {
            throw new SecurityException("Invalid URL format");
        }
    }

    private void validateHostname(String hostname, String requestId) 
            throws SecurityException {
        String normalizedHost = hostname.toLowerCase().trim();

        // Check against blocklist
        for (String blocked : BLOCKED_HOSTNAMES) {
            if (normalizedHost.equals(blocked) || 
                normalizedHost.endsWith("." + blocked)) {
                throw new SecurityException("Blocked hostname");
            }
        }

        // Block raw IP addresses in hostname (force DNS resolution)
        if (isIPAddress(hostname)) {
            InetAddress addr;
            try {
                addr = InetAddress.getByName(hostname);
            } catch (UnknownHostException e) {
                throw new SecurityException("Invalid IP address");
            }

            if (isBlockedAddress(addr)) {
                throw new SecurityException("Direct IP access to blocked range");
            }
        }
    }

    private InetAddress resolveDNSWithValidation(String hostname, String requestId,
                                                   Duration timeout) 
            throws SecurityException {

        Future<InetAddress[]> future = dnsResolver.submit(() -> 
            InetAddress.getAllByName(hostname)
        );

        InetAddress[] addresses;
        try {
            addresses = future.get(timeout.toMillis(), TimeUnit.MILLISECONDS);
        } catch (TimeoutException e) {
            future.cancel(true);
            throw new SecurityException("DNS resolution timeout");
        } catch (Exception e) {
            throw new SecurityException("DNS resolution failed");
        }

        // Validate ALL resolved addresses
        for (InetAddress addr : addresses) {
            if (isBlockedAddress(addr)) {
                logger.warn("DNS resolved to blocked IP - requestId={} hostname={} ip={}",
                          requestId, hostname, addr.getHostAddress());
                throw new SecurityException("DNS resolves to blocked IP range");
            }
        }

        // Return first valid address
        return addresses[0];
    }

    private boolean isBlockedAddress(InetAddress addr) {
        // Handle IPv4-mapped IPv6 addresses (::ffff:x.x.x.x)
        if (addr instanceof Inet6Address) {
            Inet6Address ip6 = (Inet6Address) addr;
            if (ip6.isIPv4CompatibleAddress() || isIPv4Mapped(ip6)) {
                // Extract IPv4 address and check
                byte[] bytes = addr.getAddress();
                byte[] ipv4Bytes = Arrays.copyOfRange(bytes, 12, 16);
                try {
                    addr = InetAddress.getByAddress(ipv4Bytes);
                } catch (UnknownHostException e) {
                    return true; // Block on error
                }
            }
        }

        // Standard checks
        if (addr.isLoopbackAddress() || addr.isLinkLocalAddress() ||
            addr.isSiteLocalAddress() || addr.isAnyLocalAddress() ||
            addr.isMulticastAddress()) {
            return true;
        }

        // Check against explicit ranges
        String ip = addr.getHostAddress();
        for (IpRange range : BLOCKED_RANGES) {
            if (range.contains(ip)) {
                return true;
            }
        }

        return false;
    }

    private boolean isIPv4Mapped(Inet6Address addr) {
        byte[] bytes = addr.getAddress();
        // IPv4-mapped: ::ffff:x.x.x.x
        for (int i = 0; i < 10; i++) {
            if (bytes[i] != 0) return false;
        }
        return bytes[10] == (byte)0xff && bytes[11] == (byte)0xff;
    }

    private Socket createPinnedConnection(InetAddress pinnedAddress, int port,
                                          String requestId) throws SecurityException {
        try {
            Socket socket = new Socket();
            socket.setSoTimeout(10000);  // Read timeout

            // Connect directly to pinned IP - no DNS lookup
            socket.connect(new InetSocketAddress(pinnedAddress, port), 5000);

            return socket;
        } catch (IOException e) {
            throw new SecurityException("Connection failed: " + e.getMessage());
        }
    }

    private void verifyConnectedAddress(Socket socket, InetAddress expected,
                                        String requestId) throws SecurityException {
        InetAddress connected = socket.getInetAddress();

        if (!connected.equals(expected)) {
            rebindingAttempts.increment();
            logger.error("DNS REBINDING DETECTED - requestId={} expected={} actual={}",
                        requestId, expected.getHostAddress(), 
                        connected.getHostAddress());

            try { socket.close(); } catch (IOException ignored) {}
            throw new SecurityException("DNS rebinding attack detected");
        }

        // Re-validate the connected IP (defense in depth)
        if (isBlockedAddress(connected)) {
            rebindingAttempts.increment();
            try { socket.close(); } catch (IOException ignored) {}
            throw new SecurityException("Connected to blocked IP");
        }
    }

    private void validatePort(int port, String requestId) throws SecurityException {
        if (!ALLOWED_PORTS.contains(port)) {
            throw new SecurityException("Port " + port + " not allowed");
        }
    }

    private int resolvePort(URL url) {
        int port = url.getPort();
        if (port == -1) {
            return url.getProtocol().equals("https") ? 443 : 80;
        }
        return port;
    }

    private boolean isIPAddress(String hostname) {
        return hostname.matches("^\\d{1,3}(\\.\\d{1,3}){3}$") ||
               hostname.contains(":"); // IPv6
    }

    private String sanitizeUrl(String url) {
        // Remove credentials and truncate for logging
        return url.replaceAll("//[^@]+@", "//***@")
                  .substring(0, Math.min(url.length(), 200));
    }

    private String executeRequest(Socket socket, URL url, WebhookRequest request,
                                  String requestId) throws IOException {
        // Implementation with proper HTTP handling
        // Set Host header to original hostname for virtual hosting
        // Apply response size limits
        // Handle redirects securely (re-validate each redirect URL)
        return "response";
    }
}

// Supporting classes
class IpRange {
    private final long start;
    private final long end;
    private final String hostname;

    public IpRange(String ip) {
        this.hostname = ip.toLowerCase();
        this.start = 0;
        this.end = 0;
    }

    public IpRange(String startIp, String endIp) {
        this.hostname = null;
        this.start = ipToLong(startIp);
        this.end = ipToLong(endIp);
    }

    public boolean contains(String ip) {
        if (hostname != null) {
            return ip.toLowerCase().contains(hostname);
        }
        long ipLong = ipToLong(ip);
        return ipLong >= start && ipLong <= end;
    }

    private static long ipToLong(String ip) {
        String[] parts = ip.split("\\.");
        if (parts.length != 4) return 0;
        long result = 0;
        for (int i = 0; i < 4; i++) {
            result = (result << 8) + Integer.parseInt(parts[i]);
        }
        return result;
    }
}

class WebhookRequest {
    private String url;
    private String userId;
    private Map<String, String> headers;

    public String getUrl() { return url; }
    public String getUserId() { return userId; }
    public Map<String, String> getHeaders() { return headers; }
}

class WebhookResult {
    private boolean success;
    private String response;
    private String error;
    private String requestId;

    public static WebhookResult success(String response, String requestId) {
        WebhookResult r = new WebhookResult();
        r.success = true;
        r.response = response;
        r.requestId = requestId;
        return r;
    }

    public static WebhookResult blocked(String reason, String requestId) {
        WebhookResult r = new WebhookResult();
        r.success = false;
        r.error = reason;
        r.requestId = requestId;
        return r;
    }

    public static WebhookResult error(String message, String requestId) {
        return blocked(message, requestId);
    }
}
