# Model inversion attack script
import requests
import numpy as np
from scipy.optimize import minimize

def model_inversion_attack(target_class, api_url):
    # Initialize random image
    reconstructed = np.random.rand(224, 224, 3)

    def loss_function(x):
        x_reshaped = x.reshape(1, 224, 224, 3).tolist()
        response = requests.post(api_url, json={'imageData': x_reshaped})
        probs = response.json()['predictions']
        # Minimize negative probability of target class
