```

**Why This Is Dangerous**:
- Full probability distributions allow attackers to use gradient-based optimization to reconstruct training samples
- No rate limiting enables thousands of queries needed for model inversion
- Exact confidence scores leak information about training data distribution
- No query monitoring means attacks go undetected

**SECURE VERSION**:

```javascript
const express = require('express');
const tf = require('@tensorflow/tfjs-node');
const rateLimit = require('express-rate-limit');
const crypto = require('crypto');

const app = express();
app.use(express.json());

let model;
const queryLog = new Map();

// Security configuration
const SECURITY_CONFIG = {
    topK: 3,  // Only return top K predictions
    confidenceThreshold: 0.1,  // Minimum confidence to return
    addNoise: true,
    noiseScale: 0.05,  // Differential privacy noise
    roundPrecision: 2  // Round confidence scores
};

// Rate limiting - critical for preventing model inversion
const apiLimiter = rateLimit({
    windowMs: 60 * 1000,  // 1 minute
    max: 10,  // 10 requests per minute per IP
    message: { error: 'Rate limit exceeded' },
    standardHeaders: true
});

// Add differential privacy noise
function addLaplaceNoise(value, scale) {
    const u = Math.random() - 0.5;
    return value + scale * Math.sign(u) * Math.log(1 - 2 * Math.abs(u));
}

// Secure prediction endpoint
app.post('/api/predict', apiLimiter, async (req, res) => {
    const clientId = req.ip;
    const { imageData } = req.body;

    // Input validation
    if (!Array.isArray(imageData) || imageData.length !== 1) {
        return res.status(400).json({ error: 'Invalid input format' });
    }

    try {
        const inputTensor = tf.tensor4d(imageData, [1, 224, 224, 3]);
        const predictions = model.predict(inputTensor);
        const probabilities = await predictions.array();

        // DEFENSE 1: Only return top-K predictions
        const probs = probabilities[0];
        const indexed = probs.map((p, i) => ({ class: i, confidence: p }));
        indexed.sort((a, b) => b.confidence - a.confidence);
        const topK = indexed.slice(0, SECURITY_CONFIG.topK);

        // DEFENSE 2: Add differential privacy noise
        const noisyResults = topK.map(item => ({
            class: item.class,
            confidence: Math.max(0, Math.min(1,
                addLaplaceNoise(item.confidence, SECURITY_CONFIG.noiseScale)
            ))
        }));

        // DEFENSE 3: Round confidence scores
        const roundedResults = noisyResults
            .filter(r => r.confidence >= SECURITY_CONFIG.confidenceThreshold)
            .map(r => ({
                class: r.class,
                confidence: Math.round(r.confidence * 100) / 100
            }));

        // DEFENSE 4: Log for anomaly detection
        logQuery(clientId, roundedResults);

        res.json({
            predictions: roundedResults,
            queryId: crypto.randomUUID()
        });

        inputTensor.dispose();
        predictions.dispose();

    } catch (error) {
        console.error('Prediction error:', error.message);
        res.status(500).json({ error: 'Prediction failed' });
    }
});

function logQuery(clientId, results) {
    if (!queryLog.has(clientId)) {
        queryLog.set(clientId, []);
    }
    queryLog.get(clientId).push({
        timestamp: Date.now(),
        results: results
    });
}
```

**Key Security Controls**:
- **Top-K filtering**: Only returns top 3 predictions, not full probability distribution, making gradient estimation much harder
- **Differential privacy noise**: Laplace mechanism adds calibrated noise that preserves utility while preventing exact reconstruction
- **Confidence rounding**: Reduces precision of outputs, limiting information leakage
- **Rate limiting**: 10 requests/minute prevents the thousands of queries needed for model inversion

