            suspicionScore += 50;
        }

        // Store current query for future analysis
        await this.redis.lpush(key, JSON.stringify({
            hash: inputHash,
            embedding: inputEmbedding,
            timestamp: Date.now()
        }));
        await this.redis.ltrim(key, 0, 999);
        await this.redis.expire(key, 86400);  // 24 hour retention

        return {
            suspicionScore,
            similarQueryCount,
            gradientPatternCount,
            isHighRisk: suspicionScore > 70
        };
    }

    cosineSimilarity(a, b) {
        if (!a || !b || a.length !== b.length) return 0;
        let dotProduct = 0, normA = 0, normB = 0;
        for (let i = 0; i < a.length; i++) {
            dotProduct += a[i] * b[i];
            normA += a[i] * a[i];
            normB += b[i] * b[i];
        }
        return dotProduct / (Math.sqrt(normA) * Math.sqrt(normB));
    }

    detectGradientPattern(current, previous) {
        // Detect small systematic perturbations typical of gradient attacks
        if (!current || !previous) return false;
        let smallPerturbations = 0;
        for (let i = 0; i < current.length; i++) {
            const diff = Math.abs(current[i] - previous[i]);
            if (diff > 0.001 && diff < 0.05) smallPerturbations++;
        }
        return smallPerturbations > current.length * 0.8;
    }
}

const inversionDetector = new ModelInversionDetector(redis);

// Authentication middleware
async function authenticateRequest(req, res, next) {
    const authHeader = req.headers.authorization;
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
        return res.status(401).json({ error: 'Authentication required' });
    }

    try {
        const token = authHeader.substring(7);
        const decoded = jwt.verify(token, process.env.JWT_SECRET);

        // Get customer tier from database/cache
        const customerData = await redis.hgetall(`customer:${decoded.customerId}`);
        if (!customerData || !customerData.tier) {
            return res.status(403).json({ error: 'Invalid customer' });
        }

        req.customer = {
            id: decoded.customerId,
            tier: customerData.tier,
            config: CUSTOMER_TIERS[customerData.tier]
        };

        next();
    } catch (error) {
        securityLogger.warn('Authentication failed', {
            ip: req.ip,
            error: error.message
        });
        return res.status(401).json({ error: 'Invalid token' });
    }
}

// Rate limiting per customer
async function customerRateLimit(req, res, next) {
    const { customer } = req;
    const minuteKey = `ratelimit:minute:${customer.id}`;
    const dailyKey = `ratelimit:daily:${customer.id}`;

    const [minuteCount, dailyCount] = await Promise.all([
        redis.incr(minuteKey),
        redis.incr(dailyKey)
    ]);

    // Set expiry on first increment
    if (minuteCount === 1) await redis.expire(minuteKey, 60);
    if (dailyCount === 1) await redis.expire(dailyKey, 86400);

    const batchSize = req.body.images?.length || 1;

    if (minuteCount > customer.config.rateLimitPerMinute) {
        securityLogger.warn('Rate limit exceeded', {
            customerId: customer.id,
            limit: 'minute'
        });
        return res.status(429).json({ error: 'Rate limit exceeded' });
    }

    if (dailyCount + batchSize > customer.config.dailyLimit) {
        return res.status(429).json({ error: 'Daily quota exceeded' });
    }

    next();
}

// Secure batch prediction endpoint
app.post('/api/v2/predict/batch',
    authenticateRequest,
    customerRateLimit,
    async (req, res) => {
        const { customer } = req;
        const { images } = req.body;
        const requestId = crypto.randomUUID();

        // Validate batch size
        if (!Array.isArray(images) || images.length === 0) {
            return res.status(400).json({ error: 'Images array required' });
        }

        if (images.length > customer.config.batchSize) {
            return res.status(400).json({
                error: `Batch size exceeds limit of ${customer.config.batchSize}`
            });
        }

        const startTime = Date.now();
        const results = [];
        let anomalyDetected = false;

        try {
            for (const imageData of images) {
                // Compute input hash and embedding for anomaly detection
                const inputHash = crypto
                    .createHash('sha256')
                    .update(JSON.stringify(imageData))
                    .digest('hex');

                const inputTensor = tf.tensor4d([imageData], [1, 224, 224, 3]);
                const inputEmbedding = await extractEmbedding(inputTensor);

                // Check for model inversion attack patterns
                const anomalyResult = await inversionDetector.analyzeQueryPattern(
                    customer.id,
                    inputHash,
                    inputEmbedding
                );

                if (anomalyResult.isHighRisk) {
                    anomalyDetected = true;
                    securityLogger.error('Potential model inversion attack detected', {
                        requestId,
                        customerId: customer.id,
                        suspicionScore: anomalyResult.suspicionScore,
                        similarQueries: anomalyResult.similarQueryCount,
                        gradientPatterns: anomalyResult.gradientPatternCount
                    });

                    // Increase noise for suspicious requests
                    customer.config = {
                        ...customer.config,
                        noiseScale: 0.3,
                        topK: 1
                    };
                }

                // Make prediction with security controls
                const predictions = model.predict(inputTensor);
                const probabilities = await predictions.array();

                const securedResult = applySecurityControls(
                    probabilities[0],
                    customer.config
                );

                results.push({
                    index: results.length,
                    predictions: securedResult
                });

                inputTensor.dispose();
                predictions.dispose();
            }

            // Audit log for all predictions
            securityLogger.info('Batch prediction completed', {
                requestId,
                customerId: customer.id,
                batchSize: images.length,
                processingTimeMs: Date.now() - startTime,
                anomalyDetected
            });

            res.json({
                requestId,
                results,
                metadata: {
                    processedAt: new Date().toISOString(),
                    quotaRemaining: await getQuotaRemaining(customer.id)
                }
            });

        } catch (error) {
            securityLogger.error('Prediction error', {
                requestId,
                customerId: customer.id,
                error: error.message
            });
            res.status(500).json({
                requestId,
                error: 'Prediction failed'
            });
        }
    }
);

function applySecurityControls(probabilities, config) {
    // Top-K filtering
    const indexed = probabilities.map((p, i) => ({ class: i, confidence: p }));
    indexed.sort((a, b) => b.confidence - a.confidence);
    const topK = indexed.slice(0, config.topK);

    // Apply differential privacy noise
    const noisy = topK.map(item => ({
        class: item.class,
        confidence: Math.max(0, Math.min(1,
            item.confidence + laplaceMechanism(config.noiseScale)
        ))
    }));

    // Round and filter
    return noisy
        .filter(r => r.confidence >= 0.05)
        .map(r => ({
            class: r.class,
            confidence: Math.round(r.confidence * 100) / 100
        }));
}

function laplaceMechanism(scale) {
    const u = Math.random() - 0.5;
    return scale * Math.sign(u) * Math.log(1 - 2 * Math.abs(u));
}

async function extractEmbedding(tensor) {
    // Extract intermediate layer for similarity comparison
    const embedding = await tensor.mean([1, 2]).array();
    return embedding[0];
}

async function getQuotaRemaining(customerId) {
    const used = await redis.get(`ratelimit:daily:${customerId}`) || 0;
    const tier = (await redis.hget(`customer:${customerId}`, 'tier')) || 'free';
    return CUSTOMER_TIERS[tier].dailyLimit - parseInt(used);
}
