go 1.21

require github.com/gorilla/mux v1.8.1
```

**go.sum with cryptographic verification**:
```text
github.com/gorilla/mux v1.8.1 h1:TuBL49tXwgrFYWhqrNgrUNEY92u81SPhu7sTdzQEiWY=
github.com/gorilla/mux v1.8.1/go.mod h1:AKf9I4AEqPTmMytcMc0KkNouC66V3BtZ4qD5fmWSiMQ=
```

**Key Security Controls**:
- **Verify package source**: Always check the official repository URL on pkg.go.dev before adding a dependency
- **Use go.sum**: The go.sum file contains cryptographic checksums that Go verifies automatically
- **Pin explicit versions**: Never use `latest` or floating versions in production

Protecting against supply chain attacks requires multiple layers of defense integrated into your development workflow. Here's a comprehensive approach used by organizations meeting SOC2 and FedRAMP compliance requirements.

**PRODUCTION PATTERN**:

```go
// scripts/dependency_audit.go
// Run this as part of CI/CD pipeline
package main

import (
	"bufio"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"os"
	"os/exec"
	"regexp"
	"strings"
	"time"
)

type DependencyAuditResult struct {
	Package        string   `json:"package"`
	Version        string   `json:"version"`
	RiskLevel      string   `json:"risk_level"`
	Issues         []string `json:"issues"`
	ApprovedHash   string   `json:"approved_hash"`
	CurrentHash    string   `json:"current_hash"`
	HashMatch      bool     `json:"hash_match"`
}

type AllowlistEntry struct {
	Package      string `json:"package"`
	Version      string `json:"version"`
	ApprovedBy   string `json:"approved_by"`
	ApprovalDate string `json:"approval_date"`
	ExpectedHash string `json:"expected_hash"`
}

var knownTrustedPrefixes = []string{
	"github.com/gorilla/",
	"github.com/gin-gonic/",
	"github.com/go-chi/",
	"golang.org/x/",
	"google.golang.org/",
	"github.com/stretchr/",
	"github.com/sirupsen/",
}

var commonTyposquats = map[string]string{
	"github.com/gorila/":     "github.com/gorilla/",
	"github.com/gorillla/":   "github.com/gorilla/",
	"github.com/gorrilla/":   "github.com/gorilla/",
	"github.com/gin-gonlc/":  "github.com/gin-gonic/",
	"github.com/go-chl/":     "github.com/go-chi/",
	"github.com/slrupsen/":   "github.com/sirupsen/",
	"github.com/stretchr-/":  "github.com/stretchr/",
}

func main() {
	log.Println("Starting dependency security audit...")

	// Step 1: Verify go.sum exists and is not tampered
	if err := verifyGoSum(); err != nil {
		log.Fatalf("CRITICAL: go.sum verification failed: %v", err)
	}

	// Step 2: Check for typosquatted packages
	issues, err := checkTyposquatting()
	if err != nil {
		log.Fatalf("Typosquatting check failed: %v", err)
	}
	if len(issues) > 0 {
		for _, issue := range issues {
			log.Printf("ALERT: Potential typosquat detected: %s (did you mean %s?)", 
				issue.Package, issue.Issues[0])
		}
		os.Exit(1)
	}

	// Step 3: Run govulncheck for known vulnerabilities
	if err := runVulnerabilityCheck(); err != nil {
		log.Fatalf("Vulnerability check failed: %v", err)
	}

	// Step 4: Verify against allowlist
	if err := verifyAllowlist(); err != nil {
		log.Fatalf("Allowlist verification failed: %v", err)
	}

	// Step 5: Check package ages and popularity
	checkPackageReputation()

	log.Println("Dependency audit completed successfully")
}

func verifyGoSum() error {
	// Ensure go.sum exists
	if _, err := os.Stat("go.sum"); os.IsNotExist(err) {
		return fmt.Errorf("go.sum file not found - run 'go mod tidy'")
	}

	// Verify module checksums
	cmd := exec.Command("go", "mod", "verify")
	output, err := cmd.CombinedOutput()
	if err != nil {
		return fmt.Errorf("module verification failed: %s", output)
	}

	log.Println("✓ go.sum verification passed")
	return nil
}

func checkTyposquatting() ([]DependencyAuditResult, error) {
	var issues []DependencyAuditResult

	file, err := os.Open("go.mod")
	if err != nil {
		return nil, err
	}
	defer file.Close()

	scanner := bufio.NewScanner(file)
	requireRegex := regexp.MustCompile(`^\s*(\S+)\s+v`)

	for scanner.Scan() {
		line := scanner.Text()
		if strings.HasPrefix(strings.TrimSpace(line), "//") {
			continue
		}

		matches := requireRegex.FindStringSubmatch(line)
		if len(matches) > 1 {
			pkg := matches[1]

			// Check against known typosquats
			for typo, correct := range commonTyposquats {
				if strings.HasPrefix(pkg, typo) {
					issues = append(issues, DependencyAuditResult{
						Package:   pkg,
						RiskLevel: "CRITICAL",
						Issues:    []string{correct},
					})
				}
			}

			// Check for suspicious patterns
			if isSuspiciousPackage(pkg) {
				issues = append(issues, DependencyAuditResult{
					Package:   pkg,
					RiskLevel: "HIGH",
					Issues:    []string{"Package name contains suspicious patterns"},
				})
			}
		}
	}

	log.Printf("✓ Typosquatting check completed: %d issues found", len(issues))
	return issues, nil
}

func isSuspiciousPackage(pkg string) bool {
	suspiciousPatterns := []string{
		"-official",
		"-secure",
		"-fixed",
		"_v2",
		"xgithub.com",
		"githuub.com",
		"githuh.com",
	}

	for _, pattern := range suspiciousPatterns {
		if strings.Contains(pkg, pattern) {
			return true
		}
	}
	return false
}

func runVulnerabilityCheck() error {
	cmd := exec.Command("govulncheck", "./...")
	output, err := cmd.CombinedOutput()
	if err != nil {
		// govulncheck exits non-zero if vulnerabilities found
		log.Printf("Vulnerability scan output:\n%s", output)
		return fmt.Errorf("vulnerabilities detected in dependencies")
	}

	log.Println("✓ No known vulnerabilities detected")
	return nil
}

func verifyAllowlist() error {
	allowlistFile := os.Getenv("DEPENDENCY_ALLOWLIST")
	if allowlistFile == "" {
		allowlistFile = ".dependency-allowlist.json"
	}

	if _, err := os.Stat(allowlistFile); os.IsNotExist(err) {
		log.Println("⚠ No allowlist file found - skipping allowlist verification")
		return nil
	}

	data, err := os.ReadFile(allowlistFile)
	if err != nil {
		return err
	}

	var allowlist []AllowlistEntry
	if err := json.Unmarshal(data, &allowlist); err != nil {
		return err
	}

	allowedPackages := make(map[string]AllowlistEntry)
	for _, entry := range allowlist {
		allowedPackages[entry.Package] = entry
	}

	// Get current dependencies
	cmd := exec.Command("go", "list", "-m", "all")
	output, err := cmd.Output()
	if err != nil {
		return err
	}

	scanner := bufio.NewScanner(strings.NewReader(string(output)))
	for scanner.Scan() {
		parts := strings.Fields(scanner.Text())
		if len(parts) >= 2 {
			pkg, version := parts[0], parts[1]

			// Skip main module
			if !strings.Contains(pkg, "/") {
				continue
			}

			// Check if trusted prefix
			trusted := false
			for _, prefix := range knownTrustedPrefixes {
				if strings.HasPrefix(pkg, prefix) {
					trusted = true
					break
				}
			}

			if !trusted {
				if _, ok := allowedPackages[pkg]; !ok {
					return fmt.Errorf("package %s@%s not in allowlist", pkg, version)
				}
			}
		}
	}

	log.Println("✓ All dependencies verified against allowlist")
	return nil
}

func checkPackageReputation() {
	log.Println("Checking package reputation metrics...")
	// In production, integrate with:
	// - pkg.go.dev API for package metadata
	// - GitHub API for repository age, stars, contributors
	// - Deps.dev API for security advisories
	log.Println("✓ Package reputation check completed")
}
