```

**Attack Scenario**:
```text
Sweet32 Birthday Attack:
1. Attacker captures ~32GB of encrypted traffic (2^32 blocks)
2. Due to 64-bit block size, birthday collision occurs
3. XOR of two plaintexts is revealed when blocks collide
4. Known plaintext allows recovery of sensitive data
5. DES 56-bit key can be brute-forced in <24 hours with specialized hardware
```

**Why This Is Dangerous**:
- 64-bit block size enables Sweet32 birthday attacks after ~32GB of data
- DES uses only 56-bit key (brute-forceable in hours)
- 3DES effectively provides only 112-bit security, not 168-bit
- Static IV reuse enables pattern analysis
- Hardcoded keys in source code are easily extracted
- NIST deprecated 3DES in 2017, disallowed after 2023

**SECURE VERSION**:

```csharp
using System;
using System.IO;
using System.Security.Cryptography;
using System.Text;
using Microsoft.Extensions.Configuration;

namespace SecureEncryption
{
    public class SecureEncryptionService
    {
        private readonly byte[] _masterKey;

        public SecureEncryptionService(IConfiguration configuration)
        {
            // Key loaded from secure configuration (Azure Key Vault, AWS KMS, etc.)
            string keyBase64 = configuration["Encryption:MasterKey"] 
                ?? throw new InvalidOperationException("Encryption key not configured");
            _masterKey = Convert.FromBase64String(keyBase64);

            if (_masterKey.Length != 32) // 256-bit key
                throw new ArgumentException("Key must be 256 bits (32 bytes)");
        }

        public string EncryptData(string plainText)
        {
            if (string.IsNullOrEmpty(plainText))
                throw new ArgumentNullException(nameof(plainText));

            using (Aes aes = Aes.Create())
            {
                aes.Key = _masterKey;
                aes.GenerateIV(); // CRITICAL: Fresh IV for every encryption
                aes.Mode = CipherMode.CBC;
                aes.Padding = PaddingMode.PKCS7;
                aes.KeySize = 256; // AES-256
                aes.BlockSize = 128; // 128-bit blocks (resistant to Sweet32)

                using (ICryptoTransform encryptor = aes.CreateEncryptor())
                {
                    byte[] plainBytes = Encoding.UTF8.GetBytes(plainText);
                    byte[] cipherBytes = encryptor.TransformFinalBlock(plainBytes, 0, plainBytes.Length);

                    // Prepend IV to ciphertext (IV can be public)
                    byte[] result = new byte[aes.IV.Length + cipherBytes.Length];
                    Buffer.BlockCopy(aes.IV, 0, result, 0, aes.IV.Length);
                    Buffer.BlockCopy(cipherBytes, 0, result, aes.IV.Length, cipherBytes.Length);

                    return Convert.ToBase64String(result);
                }
            }
        }

        public string DecryptData(string cipherText)
        {
            if (string.IsNullOrEmpty(cipherText))
                throw new ArgumentNullException(nameof(cipherText));

            byte[] fullCipher = Convert.FromBase64String(cipherText);

            using (Aes aes = Aes.Create())
            {
                aes.Key = _masterKey;
                aes.Mode = CipherMode.CBC;
                aes.Padding = PaddingMode.PKCS7;
                aes.KeySize = 256;
                aes.BlockSize = 128;

                // Extract IV from first 16 bytes
                byte[] iv = new byte[16];
                byte[] cipherBytes = new byte[fullCipher.Length - 16];
                Buffer.BlockCopy(fullCipher, 0, iv, 0, 16);
                Buffer.BlockCopy(fullCipher, 16, cipherBytes, 0, cipherBytes.Length);

                aes.IV = iv;

                using (ICryptoTransform decryptor = aes.CreateDecryptor())
                {
                    byte[] plainBytes = decryptor.TransformFinalBlock(cipherBytes, 0, cipherBytes.Length);
                    return Encoding.UTF8.GetString(plainBytes);
                }
            }
        }
    }
}
```

**Key Security Controls**:
- **AES-256 with 128-bit blocks**: Immune to Sweet32 attacks, requires 2^64 blocks for collision
- **Fresh IV per encryption**: Prevents pattern analysis and chosen-plaintext attacks
- **Key from secure configuration**: No hardcoded secrets, supports rotation
- **Input validation**: Prevents null reference and empty string issues

Excellent question! AES-CBC provides confidentiality but **NOT integrity or authenticity**. Without authentication, attackers can perform padding oracle attacks (like POODLE) or bit-flipping attacks to modify ciphertext. For production systems, you should use **Authenticated Encryption with Associated Data (AEAD)** - specifically AES-GCM.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.IO;
using System.Security.Cryptography;
using System.Text;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace Production.Security.Encryption
{
    public interface IEncryptionService
    {
        string Encrypt(string plainText, string associatedData = null);
        string Decrypt(string cipherText, string associatedData = null);
    }

    /// <summary>
    /// Production-ready AES-256-GCM authenticated encryption service.
    /// Provides confidentiality, integrity, and authenticity.
    /// </summary>
    public sealed class AesGcmEncryptionService : IEncryptionService, IDisposable
    {
        private readonly byte[] _masterKey;
        private readonly ILogger<AesGcmEncryptionService> _logger;
        private readonly int _nonceSize = 12; // 96 bits recommended for GCM
        private readonly int _tagSize = 16;   // 128 bits authentication tag
        private bool _disposed = false;

        public AesGcmEncryptionService(
            IConfiguration configuration, 
            ILogger<AesGcmEncryptionService> logger)
        {
            _logger = logger ?? throw new ArgumentNullException(nameof(logger));

            // Load key from secure key management (Azure Key Vault, AWS KMS, HashiCorp Vault)
            string keyBase64 = configuration["Security:Encryption:AesGcmKey"];
            if (string.IsNullOrEmpty(keyBase64))
            {
                _logger.LogCritical("Encryption key not configured - service cannot start");
                throw new InvalidOperationException("Encryption key not configured");
            }

            _masterKey = Convert.FromBase64String(keyBase64);
            ValidateKey(_masterKey);

            _logger.LogInformation("AES-GCM encryption service initialized");
        }

        private void ValidateKey(byte[] key)
        {
            if (key == null || key.Length != 32)
            {
                throw new CryptographicException("AES-256-GCM requires a 256-bit (32-byte) key");
            }
        }

        public string Encrypt(string plainText, string associatedData = null)
        {
            if (_disposed)
                throw new ObjectDisposedException(nameof(AesGcmEncryptionService));

            if (string.IsNullOrEmpty(plainText))
                throw new ArgumentNullException(nameof(plainText));

            try
            {
                byte[] plainBytes = Encoding.UTF8.GetBytes(plainText);
                byte[] aadBytes = string.IsNullOrEmpty(associatedData) 
                    ? Array.Empty<byte>() 
                    : Encoding.UTF8.GetBytes(associatedData);

                // Generate cryptographically secure random nonce
                byte[] nonce = new byte[_nonceSize];
                using (var rng = RandomNumberGenerator.Create())
                {
                    rng.GetBytes(nonce);
                }

                byte[] cipherText = new byte[plainBytes.Length];
                byte[] tag = new byte[_tagSize];

                using (var aesGcm = new AesGcm(_masterKey, _tagSize))
                {
                    aesGcm.Encrypt(nonce, plainBytes, cipherText, tag, aadBytes);
                }

                // Format: [nonce (12 bytes)][tag (16 bytes)][ciphertext]
                byte[] result = new byte[_nonceSize + _tagSize + cipherText.Length];
                Buffer.BlockCopy(nonce, 0, result, 0, _nonceSize);
                Buffer.BlockCopy(tag, 0, result, _nonceSize, _tagSize);
                Buffer.BlockCopy(cipherText, 0, result, _nonceSize + _tagSize, cipherText.Length);

                // Clear sensitive data from memory
                CryptographicOperations.ZeroMemory(plainBytes);

                return Convert.ToBase64String(result);
            }
            catch (CryptographicException ex)
            {
                _logger.LogError(ex, "Encryption failed - cryptographic error");
                throw new InvalidOperationException("Encryption operation failed", ex);
            }
        }

        public string Decrypt(string cipherText, string associatedData = null)
        {
            if (_disposed)
                throw new ObjectDisposedException(nameof(AesGcmEncryptionService));

            if (string.IsNullOrEmpty(cipherText))
                throw new ArgumentNullException(nameof(cipherText));

            try
            {
                byte[] fullCipher = Convert.FromBase64String(cipherText);

                if (fullCipher.Length < _nonceSize + _tagSize)
                {
                    _logger.LogWarning("Decryption failed - invalid ciphertext length");
                    throw new CryptographicException("Invalid ciphertext");
                }

                byte[] aadBytes = string.IsNullOrEmpty(associatedData) 
                    ? Array.Empty<byte>() 
                    : Encoding.UTF8.GetBytes(associatedData);

                // Extract components
                byte[] nonce = new byte[_nonceSize];
                byte[] tag = new byte[_tagSize];
                byte[] cipherBytes = new byte[fullCipher.Length - _nonceSize - _tagSize];

                Buffer.BlockCopy(fullCipher, 0, nonce, 0, _nonceSize);
                Buffer.BlockCopy(fullCipher, _nonceSize, tag, 0, _tagSize);
                Buffer.BlockCopy(fullCipher, _nonceSize + _tagSize, cipherBytes, 0, cipherBytes.Length);

                byte[] plainBytes = new byte[cipherBytes.Length];

                using (var aesGcm = new AesGcm(_masterKey, _tagSize))
                {
                    // This throws if authentication fails (tampering detected)
                    aesGcm.Decrypt(nonce, cipherBytes, tag, plainBytes, aadBytes);
                }

                string result = Encoding.UTF8.GetString(plainBytes);

                // Clear sensitive data from memory
                CryptographicOperations.ZeroMemory(plainBytes);

                return result;
            }
            catch (AuthenticationTagMismatchException)
            {
                _logger.LogWarning("Decryption failed - authentication tag mismatch (possible tampering)");
                throw new CryptographicException("Data integrity verification failed");
            }
            catch (CryptographicException ex)
            {
                _logger.LogError(ex, "Decryption failed - cryptographic error");
                throw new InvalidOperationException("Decryption operation failed", ex);
            }
        }

        public void Dispose()
        {
            if (!_disposed)
            {
                // Securely clear the master key from memory
                if (_masterKey != null)
                {
                    CryptographicOperations.ZeroMemory(_masterKey);
                }
                _disposed = true;
            }
        }
    }

    /// <summary>
    /// Key management utilities for secure key generation and rotation
    /// </summary>
    public static class KeyManagement
    {
        public static string GenerateAes256Key()
        {
            byte[] key = new byte[32]; // 256 bits
            using (var rng = RandomNumberGenerator.Create())
            {
                rng.GetBytes(key);
            }
            return Convert.ToBase64String(key);
        }

        public static bool ValidateKeyStrength(string keyBase64)
        {
            try
            {
                byte[] key = Convert.FromBase64String(keyBase64);
                return key.Length == 32;
            }
            catch
            {
                return false;
            }
        }
    }
}
```

**Defense in Depth Layers**:

1. **AES-256-GCM Authenticated Encryption**:
```csharp
// GCM mode provides:
// - Confidentiality (AES-256 encryption)
// - Integrity (128-bit authentication tag)
// - Authenticity (verifies data hasn't been tampered with)
using (var aesGcm = new AesGcm(_masterKey, _tagSize))
{
    aesGcm.Encrypt(nonce, plainBytes, cipherText, tag, aadBytes);
}
```

2. **Associated Data (AAD) for Context Binding**:
```csharp
// Bind ciphertext to specific context (user ID, timestamp, etc.)
string aad = $"{userId}:{DateTime.UtcNow:yyyy-MM-dd}";
string encrypted = encryptionService.Encrypt(sensitiveData, aad);

// Decryption fails if AAD doesn't match
string decrypted = encryptionService.Decrypt(encrypted, aad);
```

3. **Secure Memory Handling**:
```csharp
// Clear sensitive data immediately after use
byte[] plainBytes = Encoding.UTF8.GetBytes(plainText);
try
{
    // Use plainBytes...
}
finally
{
    CryptographicOperations.ZeroMemory(plainBytes);
}
```

**Additional Protections**:

- **Nonce uniqueness**: 96-bit random nonce with negligible collision probability for 2^32 messages per key
- **Key rotation support**: Service design supports key rotation via configuration reload
- **Constant-time operations**: Uses `CryptographicOperations` methods to prevent timing attacks
- **Fail-secure design**: All errors result in decryption failure, no partial data exposure
- **Audit logging**: All cryptographic operations logged for security monitoring
- **Memory protection**: Keys cleared from memory on disposal using `ZeroMemory`
- **FIPS compliance**: AES-GCM is FIPS 140-2 approved algorithm

Multi-tenant data isolation is critical - the 2023 Citrix ShareFile vulnerability (CVE-2023-24489) allowed attackers to access files from other tenants due to improper authorization checks, affecting hundreds of thousands of enterprise accounts.

**VULNERABLE CODE**:

```php
<?php
// WARNING: This code has critical multi-tenant isolation flaws

class DocumentController
{
    private $pdo;

    public function __construct($pdo)
    {
        $this->pdo = $pdo;
    }

    // VULNERABLE: No tenant isolation check
    public function getDocument($documentId)
    {
        // User can access ANY document by changing the ID
        $stmt = $this->pdo->prepare(
            "SELECT * FROM documents WHERE id = ?"
        );
        $stmt->execute([$documentId]);
        return $stmt->fetch(PDO::FETCH_ASSOC);
    }

    // VULNERABLE: Tenant ID from user input can be manipulated
    public function listDocuments($tenantId)
    {
        $stmt = $this->pdo->prepare(
            "SELECT * FROM documents WHERE tenant_id = ?"
        );
        $stmt->execute([$tenantId]);
        return $stmt->fetchAll(PDO::FETCH_ASSOC);
    }

    // VULNERABLE: Allows cross-tenant file sharing without validation
    public function shareDocument($documentId, $targetTenantId)
    {
        $stmt = $this->pdo->prepare(
            "INSERT INTO shared_documents (document_id, shared_with_tenant) VALUES (?, ?)"
        );
        return $stmt->execute([$documentId, $targetTenantId]);
    }
}

// Usage - attacker can manipulate parameters
$doc = $controller->getDocument($_GET['doc_id']);
$docs = $controller->listDocuments($_GET['tenant_id']);
```

**Attack Payload**:
```text
# Enumerate other tenant's documents by changing document ID
GET /api/documents?doc_id=1001
GET /api/documents?doc_id=1002
GET /api/documents?doc_id=1003

# Access another tenant's file list by changing tenant_id
GET /api/documents/list?tenant_id=competitor_corp

# IDOR attack - sequential ID enumeration
for id in {1..10000}; do curl "https://app.com/api/documents?doc_id=$id"; done
```

**Why This Is Dangerous**:
- No verification that the requesting user belongs to the document's tenant
- Tenant ID accepted from user input instead of server-side session
- Sequential/predictable document IDs enable enumeration attacks
- No audit trail for cross-tenant access attempts
- Shared documents bypass tenant boundaries entirely

**SECURE VERSION**:

```php
<?php

class SecureDocumentController
{
    private $pdo;
    private $logger;

    public function __construct(PDO $pdo, Logger $logger)
    {
        $this->pdo = $pdo;
        $this->logger = $logger;
    }

    /**
     * Get tenant ID from authenticated session - NEVER from user input
     */
    private function getCurrentTenantId(): string
    {
        if (!isset($_SESSION['authenticated']) || !$_SESSION['authenticated']) {
            throw new UnauthorizedException('Not authenticated');
        }
        return $_SESSION['tenant_id'];
    }

    /**
     * SECURE: Always filter by tenant from session
     */
    public function getDocument(string $documentId): ?array
    {
        $tenantId = $this->getCurrentTenantId();

        // CRITICAL: Always include tenant_id in WHERE clause
        $stmt = $this->pdo->prepare(
            "SELECT d.* FROM documents d 
             WHERE d.id = ? AND d.tenant_id = ?
             UNION
             SELECT d.* FROM documents d
             INNER JOIN shared_documents sd ON d.id = sd.document_id
             WHERE d.id = ? AND sd.shared_with_tenant = ?"
        );
        $stmt->execute([$documentId, $tenantId, $documentId, $tenantId]);
        $document = $stmt->fetch(PDO::FETCH_ASSOC);

        // Log access attempt for audit
        $this->logger->info('Document access', [
            'document_id' => $documentId,
            'tenant_id' => $tenantId,
            'user_id' => $_SESSION['user_id'],
            'success' => $document !== false,
            'ip' => $_SERVER['REMOTE_ADDR']
        ]);

        if (!$document) {
            throw new ForbiddenException('Document not found or access denied');
        }

        return $document;
    }

    /**
     * SECURE: List only current tenant's documents
     */
    public function listDocuments(): array
    {
        $tenantId = $this->getCurrentTenantId();

        $stmt = $this->pdo->prepare(
            "SELECT * FROM documents WHERE tenant_id = ?"
        );
        $stmt->execute([$tenantId]);
        return $stmt->fetchAll(PDO::FETCH_ASSOC);
    }
}
```

**Key Security Controls**:
- **Tenant ID from session only**: Never accept tenant_id from user input; always derive from authenticated session
- **Compound query filters**: Every query includes tenant_id filter alongside resource ID
- **Audit logging**: All access attempts logged with tenant context for security monitoring
- **Fail-closed design**: Missing or invalid tenant context throws exception rather than defaulting

Hierarchical tenants and cross-tenant admin access are where most multi-tenant vulnerabilities occur. The 2024 Salesforce Communities data exposure incidents showed how misconfigured guest access and admin permissions led to unauthorized data access across organizations.

**PRODUCTION PATTERN**:

```php
<?php

declare(strict_types=1);

namespace App\Security;

use PDO;
use Psr\Log\LoggerInterface;

class TenantSecurityContext
{
    private PDO $pdo;
    private LoggerInterface $logger;
    private LoggerInterface $auditLogger;
    private array $tenantHierarchyCache = [];

    public function __construct(
        PDO $pdo,
        LoggerInterface $logger,
        LoggerInterface $auditLogger
    ) {
        $this->pdo = $pdo;
        $this->logger = $logger;
        $this->auditLogger = $auditLogger;
    }

    /**
     * Get all tenant IDs the current user can access
     * Includes: own tenant, child tenants (if parent), cross-tenant access grants
     */
    public function getAccessibleTenantIds(): array
    {
        $currentTenantId = $this->getCurrentTenantId();
        $userId = $this->getCurrentUserId();
        $accessibleTenants = [$currentTenantId];

        // Check for hierarchical access (parent can see children)
        if ($this->hasRole('TENANT_ADMIN')) {
            $childTenants = $this->getChildTenants($currentTenantId);
            $accessibleTenants = array_merge($accessibleTenants, $childTenants);
        }

        // Check for explicit cross-tenant grants (support staff)
        if ($this->hasRole('SUPPORT_ADMIN')) {
            $grantedTenants = $this->getExplicitTenantGrants($userId);
            $accessibleTenants = array_merge($accessibleTenants, $grantedTenants);
        }

        return array_unique($accessibleTenants);
    }

    /**
     * Verify access to a specific resource with full audit trail
     */
    public function verifyResourceAccess(
        string $resourceType,
        string $resourceId,
        string $action = 'read'
    ): bool {
        $startTime = microtime(true);
        $accessGranted = false;
        $denyReason = 'Unknown';

        try {
            // Step 1: Get resource's tenant
            $resourceTenant = $this->getResourceTenant($resourceType, $resourceId);

            if ($resourceTenant === null) {
                $denyReason = 'Resource not found';
                return false;
            }

            // Step 2: Check if user's accessible tenants include resource tenant
            $accessibleTenants = $this->getAccessibleTenantIds();

            if (!in_array($resourceTenant, $accessibleTenants, true)) {
                $denyReason = 'Tenant mismatch';
                $this->logSecurityEvent('CROSS_TENANT_ACCESS_ATTEMPT', [
                    'resource_type' => $resourceType,
                    'resource_id' => $resourceId,
                    'resource_tenant' => $resourceTenant,
                    'user_tenant' => $this->getCurrentTenantId(),
                    'severity' => 'HIGH'
                ]);
                return false;
            }

            // Step 3: Check action-specific permissions
            $accessGranted = $this->checkActionPermission(
                $resourceType,
                $resourceId,
                $action,
                $resourceTenant
            );

            if (!$accessGranted) {
                $denyReason = 'Insufficient permissions for action';
            }

            return $accessGranted;

        } finally {
            // Always log access decision for audit
            $this->auditLogger->info('Resource access check', [
                'resource_type' => $resourceType,
                'resource_id' => $resourceId,
                'action' => $action,
                'user_id' => $this->getCurrentUserId(),
                'tenant_id' => $this->getCurrentTenantId(),
                'access_granted' => $accessGranted,
                'deny_reason' => $accessGranted ? null : $denyReason,
                'duration_ms' => (microtime(true) - $startTime) * 1000,
                'ip_address' => $_SERVER['REMOTE_ADDR'] ?? 'unknown',
                'user_agent' => $_SERVER['HTTP_USER_AGENT'] ?? 'unknown',
                'timestamp' => date('c')
            ]);
        }
    }

    /**
     * Get child tenants with cycle detection
     */
    private function getChildTenants(string $parentTenantId, int $maxDepth = 5): array
    {
        if (isset($this->tenantHierarchyCache[$parentTenantId])) {
            return $this->tenantHierarchyCache[$parentTenantId];
        }

        $children = [];
        $toProcess = [$parentTenantId];
        $processed = [];
        $depth = 0;

        while (!empty($toProcess) && $depth < $maxDepth) {
            $currentId = array_shift($toProcess);

            // Prevent infinite loops from circular references
            if (in_array($currentId, $processed, true)) {
                $this->logger->warning('Circular tenant hierarchy detected', [
                    'parent' => $parentTenantId,
                    'circular_at' => $currentId
                ]);
                continue;
            }
            $processed[] = $currentId;

            $stmt = $this->pdo->prepare(
                "SELECT id FROM tenants WHERE parent_tenant_id = ? AND status = 'active'"
            );
            $stmt->execute([$currentId]);
            $childIds = $stmt->fetchAll(PDO::FETCH_COLUMN);

            foreach ($childIds as $childId) {
                $children[] = $childId;
                $toProcess[] = $childId;
            }
            $depth++;
        }

        $this->tenantHierarchyCache[$parentTenantId] = $children;
        return $children;
    }

    /**
     * Time-limited cross-tenant access grants for support
     */
    private function getExplicitTenantGrants(string $userId): array
    {
        $stmt = $this->pdo->prepare(
            "SELECT target_tenant_id FROM cross_tenant_grants 
             WHERE user_id = ? 
             AND expires_at > NOW() 
             AND revoked_at IS NULL
             AND approved_by IS NOT NULL"
        );
        $stmt->execute([$userId]);
        return $stmt->fetchAll(PDO::FETCH_COLUMN);
    }

    /**
     * Grant temporary cross-tenant access with approval workflow
     */
    public function grantCrossTenantAccess(
        string $targetUserId,
        string $targetTenantId,
        string $reason,
        int $durationHours = 4
    ): string {
        // Verify granter has permission
        if (!$this->hasRole('SECURITY_ADMIN')) {
            throw new ForbiddenException('Only Security Admins can grant cross-tenant access');
        }

        // Maximum duration limit
        $maxHours = 24;
        $durationHours = min($durationHours, $maxHours);

        $grantId = bin2hex(random_bytes(16));
        $expiresAt = date('Y-m-d H:i:s', strtotime("+{$durationHours} hours"));

        $stmt = $this->pdo->prepare(
            "INSERT INTO cross_tenant_grants 
             (id, user_id, target_tenant_id, granted_by, approved_by, reason, expires_at, created_at)
             VALUES (?, ?, ?, ?, ?, ?, ?, NOW())"
        );
        $stmt->execute([
            $grantId,
            $targetUserId,
            $targetTenantId,
            $this->getCurrentUserId(),
            $this->getCurrentUserId(), // Self-approval for security admins
            $reason,
            $expiresAt
        ]);

        // Critical security event - always log
        $this->logSecurityEvent('CROSS_TENANT_ACCESS_GRANTED', [
            'grant_id' => $grantId,
            'target_user' => $targetUserId,
            'target_tenant' => $targetTenantId,
            'granted_by' => $this->getCurrentUserId(),
            'reason' => $reason,
            'expires_at' => $expiresAt,
            'severity' => 'HIGH'
        ]);

        // Notify tenant admin and security team
        $this->notifySecurityTeam('Cross-tenant access granted', [
            'grant_id' => $grantId,
            'target_tenant' => $targetTenantId
        ]);

        return $grantId;
    }

    private function logSecurityEvent(string $eventType, array $context): void
    {
        $this->auditLogger->warning($eventType, array_merge($context, [
            'event_type' => $eventType,
            'timestamp' => date('c'),
            'ip_address' => $_SERVER['REMOTE_ADDR'] ?? 'unknown'
        ]));
    }

    private function getCurrentTenantId(): string
    {
        if (empty($_SESSION['tenant_id'])) {
            throw new UnauthorizedException('No tenant context');
        }
        return $_SESSION['tenant_id'];
    }

    private function getCurrentUserId(): string
    {
        if (empty($_SESSION['user_id'])) {
            throw new UnauthorizedException('Not authenticated');
        }
        return $_SESSION['user_id'];
    }

    private function hasRole(string $role): bool
    {
        return in_array($role, $_SESSION['roles'] ?? [], true);
    }
}
