class TenantAwareRepository
{
    protected function baseQuery(): string
    {
        return "WHERE tenant_id = ?";
    }

    protected function getTenantParams(): array
    {
        return [$this->securityContext->getCurrentTenantId()];
    }

    public function find(string $id): ?array
    {
        $sql = "SELECT * FROM {$this->table} " . 
               $this->baseQuery() . " AND id = ?";
        $params = array_merge($this->getTenantParams(), [$id]);

