**Why This Is Dangerous**:
- Raw probability scores with high precision enable membership inference attacks
- Gradient exposure allows attackers to reconstruct training data
- Model architecture exposure enables model stealing and targeted attacks
- No rate limiting allows automated extraction campaigns

**SECURE VERSION**:

```javascript
const express = require('express');
const tf = require('@tensorflow/tfjs-node');
const crypto = require('crypto');

const app = express();
app.use(express.json());

let model;
const CONFIDENCE_PRECISION = 2;  // Limit decimal places
const CONFIDENCE_THRESHOLD = 0.6;  // Minimum confidence to return
const NOISE_SCALE = 0.05;  // Differential privacy noise

async function loadModel() {
  model = await tf.loadLayersModel('file://./models/classifier/model.json');
}

// Add calibrated noise for differential privacy
function addDifferentialPrivacyNoise(value, epsilon = 1.0) {
  const sensitivity = 1.0;
  const scale = sensitivity / epsilon;
  // Laplace noise
  const u = Math.random() - 0.5;
  const noise = -scale * Math.sign(u) * Math.log(1 - 2 * Math.abs(u));
  return value + noise;
}

// Discretize confidence to bins
function discretizeConfidence(confidence) {
  if (confidence >= 0.9) return 'very_high';
  if (confidence >= 0.7) return 'high';
  if (confidence >= 0.5) return 'medium';
  return 'low';
}

// SECURE: Protected prediction endpoint
app.post('/api/predict', async (req, res) => {
  const { inputData } = req.body;

  // Input validation
  if (!Array.isArray(inputData) || inputData.length !== 784) {
    return res.status(400).json({ error: 'Invalid input dimensions' });
  }

  const tensor = tf.tensor2d([inputData]);
  const prediction = model.predict(tensor);
  const probabilities = await prediction.array();

  const topClass = probabilities[0].indexOf(Math.max(...probabilities[0]));
  let confidence = probabilities[0][topClass];

  // DEFENSE 1: Add differential privacy noise
  confidence = addDifferentialPrivacyNoise(confidence);
  confidence = Math.max(0, Math.min(1, confidence));  // Clamp to [0,1]

  // DEFENSE 2: Limit precision
  confidence = parseFloat(confidence.toFixed(CONFIDENCE_PRECISION));

  // DEFENSE 3: Threshold low-confidence predictions
  if (confidence < CONFIDENCE_THRESHOLD) {
    return res.json({
      prediction: 'uncertain',
      confidence_level: 'low',
      request_id: crypto.randomUUID()
    });
  }

  // DEFENSE 4: Return discretized confidence only
  res.json({
    predicted_class: topClass,
    confidence_level: discretizeConfidence(confidence),
    request_id: crypto.randomUUID()
  });

  tensor.dispose();
  prediction.dispose();
});

// NO gradient endpoint exposed
// NO model architecture endpoint

app.listen(3000);
```

**Key Security Controls**:
- **Differential Privacy Noise**: Adds calibrated Laplace noise to outputs, preventing precise inference attacks while maintaining utility
- **Confidence Discretization**: Returns categorical confidence levels instead of precise probabilities, blocking gradient estimation
- **Precision Limiting**: Truncates decimal places to reduce information leakage
- **Threshold Filtering**: Withholds low-confidence predictions that are more vulnerable to membership inference

Membership inference is a critical concern for medical ML systems and can violate HIPAA. Attackers exploit the fact that models behave differently on training data versus unseen data. For healthcare, you need multiple defense layers including differential privacy, output perturbation, and query auditing.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const tf = require('@tensorflow/tfjs-node');
const crypto = require('crypto');
const Redis = require('ioredis');
const winston = require('winston');

const app = express();
app.use(express.json());

// Secure logging configuration
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'ml-audit.log' })
  ]
});

const redis = new Redis(process.env.REDIS_URL);

// Privacy configuration
const PRIVACY_CONFIG = {
  epsilon: 0.1,              // Strong differential privacy
  queryBudgetPerUser: 100,   // Daily query limit per user
  minResponseDelay: 100,     // Prevent timing attacks
  maxResponseDelay: 500,
  outputBins: ['negative', 'uncertain', 'positive'],
  enableAuditLog: true,
  membershipProtectionLevel: 'high'
};

class MembershipInferenceProtection {
  constructor(model, config) {
    this.model = model;
    this.config = config;
    this.queryHistory = new Map();
  }

  // Differential privacy with Gaussian mechanism
  addGaussianNoise(value, sensitivity = 1.0) {
    const sigma = sensitivity * Math.sqrt(2 * Math.log(1.25 / 0.00001)) / this.config.epsilon;
    let noise = 0;
    for (let i = 0; i < 12; i++) {
      noise += Math.random();
    }
    noise = (noise - 6) * sigma;
    return value + noise;
  }

  // Temperature scaling to reduce overconfidence
  applyTemperatureScaling(logits, temperature = 2.0) {
    return logits.map(l => l / temperature);
  }

  // Softmax with temperature
  softmaxWithTemperature(logits, temperature = 2.0) {
    const scaled = this.applyTemperatureScaling(logits, temperature);
    const maxLogit = Math.max(...scaled);
    const expScores = scaled.map(l => Math.exp(l - maxLogit));
    const sumExp = expScores.reduce((a, b) => a + b, 0);
    return expScores.map(e => e / sumExp);
  }

  // Label smoothing defense
  smoothPrediction(prediction, smoothingFactor = 0.1) {
    const numClasses = prediction.length;
    return prediction.map(p => 
      (1 - smoothingFactor) * p + smoothingFactor / numClasses
    );
  }

  // Detect potential membership inference probing
  async detectMembershipProbing(userId, inputHash) {
    const key = `mi_probe:${userId}`;
    const recentQueries = await redis.lrange(key, 0, 49);

    // Check for repeated similar queries
    const similarCount = recentQueries.filter(q => {
      const parsed = JSON.parse(q);
      return this.computeSimilarity(parsed.hash, inputHash) > 0.95;
    }).length;

    if (similarCount > 5) {
      logger.warn({
        event: 'potential_membership_inference',
        userId,
        similarQueryCount: similarCount,
        timestamp: new Date().toISOString()
      });
      return true;
    }

    // Store query hash
    await redis.lpush(key, JSON.stringify({
      hash: inputHash,
      timestamp: Date.now()
    }));
    await redis.ltrim(key, 0, 49);
    await redis.expire(key, 3600);

    return false;
  }

  computeSimilarity(hash1, hash2) {
    // Simple hash similarity (in production use better metrics)
    let matches = 0;
    for (let i = 0; i < Math.min(hash1.length, hash2.length); i++) {
      if (hash1[i] === hash2[i]) matches++;
    }
    return matches / Math.max(hash1.length, hash2.length);
  }

  async protectedPredict(inputData, userId) {
    const requestId = crypto.randomUUID();
    const inputHash = crypto.createHash('sha256')
      .update(JSON.stringify(inputData)).digest('hex');

    // Check privacy budget
    const budgetKey = `budget:${userId}:${new Date().toISOString().split('T')[0]}`;
    const queriesUsed = await redis.incr(budgetKey);
    await redis.expire(budgetKey, 86400);

    if (queriesUsed > this.config.queryBudgetPerUser) {
      logger.warn({
        event: 'privacy_budget_exceeded',
        userId,
        requestId,
        timestamp: new Date().toISOString()
      });
      throw new Error('Daily query limit exceeded');
    }

    // Detect membership inference attempts
    const probingDetected = await this.detectMembershipProbing(userId, inputHash);
    if (probingDetected) {
      // Return random response to poison attack
      return {
        prediction: this.config.outputBins[
          Math.floor(Math.random() * this.config.outputBins.length)
        ],
        request_id: requestId,
        note: 'Result may be affected by rate limiting'
      };
    }

    // Get raw prediction
    const tensor = tf.tensor2d([inputData]);
    const rawPrediction = await this.model.predict(tensor).array();
    const logits = rawPrediction[0];

    // DEFENSE 1: Temperature scaling
    const calibratedProbs = this.softmaxWithTemperature(logits, 2.5);

    // DEFENSE 2: Label smoothing
    const smoothedProbs = this.smoothPrediction(calibratedProbs, 0.15);

    // DEFENSE 3: Differential privacy noise
    const noisyProbs = smoothedProbs.map(p => 
      Math.max(0, Math.min(1, this.addGaussianNoise(p, 0.1)))
    );

    // Renormalize
    const sum = noisyProbs.reduce((a, b) => a + b, 0);
    const normalizedProbs = noisyProbs.map(p => p / sum);

    // DEFENSE 4: Discretize output
    const maxIdx = normalizedProbs.indexOf(Math.max(...normalizedProbs));
    const maxProb = normalizedProbs[maxIdx];

    let confidenceLevel;
    if (maxProb > 0.7) confidenceLevel = 'high';
    else if (maxProb > 0.5) confidenceLevel = 'moderate';
    else confidenceLevel = 'low';

    // Audit logging (no PHI)
    if (this.config.enableAuditLog) {
      logger.info({
        event: 'prediction_served',
        requestId,
        userId: crypto.createHash('sha256').update(userId).digest('hex').slice(0, 16),
        predictionClass: maxIdx,
        privacyBudgetRemaining: this.config.queryBudgetPerUser - queriesUsed,
        timestamp: new Date().toISOString()
      });
    }

    tensor.dispose();

    return {
      prediction: this.config.outputBins[maxIdx],
      confidence_level: confidenceLevel,
      request_id: requestId,
      privacy_budget_remaining: this.config.queryBudgetPerUser - queriesUsed
    };
  }
}

let miProtection;

async function initializeModel() {
  const model = await tf.loadLayersModel('file://./models/medical/model.json');
  miProtection = new MembershipInferenceProtection(model, PRIVACY_CONFIG);
}

// Add random delay to prevent timing attacks
function addTimingNoise() {
  return new Promise(resolve => {
    const delay = PRIVACY_CONFIG.minResponseDelay + 
      Math.random() * (PRIVACY_CONFIG.maxResponseDelay - PRIVACY_CONFIG.minResponseDelay);
    setTimeout(resolve, delay);
  });
}

// Secure prediction endpoint
app.post('/api/medical/predict', async (req, res) => {
  const startTime = Date.now();
  const userId = req.headers['x-user-id'];

  if (!userId) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const { features } = req.body;

    // Input validation
    if (!Array.isArray(features) || features.some(f => typeof f !== 'number')) {
      return res.status(400).json({ error: 'Invalid input format' });
    }

    const result = await miProtection.protectedPredict(features, userId);

    // Add timing noise
    await addTimingNoise();

    res.json(result);
  } catch (error) {
    logger.error({
      event: 'prediction_error',
      error: error.message,
      userId: crypto.createHash('sha256').update(userId).digest('hex').slice(0, 16),
      timestamp: new Date().toISOString()
    });

    // Consistent error response time
    await addTimingNoise();
    res.status(429).json({ error: 'Request could not be processed' });
  }
});

initializeModel().then(() => {
  app.listen(3000, () => console.log('Secure ML API running'));
});
```

