**Key Security Controls**:
- **Authentication enforcement**: Every resolver checks `isAuthenticated()` before proceeding
- **Authorization at resolver level**: `canAccessUser()` validates the requester has permission to access the target resource
- **Field-level authorization**: Sensitive fields like `salary` have individual resolvers that check permissions
- **Sensitive field removal**: `password_hash` and `ssn` are never exposed in the GraphQL schema
- **Audit logging**: Authorization violations are logged for security monitoring

Excellent question! Nested query authorization bypass is one of the most dangerous GraphQL vulnerabilities. Attackers exploit relationship traversals to access data they shouldn't have permission to see. This was exactly how CVE-2023-2825 in GitLab worked.

**PRODUCTION PATTERN**:

```php
<?php
require_once 'vendor/autoload.php';

use GraphQL\GraphQL;
use GraphQL\Type\Definition\ObjectType;
use GraphQL\Type\Definition\Type;
use GraphQL\Type\Definition\ResolveInfo;
use GraphQL\Error\UserError;
use GraphQL\Validator\Rules\QueryComplexity;
use GraphQL\Validator\Rules\QueryDepth;
use GraphQL\Validator\DocumentValidator;

/**
 * Production-grade GraphQL Authorization System
 * Implements defense-in-depth against authorization bypass attacks
 */

class GraphQLAuthorizationMiddleware {
    private $policies = [];
    private $auditLogger;

    public function __construct(AuditLogger $auditLogger) {
        $this->auditLogger = $auditLogger;
    }

    public function registerPolicy(string $typeName, string $fieldName, callable $policy): void {
        $this->policies[$typeName][$fieldName] = $policy;
    }

    public function authorize(
        string $typeName,
        string $fieldName,
        $rootValue,
        array $args,
        AuthContext $context
    ): bool {
        // Check type-level policy
        if (isset($this->policies[$typeName]['*'])) {
            if (!$this->policies[$typeName]['*']($rootValue, $args, $context)) {
                $this->logViolation($typeName, '*', $context);
                return false;
            }
        }

        // Check field-level policy
        if (isset($this->policies[$typeName][$fieldName])) {
            if (!$this->policies[$typeName][$fieldName]($rootValue, $args, $context)) {
                $this->logViolation($typeName, $fieldName, $context);
                return false;
            }
        }

        return true;
    }

    private function logViolation(string $type, string $field, AuthContext $context): void {
        $this->auditLogger->log('graphql_auth_violation', [
            'user_id' => $context->user,
            'type' => $type,
            'field' => $field,
            'ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown',
            'timestamp' => date('c'),
            'session_id' => session_id()
        ]);
    }
}

class SecureGraphQLExecutor {
    private $schema;
    private $authMiddleware;
    private $rateLimiter;

    public function __construct(
        Schema $schema,
        GraphQLAuthorizationMiddleware $authMiddleware,
        RateLimiter $rateLimiter
    ) {
        $this->schema = $schema;
        $this->authMiddleware = $authMiddleware;
        $this->rateLimiter = $rateLimiter;

        // SECURITY: Set query complexity and depth limits
        DocumentValidator::addRule(new QueryComplexity(100));
        DocumentValidator::addRule(new QueryDepth(5));
    }

    public function execute(string $query, ?array $variables, AuthContext $context): array {
        // SECURITY: Rate limiting per user
        if (!$this->rateLimiter->allowRequest($context->user, 'graphql', 100, 60)) {
            throw new UserError('Rate limit exceeded. Please try again later.');
        }

        // SECURITY: Query allow-listing in production
        if (getenv('APP_ENV') === 'production') {
            $queryHash = hash('sha256', $query);
            if (!$this->isAllowedQuery($queryHash)) {
                $this->logSuspiciousQuery($query, $context);
                throw new UserError('Query not permitted');
            }
        }

        $result = GraphQL::executeQuery(
            $this->schema,
            $query,
            null,
            $context,
            $variables
        );

        return $result->toArray();
    }

    private function isAllowedQuery(string $hash): bool {
        $allowedQueries = require 'config/allowed_queries.php';
