        error_log(json_encode([
            'event' => 'suspicious_graphql_query',
            'user_id' => $context->user,
            'query_preview' => substr($query, 0, 500),
            'ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown'
        ]));
    }
