    public function createPostType(): ObjectType {
        return new ObjectType([
            'name' => 'Post',
            'fields' => function() {
                return [
                    'id' => Type::int(),
                    'title' => Type::string(),
                    'content' => Type::string(),
                    // CRITICAL: This is the dangerous relationship
                    'author' => [
                        'type' => $this->createUserType(),
                        'resolve' => $this->wrapResolver('Post', 'author', function($post, $args, $context) {
                            // SECURITY: Re-authorize access to user through post->author
                            $authorId = $post['author_id'];

                            // Check if current user can access this author's data
                            if (!$context->canAccessUser($authorId)) {
                                // Return limited public profile only
                                return $this->getPublicProfile($authorId);
                            }

                            return $this->getFullProfile($authorId);
                        })
                    ]
                ];
            }
        ]);
    }

    private function wrapResolver(string $type, string $field, callable $resolver): callable {
        return function($root, $args, $context, $info) use ($type, $field, $resolver) {
            // SECURITY: Check authorization before every field resolution
            if (!$this->authMiddleware->authorize($type, $field, $root, $args, $context)) {
                throw new UserError('Access denied');
            }

            return $resolver($root, $args, $context, $info);
        };
    }

    private function getPublicProfile(int $userId): array {
        // Return only public fields
        return [
            'id' => $userId,
            'name' => 'User ' . $userId,
            'email' => null  // Hidden
        ];
    }

    private function getFullProfile(int $userId): array {
        // Fetch full user data from database
        global $pdo;
        $stmt = $pdo->prepare("SELECT id, name, email FROM users WHERE id = ?");
        $stmt->execute([$userId]);
        return $stmt->fetch(PDO::FETCH_ASSOC);
