Using timestamps or any predictable pattern for session IDs is extremely dangerous and allows attackers to hijack user sessions. This vulnerability was exploited in CVE-2022-42252 and similar attacks against thousands of applications.

**VULNERABLE CODE**:

```java
import javax.servlet.http.*;
import java.util.Date;
import java.util.HashMap;
import java.util.Map;

public class InsecureSessionManager {
    private static Map<String, UserSession> activeSessions = new HashMap<>();
    private static long sessionCounter = 0;

    // VULNERABLE: Predictable session ID generation
    public String createSession(String username) {
        // Using timestamp - completely predictable
        String sessionId = "SESSION_" + System.currentTimeMillis();

        // Alternative bad pattern: sequential counter
        // String sessionId = "SESSION_" + (++sessionCounter);

        // Alternative bad pattern: username-based
        // String sessionId = "SESSION_" + username.hashCode();

        UserSession session = new UserSession(username, sessionId);
        activeSessions.put(sessionId, session);

        return sessionId;
    }

    public UserSession getSession(String sessionId) {
        return activeSessions.get(sessionId);
    }

    public boolean isValidSession(String sessionId) {
        return activeSessions.containsKey(sessionId);
    }
}

class UserSession {
    private String username;
    private String sessionId;
    private long createdAt;

    public UserSession(String username, String sessionId) {
        this.username = username;
        this.sessionId = sessionId;
        this.createdAt = System.currentTimeMillis();
    }

    public String getUsername() { return username; }
    public String getSessionId() { return sessionId; }
}
```

**Attack Payload**:
```bash
# Enumerate timestamp-based session IDs
# If login happened around 1704825600000 (specific timestamp)
for i in {1704825600000..1704825601000}; do
  curl -H "Cookie: SESSIONID=SESSION_$i" https://target.com/api/profile
done

# Sequential ID enumeration
for i in {1..10000}; do
  curl -H "Cookie: SESSIONID=SESSION_$i" https://target.com/api/profile
done
```

**Why This Is Dangerous**:
- Timestamp-based IDs can be guessed within milliseconds of login time
- Sequential counters allow attackers to enumerate all valid sessions
- Username-based hashes are deterministic and reproducible
- Attackers can hijack ANY user session including administrators
- No server-side entropy means session prediction is trivial

**SECURE VERSION**:

```java
import javax.servlet.http.*;
import java.security.SecureRandom;
import java.util.Base64;
import java.util.concurrent.ConcurrentHashMap;
import java.util.Map;
import java.time.Instant;
import java.util.logging.Logger;

public class SecureSessionManager {
    private static final Logger logger = Logger.getLogger(SecureSessionManager.class.getName());
    private static final SecureRandom secureRandom = new SecureRandom();
    private static final int SESSION_ID_LENGTH = 32; // 256 bits of entropy
    private static final long SESSION_TIMEOUT_MS = 30 * 60 * 1000; // 30 minutes

    private final Map<String, SecureUserSession> activeSessions = new ConcurrentHashMap<>();

    // SECURE: Cryptographically random session ID generation
    public String createSession(String username, HttpServletRequest request) {
        // Generate cryptographically secure random session ID
        byte[] randomBytes = new byte[SESSION_ID_LENGTH];
        secureRandom.nextBytes(randomBytes);
        String sessionId = Base64.getUrlEncoder().withoutPadding().encodeToString(randomBytes);

        // Create session with security metadata
        SecureUserSession session = new SecureUserSession(
            username,
            sessionId,
            request.getRemoteAddr(),
            request.getHeader("User-Agent")
        );

        // Store session securely
        activeSessions.put(sessionId, session);

        // Audit log session creation (never log session ID)
        logger.info(String.format("Session created for user: %s from IP: %s", 
            username, request.getRemoteAddr()));

        return sessionId;
    }

    public SecureUserSession validateSession(String sessionId, HttpServletRequest request) {
        if (sessionId == null || sessionId.length() < SESSION_ID_LENGTH) {
            logger.warning("Invalid session ID format attempted");
            return null;
        }

        SecureUserSession session = activeSessions.get(sessionId);

        if (session == null) {
            return null;
        }

        // Check session expiration
        if (session.isExpired(SESSION_TIMEOUT_MS)) {
            invalidateSession(sessionId);
            logger.info("Expired session invalidated for user: " + session.getUsername());
            return null;
        }

        // Optional: IP binding validation
        if (!session.getClientIp().equals(request.getRemoteAddr())) {
            logger.warning(String.format("Session IP mismatch for user %s: expected %s, got %s",
                session.getUsername(), session.getClientIp(), request.getRemoteAddr()));
            // Consider invalidating based on security policy
        }

        // Update last accessed time
        session.touch();

        return session;
    }

    public void invalidateSession(String sessionId) {
        SecureUserSession removed = activeSessions.remove(sessionId);
        if (removed != null) {
            logger.info("Session invalidated for user: " + removed.getUsername());
        }
    }
}

class SecureUserSession {
    private final String username;
    private final String sessionId;
    private final String clientIp;
    private final String userAgent;
    private final long createdAt;
    private long lastAccessedAt;

    public SecureUserSession(String username, String sessionId, String clientIp, String userAgent) {
        this.username = username;
        this.sessionId = sessionId;
        this.clientIp = clientIp;
        this.userAgent = userAgent;
        this.createdAt = Instant.now().toEpochMilli();
        this.lastAccessedAt = this.createdAt;
    }

    public boolean isExpired(long timeoutMs) {
        return (Instant.now().toEpochMilli() - lastAccessedAt) > timeoutMs;
    }

    public void touch() {
        this.lastAccessedAt = Instant.now().toEpochMilli();
    }

    public String getUsername() { return username; }
    public String getClientIp() { return clientIp; }
    public String getUserAgent() { return userAgent; }
}
```

**Key Security Controls**:
- **SecureRandom for entropy**: Uses cryptographically secure PRNG with 256 bits of randomness, making prediction computationally infeasible
- **Session timeout**: Limits window of opportunity for session hijacking
- **IP binding validation**: Detects session theft from different networks
- **Secure session storage**: Uses ConcurrentHashMap for thread-safe operations
- **Audit logging**: Tracks session lifecycle without exposing session IDs

Excellent question! Session fixation attacks exploit the scenario where a session ID created before authentication is reused after login. In distributed environments, you need centralized session storage with proper replication. Here's a production-grade implementation:

**PRODUCTION PATTERN**:

```java
import javax.servlet.http.*;
import java.security.SecureRandom;
import java.security.MessageDigest;
import java.util.Base64;
import java.util.logging.Logger;
import java.time.Instant;
import java.time.Duration;
import redis.clients.jedis.JedisPool;
import redis.clients.jedis.Jedis;
import com.google.gson.Gson;

public class ProductionSessionManager {
    private static final Logger logger = Logger.getLogger(ProductionSessionManager.class.getName());
    private static final SecureRandom secureRandom = new SecureRandom();
    private static final int SESSION_ID_BYTES = 32; // 256 bits
    private static final Duration SESSION_TIMEOUT = Duration.ofMinutes(30);
    private static final Duration ABSOLUTE_TIMEOUT = Duration.ofHours(8);
    private static final String SESSION_PREFIX = "session:";

    private final JedisPool redisPool;
    private final Gson gson;

    public ProductionSessionManager(JedisPool redisPool) {
        this.redisPool = redisPool;
        this.gson = new Gson();
    }

    /**
     * Creates a new cryptographically secure session ID.
     * Uses multiple entropy sources for defense in depth.
     */
    private String generateSecureSessionId() {
        byte[] randomBytes = new byte[SESSION_ID_BYTES];
        secureRandom.nextBytes(randomBytes);

        // Add additional entropy from system sources
        long nanoTime = System.nanoTime();
        byte[] timeBytes = longToBytes(nanoTime);

        // XOR time entropy with random bytes
        for (int i = 0; i < 8 && i < randomBytes.length; i++) {
            randomBytes[i] ^= timeBytes[i];
        }

        return Base64.getUrlEncoder().withoutPadding().encodeToString(randomBytes);
    }

    private byte[] longToBytes(long value) {
        byte[] result = new byte[8];
        for (int i = 7; i >= 0; i--) {
            result[i] = (byte) (value & 0xFF);
            value >>= 8;
        }
        return result;
    }

    /**
     * Creates pre-authentication session (limited capabilities).
     */
    public String createPreAuthSession(HttpServletRequest request, HttpServletResponse response) {
        String sessionId = generateSecureSessionId();

        SessionData session = new SessionData();
        session.setSessionId(sessionId);
        session.setAuthenticated(false);
        session.setClientIp(getClientIp(request));
        session.setUserAgent(request.getHeader("User-Agent"));
        session.setCreatedAt(Instant.now().toEpochMilli());
        session.setLastAccessedAt(session.getCreatedAt());

        storeSession(sessionId, session, Duration.ofMinutes(5)); // Short TTL for pre-auth
        setSecureSessionCookie(response, sessionId);

        return sessionId;
    }

    /**
     * CRITICAL: Regenerates session ID after successful authentication.
     * Prevents session fixation attacks.
     */
    public String regenerateSessionOnLogin(String oldSessionId, String username, 
                                           HttpServletRequest request, 
                                           HttpServletResponse response) {
        // Invalidate old session immediately
        if (oldSessionId != null) {
            invalidateSession(oldSessionId);
            logger.info(String.format("Pre-auth session invalidated during login for user: %s", username));
        }

        // Generate completely new session ID
        String newSessionId = generateSecureSessionId();

        // Create authenticated session with full security context
        SessionData session = new SessionData();
        session.setSessionId(newSessionId);
        session.setUsername(username);
        session.setAuthenticated(true);
        session.setClientIp(getClientIp(request));
        session.setUserAgent(request.getHeader("User-Agent"));
        session.setCreatedAt(Instant.now().toEpochMilli());
        session.setLastAccessedAt(session.getCreatedAt());
        session.setAuthenticatedAt(session.getCreatedAt());

        // Generate session binding token for CSRF protection
        session.setCsrfToken(generateSecureSessionId());

        // Store with authenticated session TTL
        storeSession(newSessionId, session, SESSION_TIMEOUT);

        // Set new secure cookie
        setSecureSessionCookie(response, newSessionId);

        // Audit log
        logger.info(String.format("New authenticated session created for user: %s from IP: %s",
            username, getClientIp(request)));

        return newSessionId;
    }

    /**
     * Validates session with comprehensive security checks.
     */
    public SessionData validateSession(String sessionId, HttpServletRequest request) {
        if (sessionId == null || sessionId.length() < 40) { // Base64 of 32 bytes
            logger.warning("Invalid session ID format from IP: " + getClientIp(request));
            return null;
        }

        SessionData session = retrieveSession(sessionId);

        if (session == null) {
            return null;
        }

        // Check absolute timeout (defense against stolen sessions)
        long sessionAge = Instant.now().toEpochMilli() - session.getCreatedAt();
        if (sessionAge > ABSOLUTE_TIMEOUT.toMillis()) {
            invalidateSession(sessionId);
            logger.info(String.format("Session exceeded absolute timeout for user: %s", 
                session.getUsername()));
            return null;
        }

        // Check idle timeout
        long idleTime = Instant.now().toEpochMilli() - session.getLastAccessedAt();
        if (idleTime > SESSION_TIMEOUT.toMillis()) {
            invalidateSession(sessionId);
            logger.info(String.format("Session idle timeout for user: %s", session.getUsername()));
            return null;
        }

        // Validate client fingerprint (detect session hijacking)
        String currentIp = getClientIp(request);
        String currentUserAgent = request.getHeader("User-Agent");

        if (!session.getClientIp().equals(currentIp)) {
            logger.warning(String.format(
                "SECURITY: Session IP changed for user %s: %s -> %s",
                session.getUsername(), session.getClientIp(), currentIp));

            // Depending on security policy, may invalidate session
            // For high-security apps, uncomment below:
            // invalidateSession(sessionId);
            // return null;
        }

        // Update last accessed time with sliding expiration
        session.setLastAccessedAt(Instant.now().toEpochMilli());
        storeSession(sessionId, session, SESSION_TIMEOUT);

        return session;
    }

    /**
     * Stores session in Redis with TTL.
     */
    private void storeSession(String sessionId, SessionData session, Duration ttl) {
        try (Jedis jedis = redisPool.getResource()) {
            String key = SESSION_PREFIX + sessionId;
            String value = gson.toJson(session);
            jedis.setex(key, (int) ttl.getSeconds(), value);
        } catch (Exception e) {
            logger.severe("Failed to store session: " + e.getMessage());
            throw new RuntimeException("Session storage failed", e);
        }
    }

    private SessionData retrieveSession(String sessionId) {
        try (Jedis jedis = redisPool.getResource()) {
            String key = SESSION_PREFIX + sessionId;
            String value = jedis.get(key);
            if (value == null) {
                return null;
            }
            return gson.fromJson(value, SessionData.class);
        } catch (Exception e) {
            logger.severe("Failed to retrieve session: " + e.getMessage());
            return null;
        }
    }

    public void invalidateSession(String sessionId) {
        try (Jedis jedis = redisPool.getResource()) {
            jedis.del(SESSION_PREFIX + sessionId);
        } catch (Exception e) {
            logger.severe("Failed to invalidate session: " + e.getMessage());
        }
    }

    /**
     * Sets secure session cookie with all security flags.
     */
    private void setSecureSessionCookie(HttpServletResponse response, String sessionId) {
        Cookie sessionCookie = new Cookie("SESSIONID", sessionId);
        sessionCookie.setHttpOnly(true);     // Prevent XSS access
        sessionCookie.setSecure(true);       // HTTPS only
        sessionCookie.setPath("/");
        sessionCookie.setMaxAge(-1);         // Session cookie (browser close)

        // SameSite attribute via header (Java Servlet API limitation)
        response.setHeader("Set-Cookie", 
            String.format("SESSIONID=%s; HttpOnly; Secure; SameSite=Strict; Path=/", sessionId));
    }

    /**
     * Gets client IP, handling proxies.
     */
    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            // Take first IP (original client) from chain
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
}

/**
 * Session data structure for serialization.
