**Key Security Controls**:
- **No default typing**: Never enable `enableDefaultTyping()` without strict allowlisting
- **Explicit type binding**: Always deserialize to specific DTO classes, never to `Object.class`
- **Input validation**: Limit payload size and validate all fields after deserialization
- **Updated dependencies**: Use Jackson 2.13+ which has improved security defaults
- **Audit logging**: Log all deserialization failures with source IP for incident response

Polymorphic deserialization can be done safely with strict controls, but requires careful implementation and ongoing maintenance. Here's a production-ready approach that balances functionality with security.

**PRODUCTION PATTERN**:

```java
import com.fasterxml.jackson.annotation.JsonSubTypes;
import com.fasterxml.jackson.annotation.JsonTypeInfo;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.DeserializationFeature;
import com.fasterxml.jackson.databind.jsontype.BasicPolymorphicTypeValidator;
import com.fasterxml.jackson.databind.MapperFeature;
import com.fasterxml.jackson.core.JsonProcessingException;
import org.springframework.stereotype.Service;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Counter;

import javax.annotation.PostConstruct;
import java.util.Set;
import java.util.HashSet;

@Service
public class SecureDeserializationService {

    private static final Logger logger = LoggerFactory.getLogger(SecureDeserializationService.class);
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    private final ObjectMapper secureMapper;
    private final MeterRegistry meterRegistry;
    private Counter deserializationFailures;
    private Counter suspiciousPayloads;

    // Explicit allowlist of permitted polymorphic base types
    private static final Set<String> ALLOWED_PACKAGE_PREFIXES = Set.of(
        "com.mycompany.domain.",
        "com.mycompany.dto.",
        "com.mycompany.events."
    );

    // Known dangerous classes to block even if they slip through
    private static final Set<String> BLOCKED_CLASSES = Set.of(
        "com.sun.rowset.JdbcRowSetImpl",
        "org.apache.xalan.xsltc.trax.TemplatesImpl",
        "org.springframework.beans.factory.config.PropertyPathFactoryBean",
        "ch.qos.logback.core.db.DriverManagerConnectionSource",
        "com.zaxxer.hikari.HikariDataSource",
        "org.apache.commons.configuration.JNDIConfiguration",
        "org.apache.tomcat.dbcp.dbcp2.BasicDataSource"
    );

    public SecureDeserializationService(MeterRegistry meterRegistry) {
        this.meterRegistry = meterRegistry;
        this.secureMapper = createSecureObjectMapper();
    }

    @PostConstruct
    public void initMetrics() {
        this.deserializationFailures = meterRegistry.counter("security.deserialization.failures");
        this.suspiciousPayloads = meterRegistry.counter("security.deserialization.suspicious");
    }

    private ObjectMapper createSecureObjectMapper() {
        ObjectMapper mapper = new ObjectMapper();

        // Layer 1: Strict polymorphic type validator
        BasicPolymorphicTypeValidator ptv = BasicPolymorphicTypeValidator.builder()
            .allowIfBaseType(BaseEvent.class)
            .allowIfSubTypeIsArray()
            .allowIfSubType(clazz -> {
                String className = clazz.getName();
                // Block known dangerous classes
                if (BLOCKED_CLASSES.contains(className)) {
                    securityLogger.error("BLOCKED dangerous class: {}", className);
                    suspiciousPayloads.increment();
                    return false;
                }
                // Only allow our packages
                return ALLOWED_PACKAGE_PREFIXES.stream()
                    .anyMatch(className::startsWith);
            })
            .build();

        // Layer 2: Activate with validator (NON_FINAL is safer than OBJECT_AND_NON_CONCRETE)
        mapper.activateDefaultTyping(ptv, ObjectMapper.DefaultTyping.NON_FINAL);

        // Layer 3: Additional hardening options
        mapper.configure(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES, true);
        mapper.configure(MapperFeature.BLOCK_UNSAFE_POLYMORPHIC_BASE_TYPES, true);
        mapper.configure(DeserializationFeature.FAIL_ON_READING_DUP_TREE_KEY, true);

        return mapper;
    }

    public <T> T deserialize(String json, Class<T> targetType, String sourceIdentifier) {
        // Pre-deserialization security checks
        if (!preDeserializationCheck(json, sourceIdentifier)) {
            throw new SecurityException("Payload failed security validation");
        }

        try {
            T result = secureMapper.readValue(json, targetType);

            // Post-deserialization validation
            validateDeserializedObject(result);

            logger.debug("Successfully deserialized {} from source: {}", 
                targetType.getSimpleName(), sourceIdentifier);
            return result;

        } catch (JsonProcessingException e) {
            deserializationFailures.increment();
            securityLogger.warn("Deserialization failed for source: {} - {}", 
                sourceIdentifier, e.getMessage());
            throw new IllegalArgumentException("Invalid JSON format", e);
        }
    }

    private boolean preDeserializationCheck(String json, String source) {
        // Check for common attack patterns in raw JSON
        String[] dangerousPatterns = {
            "@class",  // Jackson type indicator
            "com.sun.",
            "javax.naming",
            "java.lang.Runtime",
            "java.lang.ProcessBuilder",
            "org.apache.xalan",
            "ch.qos.logback",
            "org.springframework.beans.factory",
            "ldap://",
            "rmi://",
            "jndi:"
        };

        String lowerJson = json.toLowerCase();
        for (String pattern : dangerousPatterns) {
            if (lowerJson.contains(pattern.toLowerCase())) {
                securityLogger.error(
                    "ATTACK_DETECTED: Suspicious pattern '{}' in payload from source: {}",
                    pattern, source);
                suspiciousPayloads.increment();

                // Alert security team
                triggerSecurityAlert(source, pattern, json);
                return false;
            }
        }
        return true;
    }

    private void validateDeserializedObject(Object obj) {
        if (obj == null) return;

        // Verify the deserialized object is from allowed packages
        String className = obj.getClass().getName();
        boolean allowed = ALLOWED_PACKAGE_PREFIXES.stream()
            .anyMatch(className::startsWith);

        if (!allowed) {
            securityLogger.error("SECURITY_VIOLATION: Unexpected class deserialized: {}", className);
            throw new SecurityException("Unauthorized object type");
        }
    }

    private void triggerSecurityAlert(String source, String pattern, String payload) {
        // Integration with SIEM/alerting system
        // This would typically send to Splunk, Datadog, PagerDuty, etc.
        logger.error("SECURITY_ALERT: Potential deserialization attack from {} using pattern {}", 
            source, pattern);
    }
}

