  maxInputLength: 4000,
  maxContextLength: 8000,
  sessionTTL: 3600,
  maxTokensPerRequest: 1000,
  dangerousPatterns: [
    /ignore\s+(all\s+)?(previous|prior|above)\s+(instructions|prompts|rules)/gi,
    /you\s+are\s+now\s+(in\s+)?\w+\s+mode/gi,
