// Multi-layer input validation
class PromptSecurityValidator {
  static validateInput(input, requestId) {
    if (typeof input !== 'string') {
      return { valid: false, reason: 'Invalid input type' };
    }

    if (input.length > SECURITY_CONFIG.maxInputLength) {
      return { valid: false, reason: 'Input too long' };
    }

    // Check for injection patterns
    for (const pattern of SECURITY_CONFIG.dangerousPatterns) {
      if (pattern.test(input)) {
        AISecurityLogger.log('PROMPT_INJECTION_ATTEMPT', {
          requestId,
          pattern: pattern.toString(),
          inputHash: crypto.createHash('sha256').update(input).digest('hex').slice(0, 16)
        });
        return { valid: false, reason: 'Potentially malicious input detected' };
      }
    }

    // Check for encoded injection attempts
    const decoded = this.decodeAllLayers(input);
    if (decoded !== input) {
      for (const pattern of SECURITY_CONFIG.dangerousPatterns) {
        if (pattern.test(decoded)) {
          AISecurityLogger.log('ENCODED_INJECTION_ATTEMPT', { requestId });
          return { valid: false, reason: 'Encoded malicious content detected' };
        }
      }
    }

    return { valid: true, sanitized: input.trim() };
  }

  static decodeAllLayers(input) {
    let decoded = input;
    try {
      // URL decode
      decoded = decodeURIComponent(decoded);
      // Base64 decode (if valid)
      if (/^[A-Za-z0-9+/=]+$/.test(decoded) && decoded.length % 4 === 0) {
        const b64decoded = Buffer.from(decoded, 'base64').toString('utf-8');
        if (b64decoded.length > 0) decoded = b64decoded;
      }
    } catch (e) {
      // Decoding failed, use original
    }
    return decoded;
  }

  // Sanitize external content that will be included in context
  static sanitizeExternalContent(content, maxLength = 2000) {
    if (!content) return '';

    // Wrap external content with clear delimiters
    const sanitized = content
      .slice(0, maxLength)
      .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '')  // Remove control chars
      .replace(/```/g, '\`\`\`');  // Escape code blocks

    return `[EXTERNAL_CONTENT_START]\n${sanitized}\n[EXTERNAL_CONTENT_END]`;
  }
}

// Secure conversation manager
class SecureConversationManager {
  constructor(redis) {
    this.redis = redis;
  }

  async getConversation(sessionId) {
    const data = await this.redis.get(`conv:${sessionId}`);
    if (!data) return { messages: [], metadata: {} };

    const conversation = JSON.parse(data);

    // Enforce turn limit
    if (conversation.messages.length > SECURITY_CONFIG.maxConversationTurns * 2) {
      conversation.messages = conversation.messages.slice(-SECURITY_CONFIG.maxConversationTurns * 2);
    }

    return conversation;
  }

  async saveConversation(sessionId, conversation) {
    // Calculate total context size
    const totalLength = conversation.messages
      .reduce((acc, msg) => acc + msg.content.length, 0);

    // Trim old messages if context too large
    while (totalLength > SECURITY_CONFIG.maxContextLength && conversation.messages.length > 2) {
      conversation.messages.splice(1, 2);  // Remove oldest user/assistant pair (keep system)
    }

    await this.redis.setex(
      `conv:${sessionId}`,
      SECURITY_CONFIG.sessionTTL,
      JSON.stringify(conversation)
    );
  }

  async clearConversation(sessionId) {
    await this.redis.del(`conv:${sessionId}`);
  }
}

const conversationManager = new SecureConversationManager(redis);

// Output security filter
class OutputSecurityFilter {
  static sensitivePatterns = [
    { pattern: /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g, name: 'email' },
    { pattern: /\b\d{3}-\d{2}-\d{4}\b/g, name: 'ssn' },
    { pattern: /\b\d{16}\b/g, name: 'credit_card' },
    { pattern: /sk-[a-zA-Z0-9]{20,}/g, name: 'api_key' },
    { pattern: /\b(password|secret|token)\s*[=:]\s*['"]?[^\s'"]+['"]?/gi, name: 'credential' }
  ];

  static filter(response, requestId) {
    let filtered = response;
    let redactionCount = 0;

    for (const { pattern, name } of this.sensitivePatterns) {
      const matches = filtered.match(pattern);
      if (matches) {
        redactionCount += matches.length;
        filtered = filtered.replace(pattern, `[REDACTED_${name.toUpperCase()}]`);
      }
    }

    if (redactionCount > 0) {
      AISecurityLogger.log('OUTPUT_REDACTION', {
        requestId,
        redactionCount
      });
    }

    // Check for potential data exfiltration in responses
    if (filtered.includes('EXTERNAL_CONTENT_START') || 
        filtered.includes('[SYSTEM')) {
      AISecurityLogger.log('POTENTIAL_DATA_LEAK', { requestId });
      filtered = filtered
        .replace(/\[EXTERNAL_CONTENT_START\].*?\[EXTERNAL_CONTENT_END\]/gs, '[CONTENT_REMOVED]')
        .replace(/\[SYSTEM.*?\]/g, '[REMOVED]');
    }

    return filtered;
  }
}

