const express = require('express');
const _ = require('lodash');

const app = express();

// Safe merge that prevents prototype pollution
function safeMerge(target, source) {
  if (!source || typeof source !== 'object') {
    return target;
  }

  const result = { ...target };

  for (const key of Object.keys(source)) {
    // Block prototype pollution attempts
    if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
      console.warn(`Blocked prototype pollution attempt: ${key}`);
      continue;
    }

    if (typeof source[key] === 'object' && source[key] !== null && !Array.isArray(source[key])) {
      result[key] = safeMerge(result[key] || {}, source[key]);
    } else {
      result[key] = source[key];
    }
  }

  return result;
}

app.post('/api/config', express.json(), (req, res) => {
  const defaultConfig = { admin: false };
  const userConfig = req.body;

  // Use safe merge instead of lodash.merge
  const merged = safeMerge(defaultConfig, userConfig);

  res.json(merged);
});

