// scripts/dependency-policy.js
// Pre-install hook to enforce dependency policies
const fs = require('fs');
const path = require('path');

const BLOCKED_PACKAGES = [
  'event-stream@3.3.6',      // Compromised version
  'flatmap-stream',           // Malicious package
  'ua-parser-js@<0.7.30',    // Compromised versions
  'coa@<2.0.3',               // Hijacked
  'rc@<1.2.9',                // Hijacked
  'colors@>1.4.0',            // Sabotaged by maintainer
  'faker@>5.5.3',             // Sabotaged by maintainer
  'node-ipc@>10.1.0',         // Protestware
  'request'                   // Deprecated, no security fixes
];

const ALLOWED_LICENSES = [
  'MIT', 'Apache-2.0', 'BSD-2-Clause', 'BSD-3-Clause', 'ISC', '0BSD'
];

const MAX_DEPENDENCY_AGE_DAYS = 365 * 2;  // 2 years

class DependencyPolicyChecker {
  constructor() {
    this.violations = [];
    this.warnings = [];
  }

  async checkPackageLock() {
    const lockPath = path.join(process.cwd(), 'package-lock.json');

    if (!fs.existsSync(lockPath)) {
      this.violations.push('CRITICAL: package-lock.json not found');
      return;
    }

    const lockfile = JSON.parse(fs.readFileSync(lockPath, 'utf8'));

    // Check lockfile version
    if (lockfile.lockfileVersion < 3) {
      this.warnings.push('WARNING: Update to lockfileVersion 3 for better security');
    }

    // Check all packages including transitive dependencies
    const packages = lockfile.packages || {};

    for (const [pkgPath, pkgInfo] of Object.entries(packages)) {
      if (!pkgPath) continue;  // Skip root

      const pkgName = pkgPath.replace('node_modules/', '');
      const version = pkgInfo.version;

      // Check against blocked list
      this.checkBlockedPackage(pkgName, version);

      // Check for missing integrity
      if (!pkgInfo.integrity && !pkgInfo.link) {
        this.violations.push(`CRITICAL: No integrity hash for ${pkgName}@${version}`);
      }

      // Check for install scripts in dependencies
      if (pkgInfo.hasInstallScript) {
        this.warnings.push(`WARNING: ${pkgName} has install scripts - review manually`);
      }
    }
  }

  checkBlockedPackage(name, version) {
    for (const blocked of BLOCKED_PACKAGES) {
      if (blocked.includes('@')) {
        const [blockedName, blockedVersion] = blocked.split('@');
        if (name === blockedName) {
          // Simple version check (production would use semver)
          if (blockedVersion.startsWith('<')) {
            const threshold = blockedVersion.substring(1);
            if (this.compareVersions(version, threshold) < 0) {
              this.violations.push(`BLOCKED: ${name}@${version} (vulnerable version)`);
            }
          } else if (blockedVersion.startsWith('>')) {
            const threshold = blockedVersion.substring(1);
            if (this.compareVersions(version, threshold) > 0) {
              this.violations.push(`BLOCKED: ${name}@${version} (compromised version)`);
            }
          } else if (version === blockedVersion) {
            this.violations.push(`BLOCKED: ${name}@${version} (known malicious)`);
          }
        }
      } else if (name === blocked) {
        this.violations.push(`BLOCKED: ${name} (deprecated/dangerous package)`);
      }
    }
  }

  compareVersions(v1, v2) {
    const parts1 = v1.split('.').map(Number);
    const parts2 = v2.split('.').map(Number);

    for (let i = 0; i < Math.max(parts1.length, parts2.length); i++) {
      const p1 = parts1[i] || 0;
      const p2 = parts2[i] || 0;
      if (p1 > p2) return 1;
      if (p1 < p2) return -1;
    }
    return 0;
  }

  async run() {
    console.log('🔍 Checking dependency policy...\n');

    await this.checkPackageLock();

    // Report warnings
    if (this.warnings.length > 0) {
      console.log('⚠️  Warnings:');
      this.warnings.forEach(w => console.log(`   ${w}`));
      console.log('');
    }

    // Report violations
    if (this.violations.length > 0) {
      console.log('🚫 Policy Violations:');
      this.violations.forEach(v => console.log(`   ${v}`));
      console.log('');
      console.log(`❌ ${this.violations.length} violation(s) found. Blocking installation.`);
      process.exit(1);
    }

    console.log('✅ All dependency policy checks passed.');
  }
}

// Run if executed directly
if (require.main === module) {
  new DependencyPolicyChecker().run().catch(console.error);
}

module.exports = { DependencyPolicyChecker };
