import jakarta.validation.constraints.NotBlank;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@SpringBootApplication
@EnableConfigurationProperties(SecureAppProperties.class)
public class ProductionSecureApplication {

    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    public static void main(String[] args) {
        // Validate production profile is active
        String profile = System.getProperty("spring.profiles.active", "development");
        if ("production".equals(profile)) {
            validateProductionRequirements();
        }
        SpringApplication.run(ProductionSecureApplication.class, args);
    }

    private static void validateProductionRequirements() {
        String[] requiredVars = {"DATABASE_URL", "DATABASE_USER", "DATABASE_PASSWORD", 
                                  "JWT_SECRET", "SSL_KEYSTORE_PASSWORD"};
        for (String var : requiredVars) {
            if (System.getenv(var) == null || System.getenv(var).isEmpty()) {
                throw new IllegalStateException(
                    "Required environment variable missing: " + var);
            }
        }
    }
}

@Validated
@ConfigurationProperties(prefix = "app.security")
class SecureAppProperties {
    @NotBlank
    private String jwtSecret;
    private int sessionTimeoutMinutes = 30;
    private int maxLoginAttempts = 5;
    private int lockoutDurationMinutes = 15;

    // Getters and setters
    public String getJwtSecret() { return jwtSecret; }
    public void setJwtSecret(String jwtSecret) { this.jwtSecret = jwtSecret; }
    public int getSessionTimeoutMinutes() { return sessionTimeoutMinutes; }
    public void setSessionTimeoutMinutes(int mins) { this.sessionTimeoutMinutes = mins; }
    public int getMaxLoginAttempts() { return maxLoginAttempts; }
    public void setMaxLoginAttempts(int attempts) { this.maxLoginAttempts = attempts; }
    public int getLockoutDurationMinutes() { return lockoutDurationMinutes; }
    public void setLockoutDurationMinutes(int mins) { this.lockoutDurationMinutes = mins; }
}

@Configuration
@EnableWebSecurity
@EnableMethodSecurity(prePostEnabled = true)
@Profile("production")
class ProductionSecurityConfig {

    private static final Logger auditLog = LoggerFactory.getLogger("SECURITY_AUDIT");

    @Bean
    public SecurityFilterChain productionFilterChain(HttpSecurity http) throws Exception {
        http
            .requiresChannel(channel -> channel
                .anyRequest().requiresSecure()  // Force HTTPS
            )
            .authorizeHttpRequests(authz -> authz
                .requestMatchers("/actuator/health/liveness").permitAll()
                .requestMatchers("/actuator/health/readiness").permitAll()
                .requestMatchers("/actuator/**").hasRole("OPERATIONS")
                .requestMatchers("/api/admin/**").hasRole("ADMIN")
                .requestMatchers("/api/**").authenticated()
                .anyRequest().denyByDefault()
            )
            .headers(headers -> headers
                .contentSecurityPolicy(csp -> csp
                    .policyDirectives("default-src 'self'; script-src 'self'; style-src 'self' 'unsafe-inline'; img-src 'self' data:; frame-ancestors 'none'")
                )
                .frameOptions(frame -> frame.deny())
                .httpStrictTransportSecurity(hsts -> hsts
                    .maxAgeInSeconds(31536000)
                    .includeSubDomains(true)
                    .preload(true)
                )
                .referrerPolicy(referrer -> referrer
                    .policy(ReferrerPolicyHeaderWriter.ReferrerPolicy.STRICT_ORIGIN_WHEN_CROSS_ORIGIN)
                )
                .permissionsPolicy(permissions -> permissions
                    .policy("geolocation=(), microphone=(), camera=()")
                )
            )
            .sessionManagement(session -> session
                .sessionCreationPolicy(SessionCreationPolicy.STATELESS)
                .maximumSessions(1)
                .maxSessionsPreventsLogin(true)
            )
            .csrf(csrf -> csrf
                .csrfTokenRepository(CookieCsrfTokenRepository.withHttpOnlyFalse())
            )
            .exceptionHandling(ex -> ex
                .authenticationEntryPoint((request, response, authException) -> {
                    auditLog.warn("Authentication failed from IP: {}, URI: {}", 
                        request.getRemoteAddr(), request.getRequestURI());
                    response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Unauthorized");
                })
            );
        return http.build();
    }

    @Bean
    public CommonsRequestLoggingFilter requestLoggingFilter() {
        CommonsRequestLoggingFilter filter = new CommonsRequestLoggingFilter();
        filter.setIncludeClientInfo(true);
        filter.setIncludeQueryString(true);
        filter.setIncludeHeaders(false);  // Don't log auth headers
        filter.setMaxPayloadLength(1000);
        return filter;
    }
}
