		return nil, fmt.Errorf("failed to list modules: %w", err)
	}

	var unapproved []string
	// Parse and check each module against allowlist
	// (implementation details omitted for brevity)

	return unapproved, nil
}

func (ds *DependencyScanner) parseVulnCheckOutput(r io.Reader, report *VulnReport) error {
	// Parse govulncheck JSON output
	decoder := json.NewDecoder(r)
	for {
		var entry map[string]interface{}
		if err := decoder.Decode(&entry); err == io.EOF {
			break
		} else if err != nil {
			return err
		}
		// Process vulnerability entries
	}
	return nil
}

func (ds *DependencyScanner) sendAlert(ctx context.Context, vuln VulnerabilityInfo) {
	// Send to security alerting system
	alertBody, _ := json.Marshal(vuln)
	req, _ := http.NewRequestWithContext(ctx, "POST", ds.alertWebhook, bytes.NewReader(alertBody))
	req.Header.Set("Content-Type", "application/json")

	client := &http.Client{Timeout: 10 * time.Second}
	client.Do(req)
}
