```java
import javax.servlet.http.*;
import java.math.BigDecimal;
import java.sql.*;
import java.util.logging.Logger;

public class SecureCheckoutController extends HttpServlet {
    private static final Logger logger = Logger.getLogger(
        SecureCheckoutController.class.getName()
    );
    private CartService cartService;
    private DiscountService discountService;
    private PaymentService paymentService;
    private OrderStateMachine orderStateMachine;

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {
        HttpSession session = request.getSession(false);
        if (session == null) {
            response.sendError(401, "Session required");
            return;
        }

        String userId = (String) session.getAttribute("userId");
        String cartId = (String) session.getAttribute("cartId");

        // SECURITY: Verify cart belongs to user and exists
        Cart cart = cartService.getCartForUser(cartId, userId);
        if (cart == null) {
            logger.warning("Cart access denied: user=" + userId);
            response.sendError(403, "Invalid cart");
            return;
        }

        // SECURITY: Calculate price server-side from database
        BigDecimal calculatedTotal = cartService.calculateTotal(cart);

        // SECURITY: Validate discount through service layer
        String discountCode = request.getParameter("discount");
        if (discountCode != null && !discountCode.isEmpty()) {
            Discount discount = discountService.validateAndApply(
                discountCode, cart, userId
            );
            if (discount != null) {
                calculatedTotal = discount.applyTo(calculatedTotal);
            }
        }

        // SECURITY: State machine enforces workflow order
        if (!orderStateMachine.canTransition(cart, OrderState.PAYMENT)) {
            logger.warning("Invalid state transition: cart=" + cartId);
            response.sendError(400, "Complete previous steps first");
            return;
        }

        // SECURITY: Process with server-calculated amount
        PaymentResult result = paymentService.processPayment(
            cart, calculatedTotal, userId
        );

        if (result.isSuccessful()) {
            orderStateMachine.transition(cart, OrderState.PAID);
            logger.info("Order completed: cart=" + cartId + 
                       ", amount=" + calculatedTotal);
        }
    }
}
```

**Key Security Controls**:
- **Server-side price calculation**: Never trust client-submitted prices; always recalculate from database
- **State machine enforcement**: Orders must progress through defined states (cart→checkout→payment→complete)
- **Ownership verification**: Validate cart belongs to authenticated user before any operation
- **Discount validation service**: Centralized validation of discount eligibility, usage limits, and expiration

Excellent question - race conditions are one of the most exploited business logic flaws. In 2024, multiple fintech applications were compromised through TOCTOU (Time-of-Check-Time-of-Use) attacks that allowed double-spending of promotional credits. Here's a production-hardened pattern.

**PRODUCTION PATTERN**:

```java
import javax.persistence.*;
import java.math.BigDecimal;
import java.time.Instant;
import java.util.UUID;
import java.util.concurrent.locks.Lock;
import java.util.logging.Logger;
import org.redisson.api.RLock;
import org.redisson.api.RedissonClient;

@Service
@Transactional
public class AtomicCheckoutService {
    private static final Logger logger = Logger.getLogger(
        AtomicCheckoutService.class.getName()
    );

    @PersistenceContext
    private EntityManager entityManager;

    private final RedissonClient redisson;
    private final PaymentGateway paymentGateway;
    private final InventoryService inventoryService;
    private final AuditService auditService;

    public AtomicCheckoutService(RedissonClient redisson, 
                                  PaymentGateway paymentGateway,
                                  InventoryService inventoryService,
                                  AuditService auditService) {
        this.redisson = redisson;
        this.paymentGateway = paymentGateway;
        this.inventoryService = inventoryService;
        this.auditService = auditService;
    }

    public CheckoutResult processCheckout(String userId, String cartId, 
                                          String discountCode) {
        String idempotencyKey = generateIdempotencyKey(userId, cartId);

        // DEFENSE 1: Distributed lock prevents concurrent checkout attempts
        RLock lock = redisson.getLock("checkout:" + cartId);

        if (!lock.tryLock()) {
            auditService.logSuspiciousActivity(userId, "CONCURRENT_CHECKOUT", 
                "Blocked concurrent checkout attempt for cart: " + cartId);
            throw new ConcurrentModificationException(
                "Checkout already in progress"
            );
        }

        try {
            // DEFENSE 2: Idempotency check prevents duplicate submissions
            CheckoutAttempt existing = findExistingAttempt(idempotencyKey);
            if (existing != null) {
                logger.info("Returning cached result for idempotency key: " + 
                           idempotencyKey);
                return existing.getResult();
            }

            // DEFENSE 3: Pessimistic locking on cart row
            Cart cart = entityManager.find(Cart.class, cartId, 
                LockModeType.PESSIMISTIC_WRITE);

            if (cart == null || !cart.getUserId().equals(userId)) {
                throw new SecurityException("Cart access denied");
            }

            // DEFENSE 4: Validate cart state hasn't changed
            validateCartState(cart);

            // DEFENSE 5: Atomic inventory reservation with version check
            InventoryReservation reservation = inventoryService
                .reserveInventoryAtomic(cart.getItems());

            if (!reservation.isSuccessful()) {
                return CheckoutResult.outOfStock(reservation.getUnavailableItems());
            }

            try {
                // DEFENSE 6: Atomic discount usage with single-use enforcement
                BigDecimal total = calculateSecureTotal(cart);
                BigDecimal finalAmount = applyDiscountAtomically(
                    discountCode, total, userId, cartId
                );

                // DEFENSE 7: Optimistic locking on order creation
                Order order = createOrderWithOptimisticLock(cart, finalAmount);

                // DEFENSE 8: Payment with idempotency
                PaymentResult payment = paymentGateway.charge(
                    order.getId(),
                    finalAmount,
                    idempotencyKey
                );

                if (payment.isSuccessful()) {
                    finalizeOrder(order, payment, reservation);
                    recordSuccessfulCheckout(idempotencyKey, order);

                    auditService.logCheckout(userId, order.getId(), 
                        finalAmount, "SUCCESS");

                    return CheckoutResult.success(order);
                } else {
                    // Rollback reservation on payment failure
                    inventoryService.releaseReservation(reservation);
                    return CheckoutResult.paymentFailed(payment.getError());
                }

            } catch (Exception e) {
                // Always release inventory on any failure
                inventoryService.releaseReservation(reservation);
                throw e;
            }

        } finally {
            lock.unlock();
        }
    }

    // DEFENSE 9: Atomic discount application with database constraint
    private BigDecimal applyDiscountAtomically(String code, BigDecimal total,
                                                String userId, String cartId) {
        if (code == null || code.isEmpty()) {
            return total;
        }

        // Use SELECT FOR UPDATE to prevent concurrent usage
        int updated = entityManager.createQuery(
            "UPDATE DiscountCode d SET d.usageCount = d.usageCount + 1, " +
            "d.lastUsedBy = :userId, d.lastUsedAt = :now " +
            "WHERE d.code = :code AND d.usageCount < d.maxUses " +
            "AND d.expiresAt > :now AND d.active = true")
            .setParameter("code", code)
            .setParameter("userId", userId)
            .setParameter("now", Instant.now())
            .executeUpdate();

        if (updated == 0) {
            logger.warning("Discount code invalid or exhausted: " + code);
            auditService.logDiscountAttempt(userId, code, "REJECTED");
            return total; // Continue without discount
        }

        DiscountCode discount = entityManager.createQuery(
            "SELECT d FROM DiscountCode d WHERE d.code = :code", 
            DiscountCode.class)
            .setParameter("code", code)
            .getSingleResult();

        auditService.logDiscountAttempt(userId, code, "APPLIED");
        return discount.applyTo(total);
    }

    // DEFENSE 10: Version-controlled order creation
    private Order createOrderWithOptimisticLock(Cart cart, BigDecimal amount) {
        Order order = new Order();
        order.setId(UUID.randomUUID().toString());
        order.setUserId(cart.getUserId());
        order.setAmount(amount);
        order.setVersion(0L); // Optimistic lock version
        order.setStatus(OrderStatus.PENDING_PAYMENT);
        order.setCreatedAt(Instant.now());

        // Copy cart items to order (snapshot)
        for (CartItem item : cart.getItems()) {
            OrderItem orderItem = new OrderItem();
            orderItem.setProductId(item.getProductId());
            orderItem.setQuantity(item.getQuantity());
            orderItem.setPriceAtPurchase(item.getCurrentPrice()); // Snapshot price
            order.addItem(orderItem);
        }

        entityManager.persist(order);
        return order;
    }

    private String generateIdempotencyKey(String userId, String cartId) {
        return "checkout:" + userId + ":" + cartId + ":" + 
               Instant.now().toEpochMilli() / 60000; // 1-minute window
    }
}
```

