    protected void doPost(HttpServletRequest req, HttpServletResponse resp) {
        String path = req.getPathInfo();

        if ("/start-checkout".equals(path)) {
            startCheckout(req, resp);
        } else if ("/add-payment".equals(path)) {
            addPayment(req, resp);
        } else if ("/confirm-order".equals(path)) {
            confirmOrder(req, resp);  // VULNERABLE: No workflow state check!
        }
    }

    private void startCheckout(HttpServletRequest req, HttpServletResponse resp) {
        String userId = req.getParameter("userId");
        String cartId = req.getParameter("cartId");

        // Creates order with 'pending' status
        String orderId = createOrder(userId, cartId);
        req.getSession().setAttribute("orderId", orderId);
    }

    private void addPayment(HttpServletRequest req, HttpServletResponse resp) {
        String orderId = (String) req.getSession().getAttribute("orderId");
        String paymentToken = req.getParameter("paymentToken");

        // Process payment - but attacker can skip this entirely!
        processPayment(orderId, paymentToken);
    }

    // CRITICAL FLAW: No verification that payment was completed!
    private void confirmOrder(HttpServletRequest req, HttpServletResponse resp) {
        String orderId = (String) req.getSession().getAttribute("orderId");

        // Directly marks order as confirmed without checking payment!
        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "UPDATE orders SET status = 'CONFIRMED' WHERE id = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, orderId);
