  ]
});

// Mutual TLS (mTLS) configuration for service-to-service communication
const mtlsOptions = {
  key: fs.readFileSync('./certs/service.key'),
  cert: fs.readFileSync('./certs/service.crt'),
  ca: fs.readFileSync('./certs/internal-ca.crt'),

  // Require client certificate verification
  requestCert: true,
  rejectUnauthorized: true,

  // TLS 1.3 for internal services
  minVersion: 'TLSv1.3',

