app.use(express.json());

// Certificate verification middleware
const verifyCertificate = (req, res, next) => {
  const cert = req.socket.getPeerCertificate();

  if (!cert || Object.keys(cert).length === 0) {
    logger.warn('Request without client certificate', {
      ip: req.ip,
      path: req.path
    });
    return res.status(401).json({ error: 'Client certificate required' });
  }

  // Verify certificate CN matches expected service
  const allowedServices = ['auth-service', 'user-service', 'payment-service'];
  const serviceName = cert.subject.CN;

  if (!allowedServices.includes(serviceName)) {
    logger.error('Unauthorized service attempted connection', {
      cn: serviceName,
      fingerprint: cert.fingerprint,
      ip: req.ip
    });
    return res.status(403).json({ error: 'Service not authorized' });
  }

  // Check certificate expiration
  const certExpiry = new Date(cert.valid_to);
  const thirtyDaysFromNow = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000);

  if (certExpiry < thirtyDaysFromNow) {
    logger.warn('Certificate expiring soon', {
      service: serviceName,
      expiresAt: certExpiry.toISOString()
    });
  }

  req.serviceName = serviceName;
  next();
};

// Secure internal API client with mTLS
class SecureServiceClient {
  constructor(serviceName) {
    this.serviceName = serviceName;
    this.httpsAgent = new https.Agent({
      key: fs.readFileSync('./certs/service.key'),
      cert: fs.readFileSync('./certs/service.crt'),
      ca: fs.readFileSync('./certs/internal-ca.crt'),
      rejectUnauthorized: true,
      minVersion: 'TLSv1.3'
    });

    this.client = axios.create({
      httpsAgent: this.httpsAgent,
      timeout: 5000
    });
  }

  async request(url, options = {}) {
    const startTime = Date.now();

    try {
      const response = await this.client.request({
        url,
        ...options,
        headers: {
          ...options.headers,
          'X-Service-Name': this.serviceName,
          'X-Request-ID': generateRequestId()
        }
      });

      logger.info('Service call successful', {
        target: url,
        duration: Date.now() - startTime,
        statusCode: response.status
      });

      return response.data;
    } catch (error) {
      logger.error('Service call failed', {
        target: url,
        error: error.code || error.message,
        duration: Date.now() - startTime
      });
      throw error;
    }
  }
}

