Embedding JSON in HTML pages is a common pattern for SSR hydration and initial data loading, but it's one of the most dangerous XSS vectors. The key is proper encoding and multiple defense layers.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const helmet = require('helmet');
const crypto = require('crypto');
const DOMPurify = require('isomorphic-dompurify');
const validator = require('validator');
const winston = require('winston');

const app = express();

// Configure security logging
const securityLogger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'security.log' })
  ]
});

// JSON-to-HTML safe serialization
class SafeJsonSerializer {
  // Characters that can break out of <script> context
  static DANGEROUS_CHARS = {
    '<': '\\u003c',
    '>': '\\u003e',
    '&': '\\u0026',
    '\'': '\\u0027',
    '"': '\\u0022',
    '/': '\\u002f',
    '\u2028': '\\u2028', // Line separator
    '\u2029': '\\u2029'  // Paragraph separator
  };

  static serialize(obj) {
    const jsonString = JSON.stringify(obj);

    // Replace all dangerous characters with Unicode escapes
    return jsonString.replace(
      /[<>&'"\/\u2028\u2029]/g,
      (char) => this.DANGEROUS_CHARS[char] || char
    );
  }

  // Validate and sanitize before serialization
  static sanitizeAndSerialize(obj, schema) {
    const sanitized = this.deepSanitize(obj, schema);
    return this.serialize(sanitized);
  }

  static deepSanitize(obj, schema) {
    if (obj === null || obj === undefined) return null;

    if (Array.isArray(obj)) {
      return obj.map(item => this.deepSanitize(item, schema?.items));
    }

    if (typeof obj === 'object') {
      const result = {};
      for (const [key, value] of Object.entries(obj)) {
        const fieldSchema = schema?.properties?.[key];
        result[key] = this.sanitizeField(value, fieldSchema);
      }
      return result;
    }

    return this.sanitizeField(obj, schema);
  }

  static sanitizeField(value, fieldSchema) {
    if (value === null || value === undefined) return null;

    const type = fieldSchema?.type || typeof value;

    switch (type) {
      case 'number':
      case 'integer':
        const num = Number(value);
        return isFinite(num) ? num : null;

      case 'boolean':
        return Boolean(value);

      case 'url':
        return validator.isURL(String(value)) ? String(value) : null;

      case 'email':
        return validator.isEmail(String(value)) ? String(value) : null;

      case 'html':
        return DOMPurify.sanitize(String(value), {
          ALLOWED_TAGS: fieldSchema?.allowedTags || ['b', 'i', 'em', 'strong']
        });

      case 'string':
      default:
        // Strip all HTML by default
        return DOMPurify.sanitize(String(value), { ALLOWED_TAGS: [] });
    }
  }
}

// Generate nonce for CSP
app.use((req, res, next) => {
  res.locals.nonce = crypto.randomBytes(16).toString('base64');
  next();
});

// Dynamic CSP with nonce
app.use((req, res, next) => {
  res.setHeader(
    'Content-Security-Policy',
    `default-src 'self'; script-src 'self' 'nonce-${res.locals.nonce}'; style-src 'self' 'unsafe-inline'; object-src 'none'; base-uri 'self'`
  );
  next();
});

app.use(helmet({
  contentSecurityPolicy: false // Using custom CSP above
}));

// Schema for user data validation
const userSchema = {
  type: 'object',
  properties: {
    id: { type: 'integer' },
    username: { type: 'string' },
    bio: { type: 'html', allowedTags: ['b', 'i', 'em', 'strong', 'a'] },
    website: { type: 'url' },
    email: { type: 'email' },
    joinDate: { type: 'string' },
    isVerified: { type: 'boolean' }
  }
};

// SECURE: Server-side rendered page with embedded JSON
app.get('/user/:id', async (req, res) => {
  const userId = parseInt(req.params.id, 10);

  if (isNaN(userId) || userId <= 0) {
    return res.status(400).send('Invalid user ID');
  }

  try {
    const user = await db.query('SELECT * FROM users WHERE id = ?', [userId]);

    if (!user) {
      return res.status(404).send('User not found');
    }

    // Sanitize and serialize with schema validation
    const safeJsonData = SafeJsonSerializer.sanitizeAndSerialize(user, userSchema);

    // Log data embedding for security monitoring
    securityLogger.info('JSON embedded in HTML', {
      userId: userId,
      ip: req.ip,
      userAgent: req.get('User-Agent'),
      timestamp: new Date().toISOString()
    });

    const nonce = res.locals.nonce;

    // Render with nonce-protected script and safe JSON
    res.send(`
      <!DOCTYPE html>
      <html lang="en">
      <head>
        <meta charset="UTF-8">
        <meta name="viewport" content="width=device-width, initial-scale=1.0">
        <title>User Profile</title>
      </head>
      <body>
        <div id="profile"></div>

        <!-- SAFE: Nonce-protected script with escaped JSON -->
        <script nonce="${nonce}">
          // Data is safely escaped - no HTML interpretation possible
          const userData = ${safeJsonData};

          // SAFE: Use textContent instead of innerHTML
          const profile = document.getElementById('profile');
          const nameEl = document.createElement('h1');
          nameEl.textContent = userData.username;
          profile.appendChild(nameEl);

          const bioEl = document.createElement('p');
          bioEl.textContent = userData.bio; // Even sanitized, use textContent
          profile.appendChild(bioEl);
        </script>
      </body>
      </html>
    `);

  } catch (error) {
    securityLogger.error('Error rendering user page', {
      error: error.message,
      userId: userId,
      ip: req.ip
    });
    res.status(500).send('An error occurred');
  }
});

// Alternative: Use data attributes instead of inline script
app.get('/user/:id/safe', async (req, res) => {
  const userId = parseInt(req.params.id, 10);
  const user = await db.query('SELECT * FROM users WHERE id = ?', [userId]);
  const safeData = SafeJsonSerializer.sanitizeAndSerialize(user, userSchema);
  const nonce = res.locals.nonce;

  // Encode as base64 for extra safety in attribute context
  const base64Data = Buffer.from(safeData).toString('base64');

  res.send(`
    <!DOCTYPE html>
    <html lang="en">
    <head><title>User Profile</title></head>
    <body>
      <!-- Data in attribute - parsed by external script -->
      <div id="profile" data-user="${base64Data}"></div>

      <script nonce="${nonce}" src="/js/profile.js"></script>
    </body>
    </html>
  `);
});

// Start server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
```

**Defense in Depth Layers**:

1. **Unicode Escaping** - Replace `<`, `>`, `/` with Unicode escapes to prevent script tag breakout:
```javascript
'<script>' becomes '\u003cscript\u003e'
// Browser interprets as literal string, not HTML
```

2. **CSP with Nonce** - Only scripts with matching nonce execute:
```javascript
const nonce = crypto.randomBytes(16).toString('base64');
res.setHeader('Content-Security-Policy', `script-src 'nonce-${nonce}'`);
// Injected scripts without nonce are blocked
```

3. **Schema-Based Sanitization** - Validate data types and sanitize appropriately:
```javascript
// URLs are validated, HTML is stripped or sanitized, numbers are parsed
const sanitized = SafeJsonSerializer.sanitizeAndSerialize(user, userSchema);
```

**Additional Protections**:
- **Use textContent not innerHTML**: Even after sanitization, avoid innerHTML for user data
- **Base64 encoding for attributes**: When embedding in HTML attributes, base64 provides extra protection
- **External scripts over inline**: Move JavaScript to external files to enable stricter CSP
- **Security logging**: Monitor all JSON embedding operations for anomaly detection
- **Line separator escaping**: `\u2028` and `\u2029` can break JavaScript parsing in some browsers

Parsing XML from untrusted sources is extremely dangerous by default. Most XML parsers enable external entity processing, which allows attackers to read files from your server, perform SSRF attacks, or even achieve remote code execution.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const libxmljs = require('libxmljs');
const fs = require('fs');

const app = express();
app.use(express.text({ type: 'application/xml' }));

app.post('/api/parse-xml', (req, res) => {
  try {
    // VULNERABLE: Default parser settings allow XXE
    const xmlDoc = libxmljs.parseXml(req.body);

    // Extract data from XML
    const root = xmlDoc.root();
    const username = root.get('//username').text();
    const email = root.get('//email').text();

    res.json({
      success: true,
      data: { username, email }
    });
  } catch (error) {
    res.status(400).json({ error: 'Invalid XML' });
  }
});

app.listen(3000);
```

**Attack Payload**:
```xml
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE foo [
  <!ENTITY xxe SYSTEM "file:///etc/passwd">
]>
<user>
  <username>&xxe;</username>
  <email>attacker@evil.com</email>
</user>
```

**AWS Credential Theft Payload**:
```xml
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE foo [
  <!ENTITY xxe SYSTEM "file:///home/app/.aws/credentials">
]>
<user>
  <username>&xxe;</username>
  <email>test@test.com</email>
</user>
```

**SSRF Attack Payload**:
```xml
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE foo [
  <!ENTITY xxe SYSTEM "http://169.254.169.254/latest/meta-data/iam/security-credentials/">
]>
<user>
  <username>&xxe;</username>
  <email>test@test.com</email>
</user>
```

**Why This Is Dangerous**:
- External entities allow reading arbitrary files from the server filesystem
- SSRF attacks can access internal services, cloud metadata endpoints, and private networks
- Billion laughs attack can cause denial of service through exponential entity expansion
- Some parsers allow PHP/expect wrappers enabling remote code execution

**SECURE VERSION**:

```javascript
const express = require('express');
const libxmljs = require('libxmljs');

const app = express();

// Limit XML payload size to prevent DoS
app.use(express.text({ 
  type: 'application/xml',
  limit: '100kb'
}));

app.post('/api/parse-xml', (req, res) => {
  try {
    // SECURE: Disable external entities and DTD processing
    const parserOptions = {
      noent: false,      // Do NOT expand entities
      dtdload: false,    // Do NOT load external DTD
      dtdvalid: false,   // Do NOT validate against DTD
      nonet: true,       // Disable network access
      nocdata: false,    // Keep CDATA as-is
      noblanks: true     // Remove blank nodes
    };

    const xmlDoc = libxmljs.parseXml(req.body, parserOptions);

    // Validate expected structure
    const root = xmlDoc.root();
    if (!root || root.name() !== 'user') {
      return res.status(400).json({ error: 'Invalid XML structure' });
    }

    const usernameNode = root.get('//username');
    const emailNode = root.get('//email');

    if (!usernameNode || !emailNode) {
      return res.status(400).json({ error: 'Missing required fields' });
    }

    const username = usernameNode.text();
    const email = emailNode.text();

    // Additional validation
    if (username.length > 100 || email.length > 255) {
      return res.status(400).json({ error: 'Field length exceeded' });
    }

    res.json({
      success: true,
      data: { username, email }
    });
  } catch (error) {
    console.error('XML parsing error:', error.message);
    res.status(400).json({ error: 'Invalid XML format' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- `noent: false` - Prevents entity expansion, blocking XXE attacks
- `dtdload: false` - Prevents loading external DTD files
- `nonet: true` - Disables all network access during parsing, blocking SSRF
- Payload size limit prevents denial of service attacks
- Structure validation ensures only expected XML format is processed

Different XML parsers have different default behaviors and configuration options. Here's how to secure the most popular Node.js XML libraries in production.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const { XMLParser, XMLValidator } = require('fast-xml-parser');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();
app.use(helmet());

// Rate limiting for XML endpoints
const xmlLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // 100 requests per window
  message: { error: 'Too many requests, please try again later' }
});

// Strict payload limits
app.use(express.text({ 
  type: ['application/xml', 'text/xml'],
  limit: '50kb'
}));

// Secure XML parser configuration factory
function createSecureXMLParser() {
  return new XMLParser({
    // SECURITY: Disable all dangerous features
    allowBooleanAttributes: false,
    ignoreAttributes: false,
    ignoreDeclaration: true,
    ignorePiTags: true,

    // Prevent entity expansion attacks
    processEntities: false,
    htmlEntities: false,

    // Limit parsing depth to prevent stack overflow
    parseTagValue: true,
    trimValues: true,

    // Disable comment processing
    commentPropName: false,

    // Custom tag validation
    isArray: (name, jpath, isLeafNode, isAttribute) => {
      // Define which tags should always be arrays
      const arrayTags = ['item', 'entry', 'record'];
      return arrayTags.includes(name);
    }
  });
}

// Pre-parsing security validation
function validateXMLSecurity(xmlString) {
  const dangerousPatterns = [
    /<!ENTITY/i,           // External entities
    /<!DOCTYPE/i,          // DTD declarations
    /SYSTEM\s+["']/i,      // SYSTEM keyword
    /PUBLIC\s+["']/i,      // PUBLIC keyword
    /<!\[CDATA\[.*\]\]>/is // CDATA sections (optional)
  ];

  for (const pattern of dangerousPatterns) {
    if (pattern.test(xmlString)) {
      return {
        valid: false,
        reason: 'XML contains potentially dangerous content'
      };
    }
  }

  // Check for entity expansion (billion laughs)
  const entityCount = (xmlString.match(/&\w+;/g) || []).length;
  if (entityCount > 100) {
    return {
      valid: false,
      reason: 'Too many entity references'
    };
  }

  return { valid: true };
}

// Audit logging
function logXMLParseAttempt(req, success, details = {}) {
  const logEntry = {
    timestamp: new Date().toISOString(),
    ip: req.ip,
    userAgent: req.get('user-agent'),
    endpoint: req.path,
    success,
    payloadSize: req.body?.length || 0,
    ...details
  };

  // Production: Send to SIEM/logging service
  console.log(JSON.stringify(logEntry));
}

app.post('/api/upload/xml', xmlLimiter, async (req, res) => {
  const startTime = Date.now();

  try {
    // Layer 1: Content-Type validation
    const contentType = req.get('content-type');
    if (!contentType?.includes('xml')) {
      logXMLParseAttempt(req, false, { reason: 'Invalid content type' });
      return res.status(415).json({ error: 'Content-Type must be XML' });
    }

    // Layer 2: Pre-parsing security scan
    const securityCheck = validateXMLSecurity(req.body);
    if (!securityCheck.valid) {
      logXMLParseAttempt(req, false, { 
        reason: securityCheck.reason,
        blocked: true 
      });
      return res.status(400).json({ error: 'Invalid XML content' });
    }

    // Layer 3: XML well-formedness validation
    const validationResult = XMLValidator.validate(req.body, {
      allowBooleanAttributes: false
    });

    if (validationResult !== true) {
      logXMLParseAttempt(req, false, { 
        reason: 'Malformed XML',
        error: validationResult.err?.msg 
      });
      return res.status(400).json({ error: 'Malformed XML document' });
    }

    // Layer 4: Secure parsing
    const parser = createSecureXMLParser();
    const result = parser.parse(req.body);

    // Layer 5: Schema/structure validation
    if (!result.user || typeof result.user !== 'object') {
      logXMLParseAttempt(req, false, { reason: 'Invalid structure' });
      return res.status(400).json({ error: 'Invalid XML structure' });
    }

    // Layer 6: Data validation
    const { username, email } = result.user;

    if (!username || typeof username !== 'string') {
      return res.status(400).json({ error: 'Missing or invalid username' });
    }

    if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      return res.status(400).json({ error: 'Missing or invalid email' });
    }

    // Sanitize output
    const sanitizedData = {
      username: username.slice(0, 100).replace(/[<>&"']/g, ''),
      email: email.slice(0, 255).toLowerCase()
    };

    logXMLParseAttempt(req, true, { 
      processingTime: Date.now() - startTime 
    });

    res.json({
      success: true,
      data: sanitizedData
    });

  } catch (error) {
    logXMLParseAttempt(req, false, { 
      reason: 'Parse exception',
      error: error.message 
    });

    // Generic error - don't leak parser details
    res.status(500).json({ error: 'Unable to process request' });
  }
});

