**VULNERABLE CODE**:

```javascript
const express = require('express');
const _ = require('lodash'); // lodash 4.17.11 or earlier

const app = express();
app.use(express.json());

const defaultSettings = {
  theme: 'light',
  notifications: true,
  language: 'en'
};

// DANGEROUS: User input directly merged with defaults
app.post('/api/preferences', (req, res) => {
  const userPrefs = req.body;

  // Vulnerable to prototype pollution!
  const mergedSettings = _.defaultsDeep({}, userPrefs, defaultSettings);

  // Save to database
  saveUserPreferences(req.user.id, mergedSettings);

  res.json({ success: true, settings: mergedSettings });
});

app.get('/api/admin', (req, res) => {
  const user = { name: req.user.name };

  // After pollution, ALL objects inherit isAdmin: true
  if (user.isAdmin) {
    res.json({ secret: 'admin_data_here' });
  } else {
    res.status(403).json({ error: 'Forbidden' });
  }
});

app.listen(3000);
```

**Attack Payload**:
```json
{
  "__proto__": {
    "isAdmin": true
  }
}
```

**Why This Is Dangerous**:
- Modifies `Object.prototype`, affecting ALL objects in the application
- Attacker can inject properties like `isAdmin: true` to bypass authorization
- Can lead to Remote Code Execution if polluted properties reach `child_process.spawn` or similar
- Affects 4.4+ million repositories that used vulnerable lodash versions

**SECURE VERSION**:

```javascript
const express = require('express');
const _ = require('lodash'); // lodash 4.17.21+ (patched version)

const app = express();
app.use(express.json());

const defaultSettings = {
  theme: 'light',
  notifications: true,
  language: 'en'
};

// Whitelist of allowed preference keys
const ALLOWED_KEYS = ['theme', 'notifications', 'language', 'fontSize'];
const ALLOWED_THEMES = ['light', 'dark', 'system'];
const ALLOWED_LANGUAGES = ['en', 'es', 'fr', 'de', 'ja'];

function sanitizePreferences(userPrefs) {
  const sanitized = {};

  for (const key of ALLOWED_KEYS) {
    if (userPrefs.hasOwnProperty(key)) {
      // Use hasOwnProperty to ignore prototype chain
      const value = userPrefs[key];

      // Validate each field type and value
      switch (key) {
        case 'theme':
          if (ALLOWED_THEMES.includes(value)) {
            sanitized.theme = value;
          }
          break;
        case 'notifications':
          if (typeof value === 'boolean') {
            sanitized.notifications = value;
          }
          break;
        case 'language':
          if (ALLOWED_LANGUAGES.includes(value)) {
            sanitized.language = value;
          }
          break;
        case 'fontSize':
          if (typeof value === 'number' && value >= 10 && value <= 24) {
            sanitized.fontSize = value;
          }
          break;
      }
    }
  }

  return sanitized;
}

app.post('/api/preferences', (req, res) => {
  // Sanitize before merging
  const sanitizedPrefs = sanitizePreferences(req.body);

  // Safe merge with sanitized input
  const mergedSettings = { ...defaultSettings, ...sanitizedPrefs };

  saveUserPreferences(req.user.id, mergedSettings);
  res.json({ success: true, settings: mergedSettings });
});

app.listen(3000);
```

**Key Security Controls**:
- **Updated lodash**: Version 4.17.21+ includes prototype pollution fixes
- **Input sanitization**: Whitelist allowed keys, ignore __proto__ and constructor
- **Type validation**: Ensure each value matches expected type
- **Spread operator**: Safer than lodash merge for simple cases
