Excellent question! Prototype pollution defense requires multiple layers across your entire application. Here's a comprehensive production approach:

**PRODUCTION PATTERN**:

```javascript
// security/prototype-pollution-guard.js
const DANGEROUS_KEYS = ['__proto__', 'constructor', 'prototype'];

/**
 * Deep sanitize object to remove prototype pollution vectors
 * @param {any} obj - Object to sanitize
 * @param {number} depth - Current recursion depth
 * @param {number} maxDepth - Maximum allowed depth
 * @returns {any} Sanitized object
 */
function deepSanitize(obj, depth = 0, maxDepth = 10) {
  // Prevent infinite recursion attacks
  if (depth > maxDepth) {
    throw new Error('Object nesting too deep');
  }

  // Handle non-objects
  if (obj === null || typeof obj !== 'object') {
    return obj;
  }

  // Handle arrays
  if (Array.isArray(obj)) {
    return obj.map(item => deepSanitize(item, depth + 1, maxDepth));
  }

  // Create clean object without prototype
  const clean = Object.create(null);

  for (const key of Object.keys(obj)) {
    // Skip dangerous keys
    if (DANGEROUS_KEYS.includes(key)) {
      console.warn(`Blocked prototype pollution attempt: ${key}`);
      continue;
    }

    // Recursively sanitize nested objects
    clean[key] = deepSanitize(obj[key], depth + 1, maxDepth);
  }

  return clean;
}

/**
 * Express middleware to sanitize all incoming JSON bodies
 */
function prototypePollutionGuard() {
  return (req, res, next) => {
    if (req.body && typeof req.body === 'object') {
      try {
        req.body = deepSanitize(req.body);
      } catch (error) {
        return res.status(400).json({ 
          error: 'Invalid request structure' 
        });
      }
    }
    next();
  };
}

module.exports = { deepSanitize, prototypePollutionGuard };
```

