**Why This Is Dangerous**:
- node-serialize can deserialize and execute JavaScript functions
- The `_$$ND_FUNC$$_` marker triggers automatic function execution
- Attacker gains full remote code execution with server privileges
- Can read files, establish reverse shells, pivot to other systems

**SECURE VERSION**:

```javascript
const express = require('express');
const cookieParser = require('cookie-parser');
const Ajv = require('ajv');
const crypto = require('crypto');

const app = express();
app.use(cookieParser());
app.use(express.json());

const ajv = new Ajv({ allErrors: true });
const SIGNING_KEY = process.env.COOKIE_SIGNING_KEY;

// Define strict schema for user preferences
const preferencesSchema = {
  type: 'object',
  properties: {
    theme: { type: 'string', enum: ['light', 'dark', 'system'] },
    language: { type: 'string', pattern: '^[a-z]{2}(-[A-Z]{2})?$' },
    notifications: { type: 'boolean' },
    fontSize: { type: 'integer', minimum: 10, maximum: 24 }
  },
  additionalProperties: false,
  required: ['theme']
};

const validatePreferences = ajv.compile(preferencesSchema);

// SECURE: Sign serialized data to prevent tampering
function signData(data) {
  const json = JSON.stringify(data);
  const signature = crypto.createHmac('sha256', SIGNING_KEY)
    .update(json)
    .digest('hex');
  return Buffer.from(`${json}.${signature}`).toString('base64');
}

// SECURE: Verify signature before parsing
function verifyAndParse(signedData) {
  try {
    const decoded = Buffer.from(signedData, 'base64').toString('utf8');
    const lastDotIndex = decoded.lastIndexOf('.');
    if (lastDotIndex === -1) return null;

    const json = decoded.substring(0, lastDotIndex);
    const signature = decoded.substring(lastDotIndex + 1);

    const expectedSignature = crypto.createHmac('sha256', SIGNING_KEY)
      .update(json)
      .digest('hex');

    // Timing-safe comparison
    if (!crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expectedSignature))) {
      return null;
    }

    return JSON.parse(json);
  } catch (e) {
    return null;
  }
}

app.get('/profile', (req, res) => {
  const userPrefs = req.cookies.preferences;

  if (userPrefs) {
    // SECURE: Verify signature and use safe JSON.parse
    const preferences = verifyAndParse(userPrefs);

    if (!preferences || !validatePreferences(preferences)) {
      return res.status(400).json({ error: 'Invalid preferences' });
    }

    res.json({ preferences });
  } else {
    res.json({ preferences: { theme: 'system' } });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Use JSON.parse instead of unserialize**: JSON.parse cannot execute code, only parse data
- **HMAC signing**: Prevents tampering with serialized data
- **Schema validation**: Strict allowlist of permitted fields and values
- **Timing-safe comparison**: Prevents timing attacks on signature verification

Complex object handling requires careful attention to prototype pollution attacks and type coercion. The 2022 Formidable prototype pollution (CVE-2022-29622) and similar attacks in lodash, jQuery, and minimist show how dangerous this can be.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const Ajv = require('ajv');
const addFormats = require('ajv-formats');
const crypto = require('crypto');
const winston = require('winston');
const rateLimit = require('express-rate-limit');

const app = express();

// Security logging
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'security.log' })
  ]
});

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: { error: 'Too many requests' }
});
app.use(limiter);

// SECURE: Prototype pollution safe JSON parser
function safeJSONParse(jsonString, maxDepth = 10) {
  const FORBIDDEN_KEYS = ['__proto__', 'constructor', 'prototype'];

  function sanitizeObject(obj, depth = 0) {
    if (depth > maxDepth) {
      throw new Error('Maximum depth exceeded');
    }

    if (obj === null || typeof obj !== 'object') {
      return obj;
    }

    if (Array.isArray(obj)) {
      return obj.map(item => sanitizeObject(item, depth + 1));
    }

    // Create clean object without prototype chain
    const clean = Object.create(null);

    for (const key of Object.keys(obj)) {
      // Block prototype pollution vectors
      if (FORBIDDEN_KEYS.includes(key)) {
        logger.warn('Prototype pollution attempt blocked', { key });
        continue;
      }

      // Validate key format
      if (!/^[a-zA-Z_][a-zA-Z0-9_]*$/.test(key)) {
        logger.warn('Invalid key format rejected', { key });
        continue;
      }

      clean[key] = sanitizeObject(obj[key], depth + 1);
    }

    return clean;
  }

  try {
    const parsed = JSON.parse(jsonString);
    return sanitizeObject(parsed);
  } catch (e) {
    logger.error('JSON parse error', { error: e.message });
    return null;
  }
}

// SECURE: Custom serializer with type preservation
class SafeSerializer {
  static ALLOWED_TYPES = ['string', 'number', 'boolean', 'null', 'date', 'array', 'object'];

  static serialize(obj) {
    const transformed = this.transform(obj);
    return JSON.stringify(transformed);
  }

  static transform(value) {
    if (value === null) return { type: 'null', value: null };
    if (value instanceof Date) {
      return { type: 'date', value: value.toISOString() };
    }
    if (Array.isArray(value)) {
      return { type: 'array', value: value.map(v => this.transform(v)) };
    }
    if (typeof value === 'object') {
      const transformed = Object.create(null);
      for (const [k, v] of Object.entries(value)) {
        transformed[k] = this.transform(v);
      }
      return { type: 'object', value: transformed };
    }
    return { type: typeof value, value: value };
  }

  static deserialize(jsonString) {
    const parsed = safeJSONParse(jsonString);
    if (!parsed) return null;
    return this.restore(parsed);
  }

  static restore(wrapped) {
    if (!wrapped || !this.ALLOWED_TYPES.includes(wrapped.type)) {
      throw new Error('Invalid type in serialized data');
    }

    switch (wrapped.type) {
      case 'null': return null;
      case 'string': return String(wrapped.value);
      case 'number': {
        const num = Number(wrapped.value);
        if (!Number.isFinite(num)) throw new Error('Invalid number');
        return num;
      }
      case 'boolean': return Boolean(wrapped.value);
      case 'date': {
        const date = new Date(wrapped.value);
        if (isNaN(date.getTime())) throw new Error('Invalid date');
        return date;
      }
      case 'array': return wrapped.value.map(v => this.restore(v));
      case 'object': {
        const obj = Object.create(null);
        for (const [k, v] of Object.entries(wrapped.value)) {
          obj[k] = this.restore(v);
        }
        return obj;
      }
      default: throw new Error('Unknown type');
    }
  }
}

// SECURE: Integrity-protected data wrapper
class IntegrityProtectedData {
  constructor(encryptionKey, signingKey) {
    this.encryptionKey = Buffer.from(encryptionKey, 'hex');
    this.signingKey = Buffer.from(signingKey, 'hex');
  }

  wrap(data, expiresInMs = 3600000) {
    const payload = {
      data: SafeSerializer.serialize(data),
      exp: Date.now() + expiresInMs,
      jti: crypto.randomBytes(16).toString('hex')
    };

    const payloadJson = JSON.stringify(payload);

    // Encrypt
    const iv = crypto.randomBytes(12);
    const cipher = crypto.createCipheriv('aes-256-gcm', this.encryptionKey, iv);
    const encrypted = Buffer.concat([cipher.update(payloadJson, 'utf8'), cipher.final()]);
    const authTag = cipher.getAuthTag();

    // Sign
    const toSign = Buffer.concat([iv, authTag, encrypted]);
    const signature = crypto.createHmac('sha256', this.signingKey).update(toSign).digest();

    return Buffer.concat([signature, iv, authTag, encrypted]).toString('base64url');
  }

  unwrap(wrapped) {
    try {
      const buffer = Buffer.from(wrapped, 'base64url');

      const signature = buffer.subarray(0, 32);
      const iv = buffer.subarray(32, 44);
      const authTag = buffer.subarray(44, 60);
      const encrypted = buffer.subarray(60);

      // Verify signature
      const toVerify = Buffer.concat([iv, authTag, encrypted]);
      const expectedSig = crypto.createHmac('sha256', this.signingKey).update(toVerify).digest();

      if (!crypto.timingSafeEqual(signature, expectedSig)) {
        logger.warn('Signature verification failed');
        return null;
      }

      // Decrypt
      const decipher = crypto.createDecipheriv('aes-256-gcm', this.encryptionKey, iv);
      decipher.setAuthTag(authTag);
      const decrypted = Buffer.concat([decipher.update(encrypted), decipher.final()]);

      const payload = JSON.parse(decrypted.toString('utf8'));

      // Check expiration
      if (payload.exp < Date.now()) {
        logger.info('Token expired');
        return null;
      }

      return SafeSerializer.deserialize(payload.data);
    } catch (e) {
      logger.error('Unwrap failed', { error: e.message });
      return null;
    }
  }
}

// Usage
