**Attack Reconnaissance Payload**:
```bash
# Fingerprint the server
curl -I http://target.com/api/user/1
# Response reveals: X-Powered-By: Express

# Trigger error to get stack trace
curl http://target.com/api/user/invalid'
# Response reveals internal file paths, Node.js version, dependencies
```

**Why This Is Dangerous**:
- `X-Powered-By: Express` header reveals technology stack for targeted exploits
- Default session secret is publicly known and allows session forgery
- Missing `secure` flag allows session cookies over HTTP (MITM attacks)
- Missing `httpOnly` flag enables JavaScript access to cookies (XSS theft)
- Stack traces reveal internal paths, code structure, and dependency versions
- No CSP, HSTS, or X-Frame-Options enables clickjacking and injection attacks

**SECURE VERSION**:

```javascript
const express = require('express');
const session = require('express-session');
const helmet = require('helmet');
const crypto = require('crypto');

const app = express();

// SECURITY: Disable X-Powered-By header
app.disable('x-powered-by');

// SECURITY: Apply security headers via Helmet
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],
      styleSrc: ["'self'", "'unsafe-inline'"],
      imgSrc: ["'self'", 'data:', 'https:'],
      connectSrc: ["'self'"],
      frameSrc: ["'none'"],
      objectSrc: ["'none'"]
    }
  },
  hsts: {
    maxAge: 31536000,
    includeSubDomains: true,
    preload: true
  }
}));

// SECURITY: Hardened session configuration
app.use(session({
  secret: process.env.SESSION_SECRET,  // From environment variable
  name: '__Host-sessionId',  // Cookie prefix for additional security
  resave: false,
  saveUninitialized: false,  // Don't create sessions until needed
  cookie: {
    secure: true,      // HTTPS only
    httpOnly: true,    // No JavaScript access
    sameSite: 'strict', // CSRF protection
    maxAge: 3600000,   // 1 hour expiry
    path: '/',
    domain: process.env.COOKIE_DOMAIN
  }
}));

app.get('/api/user/:id', (req, res) => {
  try {
    const user = getUserById(req.params.id);
    res.json(user);
  } catch (error) {
    // SECURITY: Log internally, return generic message
    console.error('User fetch error:', error);
    res.status(500).json({ error: 'An error occurred' });
  }
});

// SECURITY: Production error handler
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);
  res.status(500).json({ error: 'Internal server error' });
});

app.listen(3000);
```

**Key Security Controls**:
- **Helmet middleware**: Automatically sets 11+ security headers including CSP, HSTS, X-Frame-Options, X-Content-Type-Options
- **Hardened session cookies**: secure, httpOnly, sameSite flags prevent session theft via XSS, MITM, and CSRF
- **Environment-based secrets**: Session secrets from env vars, never hardcoded
- **Generic error responses**: Internal errors logged but not exposed to users

Environment-aware configuration is critical for maintaining security in production while keeping development productive. The key is implementing secure defaults that get progressively stricter, never the reverse.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const session = require('express-session');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const RedisStore = require('connect-redis').default;
const { createClient } = require('redis');
const winston = require('winston');

// Environment detection
const NODE_ENV = process.env.NODE_ENV || 'development';
const isProduction = NODE_ENV === 'production';
const isTest = NODE_ENV === 'test';

// SECURITY: Validate required production secrets
if (isProduction) {
  const requiredEnvVars = ['SESSION_SECRET', 'REDIS_URL', 'COOKIE_DOMAIN'];
  const missing = requiredEnvVars.filter(v => !process.env[v]);
  if (missing.length > 0) {
    console.error(`FATAL: Missing required env vars: ${missing.join(', ')}`);
    process.exit(1);
  }
}

// Logging configuration - different levels per environment
const logger = winston.createLogger({
  level: isProduction ? 'warn' : 'debug',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.errors({ stack: !isProduction }),
    isProduction 
      ? winston.format.json() 
      : winston.format.prettyPrint()
  ),
  defaultMeta: { service: 'api-server', env: NODE_ENV },
  transports: [
    new winston.transports.Console(),
    ...(isProduction ? [
      new winston.transports.File({ filename: '/var/log/app/error.log', level: 'error' }),
      new winston.transports.File({ filename: '/var/log/app/audit.log', level: 'info' })
    ] : [])
  ]
});

const app = express();

// SECURITY: Always disable x-powered-by
app.disable('x-powered-by');

// SECURITY: Trust proxy only in production behind load balancer
if (isProduction) {
  app.set('trust proxy', 1);
}

// SECURITY: Environment-aware Helmet configuration
const helmetConfig = {
  contentSecurityPolicy: isProduction ? {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],
      styleSrc: ["'self'"],
      imgSrc: ["'self'", 'data:'],
      connectSrc: ["'self'"],
      frameSrc: ["'none'"],
      objectSrc: ["'none'"],
      upgradeInsecureRequests: []
    }
  } : false,  // Disabled in dev for easier debugging
  hsts: isProduction ? {
    maxAge: 31536000,
    includeSubDomains: true,
    preload: true
  } : false
};
app.use(helmet(helmetConfig));

// SECURITY: Rate limiting - stricter in production
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: isProduction ? 100 : 1000,
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req, res) => {
    logger.warn('Rate limit exceeded', {
      ip: req.ip,
      path: req.path,
      userAgent: req.get('User-Agent')
    });
    res.status(429).json({ error: 'Too many requests' });
  }
});
app.use('/api/', limiter);

// Session store - Redis in production, memory in dev
async function initializeSessionStore() {
  if (isProduction) {
    const redisClient = createClient({ url: process.env.REDIS_URL });
    await redisClient.connect();
    return new RedisStore({ client: redisClient, prefix: 'sess:' });
  }
  return undefined;  // Uses default MemoryStore in dev
}

async function configureApp() {
  const sessionStore = await initializeSessionStore();

  // SECURITY: Environment-specific session configuration
  const sessionConfig = {
    store: sessionStore,
    secret: process.env.SESSION_SECRET || (isProduction ? undefined : 'dev-secret-only'),
    name: isProduction ? '__Host-sid' : 'sid',
    resave: false,
    saveUninitialized: false,
    cookie: {
      secure: isProduction,
      httpOnly: true,
      sameSite: isProduction ? 'strict' : 'lax',
      maxAge: isProduction ? 3600000 : 86400000,
      ...(isProduction && { domain: process.env.COOKIE_DOMAIN })
    }
  };
  app.use(session(sessionConfig));

  // API routes
  app.get('/api/user/:id', (req, res) => {
    try {
      const user = getUserById(req.params.id);
      res.json(user);
    } catch (error) {
      logger.error('User fetch failed', {
        userId: req.params.id,
        error: error.message,
        stack: error.stack,
        requestId: req.id
      });

      // SECURITY: Different error responses per environment
      if (isProduction) {
        res.status(500).json({
          error: 'An error occurred',
          requestId: req.id  // For support correlation
        });
      } else {
        res.status(500).json({
          error: error.message,
          stack: error.stack
        });
      }
    }
  });

  // SECURITY: Global error handler with environment awareness
  app.use((err, req, res, next) => {
    const errorId = crypto.randomUUID();

    logger.error('Unhandled error', {
      errorId,
      error: err.message,
      stack: err.stack,
      path: req.path,
      method: req.method,
      ip: req.ip
    });

    if (isProduction) {
      res.status(500).json({
        error: 'Internal server error',
        errorId  // Reference for support tickets
      });
    } else {
      res.status(500).json({
        error: err.message,
        stack: err.stack,
        errorId
      });
    }
  });

  return app;
}

module.exports = { configureApp, logger };
```

**Defense in Depth Layers**:

1. **Configuration Validation Layer**:
```javascript
// Fail fast if production secrets are missing
if (isProduction && !process.env.SESSION_SECRET) {
  throw new Error('SESSION_SECRET required in production');
}
```

2. **Security Headers Layer**:
```javascript
// Always present but environment-tuned
app.use(helmet({
  contentSecurityPolicy: isProduction,
  crossOriginEmbedderPolicy: isProduction,
  crossOriginOpenerPolicy: isProduction
}));
```

3. **Error Sanitization Layer**:
```javascript
// Never leak internals in production
const sanitizeError = (err) => isProduction 
  ? { error: 'An error occurred' } 
  : { error: err.message, stack: err.stack };
```

**Additional Protections**:
- **Secret rotation**: Use AWS Secrets Manager or HashiCorp Vault for production secrets with automatic rotation
- **Configuration auditing**: Log all configuration at startup (without secrets) for debugging deploys
- **Health checks**: Expose `/health` endpoint that validates configuration without revealing details
- **Security monitoring**: Send security events (rate limits, auth failures) to SIEM via structured logging
- **Immutable infrastructure**: Use environment variables exclusively, never config files that could be modified

Leaning too much on defaults and bypassing ASP.NET Core Identity's built‑in flows can introduce serious authentication issues, like user enumeration and weak session handling.

**VULNERABLE CODE**:

```csharp
