import type { CommentProps } from "../components/Comment";

export interface ApiError extends Error {
  status?: number;
}

export const fetchJson = async <T>(
  input: RequestInfo,
  init?: RequestInit
): Promise<T> => {
  const response = await fetch(input, {
    credentials: "include",
    ...init
  });

  if (!response.ok) {
    const err: ApiError = new Error(`Request failed with status ${response.status}`);
    err.status = response.status;
    // Central place to hook into monitoring (e.g., Sentry, Datadog)
    console.error("API error", { url: input, status: response.status });
    throw err;
  }

  return (await response.json()) as T;
};

