// Pseudo-TypeScript (server-side):

export const securityHeaders = (env: "development" | "production") => {
  const common = {
    "X-Content-Type-Options": "nosniff",
    "X-Frame-Options": "DENY",
    "Referrer-Policy": "strict-origin-when-cross-origin",
    "Permissions-Policy": "geolocation=()"
  } as Record<string, string>;

  if (env === "production") {
    return {
      ...common,
      // Strict CSP: disallow inline scripts; trust only your own domain & known CDNs.
      "Content-Security-Policy": [
        "default-src 'self'",
        "script-src 'self' https://cdn.example.com",
        "style-src 'self' 'unsafe-inline' https://fonts.googleapis.com",
        "img-src 'self' data:",
        "object-src 'none'",
        "base-uri 'self'",
        "frame-ancestors 'none'"
      ].join("; ")
    };
  }

  // Dev: slightly relaxed for debugging, but still reasonable
  return {
    ...common,
    "Content-Security-Policy": [
      "default-src 'self'",
      "script-src 'self' 'unsafe-inline' 'unsafe-eval'",
      "style-src 'self' 'unsafe-inline'",
      "img-src 'self' data:",
      "object-src 'none'",
      "base-uri 'self'",
      "frame-ancestors 'none'"
    ].join("; ")
  };
};
```

**Defense in Depth Layers**:
1. **Centralized HTML sanitization component**:
   - `SafeHtml` and `sanitizeHtml` ensure *all* HTML injection flows through a single, audited path.
   - Example:
     ```typescript
     <SafeHtml html={userSuppliedHtml} trustLevel="untrusted" />
     ```
2. **Context-aware trust levels**:
   - Different allowlists for `untrusted`, `trusted-admin`, and `system` content limit the blast radius even if an admin account is compromised.
   - Example:
     ```typescript
     const safeAdminHtml = sanitizeHtml(adminHtml, { trustLevel: "trusted-admin" });
     ```
3. **Browser-enforced protections (CSP & headers)**:
   - Strict CSP and security headers mitigate the impact of any missed sanitization or third-party script compromise.
   - Example header configuration:
     ```typescript
     {
       "Content-Security-Policy": "default-src 'self'; script-src 'self' https://cdn.example.com; object-src 'none'",
       "X-Content-Type-Options": "nosniff"
     }
     ```

**Additional Protections**:
- **Server-side validation and sanitization**: Sanitize or reject dangerous HTML on the server as well, so malicious content never reaches the database. Use the same allowlist policy (e.g., DOMPurify on Node or an equivalent library).
- **Audit logging and anomaly detection**: Log creation and editing of rich HTML content with user IDs, IPs, and diffs; alert on suspicious patterns (e.g., `<script>`, `onerror`, `javascript:`) being repeatedly submitted.
- **Rate limiting and abuse controls**: Apply rate limiting to endpoints that accept HTML content and to read-heavy endpoints when unusual access patterns appear, to limit the impact of automated XSS exploitation and reduce log noise during attacks.

When building file upload endpoints, a common mistake is to only check that the user is logged in and forget to verify that they are allowed to upload to a specific project or path. That leads to broken access control and potential arbitrary file overwrite.

**VULNERABLE CODE**:

```typescript
import express, { Request, Response } from 'express';
import multer from 'multer';
import path from 'path';
import fs from 'fs';

const app = express();
const upload = multer({ dest: 'uploads/' });

// Fake middleware: only checks that user is authenticated
function requireAuth(req: Request, res: Response, next: () => void) {
  if (!req.headers['x-user-id']) {
    return res.status(401).json({ error: 'Not authenticated' });
  }
  // In reality you would load the user from DB, but we just attach an ID
  (req as any).user = { id: req.headers['x-user-id'] };
  next();
}

// VULNERABLE: any authenticated user can upload to any project and overwrite files
app.post('/api/projects/:projectId/upload', requireAuth, upload.single('file'), (req: Request, res: Response) => {
  const projectId = req.params.projectId; // no authorization check
  const file = req.file;

  if (!file) {
    return res.status(400).json({ error: 'No file uploaded' });
  }

  // Directly trust projectId for file path
  const targetDir = path.join(__dirname, 'project_files', projectId);
  if (!fs.existsSync(targetDir)) {
    fs.mkdirSync(targetDir, { recursive: true });
  }

  const targetPath = path.join(targetDir, file.originalname);

  fs.renameSync(file.path, targetPath); // may overwrite existing file

  res.json({ message: 'File uploaded', path: targetPath });
});

app.listen(3000, () => {
  console.log('Server started on port 3000');
});
```

**Attack Payload** (HTTP request exploiting authorization flaw):
```bash
curl -X POST "http://localhost:3000/api/projects/12345/upload" \
  -H "x-user-id: attacker" \
  -F "file=@/tmp/malicious-config.yml;filename=config.yml"
```

This payload assumes that project `12345` belongs to another user. The attacker can overwrite `config.yml` or other sensitive files for that project just by being authenticated.

**Why This Is Dangerous**:
- Any authenticated user can upload or overwrite files for any project ID (insecure direct object reference).
- There is no check that the user is a member/owner of the project, or that they have upload permissions.
- The server trusts user-controlled identifiers (`projectId` and `originalname`) in file system paths, which may lead to overwrites and chaining with other vulnerabilities.

**SECURE VERSION**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import multer from 'multer';
import path from 'path';
import fs from 'fs';

const app = express();
const upload = multer({ dest: 'uploads/' });

interface User {
  id: string;
  role: 'user' | 'admin';
}

interface Project {
  id: string;
  ownerId: string;
  members: string[];
  uploadsEnabled: boolean;
}

// Simulated project store
const projects: Project[] = [
  { id: '1', ownerId: 'u1', members: ['u1', 'u2'], uploadsEnabled: true },
  { id: '2', ownerId: 'u3', members: ['u3'], uploadsEnabled: false }
];

function findProjectById(id: string): Project | undefined {
  return projects.find(p => p.id === id);
}

function requireAuth(req: Request, res: Response, next: NextFunction) {
  const userId = req.headers['x-user-id'];
  if (!userId || typeof userId !== 'string') {
    return res.status(401).json({ error: 'Not authenticated' });
  }
  (req as any).user = { id: userId, role: 'user' } as User;
  next();
}

// Authorization middleware: check user is member/owner and uploads allowed
function requireProjectUploadPermission(req: Request, res: Response, next: NextFunction) {
  const user = (req as any).user as User | undefined;
  const projectId = req.params.projectId;

  if (!user) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  const project = findProjectById(projectId);

  if (!project) {
    return res.status(404).json({ error: 'Project not found' });
  }

  const isMember = project.members.includes(user.id);
  const isOwner = project.ownerId === user.id;

  if (!isMember && user.role !== 'admin') {
    return res.status(403).json({ error: 'Not authorized to upload to this project' });
  }

  if (!project.uploadsEnabled && user.role !== 'admin') {
    return res.status(403).json({ error: 'Uploads are disabled for this project' });
  }

  // Attach project to request for later handlers
  (req as any).project = project;
  next();
}

// Simple filename whitelist (defense-in-depth)
function sanitizeFilename(filename: string): string {
  const base = path.basename(filename); // remove any directory components
  // Only allow alphanumerics, dash, underscore, dot
  return base.replace(/[^a-zA-Z0-9._-]/g, '_');
}

app.post(
  '/api/projects/:projectId/upload',
  requireAuth,
  requireProjectUploadPermission,
  upload.single('file'),
  (req: Request, res: Response) => {
    const user = (req as any).user as User;
    const project = (req as any).project as Project;
    const file = req.file;

    if (!file) {
      return res.status(400).json({ error: 'No file uploaded' });
    }

    try {
      const safeFilename = sanitizeFilename(file.originalname);
      const targetDir = path.join(__dirname, 'project_files', project.id);

      if (!fs.existsSync(targetDir)) {
        fs.mkdirSync(targetDir, { recursive: true });
      }

      const targetPath = path.join(targetDir, safeFilename);

      // Avoid silent overwrite: if file exists, require explicit replace flag
      const allowReplace = req.query.replace === 'true';
      if (fs.existsSync(targetPath) && !allowReplace) {
        fs.unlinkSync(file.path); // delete temp file
        return res.status(409).json({
          error: 'File already exists. Use ?replace=true to overwrite.'
        });
      }

      fs.renameSync(file.path, targetPath);

      console.log(
        `User ${user.id} uploaded file ${safeFilename} to project ${project.id}`
      );

      res.json({
        message: 'File uploaded',
        projectId: project.id,
        filename: safeFilename
      });
    } catch (err) {
      console.error('Upload error:', err);
      if (req.file && fs.existsSync(req.file.path)) {
        fs.unlinkSync(req.file.path);
      }
      res.status(500).json({ error: 'Internal server error' });
    }
  }
);

app.listen(3000, () => {
  console.log('Secure upload server started on port 3000');
});
```

**Key Security Controls**:
- **Project-level authorization checks**: `requireProjectUploadPermission` verifies that the user is a project member/owner (or admin) and that uploads are enabled before allowing file writes.
- **Path and filename hardening**: `sanitizeFilename` removes directory traversal attempts and limits filenames to a safe character set, preventing path manipulation.
- **Controlled overwrite behavior with logging**: The handler prevents silent overwrites unless the client explicitly opts in (`?replace=true`), and logs who uploaded which file to which project for auditability and incident response.

In production, you should centralize authorization logic, separate metadata from storage, and add multiple protection layers: strict RBAC, size/type limits, rate limiting, secure storage, and audit logging that can feed monitoring systems.

**PRODUCTION PATTERN**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import multer from 'multer';
import path from 'path';
import fs from 'fs';
import crypto from 'crypto';

// In real systems use a proper logger and monitoring (e.g., pino + Prometheus)
const app = express();

// Environment-specific config
const ENV = process.env.NODE_ENV || 'development';
const MAX_FILE_SIZE_MB = ENV === 'production' ? 50 : 5;
const MAX_FILE_SIZE = MAX_FILE_SIZE_MB * 1024 * 1024;

// Simple in-memory rate limit store (replace with Redis or similar in prod)
const uploadAttempts: Record<string, { count: number; resetAt: number }> = {};

interface User {
  id: string;
  role: 'user' | 'manager' | 'admin';
}

interface Project {
  id: string;
  ownerId: string;
  members: string[];
  managers: string[];
  uploadsEnabled: boolean;
}

const projects: Project[] = [
  {
    id: '1',
    ownerId: 'u1',
    members: ['u1', 'u2', 'u4'],
    managers: ['u2'],
    uploadsEnabled: true
  }
];

function findProject(id: string): Project | undefined {
  return projects.find(p => p.id === id);
}

function logAudit(event: string, details: Record<string, unknown>): void {
  const entry = {
    ts: new Date().toISOString(),
    event,
    ...details
  };
  console.log('[AUDIT]', JSON.stringify(entry));
}

function requireAuth(req: Request, res: Response, next: NextFunction) {
  const userId = req.headers['x-user-id'];
  const role = (req.headers['x-role'] as string) || 'user';

  if (!userId || typeof userId !== 'string') {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  const user: User = { id: userId, role: role as User['role'] };
  (req as any).user = user;
  next();
}

// Role & project-based authorization
function requireProjectUploadPermission(req: Request, res: Response, next: NextFunction) {
  const user = (req as any).user as User | undefined;
  const projectId = req.params.projectId;

  if (!user) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  const project = findProject(projectId);
  if (!project) {
    return res.status(404).json({ error: 'Project not found' });
  }

  const isOwner = project.ownerId === user.id;
  const isManager = project.managers.includes(user.id);
  const isMember = project.members.includes(user.id);

  const canUpload =
    user.role === 'admin' ||
    isOwner ||
    isManager ||
    (isMember && project.uploadsEnabled);

  if (!canUpload) {
    logAudit('upload_denied', {
      userId: user.id,
      projectId: project.id,
      reason: 'insufficient_permissions'
    });
    return res.status(403).json({ error: 'Not authorized to upload to this project' });
  }

  (req as any).project = project;
  next();
}

// Rate limiting per user (very simple variant)
function uploadRateLimit(req: Request, res: Response, next: NextFunction) {
  const user = (req as any).user as User | undefined;
  if (!user) return res.status(401).json({ error: 'Not authenticated' });

  const key = user.id;
  const now = Date.now();
  const windowMs = 15 * 60 * 1000; // 15 minutes
  const maxUploads = ENV === 'production' ? 50 : 1000;

  let bucket = uploadAttempts[key];
  if (!bucket || bucket.resetAt < now) {
    bucket = { count: 0, resetAt: now + windowMs };
    uploadAttempts[key] = bucket;
  }

  if (bucket.count >= maxUploads) {
    logAudit('upload_rate_limited', { userId: user.id });
    return res.status(429).json({ error: 'Too many upload attempts, slow down' });
  }

  bucket.count++;
  next();
}

// Multer config with strict limits
const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    cb(null, 'tmp_uploads/');
  },
  filename: (req, file, cb) => {
    const randomName = crypto.randomBytes(16).toString('hex');
    cb(null, randomName + path.extname(file.originalname));
  }
});

const upload = multer({
  storage,
  limits: {
    fileSize: MAX_FILE_SIZE
  },
  fileFilter: (req, file, cb) => {
    // Allow only a few safe mime types (example)
    const allowed = ['image/png', 'image/jpeg', 'application/pdf'];
    if (!allowed.includes(file.mimetype)) {
      return cb(new Error('Unsupported file type'));
    }
    cb(null, true);
  }
});

function sanitizeFilename(original: string): string {
  const base = path.basename(original);
  return base.replace(/[^a-zA-Z0-9._-]/g, '_');
}

app.post(
  '/api/projects/:projectId/upload',
  requireAuth,
  uploadRateLimit,
  requireProjectUploadPermission,
  upload.single('file'),
  (req: Request, res: Response) => {
    const user = (req as any).user as User;
    const project = (req as any).project as Project;
    const file = req.file;

    if (!file) {
      return res.status(400).json({ error: 'No file uploaded' });
    }

    const originalName = sanitizeFilename(file.originalname);
    const targetDir = path.join(__dirname, 'project_files', project.id);
    const targetPath = path.join(targetDir, originalName);

    try {
      if (!fs.existsSync(targetDir)) {
        fs.mkdirSync(targetDir, { recursive: true });
      }

      const allowReplace = req.query.replace === 'true';
      const exists = fs.existsSync(targetPath);

      if (exists && !allowReplace) {
        fs.unlinkSync(file.path);
        logAudit('upload_conflict', {
          userId: user.id,
          projectId: project.id,
          filename: originalName
        });
        return res.status(409).json({
          error: 'File already exists. Use ?replace=true to overwrite.'
        });
      }

      // Move from temp storage to project storage
      fs.renameSync(file.path, targetPath);

      logAudit('upload_success', {
        userId: user.id,
        projectId: project.id,
        filename: originalName,
        size: file.size,
        mimetype: file.mimetype
      });

      res.status(exists ? 200 : 201).json({
        message: exists ? 'File replaced' : 'File uploaded',
        projectId: project.id,
        filename: originalName
      });
    } catch (err) {
      console.error('Upload error:', err);
      logAudit('upload_error', {
        userId: user.id,
        projectId: project.id,
        error: (err as Error).message
      });

      if (file && fs.existsSync(file.path)) {
        fs.unlinkSync(file.path);
      }
      res.status(500).json({ error: 'Internal server error' });
    }
  }
);

// Basic security headers (for a full web app you would add more)
app.use((req: Request, res: Response, next: NextFunction) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  next();
});

app.listen(3000, () => {
  console.log(`Prod-style upload server listening on 3000 (env=${ENV})`);
});
```

**Defense in Depth Layers**:
1. **Centralized RBAC and project checks**:
   ```typescript
   const canUpload =
     user.role === 'admin' ||
     isOwner ||
     isManager ||
     (isMember && project.uploadsEnabled);
   if (!canUpload) {
     return res.status(403).json({ error: 'Not authorized' });
   }
   ```
   This enforces role- and project-based permissions before any file system operations.

2. **Resource and abuse controls (limits + rate limiting)**:
   ```typescript
   const upload = multer({ limits: { fileSize: MAX_FILE_SIZE } });
   if (bucket.count >= maxUploads) {
     return res.status(429).json({ error: 'Too many upload attempts' });
   }
   ```
   This prevents oversized uploads and brute-force/DoS via upload spam.

3. **Audit logging and monitoring hooks**:
   ```typescript
   logAudit('upload_success', {
     userId: user.id,
     projectId: project.id,
     filename: originalName,
     size: file.size
   });
   ```
   These logs provide traceability for every upload attempt and outcome, feeding into SIEM/monitoring.

**Additional Protections**:
- **Store only metadata in the DB and files in object storage** (e.g., S3 with per-project buckets and explicit IAM policies) to isolate file access from app server compromise.
- **Background virus/malware scanning** of uploaded files before they are made available to others, with quarantine and notification workflows.
- **Strict content-type and download controls** (set `Content-Disposition: attachment` and do not serve user uploads from the same domain as your main app) to reduce XSS and drive-by download risks.

Checking balance before deducting is NOT safe without proper synchronization. This creates a classic Time-of-Check to Time-of-Use (TOCTOU) race condition that attackers can exploit through concurrent requests.

**VULNERABLE CODE**:

```go
package main

import (
	"database/sql"
	"encoding/json"
	"log"
	"net/http"

	_ "github.com/lib/pq"
)

var db *sql.DB

type TransferRequest struct {
	FromAccount string  `json:"from_account"`
	ToAccount   string  `json:"to_account"`
	Amount      float64 `json:"amount"`
}

// VULNERABLE: Race condition between check and update
func transferFunds(w http.ResponseWriter, r *http.Request) {
	var req TransferRequest
	json.NewDecoder(r.Body).Decode(&req)

	// Step 1: Check balance (Time-of-Check)
	var balance float64
	err := db.QueryRow("SELECT balance FROM accounts WHERE id = $1", req.FromAccount).Scan(&balance)
	if err != nil {
		http.Error(w, "Account not found", http.StatusNotFound)
		return
	}

	// VULNERABLE: Race window exists here!
	// Another concurrent request can pass the check before deduction
	if balance < req.Amount {
		http.Error(w, "Insufficient funds", http.StatusBadRequest)
		return
	}

	// Step 2: Deduct from source (Time-of-Use)
	_, err = db.Exec("UPDATE accounts SET balance = balance - $1 WHERE id = $2", req.Amount, req.FromAccount)
	if err != nil {
		http.Error(w, "Transfer failed", http.StatusInternalServerError)
		return
	}

	// Step 3: Add to destination
	_, err = db.Exec("UPDATE accounts SET balance = balance + $1 WHERE id = $2", req.Amount, req.ToAccount)
	if err != nil {
		http.Error(w, "Transfer failed", http.StatusInternalServerError)
		return
	}

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{"status": "success"})
}
```

**Attack Payload**:
```bash
# Attacker sends 100 concurrent requests to transfer $1000 from account with $1000 balance
# Race condition allows multiple transfers before balance is deducted
for i in {1..100}; do
  curl -X POST http://target.com/transfer \
    -H "Content-Type: application/json" \
    -d '{"from_account":"attacker123","to_account":"mule456","amount":1000}' &
done
wait
# Result: Multiple successful transfers, negative balance or overdraft
```

**Why This Is Dangerous**:
- TOCTOU window between balance check and deduction allows concurrent exploitation
- No atomicity guarantee - operations can interleave unpredictably
- No database-level locking prevents simultaneous reads of stale balance
- Attacker can drain accounts beyond their actual balance

**SECURE VERSION**:

```go
package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"errors"
	"log"
	"net/http"
	"time"

	_ "github.com/lib/pq"
)

var db *sql.DB

type TransferRequest struct {
	FromAccount string  `json:"from_account"`
	ToAccount   string  `json:"to_account"`
	Amount      float64 `json:"amount"`
}

var ErrInsufficientFunds = errors.New("insufficient funds")

// SECURE: Atomic transaction with row-level locking
func transferFundsSecure(w http.ResponseWriter, r *http.Request) {
	var req TransferRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// Validate input
	if req.Amount <= 0 {
		http.Error(w, "Invalid amount", http.StatusBadRequest)
		return
	}

	ctx, cancel := context.WithTimeout(r.Context(), 10*time.Second)
	defer cancel()

	err := executeAtomicTransfer(ctx, req)
	if errors.Is(err, ErrInsufficientFunds) {
		http.Error(w, "Insufficient funds", http.StatusBadRequest)
		return
	}
	if err != nil {
		log.Printf("Transfer error: %v", err)
		http.Error(w, "Transfer failed", http.StatusInternalServerError)
		return
	}

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{"status": "success"})
}

func executeAtomicTransfer(ctx context.Context, req TransferRequest) error {
	// Begin transaction with SERIALIZABLE isolation
	tx, err := db.BeginTx(ctx, &sql.TxOptions{Isolation: sql.LevelSerializable})
	if err != nil {
		return err
	}
	defer tx.Rollback() // Rollback if not committed

	// SECURE: SELECT FOR UPDATE locks the row, preventing concurrent reads
	var balance float64
	err = tx.QueryRowContext(ctx,
		"SELECT balance FROM accounts WHERE id = $1 FOR UPDATE",
		req.FromAccount).Scan(&balance)
	if err != nil {
		return err
	}

	// Check with locked row - no race condition possible
	if balance < req.Amount {
		return ErrInsufficientFunds
	}

	// Atomic deduction
	_, err = tx.ExecContext(ctx,
		"UPDATE accounts SET balance = balance - $1 WHERE id = $2",
		req.Amount, req.FromAccount)
	if err != nil {
		return err
	}

	// Atomic addition
	_, err = tx.ExecContext(ctx,
		"UPDATE accounts SET balance = balance + $1 WHERE id = $2",
		req.Amount, req.ToAccount)
	if err != nil {
		return err
	}

	// Commit transaction atomically
	return tx.Commit()
}
```

**Key Security Controls**:
- **SELECT FOR UPDATE**: Acquires exclusive row lock preventing concurrent reads until transaction completes
- **SERIALIZABLE isolation**: Highest isolation level prevents phantom reads and write skew anomalies
- **Atomic transaction**: All operations succeed or fail together, no partial state
- **Context timeout**: Prevents deadlocks from holding locks indefinitely

For high-throughput systems, pessimistic locking (SELECT FOR UPDATE) can create bottlenecks. You can use optimistic concurrency control, distributed locks, or idempotency patterns. Here's a production-ready implementation:

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/sha256"
	"database/sql"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"log"
	"net/http"
	"sync"
	"time"

	"github.com/go-redis/redis/v8"
	"github.com/google/uuid"
	_ "github.com/lib/pq"
	"golang.org/x/time/rate"
)

var (
	db          *sql.DB
	redisClient *redis.Client
	rateLimiter = make(map[string]*rate.Limiter)
	rateMu      sync.RWMutex
)

type TransferRequest struct {
	FromAccount   string  `json:"from_account"`
	ToAccount     string  `json:"to_account"`
	Amount        float64 `json:"amount"`
	IdempotencyKey string `json:"idempotency_key"`
}

type AuditLog struct {
	TransactionID  string    `json:"transaction_id"`
	FromAccount    string    `json:"from_account"`
	ToAccount      string    `json:"to_account"`
	Amount         float64   `json:"amount"`
	Status         string    `json:"status"`
	Timestamp      time.Time `json:"timestamp"`
	ClientIP       string    `json:"client_ip"`
	IdempotencyKey string    `json:"idempotency_key"`
}

var (
	ErrInsufficientFunds = errors.New("insufficient funds")
	ErrVersionConflict   = errors.New("version conflict - retry")
	ErrDuplicateRequest  = errors.New("duplicate request")
	ErrRateLimited       = errors.New("rate limited")
)

// Production handler with defense in depth
func transferFundsProduction(w http.ResponseWriter, r *http.Request) {
	ctx, cancel := context.WithTimeout(r.Context(), 30*time.Second)
	defer cancel()

	var req TransferRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	clientIP := r.RemoteAddr
	transactionID := uuid.New().String()

	// Layer 1: Rate limiting per account
	if !checkRateLimit(req.FromAccount) {
		logAudit(ctx, AuditLog{
			TransactionID: transactionID,
			FromAccount:   req.FromAccount,
			Status:        "RATE_LIMITED",
			Timestamp:     time.Now(),
			ClientIP:      clientIP,
		})
		http.Error(w, "Too many requests", http.StatusTooManyRequests)
		return
	}

	// Layer 2: Idempotency check with distributed lock
	if req.IdempotencyKey != "" {
		duplicate, err := checkIdempotency(ctx, req.IdempotencyKey)
		if err != nil {
			log.Printf("Idempotency check error: %v", err)
		}
		if duplicate {
			http.Error(w, "Duplicate request", http.StatusConflict)
			return
		}
	}

	// Layer 3: Distributed lock to prevent concurrent processing
	lockKey := fmt.Sprintf("transfer_lock:%s", req.FromAccount)
	locked, err := acquireDistributedLock(ctx, lockKey, 10*time.Second)
	if err != nil || !locked {
		http.Error(w, "Service temporarily unavailable", http.StatusServiceUnavailable)
		return
	}
	defer releaseDistributedLock(ctx, lockKey)

	// Layer 4: Optimistic concurrency control with retry
	var lastErr error
	for attempt := 0; attempt < 3; attempt++ {
		lastErr = executeOptimisticTransfer(ctx, req, transactionID)
		if lastErr == nil {
			break
		}
		if !errors.Is(lastErr, ErrVersionConflict) {
			break
		}
		time.Sleep(time.Duration(attempt*100) * time.Millisecond)
	}

	if errors.Is(lastErr, ErrInsufficientFunds) {
		logAudit(ctx, AuditLog{
			TransactionID: transactionID,
			FromAccount:   req.FromAccount,
			ToAccount:     req.ToAccount,
			Amount:        req.Amount,
			Status:        "INSUFFICIENT_FUNDS",
			Timestamp:     time.Now(),
			ClientIP:      clientIP,
		})
		http.Error(w, "Insufficient funds", http.StatusBadRequest)
		return
	}
	if lastErr != nil {
		logAudit(ctx, AuditLog{
			TransactionID: transactionID,
			FromAccount:   req.FromAccount,
			Status:        "FAILED",
			Timestamp:     time.Now(),
			ClientIP:      clientIP,
		})
		log.Printf("Transfer failed: %v", lastErr)
		http.Error(w, "Transfer failed", http.StatusInternalServerError)
		return
	}

	// Mark idempotency key as used
	if req.IdempotencyKey != "" {
		markIdempotencyUsed(ctx, req.IdempotencyKey, transactionID)
	}

	logAudit(ctx, AuditLog{
		TransactionID:  transactionID,
		FromAccount:    req.FromAccount,
		ToAccount:      req.ToAccount,
		Amount:         req.Amount,
		Status:         "SUCCESS",
		Timestamp:      time.Now(),
		ClientIP:       clientIP,
		IdempotencyKey: req.IdempotencyKey,
	})

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{
		"status":         "success",
		"transaction_id": transactionID,
	})
}

// Optimistic Concurrency Control using version column
func executeOptimisticTransfer(ctx context.Context, req TransferRequest, txID string) error {
	tx, err := db.BeginTx(ctx, &sql.TxOptions{Isolation: sql.LevelReadCommitted})
	if err != nil {
		return err
	}
	defer tx.Rollback()

	// Read current state with version
	var balance float64
	var version int64
	err = tx.QueryRowContext(ctx,
		"SELECT balance, version FROM accounts WHERE id = $1",
		req.FromAccount).Scan(&balance, &version)
	if err != nil {
		return err
	}

	if balance < req.Amount {
		return ErrInsufficientFunds
	}

	// Conditional update - only succeeds if version unchanged
	result, err := tx.ExecContext(ctx,
		`UPDATE accounts 
		 SET balance = balance - $1, version = version + 1, updated_at = NOW()
		 WHERE id = $2 AND version = $3 AND balance >= $1`,
		req.Amount, req.FromAccount, version)
	if err != nil {
		return err
	}

	rowsAffected, _ := result.RowsAffected()
	if rowsAffected == 0 {
		// Version changed or balance insufficient - concurrent modification detected
		return ErrVersionConflict
	}

	// Credit destination
	_, err = tx.ExecContext(ctx,
		"UPDATE accounts SET balance = balance + $1, version = version + 1 WHERE id = $2",
		req.Amount, req.ToAccount)
	if err != nil {
		return err
	}

	// Record transaction for audit trail
	_, err = tx.ExecContext(ctx,
		`INSERT INTO transactions (id, from_account, to_account, amount, status, created_at)
		 VALUES ($1, $2, $3, $4, 'COMPLETED', NOW())`,
		txID, req.FromAccount, req.ToAccount, req.Amount)
	if err != nil {
		return err
	}

	return tx.Commit()
}

// Rate limiting per account
func checkRateLimit(accountID string) bool {
	rateMu.Lock()
	defer rateMu.Unlock()

	limiter, exists := rateLimiter[accountID]
	if !exists {
		// 10 requests per second with burst of 20
		limiter = rate.NewLimiter(10, 20)
		rateLimiter[accountID] = limiter
	}
	return limiter.Allow()
}

// Distributed lock using Redis
func acquireDistributedLock(ctx context.Context, key string, ttl time.Duration) (bool, error) {
	lockValue := uuid.New().String()
	result, err := redisClient.SetNX(ctx, key, lockValue, ttl).Result()
	return result, err
}

func releaseDistributedLock(ctx context.Context, key string) {
	redisClient.Del(ctx, key)
}

// Idempotency tracking
func checkIdempotency(ctx context.Context, key string) (bool, error) {
	hash := sha256.Sum256([]byte(key))
	hashKey := "idempotency:" + hex.EncodeToString(hash[:])
	exists, err := redisClient.Exists(ctx, hashKey).Result()
	return exists > 0, err
}

func markIdempotencyUsed(ctx context.Context, key, txID string) {
	hash := sha256.Sum256([]byte(key))
	hashKey := "idempotency:" + hex.EncodeToString(hash[:])
	// Store for 24 hours
	redisClient.Set(ctx, hashKey, txID, 24*time.Hour)
}

// Audit logging
func logAudit(ctx context.Context, audit AuditLog) {
	data, _ := json.Marshal(audit)
	log.Printf("AUDIT: %s", string(data))
	// In production: send to SIEM, write to audit table, etc.
}
```

**Defense in Depth Layers**:

1. **Rate Limiting**: Prevents brute-force race condition attempts
```go
// Per-account rate limiter prevents flooding
limiter = rate.NewLimiter(10, 20) // 10 req/sec, burst of 20
if !limiter.Allow() {
    return ErrRateLimited
}
```

2. **Idempotency Keys**: Prevents duplicate processing of same request
```go
// Client provides unique key, server tracks completion
if exists, _ := redis.Exists(ctx, "idempotency:"+key); exists {
    return previousResult // Return cached response
}
```

3. **Optimistic Concurrency Control**: Version-based conflict detection
```go
// Only update if version unchanged - detects concurrent modifications
UPDATE accounts SET balance = balance - $1, version = version + 1
WHERE id = $2 AND version = $3 AND balance >= $1
```

**Additional Protections**:

- **Distributed Locks**: Redis SETNX provides cluster-wide mutual exclusion for critical sections
- **Comprehensive Audit Trail**: Every attempt logged with client IP, timestamp, and outcome for forensics
- **Graceful Retry**: Automatic retry with exponential backoff on version conflicts
- **Context Timeouts**: Prevents lock starvation and hung transactions
- **Database Constraints**: Balance >= 0 constraint at database level as final safety net:
```sql
ALTER TABLE accounts ADD CONSTRAINT balance_non_negative CHECK (balance >= 0);
```
- **Monitoring Alerts**: Set up alerts for high version conflict rates indicating potential attack
- **Circuit Breaker**: Implement circuit breaker pattern for cascading failure protection

