```

This payload works because the client accepts any certificate. The attacker can terminate TLS, read authentication tokens, and impersonate users.

**Why This Is Dangerous**:
- Breaks TLS authentication: certificate verification is what proves you are talking to the real server.
- Enables full traffic decryption: MITM can steal access tokens, passwords, and session cookies.
- Hard to detect: looks like normal HTTPS; logs still show `https://` even though it's intercepted.

**SECURE VERSION**:

```rust
use axum::{routing::get, Router};
use hyper::{Body, Client, Request, Server};
use hyper_rustls::HttpsConnectorBuilder;
use rustls::{ClientConfig, RootCertStore};
use rustls_native_certs::load_native_certs;
use std::sync::Arc;
use tokio::time::{timeout, Duration};
use tracing::{error, info, Level};
use tracing_subscriber::FmtSubscriber;

fn build_tls_config() -> Arc<ClientConfig> {
    let mut root_store = RootCertStore::empty();

    // PRIMARY DEFENSE: Use system trust store (or bundle) instead of disabling verification
    let native_certs = load_native_certs()
        .expect("failed to load platform certificates");

    for cert in native_certs { 
        let _ = root_store.add(&rustls::Certificate(cert.0));
    }

    let config = ClientConfig::builder()
        .with_safe_defaults()
        .with_root_certificates(root_store)
        .with_no_client_auth();

    Arc::new(config)
}

fn secure_https_client() -> Client<hyper_rustls::HttpsConnector<hyper::client::HttpConnector>, Body> {
    let tls_config = build_tls_config();

    let https = HttpsConnectorBuilder::new()
        .with_tls_config(tls_config)
        .https_or_http()
        .enable_http1()
        .build();

    Client::builder().build::<_, Body>(https)
}

async fn call_upstream() -> Result<String, String> {
    let client = secure_https_client();

    let req = Request::builder()
        .method("GET")
        .uri("https://auth.example.com/userinfo")
        .body(Body::empty())
        .map_err(|e| format!("build request error: {e}"))?;

    // DEFENSE IN DEPTH: Network timeout to avoid hanging on MITM attempts
    let resp = timeout(Duration::from_secs(5), client.request(req))
        .await
        .map_err(|_| "upstream timeout".to_string())
        .and_then(|r| r.map_err(|e| format!("upstream error: {e}")))?;

    let status = resp.status();
    let bytes = hyper::body::to_bytes(resp.into_body())
        .await
        .map_err(|e| format!("body read error: {e}"))?;

    if !status.is_success() {
        error!("Upstream returned non-success status: {}", status);
        return Err("upstream failure".to_string());
    }

    Ok(String::from_utf8_lossy(&bytes).to_string())
}

#[tokio::main]
