            String internalPayload = req.getHeader("X-Internal-Order-Data");
            Gson gson = new Gson();
            OrderRequest order = gson.fromJson(internalPayload, OrderRequest.class);

            // DEFENSE 2: ALWAYS validate at trust boundaries
            ValidationResult validation = validateOrderAtTrustBoundary(order, requestId);
            if (!validation.isValid()) {
                logger.warn("[{}] Trust boundary validation failed: {}", requestId, validation.getErrors());
                resp.setStatus(400);
                return;
            }

            // DEFENSE 3: Use parameterized queries
            try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
                String sql = "INSERT INTO orders (user_id, product, quantity, price) VALUES (?, ?, ?, ?)";

                try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
                    pstmt.setString(1, order.getUserId());
                    pstmt.setString(2, order.getProduct());
                    pstmt.setInt(3, order.getQuantity());
                    pstmt.setBigDecimal(4, java.math.BigDecimal.valueOf(order.getPrice()));

                    pstmt.executeUpdate();
                }
            }

            // DEFENSE 4: Use message queue instead of system commands
            notifyWarehouseSecurely(order.getProduct(), requestId);

            logger.info("[{}] Order processed for user: {}", requestId, order.getUserId());
            resp.setStatus(200);

        } catch (Exception e) {
            logger.error("[{}] Order processing error", requestId, e);
            resp.setStatus(500);
        }
    }

    private boolean verifyInternalServiceToken(String service, String token) {
        // Verify JWT or HMAC signature from internal service registry
        return service != null && token != null && 
               InternalServiceRegistry.verifyToken(service, token);
    }

    private ValidationResult validateOrderAtTrustBoundary(OrderRequest order, String requestId) {
        ValidationResult result = new ValidationResult();

        if (order.getUserId() == null || !USER_ID_PATTERN.matcher(order.getUserId()).matches()) {
            result.addError("Invalid userId format");
        }

        if (order.getProduct() == null || !PRODUCT_PATTERN.matcher(order.getProduct()).matches()) {
            result.addError("Invalid product format");
        }

        if (order.getQuantity() < 1 || order.getQuantity() > MAX_QUANTITY) {
            result.addError("Quantity out of valid range");
        }

        // CRITICAL: Verify price against product catalog - don't trust client price
        double catalogPrice = ProductCatalog.getPrice(order.getProduct());
        if (Math.abs(order.getPrice() - catalogPrice) > 0.01) {
            result.addError("Price mismatch - possible tampering");
            logger.warn("[{}] Price manipulation attempt: submitted={}, catalog={}", 
                requestId, order.getPrice(), catalogPrice);
        }

        return result;
    }

    private void notifyWarehouseSecurely(String productId, String requestId) {
        // Use message queue with validated product ID lookup
        String validatedProductCode = ProductCatalog.getProductCode(productId);
        if (validatedProductCode != null) {
            MessageQueue.publish("warehouse-notifications", 
                new WarehouseNotification(validatedProductCode, requestId));
        }
    }
}
```

**Key Security Controls**:
- **Service-to-service authentication**: Verify internal requests with signed tokens, not just network location
- **Validation at every trust boundary**: Re-validate ALL data when crossing from untrusted to trusted zones
- **Parameterized queries**: Prevent SQL injection even with validated data (defense in depth)
- **Price verification against catalog**: Never trust client-supplied prices or business-critical values
- **Secure inter-service communication**: Use message queues instead of shell commands

