import javax.servlet.http.*;
import java.sql.*;
import java.security.*;
import java.util.*;
import io.jsonwebtoken.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * Trust Boundary Enforcement Framework
 * Implements Zero Trust architecture for multi-tier applications
 */
public class TrustBoundaryEnforcementService {
    private static final Logger logger = LoggerFactory.getLogger(TrustBoundaryEnforcementService.class);
    private static final Logger securityAuditLog = LoggerFactory.getLogger("SECURITY_AUDIT");

    // Define trust zones
    public enum TrustZone {
        EXTERNAL(0),      // Internet/untrusted clients
        DMZ(1),           // Load balancers, API gateways
        APPLICATION(2),   // Business logic services
        DATA(3);          // Databases, caches

        private final int trustLevel;
        TrustZone(int level) { this.trustLevel = level; }
        public int getTrustLevel() { return trustLevel; }
    }

    // Request context that tracks data provenance through trust boundaries
    public static class TrustBoundaryContext {
        private final String requestId;
        private final TrustZone originZone;
        private final TrustZone currentZone;
        private final List<String> crossedBoundaries;
        private final Map<String, ValidationStatus> fieldValidations;
        private final String sourceServiceId;
        private final long timestamp;

        public TrustBoundaryContext(String requestId, TrustZone origin, String sourceService) {
            this.requestId = requestId;
            this.originZone = origin;
            this.currentZone = origin;
            this.crossedBoundaries = new ArrayList<>();
            this.fieldValidations = new HashMap<>();
            this.sourceServiceId = sourceService;
            this.timestamp = System.currentTimeMillis();
        }

        public void recordBoundaryCrossing(TrustZone from, TrustZone to) {
            crossedBoundaries.add(from + "->" + to + "@" + System.currentTimeMillis());
        }

        public void markFieldValidated(String field, TrustZone zone) {
            fieldValidations.put(field, new ValidationStatus(zone, System.currentTimeMillis()));
        }

        public boolean wasValidatedInZone(String field, TrustZone zone) {
            ValidationStatus status = fieldValidations.get(field);
            return status != null && status.getZone().getTrustLevel() >= zone.getTrustLevel();
        }

        public String getRequestId() { return requestId; }
        public TrustZone getOriginZone() { return originZone; }
    }

    /**
     * DMZ Gateway Service - First trust boundary
     */
    public static class DMZGatewayService {
        private final TrustBoundaryValidator validator;

        public DMZGatewayService() {
            this.validator = new TrustBoundaryValidator(TrustZone.DMZ);
        }

        public ProcessedRequest processExternalRequest(HttpServletRequest req) {
            String requestId = UUID.randomUUID().toString();
            TrustBoundaryContext ctx = new TrustBoundaryContext(
                requestId, TrustZone.EXTERNAL, "external-client");

            securityAuditLog.info("[{}] Request entering DMZ from EXTERNAL zone, IP: {}", 
                requestId, req.getRemoteAddr());

            // BOUNDARY CROSSING: EXTERNAL -> DMZ
            // Validate ALL external input at first boundary
            Map<String, String> validatedParams = new HashMap<>();

            for (String param : req.getParameterMap().keySet()) {
                String rawValue = req.getParameter(param);

                // Step 1: Decode and normalize
                String normalizedValue = validator.normalizeInput(rawValue);

                // Step 2: Check for attack patterns
                if (validator.containsAttackPattern(normalizedValue)) {
                    securityAuditLog.warn("[{}] Attack pattern detected in param '{}': {}", 
                        requestId, param, rawValue.substring(0, Math.min(100, rawValue.length())));
                    throw new SecurityException("Invalid input detected");
                }

                // Step 3: Apply schema validation
                String sanitizedValue = validator.sanitizeForSchema(param, normalizedValue);
                validatedParams.put(param, sanitizedValue);

                ctx.markFieldValidated(param, TrustZone.DMZ);
            }

            ctx.recordBoundaryCrossing(TrustZone.EXTERNAL, TrustZone.DMZ);

            // Generate signed token proving DMZ validation occurred
            String dmzValidationToken = generateBoundaryToken(ctx, validatedParams);

            return new ProcessedRequest(ctx, validatedParams, dmzValidationToken);
        }

        private String generateBoundaryToken(TrustBoundaryContext ctx, Map<String, String> params) {
            // Sign the validated data to prove it passed DMZ validation
            return Jwts.builder()
                .setId(ctx.getRequestId())
                .claim("zone", TrustZone.DMZ.name())
                .claim("validated_fields", new ArrayList<>(params.keySet()))
                .claim("origin", ctx.getOriginZone().name())
                .setIssuedAt(new Date())
                .setExpiration(new Date(System.currentTimeMillis() + 30000)) // 30 seconds
                .signWith(SignatureAlgorithm.HS256, getZoneSigningKey(TrustZone.DMZ))
                .compact();
        }

        private byte[] getZoneSigningKey(TrustZone zone) {
            return System.getenv("ZONE_KEY_" + zone.name()).getBytes();
        }
    }

    /**
     * Application Tier Service - Second trust boundary
     */
    public static class ApplicationTierService {
        private final TrustBoundaryValidator validator;

        public ApplicationTierService() {
            this.validator = new TrustBoundaryValidator(TrustZone.APPLICATION);
        }

        public void processOrder(ProcessedRequest dmzRequest) {
            TrustBoundaryContext ctx = dmzRequest.getContext();
            String requestId = ctx.getRequestId();

            // BOUNDARY CROSSING: DMZ -> APPLICATION
            securityAuditLog.info("[{}] Request crossing to APPLICATION zone", requestId);

            // Step 1: Verify the DMZ boundary token
            if (!verifyBoundaryToken(dmzRequest.getBoundaryToken(), TrustZone.DMZ)) {
                securityAuditLog.error("[{}] Invalid DMZ boundary token - possible boundary bypass", requestId);
                throw new SecurityException("Trust boundary violation: Invalid origin token");
            }

            // Step 2: RE-VALIDATE at application tier (defense in depth)
            // Even trusted DMZ data gets re-validated with business rules
            Map<String, String> params = dmzRequest.getValidatedParams();

            OrderData order = new OrderData();

            // Validate userId with application-tier business rules
            String userId = params.get("userId");
            if (!validator.isValidUserId(userId)) {
                throw new SecurityException("Invalid userId at application boundary");
            }
            order.setUserId(userId);
            ctx.markFieldValidated("userId", TrustZone.APPLICATION);

            // Validate product against inventory system
            String productId = params.get("productId");
            if (!validator.productExistsInCatalog(productId)) {
                securityAuditLog.warn("[{}] Invalid product reference: {}", requestId, productId);
                throw new SecurityException("Invalid product");
            }
            order.setProductId(productId);
            ctx.markFieldValidated("productId", TrustZone.APPLICATION);

            // CRITICAL: Price comes from server-side catalog, NOT from request
            double trustedPrice = PricingService.getCurrentPrice(productId);
            order.setPrice(trustedPrice);

            // Quantity validation
            int quantity = Integer.parseInt(params.get("quantity"));
            if (!validator.isValidQuantity(productId, quantity)) {
                throw new SecurityException("Invalid quantity");
            }
            order.setQuantity(quantity);
            ctx.markFieldValidated("quantity", TrustZone.APPLICATION);

            ctx.recordBoundaryCrossing(TrustZone.DMZ, TrustZone.APPLICATION);

            // Prepare for data tier with application-tier token
            String appTierToken = generateApplicationTierToken(ctx, order);

            // Pass to data tier with full provenance
            DataTierService dataTier = new DataTierService();
            dataTier.persistOrder(new DataTierRequest(ctx, order, appTierToken));
        }

        private boolean verifyBoundaryToken(String token, TrustZone expectedZone) {
            try {
                Claims claims = Jwts.parser()
                    .setSigningKey(getZoneSigningKey(expectedZone))
                    .parseClaimsJws(token)
                    .getBody();

                return expectedZone.name().equals(claims.get("zone"));
            } catch (Exception e) {
                return false;
            }
        }

        private String generateApplicationTierToken(TrustBoundaryContext ctx, OrderData order) {
            return Jwts.builder()
                .setId(ctx.getRequestId())
                .claim("zone", TrustZone.APPLICATION.name())
                .claim("order_hash", calculateOrderHash(order))
                .claim("boundaries_crossed", ctx.crossedBoundaries)
                .setIssuedAt(new Date())
                .setExpiration(new Date(System.currentTimeMillis() + 10000))
                .signWith(SignatureAlgorithm.HS256, getZoneSigningKey(TrustZone.APPLICATION))
                .compact();
        }

        private String calculateOrderHash(OrderData order) {
            return DigestUtils.sha256Hex(
                order.getUserId() + order.getProductId() + order.getQuantity() + order.getPrice());
        }

        private byte[] getZoneSigningKey(TrustZone zone) {
            return System.getenv("ZONE_KEY_" + zone.name()).getBytes();
        }
    }

    /**
     * Data Tier Service - Final trust boundary before database
     */
    public static class DataTierService {
        private static final Logger logger = LoggerFactory.getLogger(DataTierService.class);
        private final TrustBoundaryValidator validator;

        public DataTierService() {
            this.validator = new TrustBoundaryValidator(TrustZone.DATA);
        }

        public void persistOrder(DataTierRequest request) {
            TrustBoundaryContext ctx = request.getContext();
            String requestId = ctx.getRequestId();

            // BOUNDARY CROSSING: APPLICATION -> DATA
            securityAuditLog.info("[{}] Request entering DATA zone, boundaries crossed: {}", 
                requestId, ctx.crossedBoundaries);

            // Step 1: Verify application tier token
            if (!verifyApplicationTierToken(request)) {
                securityAuditLog.error("[{}] CRITICAL: Data tier access without valid app tier token", 
                    requestId);
                throw new SecurityException("Trust boundary violation at data tier");
            }

            // Step 2: Verify complete trust chain
            if (!verifyCompleteTrustChain(ctx)) {
                securityAuditLog.error("[{}] CRITICAL: Incomplete trust chain detected", requestId);
                throw new SecurityException("Trust chain verification failed");
            }

            // Step 3: Final validation before database operations
            OrderData order = request.getOrder();

            // Even at data tier, validate one more time (defense in depth)
            if (!validator.isSafeForPersistence(order)) {
                throw new SecurityException("Order failed data tier validation");
            }

            ctx.recordBoundaryCrossing(TrustZone.APPLICATION, TrustZone.DATA);

            // Step 4: Execute with parameterized queries and audit logging
            String connectionString = System.getenv("DATA_TIER_DB_URL");

            try (Connection conn = DriverManager.getConnection(connectionString)) {
                conn.setAutoCommit(false);

                String sql = "INSERT INTO orders (request_id, user_id, product_id, quantity, " +
                    "price, trust_chain, created_at) VALUES (?, ?, ?, ?, ?, ?::jsonb, NOW())";

                try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
                    pstmt.setString(1, requestId);
                    pstmt.setString(2, order.getUserId());
                    pstmt.setString(3, order.getProductId());
                    pstmt.setInt(4, order.getQuantity());
                    pstmt.setBigDecimal(5, java.math.BigDecimal.valueOf(order.getPrice()));
                    pstmt.setString(6, serializeTrustChain(ctx));

                    pstmt.executeUpdate();
                    conn.commit();

                    securityAuditLog.info("[{}] Order persisted successfully, trust chain: {}", 
                        requestId, ctx.crossedBoundaries);
                }
            } catch (SQLException e) {
                logger.error("[{}] Database error", requestId, e);
                throw new RuntimeException("Failed to persist order");
            }
        }

        private boolean verifyApplicationTierToken(DataTierRequest request) {
            // Verify token and hash integrity
            try {
                Claims claims = Jwts.parser()
                    .setSigningKey(System.getenv("ZONE_KEY_APPLICATION").getBytes())
                    .parseClaimsJws(request.getAppTierToken())
                    .getBody();

                String tokenHash = (String) claims.get("order_hash");
                String computedHash = calculateOrderHash(request.getOrder());

                return tokenHash.equals(computedHash);
            } catch (Exception e) {
                return false;
            }
        }

        private boolean verifyCompleteTrustChain(TrustBoundaryContext ctx) {
            // Verify request crossed all required boundaries in order
            List<String> boundaries = ctx.crossedBoundaries;

            return boundaries.size() >= 2 &&
                   boundaries.get(0).startsWith("EXTERNAL->DMZ") &&
                   boundaries.get(1).startsWith("DMZ->APPLICATION");
        }

        private String serializeTrustChain(TrustBoundaryContext ctx) {
            return new Gson().toJson(Map.of(
                "request_id", ctx.getRequestId(),
                "origin", ctx.getOriginZone().name(),
                "boundaries", ctx.crossedBoundaries,
                "validations", ctx.fieldValidations
            ));
        }

        private String calculateOrderHash(OrderData order) {
            return DigestUtils.sha256Hex(
                order.getUserId() + order.getProductId() + order.getQuantity() + order.getPrice());
        }
    }
}
