**Key Security Controls**:
- **Never use Java native serialization for untrusted data** - use JSON, Protocol Buffers, or other safe formats
- **HMAC signature verification** - ensures data integrity and authenticity before parsing
- **Simple DTOs with no custom deserialization logic** - prevents gadget chain attacks
- **Constant-time comparison** using `MessageDigest.isEqual()` prevents timing attacks

If you absolutely must use Java serialization (which I strongly advise against), you need multiple layers of defense. Here's a production-hardened approach:

**PRODUCTION PATTERN**:

```java
import java.io.*;
import java.util.*;
import java.util.logging.*;
import javax.crypto.*;
import javax.crypto.spec.*;
import org.apache.commons.io.serialization.ValidatingObjectInputStream;

public class HardenedDeserializer {

    private static final Logger SECURITY_LOG = Logger.getLogger("security.deserialization");

    // LAYER 1: Strict allowlist of permitted classes
    private static final Set<String> ALLOWED_CLASSES = Set.of(
        "com.myapp.model.UserSession",
        "com.myapp.model.UserPreferences",
        "java.lang.String",
        "java.lang.Long",
        "java.lang.Integer",
        "java.util.HashMap",
        "java.util.ArrayList"
    );

    // LAYER 2: Explicit denylist of dangerous classes
    private static final Set<String> BLOCKED_CLASSES = Set.of(
        "org.apache.commons.collections.functors",
        "org.apache.commons.collections4.functors",
        "org.apache.xalan",
        "javax.management",
        "java.lang.Runtime",
        "java.lang.ProcessBuilder",
        "java.lang.reflect.Proxy",
        "sun.rmi",
        "com.sun.jndi",
        "javax.naming",
        "org.springframework.beans.factory.config",
        "com.mchange.v2.c3p0"
    );

    private final SecretKey hmacKey;
    private final int maxObjectSize;
    private final int maxDepth;

    public HardenedDeserializer(byte[] keyBytes) {
        this.hmacKey = new SecretKeySpec(keyBytes, "HmacSHA256");
        this.maxObjectSize = 1024 * 100; // 100KB max
        this.maxDepth = 10; // Prevent deep nesting attacks
    }

    public <T> T deserialize(byte[] signedData, Class<T> expectedType, String clientIp) 
            throws SecurityException, IOException, ClassNotFoundException {

        // LAYER 3: Signature verification BEFORE any deserialization
        if (signedData.length < 32) {
            logSecurityEvent("INVALID_SIZE", clientIp, "Data too small");
            throw new SecurityException("Invalid data format");
        }

        byte[] signature = Arrays.copyOfRange(signedData, 0, 32);
        byte[] payload = Arrays.copyOfRange(signedData, 32, signedData.length);

        if (!verifyHmac(payload, signature)) {
            logSecurityEvent("SIGNATURE_MISMATCH", clientIp, 
                "Possible tampering detected");
            throw new SecurityException("Data integrity check failed");
        }

        // LAYER 4: Size limits
        if (payload.length > maxObjectSize) {
            logSecurityEvent("SIZE_EXCEEDED", clientIp, 
                "Payload size: " + payload.length);
            throw new SecurityException("Payload exceeds maximum size");
        }

        // LAYER 5: Use ValidatingObjectInputStream with strict filtering
        try (ByteArrayInputStream bais = new ByteArrayInputStream(payload);
             ValidatingObjectInputStream ois = new ValidatingObjectInputStream(bais)) {

            // Configure the allowlist
            for (String allowed : ALLOWED_CLASSES) {
                ois.accept(allowed);
            }

            // Block all others explicitly
            ois.reject("*");

            // LAYER 6: Custom ObjectInputFilter (Java 9+)
            ObjectInputFilter filter = createSecurityFilter(clientIp);
            ois.setObjectInputFilter(filter);

            Object result = ois.readObject();

            // LAYER 7: Type verification after deserialization
            if (!expectedType.isInstance(result)) {
                logSecurityEvent("TYPE_MISMATCH", clientIp,
                    "Expected: " + expectedType.getName() + 
                    ", Got: " + result.getClass().getName());
                throw new SecurityException("Unexpected object type");
            }

            SECURITY_LOG.info("Successful deserialization for " + clientIp + 
                ": " + expectedType.getSimpleName());

            return expectedType.cast(result);

        } catch (InvalidClassException e) {
            logSecurityEvent("BLOCKED_CLASS", clientIp, e.getMessage());
            throw new SecurityException("Blocked class detected", e);
        }
    }

    private ObjectInputFilter createSecurityFilter(String clientIp) {
        return filterInfo -> {
            Class<?> clazz = filterInfo.serialClass();

            if (clazz != null) {
                String className = clazz.getName();

                // Check denylist
                for (String blocked : BLOCKED_CLASSES) {
                    if (className.startsWith(blocked)) {
                        logSecurityEvent("GADGET_CHAIN_BLOCKED", clientIp, className);
                        return ObjectInputFilter.Status.REJECTED;
                    }
                }

                // Check allowlist
                if (!ALLOWED_CLASSES.contains(className)) {
                    logSecurityEvent("UNLISTED_CLASS", clientIp, className);
                    return ObjectInputFilter.Status.REJECTED;
                }
            }

            // Enforce depth limit
            if (filterInfo.depth() > maxDepth) {
                logSecurityEvent("DEPTH_EXCEEDED", clientIp, 
                    "Depth: " + filterInfo.depth());
                return ObjectInputFilter.Status.REJECTED;
            }

            // Enforce array size limit
            if (filterInfo.arrayLength() > 10000) {
                logSecurityEvent("ARRAY_TOO_LARGE", clientIp, 
                    "Length: " + filterInfo.arrayLength());
                return ObjectInputFilter.Status.REJECTED;
            }

            return ObjectInputFilter.Status.ALLOWED;
        };
    }

    private boolean verifyHmac(byte[] data, byte[] expectedSignature) {
        try {
            Mac mac = Mac.getInstance("HmacSHA256");
            mac.init(hmacKey);
            byte[] computed = mac.doFinal(data);
            return MessageDigest.isEqual(computed, expectedSignature);
        } catch (Exception e) {
            return false;
        }
    }

    private void logSecurityEvent(String eventType, String clientIp, String details) {
        SECURITY_LOG.warning(String.format(
            "DESERIALIZATION_SECURITY_EVENT | Type: %s | IP: %s | Details: %s | Time: %d",
            eventType, clientIp, details, System.currentTimeMillis()));

        // In production, send to SIEM
        // SecurityMetrics.incrementCounter("deserialization.blocked", eventType);
    }
}
