**Key Security Controls**:
- **X-Frame-Options: DENY**: Completely prevents the page from being embedded in iframes, blocking clickjacking
- **Content-Security-Policy**: Restricts where scripts, styles, and other resources can load from, mitigating XSS
- **Strict-Transport-Security**: Forces browsers to use HTTPS for all future requests, preventing SSL stripping
- **X-Content-Type-Options: nosniff**: Prevents browsers from MIME-sniffing responses, blocking content-type confusion attacks
- **Referrer-Policy**: Controls what information is sent in the Referer header, preventing information leakage

Great questions! Production environments often need flexible configurations for different services and trusted embedding scenarios. Here's a comprehensive production-ready approach.

**PRODUCTION PATTERN**:

```java
import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.context.annotation.Profile;
import org.springframework.core.env.Environment;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.header.writers.*;
import org.springframework.web.filter.OncePerRequestFilter;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import javax.servlet.FilterChain;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.util.Arrays;
import java.util.List;

@SpringBootApplication
public class SecureApiApplication {
    public static void main(String[] args) {
        SpringApplication.run(SecureApiApplication.class, args);
    }
}

@Configuration
@EnableWebSecurity
class ProductionSecurityConfig {

    private static final Logger logger = LoggerFactory.getLogger(ProductionSecurityConfig.class);

    @Value("${security.headers.allowed-frame-ancestors:}")
    private String allowedFrameAncestors;

    @Value("${security.headers.csp.report-uri:}")
    private String cspReportUri;

    @Value("${security.headers.hsts.max-age:31536000}")
    private long hstsMaxAge;

    @Value("${security.headers.hsts.include-subdomains:true}")
    private boolean hstsIncludeSubdomains;

    private final Environment environment;

    public ProductionSecurityConfig(Environment environment) {
        this.environment = environment;
    }

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        boolean isProduction = Arrays.asList(environment.getActiveProfiles()).contains("prod");

        http
            .addFilterBefore(new SecurityHeaderAuditFilter(), 
                org.springframework.security.web.context.SecurityContextPersistenceFilter.class)
            .headers(headers -> {
                // Frame Options - configurable for trusted embedding
                if (allowedFrameAncestors != null && !allowedFrameAncestors.isEmpty()) {
                    // Use CSP frame-ancestors for more granular control
                    headers.frameOptions(frame -> frame.disable()); // Disable legacy header
                    logger.info("Configured frame-ancestors for trusted domains: {}", allowedFrameAncestors);
                } else {
                    headers.frameOptions(frame -> frame.deny());
                }

                // MIME type sniffing protection - always enabled
                headers.contentTypeOptions(content -> {});

                // XSS Protection - legacy but still useful
                headers.xssProtection(xss -> xss.block(true));

                // HSTS - only in production (requires valid HTTPS)
                if (isProduction) {
                    headers.httpStrictTransportSecurity(hsts -> hsts
                        .maxAgeInSeconds(hstsMaxAge)
                        .includeSubDomains(hstsIncludeSubdomains)
                        .preload(true)
                    );
                }

                // Content Security Policy
                String cspPolicy = buildContentSecurityPolicy(isProduction);
                headers.contentSecurityPolicy(csp -> csp.policyDirectives(cspPolicy));

                // Referrer Policy
                headers.referrerPolicy(referrer -> referrer
                    .policy(ReferrerPolicyHeaderWriter.ReferrerPolicy.STRICT_ORIGIN_WHEN_CROSS_ORIGIN)
                );

                // Permissions Policy
                headers.permissionsPolicy(permissions -> permissions
                    .policy(buildPermissionsPolicy())
                );

                // Cache Control for sensitive endpoints
                headers.cacheControl(cache -> {});
            })
            .authorizeHttpRequests(auth -> auth
                .antMatchers("/actuator/health").permitAll()
                .antMatchers("/api/public/**").permitAll()
                .anyRequest().authenticated()
            );

        logger.info("Security headers configured for environment: {}", 
            isProduction ? "PRODUCTION" : "DEVELOPMENT");

        return http.build();
    }

    private String buildContentSecurityPolicy(boolean isProduction) {
        StringBuilder csp = new StringBuilder();

        // Default: only allow resources from same origin
        csp.append("default-src 'self'; ");

        // Scripts: strict, no inline (use nonces in production)
        csp.append("script-src 'self'; ");

        // Styles: allow inline for some frameworks
        csp.append("style-src 'self' 'unsafe-inline'; ");

        // Images: allow data URIs for base64 images
        csp.append("img-src 'self' data: https:; ");

        // Fonts: self only
        csp.append("font-src 'self'; ");

        // Connections: allow API calls
        csp.append("connect-src 'self'; ");

        // Frame ancestors: configurable trusted domains
        if (allowedFrameAncestors != null && !allowedFrameAncestors.isEmpty()) {
            csp.append("frame-ancestors ").append(allowedFrameAncestors).append("; ");
        } else {
            csp.append("frame-ancestors 'none'; ");
        }

        // Form actions
        csp.append("form-action 'self'; ");

        // Base URI
        csp.append("base-uri 'self'; ");

        // Object source: block plugins
        csp.append("object-src 'none'; ");

        // Upgrade insecure requests in production
        if (isProduction) {
            csp.append("upgrade-insecure-requests; ");
        }

        // CSP violation reporting
        if (cspReportUri != null && !cspReportUri.isEmpty()) {
            csp.append("report-uri ").append(cspReportUri).append("; ");
        }

        return csp.toString().trim();
    }

    private String buildPermissionsPolicy() {
        return "geolocation=(), " +
               "microphone=(), " +
               "camera=(), " +
               "payment=(), " +
               "usb=(), " +
               "magnetometer=(), " +
               "gyroscope=(), " +
               "accelerometer=()";
    }
}

// Audit filter to log security header violations and monitor attacks
class SecurityHeaderAuditFilter extends OncePerRequestFilter {

    private static final Logger auditLogger = LoggerFactory.getLogger("SECURITY_AUDIT");
    private static final List<String> SUSPICIOUS_REFERERS = Arrays.asList(
        "attacker.com", "malicious.site", "phishing.page"
    );

    @Override
    protected void doFilterInternal(HttpServletRequest request, 
                                    HttpServletResponse response, 
                                    FilterChain filterChain) 
            throws ServletException, IOException {

        // Check for potential clickjacking attempt indicators
        String referer = request.getHeader("Referer");
        String secFetchDest = request.getHeader("Sec-Fetch-Dest");
        String secFetchMode = request.getHeader("Sec-Fetch-Mode");

        // Detect iframe embedding attempts
        if ("iframe".equals(secFetchDest) || "embed".equals(secFetchDest)) {
            auditLogger.warn("SECURITY_EVENT: Potential iframe embedding attempt - " +
                "IP: {}, Path: {}, Referer: {}, User-Agent: {}",
                request.getRemoteAddr(),
                request.getRequestURI(),
                referer,
                request.getHeader("User-Agent"));
        }

        // Check for suspicious referers
        if (referer != null) {
            for (String suspicious : SUSPICIOUS_REFERERS) {
                if (referer.toLowerCase().contains(suspicious)) {
                    auditLogger.error("SECURITY_ALERT: Suspicious referer detected - " +
                        "IP: {}, Path: {}, Referer: {}",
                        request.getRemoteAddr(),
                        request.getRequestURI(),
                        referer);
                    break;
                }
            }
        }

        filterChain.doFilter(request, response);

        // Log outgoing security headers for monitoring
        if (auditLogger.isDebugEnabled()) {
            auditLogger.debug("Response headers - X-Frame-Options: {}, CSP: {}, HSTS: {}",
                response.getHeader("X-Frame-Options"),
                response.getHeader("Content-Security-Policy"),
                response.getHeader("Strict-Transport-Security"));
        }
    }
}

// Microservice-specific header configuration
@Configuration
@Profile("internal-service")
class InternalServiceSecurityConfig {

    @Bean
    public SecurityFilterChain internalFilterChain(HttpSecurity http) throws Exception {
        // Internal services may have relaxed frame options for admin panels
        // but should still enforce other security headers
        http
            .headers(headers -> headers
                // Allow framing from internal admin domains only
                .frameOptions(frame -> frame.sameOrigin())
                .contentTypeOptions(content -> {})
                .xssProtection(xss -> xss.block(true))
                // Shorter HSTS for internal services
                .httpStrictTransportSecurity(hsts -> hsts
                    .maxAgeInSeconds(86400) // 1 day
                    .includeSubDomains(false)
                )
                .contentSecurityPolicy(csp -> csp
                    .policyDirectives(
                        "default-src 'self'; " +
                        "frame-ancestors 'self' https://admin.internal.company.com; " +
                        "script-src 'self' 'unsafe-inline'; " + // May need inline for admin tools
                        "style-src 'self' 'unsafe-inline'"
                    )
                )
            );

        return http.build();
    }
}
