// Request Context Filter - Populates MDC for All Requests
@Component
public class SecurityContextFilter implements Filter {

    @Override
    public void doFilter(ServletRequest request, ServletResponse response, FilterChain chain)
            throws IOException, ServletException {

        HttpServletRequest httpRequest = (HttpServletRequest) request;

        try {
            // Populate MDC with request context
            MDC.put("requestId", UUID.randomUUID().toString());
            MDC.put("clientIp", extractClientIp(httpRequest));
            MDC.put("userAgent", sanitizeHeader(httpRequest.getHeader("User-Agent")));
            MDC.put("requestPath", httpRequest.getRequestURI());
            MDC.put("requestMethod", httpRequest.getMethod());

            HttpSession session = httpRequest.getSession(false);
            if (session != null) {
                MDC.put("sessionId", session.getId());
            }

            // Add authenticated user if available
            Principal principal = httpRequest.getUserPrincipal();
            if (principal != null) {
                MDC.put("authenticatedUser", principal.getName());
            }

            chain.doFilter(request, response);

        } finally {
            MDC.clear();
        }
    }

    private String extractClientIp(HttpServletRequest request) {
        String xff = request.getHeader("X-Forwarded-For");
        if (xff != null && !xff.isEmpty()) {
            // Take first IP, validate format
            String ip = xff.split(",")[0].trim();
            if (isValidIp(ip)) {
                return ip;
            }
        }
        return request.getRemoteAddr();
    }

    private boolean isValidIp(String ip) {
        return ip.matches("^[0-9]{1,3}\\.[0-9]{1,3}\\.[0-9]{1,3}\\.[0-9]{1,3}$") ||
               ip.matches("^[0-9a-fA-F:]+$");  // IPv6
    }

    private String sanitizeHeader(String header) {
        if (header == null) return "unknown";
        // Prevent log injection by removing newlines and limiting length
        return header.replaceAll("[\\r\\n]", "")
                     .substring(0, Math.min(header.length(), 200));
    }
}

