            .user(requestingUserId, MDC.get("authenticatedUser"))
            .resource("PatientRecords", "BULK")
            .action("EXPORT")
            .severity("HIGH")
            .addContext("recordCount", patientIds.size())
            .addContext("patientIds", patientIds)
            .success()
            .build();

        auditLogger.logSecurityEvent(exportEvent);

        // Proceed with export
    }
