var db *sql.DB

type contextKey string

const userContextKey contextKey = "user"

type AuthenticatedUser struct {
	ID    int
	Role  string
}

type User struct {
	ID      int    `json:"id"`
	Name    string `json:"name"`
	Email   string `json:"email"`
