    ctx := context.Background()

    // DANGEROUS: User input directly in Redis command
    val, err := rdb.Get(ctx, key).Result()
    if err == redis.Nil {
        c.JSON(404, gin.H{"error": "Not found"})
        return
    } else if err != nil {
        c.JSON(500, gin.H{"error": err.Error()})
        return
    }

    c.JSON(200, gin.H{"value": val})
