public override object GetEntity(Uri absoluteUri, string role, Type ofObjectToReturn)
{
    if (absoluteUri.Scheme != "file")
        throw new XmlSecurityException("External URI blocked", "blocked");

    if (!fullPath.StartsWith(_trustedBasePath))
        throw new XmlSecurityException("Path escape blocked", "blocked");

