```

**Additional Protections**:
- **Introspection disabled in production**: Prevents attackers from discovering schema structure
- **Rate limiting per user**: Prevents automated extraction attacks
- **Audit logging at every authorization decision**: Enables detection of bypass attempts
- **Metrics collection**: Track authorization denials to identify attack patterns
- **Query allowlisting (for high-security apps)**: Only permit pre-approved query structures

Making HTTPS requests in C# requires careful attention to TLS configuration. Many legacy codebases still allow weak protocols that expose your application to serious attacks like POODLE and BEAST.

**VULNERABLE CODE**:

```csharp
using System;
using System.Net;
using System.Net.Http;
using System.Threading.Tasks;

namespace VulnerableApi
{
    public class ApiClient
    {
        private readonly HttpClient _httpClient;

        public ApiClient()
        {
            // VULNERABLE: Allows SSLv3 and TLS 1.0/1.1
            ServicePointManager.SecurityProtocol = SecurityProtocolType.Ssl3 
                | SecurityProtocolType.Tls 
                | SecurityProtocolType.Tls11 
                | SecurityProtocolType.Tls12;

            // VULNERABLE: Disables certificate validation entirely
            ServicePointManager.ServerCertificateValidationCallback = 
                (sender, certificate, chain, sslPolicyErrors) => true;

            _httpClient = new HttpClient();
        }

        public async Task<string> GetUserDataAsync(string userId)
        {
            var url = $"https://api.example.com/users/{userId}";
            var response = await _httpClient.GetAsync(url);
            return await response.Content.ReadAsStringAsync();
        }
    }
}
```

**Attack Scenario**:
```text
1. Attacker positions themselves on the network (coffee shop WiFi, compromised router)
2. Forces TLS downgrade by blocking TLS 1.2/1.3 handshakes
3. Client falls back to SSLv3 or TLS 1.0
4. Attacker exploits POODLE or BEAST to decrypt traffic
5. Steals API keys, session tokens, user data from decrypted requests
```

**Why This Is Dangerous**:
- SSLv3 is completely broken (POODLE attack can decrypt any data)
- TLS 1.0/1.1 have known vulnerabilities (BEAST, Lucky13)
- Disabling certificate validation allows MITM with fake certificates
- PCI DSS explicitly forbids SSLv3 and TLS 1.0 since June 2018

**SECURE VERSION**:

```csharp
using System;
using System.Net;
using System.Net.Http;
using System.Security.Authentication;
using System.Threading.Tasks;
using Microsoft.Extensions.Logging;

namespace SecureApi
{
    public class SecureApiClient : IDisposable
    {
        private readonly HttpClient _httpClient;
        private readonly ILogger<SecureApiClient> _logger;

        public SecureApiClient(ILogger<SecureApiClient> logger)
        {
            _logger = logger;

            // SECURE: Only allow TLS 1.2 and TLS 1.3
            ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12 
                | SecurityProtocolType.Tls13;

            var handler = new HttpClientHandler
            {
                // SECURE: Enforce TLS 1.2 minimum
                SslProtocols = SslProtocols.Tls12 | SslProtocols.Tls13,

                // SECURE: Validate server certificates properly
                ServerCertificateCustomValidationCallback = null,
                CheckCertificateRevocationList = true
            };

            _httpClient = new HttpClient(handler)
            {
                Timeout = TimeSpan.FromSeconds(30)
            };

            _logger.LogInformation("SecureApiClient initialized with TLS 1.2/1.3 only");
        }

        public async Task<string> GetUserDataAsync(string userId)
        {
            if (string.IsNullOrWhiteSpace(userId))
                throw new ArgumentException("User ID cannot be empty", nameof(userId));

            var url = $"https://api.example.com/users/{Uri.EscapeDataString(userId)}";

            try
            {
                var response = await _httpClient.GetAsync(url);
                response.EnsureSuccessStatusCode();
                return await response.Content.ReadAsStringAsync();
            }
            catch (HttpRequestException ex)
            {
                _logger.LogError(ex, "Failed to fetch user data for {UserId}", userId);
                throw;
            }
        }

        public void Dispose()
        {
            _httpClient?.Dispose();
        }
    }
}
```

**Key Security Controls**:
- **TLS 1.2/1.3 only**: Eliminates all known protocol-level attacks (POODLE, BEAST, Lucky13)
- **Certificate validation enabled**: Prevents MITM attacks with forged certificates
- **Certificate revocation checking**: Rejects compromised certificates
- **Proper timeout**: Prevents resource exhaustion from slow connections

Configuring Kestrel for strong TLS requires explicit protocol and cipher suite settings. Here's a production-ready configuration that enforces modern security standards.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Net;
using System.Security.Authentication;
using System.Security.Cryptography.X509Certificates;
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Server.Kestrel.Core;
using Microsoft.AspNetCore.Server.Kestrel.Https;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;

namespace SecureApiServer
{
    public class Program
    {
        public static void Main(string[] args)
        {
            CreateHostBuilder(args).Build().Run();
        }

        public static IHostBuilder CreateHostBuilder(string[] args) =>
            Host.CreateDefaultBuilder(args)
                .ConfigureWebHostDefaults(webBuilder =>
                {
                    webBuilder.UseStartup<Startup>();
                    webBuilder.ConfigureKestrel((context, options) =>
                    {
                        var env = context.HostingEnvironment;
                        var config = context.Configuration;

                        options.ConfigureHttpsDefaults(httpsOptions =>
                        {
                            // SECURE: TLS 1.2 and 1.3 only
                            httpsOptions.SslProtocols = SslProtocols.Tls12 | SslProtocols.Tls13;

                            // SECURE: Require client to support modern TLS
                            httpsOptions.ClientCertificateMode = ClientCertificateMode.NoCertificate;

                            // SECURE: Check certificate revocation
                            httpsOptions.CheckCertificateRevocation = true;
                        });

                        // Production HTTPS endpoint
                        options.Listen(IPAddress.Any, 443, listenOptions =>
                        {
                            var certPath = config["TLS:CertificatePath"];
                            var certPassword = config["TLS:CertificatePassword"];

                            if (string.IsNullOrEmpty(certPath))
                                throw new InvalidOperationException("TLS certificate path not configured");

                            listenOptions.UseHttps(certPath, certPassword, httpsOptions =>
                            {
                                httpsOptions.SslProtocols = SslProtocols.Tls12 | SslProtocols.Tls13;
                            });
                        });

                        // HTTP redirect endpoint (optional)
                        options.Listen(IPAddress.Any, 80, listenOptions =>
                        {
                            // Only used for HTTPS redirect
                        });

                        // Connection limits for DoS protection
                        options.Limits.MaxConcurrentConnections = 1000;
                        options.Limits.MaxConcurrentUpgradedConnections = 100;
                        options.Limits.MaxRequestBodySize = 10 * 1024 * 1024; // 10MB
                        options.Limits.RequestHeadersTimeout = TimeSpan.FromSeconds(30);
                    });
                });
    }

    public class Startup
    {
        private readonly IConfiguration _configuration;

        public Startup(IConfiguration configuration)
        {
            _configuration = configuration;
        }

        public void ConfigureServices(IServiceCollection services)
        {
            services.AddControllers();

            // Add HSTS for production
            services.AddHsts(options =>
            {
                options.Preload = true;
                options.IncludeSubDomains = true;
                options.MaxAge = TimeSpan.FromDays(365);
            });

            services.AddHttpsRedirection(options =>
            {
                options.RedirectStatusCode = StatusCodes.Status307TemporaryRedirect;
                options.HttpsPort = 443;
            });
        }

        public void Configure(IApplicationBuilder app, IWebHostEnvironment env, ILogger<Startup> logger)
        {
            if (!env.IsDevelopment())
            {
                // SECURE: Force HTTPS in production
                app.UseHsts();
            }

            app.UseHttpsRedirection();

            // Security headers middleware
            app.Use(async (context, next) =>
            {
                context.Response.Headers.Add("X-Content-Type-Options", "nosniff");
                context.Response.Headers.Add("X-Frame-Options", "DENY");
                context.Response.Headers.Add("X-XSS-Protection", "1; mode=block");
                context.Response.Headers.Add("Referrer-Policy", "strict-origin-when-cross-origin");
                context.Response.Headers.Add("Content-Security-Policy", "default-src 'self'");
                await next();
            });

            // Log TLS connection info
            app.Use(async (context, next) =>
            {
                var tlsVersion = context.Connection.GetHttpsTokenBinding();
                logger.LogDebug(
                    "Request from {RemoteIp} using {Protocol}",
                    context.Connection.RemoteIpAddress,
                    context.Request.Protocol);
                await next();
            });

            app.UseRouting();
            app.UseAuthorization();
            app.UseEndpoints(endpoints => endpoints.MapControllers());
        }
    }
}
```

