3. **Certificate Validation Middleware**:
```csharp
public class CertificateValidationMiddleware
{
    private readonly RequestDelegate _next;
    private readonly ILogger<CertificateValidationMiddleware> _logger;

    public CertificateValidationMiddleware(
        RequestDelegate next, 
        ILogger<CertificateValidationMiddleware> logger)
    {
        _next = next;
        _logger = logger;
    }

    public async Task InvokeAsync(HttpContext context)
    {
        var clientCert = await context.Connection.GetClientCertificateAsync();

        if (clientCert != null)
        {
            // Log certificate details for audit
            _logger.LogInformation(
                "Client certificate: Subject={Subject}, Thumbprint={Thumbprint}, Expiry={Expiry}",
                clientCert.Subject,
                clientCert.Thumbprint,
                clientCert.NotAfter);

            // Validate certificate is not expired
            if (DateTime.UtcNow > clientCert.NotAfter)
            {
                _logger.LogWarning("Expired client certificate rejected");
                context.Response.StatusCode = 403;
                return;
            }
        }

        await _next(context);
    }
}
