	query := "SELECT id, tenant_id, amount, customer FROM invoices WHERE tenant_id = $1 AND id = $2"
	row := db.QueryRow(query, tenantID, invoiceID)

	var invoice Invoice
	err := row.Scan(&invoice.ID, &invoice.TenantID, &invoice.Amount, &invoice.Customer)
	if err != nil {
