func ListInvoices(w http.ResponseWriter, r *http.Request) {
	tenantID := r.URL.Query().Get("tenant_id") // Easily manipulated

	rows, _ := db.Query("SELECT id, tenant_id, amount, customer FROM invoices WHERE tenant_id = $1", tenantID)
	defer rows.Close()

	var invoices []Invoice
	for rows.Next() {
		var inv Invoice
		rows.Scan(&inv.ID, &inv.TenantID, &inv.Amount, &inv.Customer)
