public class PermissionUpdateRequest {
    @NotBlank
    @Pattern(regexp = "^[a-zA-Z0-9]{1,36}$")
    private String targetUserId;

    @NotEmpty
    @Size(max = 10)
    private List<@Pattern(regexp = "^[A-Z_]{1,50}$") String> permissions;

    // Getters and setters
