Fetching content from user-provided URLs is extremely dangerous and a common source of Server-Side Request Forgery (SSRF) vulnerabilities. This was the root cause of the Capital One breach in 2019, where attackers accessed AWS metadata endpoints to steal IAM credentials.

**VULNERABLE CODE**:

```go
package main

import (
	"io"
	"net/http"
)

func webhookHandler(w http.ResponseWriter, r *http.Request) {
	// VULNERABLE: Directly using user-provided URL
	targetURL := r.URL.Query().Get("url")
	if targetURL == "" {
		http.Error(w, "URL parameter required", http.StatusBadRequest)
		return
	}

	// DANGEROUS: No validation of the target URL
	resp, err := http.Get(targetURL)
	if err != nil {
		http.Error(w, "Failed to fetch URL", http.StatusInternalServerError)
		return
	}
	defer resp.Body.Close()

	// Return fetched content to user
	body, _ := io.ReadAll(resp.Body)
	w.Write(body)
}

func main() {
	http.HandleFunc("/webhook", webhookHandler)
	http.ListenAndServe(":8080", nil)
}
```

**Attack Payload**:
```bash
# Access AWS metadata service to steal IAM credentials
curl "http://vulnerable-app.com/webhook?url=http://169.254.169.254/latest/meta-data/iam/security-credentials/"

# Access internal Kubernetes API
curl "http://vulnerable-app.com/webhook?url=https://kubernetes.default.svc/api/v1/secrets"

# Scan internal network
curl "http://vulnerable-app.com/webhook?url=http://10.0.0.1:8080/admin"

# Access internal Redis/Elasticsearch
curl "http://vulnerable-app.com/webhook?url=http://redis.internal:6379/"
```

**Why This Is Dangerous**:
- Attacker can access cloud metadata endpoints (AWS, GCP, Azure) to steal credentials
- Internal services on private networks become accessible (databases, caches, admin panels)
- Port scanning and internal network reconnaissance becomes possible
- Sensitive data from internal APIs can be exfiltrated through the application

**SECURE VERSION**:

```go
package main

import (
	"fmt"
	"io"
	"net"
	"net/http"
	"net/url"
	"strings"
	"time"
)

var (
	allowedHosts = map[string]bool{
		"api.github.com":    true,
		"api.slack.com":     true,
		"hooks.zapier.com":  true,
	}

	blockedCIDRs = []string{
		"10.0.0.0/8",       // Private network
		"172.16.0.0/12",    // Private network
		"192.168.0.0/16",   // Private network
		"127.0.0.0/8",      // Loopback
		"169.254.0.0/16",   // Link-local (AWS metadata)
		"0.0.0.0/8",        // Current network
	}
)

func isBlockedIP(ip net.IP) bool {
	for _, cidr := range blockedCIDRs {
		_, network, _ := net.ParseCIDR(cidr)
		if network.Contains(ip) {
			return true
		}
	}
	return false
}

func validateURL(targetURL string) error {
	parsed, err := url.Parse(targetURL)
	if err != nil {
		return fmt.Errorf("invalid URL format")
	}

	// Only allow HTTPS
	if parsed.Scheme != "https" {
		return fmt.Errorf("only HTTPS URLs are allowed")
	}

	// Check against allowlist
	if !allowedHosts[parsed.Host] {
		return fmt.Errorf("host not in allowlist")
	}

	// Resolve DNS and check IP
	ips, err := net.LookupIP(parsed.Hostname())
	if err != nil {
		return fmt.Errorf("DNS resolution failed")
	}

	for _, ip := range ips {
		if isBlockedIP(ip) {
			return fmt.Errorf("blocked IP address")
		}
	}

	return nil
}

func secureWebhookHandler(w http.ResponseWriter, r *http.Request) {
	targetURL := r.URL.Query().Get("url")
	if targetURL == "" {
		http.Error(w, "URL parameter required", http.StatusBadRequest)
		return
	}

	if err := validateURL(targetURL); err != nil {
		http.Error(w, "Invalid URL: "+err.Error(), http.StatusBadRequest)
		return
	}

	client := &http.Client{
		Timeout: 10 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			if len(via) >= 3 {
				return fmt.Errorf("too many redirects")
			}
			// Validate redirect target
			if err := validateURL(req.URL.String()); err != nil {
				return fmt.Errorf("redirect blocked: %v", err)
			}
			return nil
		},
	}

	resp, err := client.Get(targetURL)
	if err != nil {
		http.Error(w, "Failed to fetch URL", http.StatusInternalServerError)
		return
	}
	defer resp.Body.Close()

	// Limit response size
	limitedReader := io.LimitReader(resp.Body, 1024*1024) // 1MB max
	body, _ := io.ReadAll(limitedReader)
	w.Write(body)
}
```

**Key Security Controls**:
- **Allowlist validation**: Only pre-approved external hosts can be accessed
- **IP blocklist**: Blocks private networks, loopback, and cloud metadata IPs
- **DNS rebinding protection**: Resolves hostname and validates IP before request
- **Redirect validation**: Each redirect target is validated against the same rules
- **Response size limit**: Prevents denial of service via large responses

Dynamic URL access is one of the hardest SSRF scenarios to secure. You need multiple layers of defense including network-level isolation, DNS rebinding protection, and continuous validation. This pattern is based on how companies like Slack and Notion implement their URL preview features.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/tls"
	"fmt"
	"io"
	"log"
	"net"
	"net/http"
	"net/url"
	"strings"
	"sync"
	"time"
)

type SSRFProtector struct {
	blockedCIDRs  []*net.IPNet
	blockedPorts  map[int]bool
	allowedSchemes map[string]bool
	logger        *log.Logger
	mu            sync.RWMutex
	requestCount  map[string]int
	rateLimit     int
}

func NewSSRFProtector(logger *log.Logger) *SSRFProtector {
	protector := &SSRFProtector{
		blockedPorts: map[int]bool{
			22: true, 23: true, 25: true, 445: true,
			3306: true, 5432: true, 6379: true, 27017: true,
		},
		allowedSchemes: map[string]bool{
			"https": true,
			"http":  true, // Only if required
		},
		logger:       logger,
		requestCount: make(map[string]int),
		rateLimit:    10, // per minute per IP
	}

	// Block private and special ranges
	cidrBlocks := []string{
		"0.0.0.0/8", "10.0.0.0/8", "100.64.0.0/10",
		"127.0.0.0/8", "169.254.0.0/16", "172.16.0.0/12",
		"192.0.0.0/24", "192.0.2.0/24", "192.168.0.0/16",
		"198.18.0.0/15", "198.51.100.0/24", "203.0.113.0/24",
		"224.0.0.0/4", "240.0.0.0/4", "255.255.255.255/32",
		"::1/128", "fc00::/7", "fe80::/10", "ff00::/8",
	}

	for _, cidr := range cidrBlocks {
		_, network, _ := net.ParseCIDR(cidr)
		protector.blockedCIDRs = append(protector.blockedCIDRs, network)
	}

	return protector
}

func (p *SSRFProtector) isBlockedIP(ip net.IP) bool {
	for _, network := range p.blockedCIDRs {
		if network.Contains(ip) {
			return true
		}
	}
	return false
}

func (p *SSRFProtector) checkRateLimit(clientIP string) bool {
	p.mu.Lock()
	defer p.mu.Unlock()

	p.requestCount[clientIP]++
	return p.requestCount[clientIP] <= p.rateLimit
}

func (p *SSRFProtector) ValidateAndFetch(ctx context.Context, targetURL, clientIP string) ([]byte, error) {
	// Rate limiting
	if !p.checkRateLimit(clientIP) {
		p.logger.Printf("SECURITY: Rate limit exceeded for %s", clientIP)
		return nil, fmt.Errorf("rate limit exceeded")
	}

	// Parse and validate URL structure
	parsed, err := url.Parse(targetURL)
	if err != nil {
		p.logger.Printf("SECURITY: Invalid URL from %s: %s", clientIP, targetURL)
		return nil, fmt.Errorf("invalid URL format")
	}

	// Scheme validation
	if !p.allowedSchemes[parsed.Scheme] {
		p.logger.Printf("SECURITY: Blocked scheme %s from %s", parsed.Scheme, clientIP)
		return nil, fmt.Errorf("scheme not allowed")
	}

	// Block common internal hostnames
	hostLower := strings.ToLower(parsed.Hostname())
	blockedHostPatterns := []string{
		"localhost", "metadata", "internal", "kubernetes",
		"docker", "consul", "vault", "etcd", "redis",
		"elasticsearch", "mongo", "mysql", "postgres",
	}
	for _, pattern := range blockedHostPatterns {
		if strings.Contains(hostLower, pattern) {
			p.logger.Printf("SECURITY: Blocked hostname pattern %s from %s", hostLower, clientIP)
			return nil, fmt.Errorf("hostname not allowed")
		}
	}

	// Port validation
	port := parsed.Port()
	if port != "" {
		var portNum int
		fmt.Sscanf(port, "%d", &portNum)
		if p.blockedPorts[portNum] {
			p.logger.Printf("SECURITY: Blocked port %d from %s", portNum, clientIP)
			return nil, fmt.Errorf("port not allowed")
		}
	}

	// DNS resolution with timeout
	resolver := &net.Resolver{
		PreferGo: true,
		Dial: func(ctx context.Context, network, address string) (net.Conn, error) {
			d := net.Dialer{Timeout: 2 * time.Second}
			return d.DialContext(ctx, "udp", "8.8.8.8:53")
		},
	}

	resolveCtx, cancel := context.WithTimeout(ctx, 3*time.Second)
	defer cancel()

	ips, err := resolver.LookupIP(resolveCtx, "ip", parsed.Hostname())
	if err != nil {
		p.logger.Printf("SECURITY: DNS resolution failed for %s from %s", parsed.Hostname(), clientIP)
		return nil, fmt.Errorf("DNS resolution failed")
	}

	// Validate all resolved IPs
	var validIP net.IP
	for _, ip := range ips {
		if p.isBlockedIP(ip) {
			p.logger.Printf("SECURITY: Blocked IP %s for host %s from %s", ip.String(), parsed.Hostname(), clientIP)
			return nil, fmt.Errorf("IP address not allowed")
		}
		validIP = ip
	}

	if validIP == nil {
		return nil, fmt.Errorf("no valid IP found")
	}

	// Create custom transport that connects to resolved IP
	// This prevents DNS rebinding attacks
	transport := &http.Transport{
		DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
			// Re-validate IP at connection time (DNS rebinding protection)
			ips, err := resolver.LookupIP(ctx, "ip", parsed.Hostname())
			if err != nil {
				return nil, err
			}
			for _, ip := range ips {
				if p.isBlockedIP(ip) {
					return nil, fmt.Errorf("DNS rebinding attack detected")
				}
			}

			dialer := &net.Dialer{Timeout: 5 * time.Second}
			return dialer.DialContext(ctx, network, addr)
		},
		TLSClientConfig:       &tls.Config{MinVersion: tls.VersionTLS12},
		MaxIdleConns:          10,
		IdleConnTimeout:       30 * time.Second,
		DisableKeepAlives:     true,
		ResponseHeaderTimeout: 10 * time.Second,
	}

	client := &http.Client{
		Transport: transport,
		Timeout:   15 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			if len(via) >= 3 {
				return fmt.Errorf("too many redirects")
			}

			// Validate each redirect destination
			redirectParsed := req.URL
			if !p.allowedSchemes[redirectParsed.Scheme] {
				return fmt.Errorf("redirect to blocked scheme")
			}

			ips, err := resolver.LookupIP(ctx, "ip", redirectParsed.Hostname())
			if err != nil {
				return fmt.Errorf("redirect DNS failed")
			}
			for _, ip := range ips {
				if p.isBlockedIP(ip) {
					p.logger.Printf("SECURITY: Redirect to blocked IP %s from %s", ip.String(), clientIP)
					return fmt.Errorf("redirect to blocked IP")
				}
			}
			return nil
		},
	}

	req, err := http.NewRequestWithContext(ctx, "GET", targetURL, nil)
	if err != nil {
		return nil, err
	}

	// Set safe headers
	req.Header.Set("User-Agent", "URLPreview/1.0 (Security Bot)")
	req.Header.Set("Accept", "text/html,application/xhtml+xml")

	resp, err := client.Do(req)
	if err != nil {
		p.logger.Printf("SECURITY: Request failed for %s from %s: %v", targetURL, clientIP, err)
		return nil, fmt.Errorf("request failed")
	}
	defer resp.Body.Close()

	// Validate response content type
	contentType := resp.Header.Get("Content-Type")
	allowedContentTypes := []string{"text/html", "application/json", "text/plain"}
	validContent := false
	for _, allowed := range allowedContentTypes {
		if strings.HasPrefix(contentType, allowed) {
			validContent = true
			break
		}
	}
	if !validContent {
		return nil, fmt.Errorf("content type not allowed: %s", contentType)
	}

	// Limit response size (1MB)
	limitedReader := io.LimitReader(resp.Body, 1024*1024)
	body, err := io.ReadAll(limitedReader)
	if err != nil {
		return nil, fmt.Errorf("failed to read response")
	}

	p.logger.Printf("AUDIT: Successful fetch of %s by %s", parsed.Host, clientIP)
	return body, nil
}

func main() {
	logger := log.New(log.Writer(), "[SSRF-PROTECT] ", log.LstdFlags)
	protector := NewSSRFProtector(logger)

	http.HandleFunc("/preview", func(w http.ResponseWriter, r *http.Request) {
		targetURL := r.URL.Query().Get("url")
		if targetURL == "" {
			http.Error(w, "URL required", http.StatusBadRequest)
			return
		}

		clientIP := r.RemoteAddr
		if forwarded := r.Header.Get("X-Forwarded-For"); forwarded != "" {
			clientIP = strings.Split(forwarded, ",")[0]
		}

		ctx, cancel := context.WithTimeout(r.Context(), 20*time.Second)
		defer cancel()

		body, err := protector.ValidateAndFetch(ctx, targetURL, clientIP)
		if err != nil {
			http.Error(w, "Request blocked", http.StatusForbidden)
			return
		}

		w.Header().Set("Content-Type", "text/html; charset=utf-8")
		w.Header().Set("X-Content-Type-Options", "nosniff")
		w.Write(body)
	})

	logger.Println("Starting secure URL preview server on :8080")
	http.ListenAndServe(":8080", nil)
}
