    def get_auth(self, idp_id: str, request_data: Dict) -> Optional[OneLogin_Saml2_Auth]:
        """Get SAML auth instance for specific IDP."""
        if idp_id not in self.idp_configs:
            logger.warning(f"Unknown IDP requested: {idp_id}")
            return None

        return OneLogin_Saml2_Auth(request_data, self.idp_configs[idp_id])

    def validate_and_process(self, idp_id: str, request_data: Dict) -> Dict:
        """Validate SAML response with comprehensive security checks."""
        auth = self.get_auth(idp_id, request_data)
        if not auth:
            raise ValueError(f"Invalid IDP: {idp_id}")

        # Process with full validation
        auth.process_response()

        errors = auth.get_errors()
        if errors:
            raise SecurityError(f"SAML validation failed: {errors}")

        if not auth.is_authenticated():
            raise SecurityError("SAML assertion not authenticated")

        # Extract assertion ID for replay protection
        last_assertion_id = auth.get_last_assertion_id()
        last_assertion_issuer = auth.get_last_assertion_issuer()

        if not last_assertion_id:
            raise SecurityError("Missing assertion ID")

        # CRITICAL: Check for replay attack
        if self.replay_protection.is_assertion_replayed(
            last_assertion_id, 
            last_assertion_issuer
        ):
            logger.critical(
                f"SAML REPLAY ATTACK DETECTED! "
                f"Assertion ID: {last_assertion_id}, "
                f"Issuer: {last_assertion_issuer}"
            )
            raise SecurityError("Assertion replay detected")

        return {
            'name_id': auth.get_nameid(),
            'session_index': auth.get_session_index(),
            'attributes': auth.get_attributes(),
            'issuer': last_assertion_issuer,
            'assertion_id': last_assertion_id
        }

