**PRODUCTION PATTERN**:

```java
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.SAXParserFactory;
import javax.xml.stream.XMLInputFactory;
import javax.xml.transform.TransformerFactory;
import javax.xml.XMLConstants;
import javax.xml.validation.Schema;
import javax.xml.validation.SchemaFactory;
import org.w3c.dom.Document;
import org.xml.sax.helpers.DefaultHandler;
import java.io.InputStream;
import java.io.ByteArrayInputStream;
import java.util.concurrent.atomic.AtomicLong;
import java.util.logging.Logger;
import java.util.logging.Level;

public class SecureXmlParserFactory {

    private static final Logger LOGGER = Logger.getLogger(SecureXmlParserFactory.class.getName());
    private static final long MAX_XML_SIZE_BYTES = 10 * 1024 * 1024; // 10MB limit
    private static final int MAX_ENTITY_EXPANSIONS = 0; // No entity expansion allowed

    // Metrics for monitoring
    private final AtomicLong parseAttempts = new AtomicLong(0);
    private final AtomicLong parseFailures = new AtomicLong(0);
    private final AtomicLong suspiciousInputs = new AtomicLong(0);

    /**
     * Creates a secure DocumentBuilderFactory with all XXE protections enabled
     */
    public DocumentBuilderFactory createSecureDocumentBuilderFactory() {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();

            // Core XXE protections
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);

            // Additional hardening
            factory.setXIncludeAware(false);
            factory.setExpandEntityReferences(false);
            factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

            LOGGER.fine("Created secure DocumentBuilderFactory");
            return factory;

        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Failed to create secure DocumentBuilderFactory", e);
            throw new SecurityException("XML parser initialization failed");
        }
    }

    /**
     * Creates a secure SAXParserFactory for streaming XML processing
     */
    public SAXParserFactory createSecureSAXParserFactory() {
        try {
            SAXParserFactory factory = SAXParserFactory.newInstance();

            // SAX-specific XXE protections
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);

            LOGGER.fine("Created secure SAXParserFactory");
            return factory;

        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Failed to create secure SAXParserFactory", e);
            throw new SecurityException("SAX parser initialization failed");
        }
    }

    /**
     * Creates a secure XMLInputFactory for StAX processing
     */
    public XMLInputFactory createSecureXMLInputFactory() {
        XMLInputFactory factory = XMLInputFactory.newInstance();

        // StAX-specific XXE protections
        factory.setProperty(XMLInputFactory.SUPPORT_DTD, false);
        factory.setProperty(XMLInputFactory.IS_SUPPORTING_EXTERNAL_ENTITIES, false);
        factory.setProperty(XMLInputFactory.IS_REPLACING_ENTITY_REFERENCES, false);

        // Additional StAX hardening
        try {
            factory.setProperty(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            factory.setProperty(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");
        } catch (IllegalArgumentException e) {
            // Some implementations don't support these properties
            LOGGER.warning("XMLInputFactory doesn't support external access restrictions");
        }

        LOGGER.fine("Created secure XMLInputFactory");
        return factory;
    }

    /**
     * Creates a secure TransformerFactory for XSLT processing
     */
    public TransformerFactory createSecureTransformerFactory() {
        try {
            TransformerFactory factory = TransformerFactory.newInstance();

            // Transformer-specific protections
            factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
            factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_STYLESHEET, "");

            LOGGER.fine("Created secure TransformerFactory");
            return factory;

        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Failed to create secure TransformerFactory", e);
            throw new SecurityException("Transformer initialization failed");
        }
    }

    /**
     * Validates and parses XML with comprehensive security checks
     */
    public Document parseWithValidation(InputStream xmlInput, String clientId, String sourceType) 
            throws SecurityException {

        parseAttempts.incrementAndGet();
        long startTime = System.currentTimeMillis();

        try {
            // LAYER 1: Size validation
            byte[] xmlBytes = xmlInput.readAllBytes();
            if (xmlBytes.length > MAX_XML_SIZE_BYTES) {
                suspiciousInputs.incrementAndGet();
                LOGGER.warning(String.format(
                    "XML size exceeded limit: client=%s, size=%d, source=%s",
                    clientId, xmlBytes.length, sourceType));
                throw new SecurityException("XML document exceeds maximum allowed size");
            }

            // LAYER 2: Pre-parse content inspection for suspicious patterns
            String xmlContent = new String(xmlBytes, "UTF-8");
            if (containsSuspiciousPatterns(xmlContent)) {
                suspiciousInputs.incrementAndGet();
                LOGGER.severe(String.format(
                    "SECURITY_ALERT: Suspicious XML pattern detected: client=%s, source=%s",
                    clientId, sourceType));
                throw new SecurityException("Invalid XML content detected");
            }

            // LAYER 3: Secure parsing with hardened factory
            DocumentBuilderFactory factory = createSecureDocumentBuilderFactory();
            Document doc = factory.newDocumentBuilder()
                .parse(new ByteArrayInputStream(xmlBytes));

            long duration = System.currentTimeMillis() - startTime;
            LOGGER.info(String.format(
                "XML parsed successfully: client=%s, source=%s, size=%d, duration=%dms",
                clientId, sourceType, xmlBytes.length, duration));

            return doc;

        } catch (SecurityException se) {
            parseFailures.incrementAndGet();
            throw se;
        } catch (Exception e) {
            parseFailures.incrementAndGet();
            LOGGER.log(Level.SEVERE, String.format(
                "XML parsing failed: client=%s, source=%s, error=%s",
                clientId, sourceType, e.getMessage()), e);
            throw new SecurityException("Failed to parse XML document");
        }
    }

    /**
     * Detects suspicious XXE attack patterns in raw XML content
     */
    private boolean containsSuspiciousPatterns(String xmlContent) {
        String lowerContent = xmlContent.toLowerCase();

        // Check for DOCTYPE declarations (should be blocked but defense in depth)
        if (lowerContent.contains("<!doctype") || lowerContent.contains("<!entity")) {
            return true;
        }

        // Check for common XXE attack protocols
        String[] dangerousProtocols = {
            "file://", "file:\\", "http://", "https://", "ftp://",
            "expect://", "php://", "data://", "jar:", "netdoc:"
        };

        for (String protocol : dangerousProtocols) {
            if (lowerContent.contains(protocol)) {
                return true;
            }
        }

        // Check for cloud metadata endpoints (SSRF)
        if (lowerContent.contains("169.254.169.254") || 
            lowerContent.contains("metadata.google.internal")) {
            return true;
        }

        return false;
    }

    /**
     * Returns current parsing metrics for monitoring dashboards
     */
    public ParsingMetrics getMetrics() {
        return new ParsingMetrics(
            parseAttempts.get(),
            parseFailures.get(),
            suspiciousInputs.get()
        );
    }

    public static class ParsingMetrics {
        public final long attempts;
        public final long failures;
        public final long suspiciousInputs;

        public ParsingMetrics(long attempts, long failures, long suspiciousInputs) {
            this.attempts = attempts;
            this.failures = failures;
            this.suspiciousInputs = suspiciousInputs;
        }
    }
}
```

**Defense in Depth Layers**:

1. **Input Size Limiting** - Prevents denial of service via large XML documents:
```java
if (xmlBytes.length > MAX_XML_SIZE_BYTES) {
    throw new SecurityException("XML document exceeds maximum allowed size");
}
```

2. **Pre-Parse Pattern Detection** - Catches attacks before they reach the parser:
```java
if (lowerContent.contains("<!doctype") || lowerContent.contains("file://")) {
    return true; // Block suspicious content
}
```

3. **Hardened Parser Configuration** - Multiple factory settings as primary defense:
```java
factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
```

**Additional Protections**:
- **Audit Logging**: All parse attempts logged with client ID, source type, and outcome
- **Metrics Collection**: Track parse attempts, failures, and suspicious inputs for alerting
- **Library-Specific Configurations**: Different factories for DOM, SAX, StAX, and XSLT
- **Schema Validation**: Optional XSD validation for known document types
- **Fail-Secure Error Handling**: Generic error messages that don't leak implementation details
- **Rate Limiting**: Integrate with application rate limiter to prevent abuse

File upload handling is extremely security-sensitive. A common mistake is trusting the user-provided filename, which allows path traversal attacks to write files anywhere on the server.

**VULNERABLE CODE**:

```java
import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import javax.servlet.annotation.*;

@WebServlet("/upload")
@MultipartConfig
public class VulnerableFileUploadServlet extends HttpServlet {

    private static final String UPLOAD_DIR = "/var/www/uploads/";

    protected void doPost(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {

        Part filePart = request.getPart("file");

        // VULNERABLE: Directly using user-provided filename
        String fileName = filePart.getSubmittedFileName();

        // VULNERABLE: No validation of filename or path
        String filePath = UPLOAD_DIR + fileName;

        // Attacker controls where file is written
        try (InputStream input = filePart.getInputStream();
             FileOutputStream output = new FileOutputStream(filePath)) {

            byte[] buffer = new byte[1024];
            int bytesRead;
            while ((bytesRead = input.read(buffer)) != -1) {
                output.write(buffer, 0, bytesRead);
            }
        }

        response.getWriter().println("File uploaded to: " + filePath);
    }
}
```

**Attack Payload**:
```text
Filename: ../../../var/www/html/shell.jsp
Content: <% Runtime.getRuntime().exec(request.getParameter("cmd")); %>
```

**Why This Is Dangerous**:
- Attacker supplies filename like `../../../etc/cron.d/malicious` to write outside upload directory
- Web shells can be uploaded to web-accessible directories for remote code execution
- Critical system files can be overwritten causing denial of service
- No authorization check on who can upload or what they can upload

**SECURE VERSION**:

```java
import java.io.*;
import java.nio.file.*;
import java.util.UUID;
import javax.servlet.*;
import javax.servlet.http.*;
import javax.servlet.annotation.*;
import org.apache.tika.Tika;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@WebServlet("/upload")
@MultipartConfig(maxFileSize = 5 * 1024 * 1024) // 5MB limit
public class SecureFileUploadServlet extends HttpServlet {

    private static final Logger logger = LoggerFactory.getLogger(SecureFileUploadServlet.class);
    private static final String UPLOAD_DIR = "/var/www/uploads/";
    private static final String[] ALLOWED_EXTENSIONS = {".jpg", ".jpeg", ".png", ".gif"};
    private static final String[] ALLOWED_MIME_TYPES = {"image/jpeg", "image/png", "image/gif"};
    private final Tika tika = new Tika();

    protected void doPost(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {

        // Authorization check
        HttpSession session = request.getSession(false);
        if (session == null || session.getAttribute("userId") == null) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Login required");
            return;
        }
        String userId = (String) session.getAttribute("userId");

        Part filePart = request.getPart("file");
        if (filePart == null || filePart.getSize() == 0) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "No file provided");
            return;
        }

        String originalFileName = filePart.getSubmittedFileName();

        // SECURE: Validate and sanitize extension
        String extension = getValidatedExtension(originalFileName);
        if (extension == null) {
            logger.warn("Invalid file extension attempted by user {}: {}", userId, originalFileName);
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid file type");
            return;
        }

        // SECURE: Validate MIME type using content inspection (not just header)
        String detectedMimeType = tika.detect(filePart.getInputStream());
        if (!isAllowedMimeType(detectedMimeType)) {
            logger.warn("MIME type mismatch by user {}: claimed {}, detected {}", 
                       userId, originalFileName, detectedMimeType);
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid file content");
            return;
        }

        // SECURE: Generate random filename to prevent path traversal
        String safeFileName = UUID.randomUUID().toString() + extension;

        // SECURE: Use Path.resolve and verify canonical path stays within upload dir
        Path uploadPath = Paths.get(UPLOAD_DIR).toAbsolutePath().normalize();
        Path targetPath = uploadPath.resolve(safeFileName).normalize();

        if (!targetPath.startsWith(uploadPath)) {
            logger.error("Path traversal attempt by user {}: {}", userId, originalFileName);
            response.sendError(HttpServletResponse.SC_FORBIDDEN, "Invalid path");
            return;
        }

        // Write file safely
        try (InputStream input = filePart.getInputStream()) {
            Files.copy(input, targetPath, StandardCopyOption.REPLACE_EXISTING);
        }

        logger.info("File uploaded by user {}: {} -> {}", userId, originalFileName, safeFileName);
        response.getWriter().println("File uploaded successfully");
    }

    private String getValidatedExtension(String fileName) {
        if (fileName == null || fileName.isEmpty()) return null;
        int lastDot = fileName.lastIndexOf('.');
        if (lastDot < 0) return null;
        String ext = fileName.substring(lastDot).toLowerCase();
        for (String allowed : ALLOWED_EXTENSIONS) {
            if (allowed.equals(ext)) return ext;
        }
        return null;
    }

    private boolean isAllowedMimeType(String mimeType) {
        for (String allowed : ALLOWED_MIME_TYPES) {
            if (allowed.equals(mimeType)) return true;
        }
        return false;
    }
}
```

**Key Security Controls**:
- **UUID filename generation**: Eliminates path traversal by ignoring user-supplied filename entirely
- **Canonical path validation**: Verifies resolved path stays within intended directory using `startsWith()` check
- **Content-based MIME detection**: Uses Apache Tika to inspect actual file bytes, not just headers
- **Authorization check**: Verifies user is authenticated before accepting uploads
- **Audit logging**: Records all upload attempts with user context for forensics

Excellent questions! In production, you need to separate the storage filename from the display filename, and use centralized storage for distributed systems.

**PRODUCTION PATTERN**:

```java
import java.io.*;
import java.nio.file.*;
import java.security.MessageDigest;
import java.sql.*;
import java.time.Instant;
import java.util.*;
import javax.servlet.*;
import javax.servlet.http.*;
import javax.servlet.annotation.*;

import software.amazon.awssdk.services.s3.S3Client;
import software.amazon.awssdk.services.s3.model.*;
import software.amazon.awssdk.core.sync.RequestBody;
import org.apache.tika.Tika;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Counter;

@WebServlet("/api/v1/upload")
@MultipartConfig(
    maxFileSize = 10 * 1024 * 1024,      // 10MB per file
    maxRequestSize = 50 * 1024 * 1024,   // 50MB total
    fileSizeThreshold = 1024 * 1024       // 1MB before disk write
)
public class ProductionFileUploadServlet extends HttpServlet {

    private static final Logger logger = LoggerFactory.getLogger(ProductionFileUploadServlet.class);
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    private static final Set<String> ALLOWED_EXTENSIONS = Set.of(".jpg", ".jpeg", ".png", ".gif", ".pdf");
    private static final Set<String> ALLOWED_MIME_TYPES = Set.of(
        "image/jpeg", "image/png", "image/gif", "application/pdf"
    );
    private static final long MAX_FILE_SIZE = 10 * 1024 * 1024;
    private static final String S3_BUCKET = System.getenv("UPLOAD_BUCKET");

    private final Tika tika = new Tika();
    private final S3Client s3Client;
    private final DataSource dataSource;
    private final Counter uploadSuccessCounter;
    private final Counter uploadFailureCounter;
    private final Counter securityViolationCounter;

    public ProductionFileUploadServlet(S3Client s3Client, DataSource dataSource, 
                                        MeterRegistry meterRegistry) {
        this.s3Client = s3Client;
        this.dataSource = dataSource;
        this.uploadSuccessCounter = meterRegistry.counter("file.upload.success");
        this.uploadFailureCounter = meterRegistry.counter("file.upload.failure");
        this.securityViolationCounter = meterRegistry.counter("file.upload.security_violation");
    }

    protected void doPost(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {

        String requestId = UUID.randomUUID().toString();
        long startTime = System.currentTimeMillis();

        try {
            // Layer 1: Authentication & Authorization
            UserContext user = authenticateAndAuthorize(request);
            if (user == null) {
                securityLogger.warn("requestId={} action=UPLOAD_DENIED reason=UNAUTHENTICATED ip={}",
                    requestId, request.getRemoteAddr());
                response.sendError(HttpServletResponse.SC_UNAUTHORIZED);
                return;
            }

            // Layer 2: Rate limiting check (implemented via filter or here)
            if (isRateLimited(user.getId())) {
                securityLogger.warn("requestId={} action=UPLOAD_DENIED reason=RATE_LIMITED userId={}",
                    requestId, user.getId());
                response.sendError(429, "Too many uploads");
                return;
            }

            Part filePart = request.getPart("file");
            if (filePart == null || filePart.getSize() == 0) {
                response.sendError(HttpServletResponse.SC_BAD_REQUEST, "No file provided");
                return;
            }

            // Layer 3: Validate original filename (for display only)
            String originalFileName = sanitizeDisplayFilename(filePart.getSubmittedFileName());

            // Layer 4: Extension validation
            String extension = extractAndValidateExtension(originalFileName);
            if (extension == null) {
                securityViolationCounter.increment();
                securityLogger.warn("requestId={} action=UPLOAD_DENIED reason=INVALID_EXTENSION " +
                    "userId={} filename={}", requestId, user.getId(), originalFileName);
                response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid file type");
                return;
            }

            // Layer 5: Read file to temp buffer for analysis
            byte[] fileContent;
            try (InputStream input = filePart.getInputStream()) {
                if (filePart.getSize() > MAX_FILE_SIZE) {
                    response.sendError(HttpServletResponse.SC_REQUEST_ENTITY_TOO_LARGE);
                    return;
                }
                fileContent = input.readAllBytes();
            }

            // Layer 6: Content-based MIME type detection
            String detectedMimeType = tika.detect(fileContent);
            if (!ALLOWED_MIME_TYPES.contains(detectedMimeType)) {
                securityViolationCounter.increment();
                securityLogger.warn("requestId={} action=UPLOAD_DENIED reason=INVALID_MIME " +
                    "userId={} filename={} detectedMime={}", 
                    requestId, user.getId(), originalFileName, detectedMimeType);
                response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid file content");
                return;
            }

            // Layer 7: Malware scanning (integration point)
            if (!scanForMalware(fileContent, requestId)) {
                securityViolationCounter.increment();
                securityLogger.error("requestId={} action=UPLOAD_DENIED reason=MALWARE_DETECTED " +
                    "userId={}", requestId, user.getId());
                response.sendError(HttpServletResponse.SC_BAD_REQUEST, "File rejected");
                return;
            }

            // Layer 8: Generate secure storage key (no user input in path)
            String fileHash = computeSHA256(fileContent);
            String storageKey = String.format("uploads/%s/%s/%s%s",
                user.getId(),
                Instant.now().toString().substring(0, 10), // Date partition
                fileHash,
                extension
            );

            // Layer 9: Upload to S3 with security metadata
            PutObjectRequest putRequest = PutObjectRequest.builder()
                .bucket(S3_BUCKET)
                .key(storageKey)
                .contentType(detectedMimeType)
                .contentDisposition("attachment") // Prevent browser execution
                .metadata(Map.of(
                    "original-filename", originalFileName,
                    "uploader-id", user.getId(),
                    "upload-timestamp", Instant.now().toString(),
                    "request-id", requestId,
                    "content-hash", fileHash
                ))
                .serverSideEncryption(ServerSideEncryption.AES256)
                .build();

            s3Client.putObject(putRequest, RequestBody.fromBytes(fileContent));

            // Layer 10: Store metadata in database (original filename preserved here)
            String fileId = UUID.randomUUID().toString();
            storeFileMetadata(fileId, user.getId(), originalFileName, storageKey, 
                              fileContent.length, detectedMimeType, fileHash);

            // Success logging and metrics
            uploadSuccessCounter.increment();
            long duration = System.currentTimeMillis() - startTime;
            logger.info("requestId={} action=UPLOAD_SUCCESS userId={} fileId={} size={} duration={}ms",
                requestId, user.getId(), fileId, fileContent.length, duration);

            // Return file ID, not storage path
            response.setContentType("application/json");
            response.getWriter().write(String.format(
                "{\"success\":true,\"fileId\":\"%s\",\"displayName\":\"%s\"}",
                fileId, originalFileName
            ));

        } catch (Exception e) {
            uploadFailureCounter.increment();
            logger.error("requestId={} action=UPLOAD_ERROR error={}", requestId, e.getMessage(), e);
            response.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR, "Upload failed");
        }
    }

    private String sanitizeDisplayFilename(String filename) {
        if (filename == null) return "unnamed";
        // Remove path separators and null bytes
        return filename.replaceAll("[/\\\\\\x00]", "_")
                       .replaceAll("\\.\\.", "_")
                       .substring(0, Math.min(filename.length(), 255));
    }

    private String extractAndValidateExtension(String filename) {
        int lastDot = filename.lastIndexOf('.');
        if (lastDot < 0 || lastDot == filename.length() - 1) return null;
        String ext = filename.substring(lastDot).toLowerCase();
        return ALLOWED_EXTENSIONS.contains(ext) ? ext : null;
    }

    private String computeSHA256(byte[] content) throws Exception {
        MessageDigest digest = MessageDigest.getInstance("SHA-256");
        byte[] hash = digest.digest(content);
        StringBuilder hexString = new StringBuilder();
        for (byte b : hash) {
            hexString.append(String.format("%02x", b));
        }
        return hexString.toString();
    }

