    }

    // Generate presigned URL (time-limited, no path exposure)
    GetObjectPresignRequest presignRequest = GetObjectPresignRequest.builder()
        .signatureDuration(Duration.ofMinutes(5))
        .getObjectRequest(GetObjectRequest.builder()
            .bucket(S3_BUCKET)
            .key(meta.getStorageKey())
            .responseContentDisposition("attachment; filename=\"" + 
                meta.getOriginalFilename() + "\"")
            .build())
        .build();

    URL presignedUrl = s3Presigner.presignGetObject(presignRequest).url();
    return ResponseEntity.status(HttpStatus.FOUND)
        .location(URI.create(presignedUrl.toString()))
        .build();
}
```

**Additional Protections**:
- **Content-Disposition: attachment**: Prevents browser from executing uploaded files inline
- **Separate domain for uploads**: Serve user content from `cdn.example.com` not `www.example.com` to prevent cookie theft
- **S3 bucket policy**: Block public access, require authentication for all operations
- **Virus scanning pipeline**: Async scanning with quarantine for suspicious files
- **File quota enforcement**: Prevent storage exhaustion attacks per user/tenant
- **Retention policies**: Auto-delete old uploads, GDPR compliance for user data deletion

Be very careful with error messages in APIs - verbose errors are a goldmine for attackers. They reveal your internal architecture, database schema, file paths, and technology stack.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const mysql = require('mysql2/promise');

const app = express();
app.use(express.json());

const pool = mysql.createPool({
  host: 'db.internal.company.com',
  user: 'app_user',
  password: 'SuperSecret123!',
  database: 'customers_prod'
});

app.get('/api/users/:id', async (req, res) => {
  try {
    const [rows] = await pool.execute(
      'SELECT * FROM users WHERE id = ?',
      [req.params.id]
    );
    if (rows.length === 0) {
      return res.status(404).json({
        error: 'User not found in table users (database: customers_prod)'
      });
    }
    res.json(rows[0]);
  } catch (error) {
    // DANGEROUS: Exposing full error details
    res.status(500).json({
      error: error.message,
      stack: error.stack,
      query: error.sql,
      code: error.code,
      errno: error.errno,
      sqlState: error.sqlState
    });
  }
});

// Global error handler - also vulnerable
app.use((err, req, res, next) => {
  res.status(500).json({
    message: err.message,
    stack: err.stack,
    file: err.fileName,
    line: err.lineNumber
  });
});

app.listen(3000);
```

**Example Verbose Error Response**:
```json
{
  "error": "ER_BAD_FIELD_ERROR: Unknown column 'password_hash' in 'field list'",
  "stack": "Error: ER_BAD_FIELD_ERROR\n    at /var/www/app/node_modules/mysql2/lib/packets/packet.js:728:17\n    at /var/www/app/src/controllers/UserController.js:45:23",
  "query": "SELECT id, username, password_hash, email, ssn FROM users WHERE id = 1",
  "code": "ER_BAD_FIELD_ERROR",
  "errno": 1054,
  "sqlState": "42S22"
