const express = require('express');
const crypto = require('crypto');
const winston = require('winston');

const app = express();
app.use(express.json());

// Environment detection
const isDevelopment = process.env.NODE_ENV === 'development';
const isProduction = process.env.NODE_ENV === 'production';

// Production-grade logger with different transports
const logger = winston.createLogger({
  level: isDevelopment ? 'debug' : 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.errors({ stack: true }),
    winston.format.json()
  ),
  defaultMeta: { service: 'user-api' },
  transports: [
    new winston.transports.File({ 
      filename: 'error.log', 
      level: 'error',
      maxsize: 10485760, // 10MB
      maxFiles: 5
    }),
    new winston.transports.File({ 
      filename: 'combined.log',
      maxsize: 10485760,
      maxFiles: 10
    })
  ]
});

// Console output only in development
if (isDevelopment) {
  logger.add(new winston.transports.Console({
    format: winston.format.combine(
      winston.format.colorize(),
      winston.format.simple()
    )
  }));
}

// Error classification for appropriate responses
const ErrorTypes = {
  VALIDATION: 'VALIDATION_ERROR',
  NOT_FOUND: 'NOT_FOUND',
  UNAUTHORIZED: 'UNAUTHORIZED',
  FORBIDDEN: 'FORBIDDEN',
  RATE_LIMITED: 'RATE_LIMITED',
  INTERNAL: 'INTERNAL_ERROR',
  DATABASE: 'DATABASE_ERROR',
  EXTERNAL_SERVICE: 'EXTERNAL_SERVICE_ERROR'
};

// Custom application error class
class AppError extends Error {
  constructor(message, type, statusCode, details = null) {
    super(message);
    this.type = type;
    this.statusCode = statusCode;
    this.details = details;
    this.isOperational = true;
    Error.captureStackTrace(this, this.constructor);
  }
}

// Generate secure correlation ID
function generateCorrelationId() {
  return `err_${Date.now()}_${crypto.randomBytes(6).toString('hex')}`;
}

// Sanitize error for client response
function sanitizeErrorForClient(error, correlationId) {
  // Safe messages that don't reveal internals
  const safeMessages = {
    [ErrorTypes.VALIDATION]: 'Invalid request data',
    [ErrorTypes.NOT_FOUND]: 'Resource not found',
    [ErrorTypes.UNAUTHORIZED]: 'Authentication required',
    [ErrorTypes.FORBIDDEN]: 'Access denied',
    [ErrorTypes.RATE_LIMITED]: 'Too many requests',
    [ErrorTypes.INTERNAL]: 'An unexpected error occurred',
    [ErrorTypes.DATABASE]: 'Service temporarily unavailable',
    [ErrorTypes.EXTERNAL_SERVICE]: 'Service temporarily unavailable'
  };

  const baseResponse = {
    success: false,
    error: {
      code: error.type || ErrorTypes.INTERNAL,
      message: safeMessages[error.type] || safeMessages[ErrorTypes.INTERNAL],
      correlationId: correlationId
    }
  };

  // In development, add detailed information
  if (isDevelopment) {
    baseResponse.error.debug = {
      originalMessage: error.message,
      stack: error.stack,
      details: error.details
    };
  }

  // For validation errors, include field-level details (safe to expose)
  if (error.type === ErrorTypes.VALIDATION && error.details) {
    baseResponse.error.validationErrors = error.details;
  }

  return baseResponse;
}

// Comprehensive error logging
function logError(error, req, correlationId) {
  const logData = {
    correlationId: correlationId,
    timestamp: new Date().toISOString(),
    error: {
      message: error.message,
      type: error.type,
      stack: error.stack,
      isOperational: error.isOperational || false
    },
    request: {
      method: req.method,
      path: req.path,
      query: req.query,
      // Never log full body - may contain passwords
      bodyKeys: Object.keys(req.body || {}),
      ip: req.ip,
      userAgent: req.get('User-Agent'),
      userId: req.user?.id || 'anonymous'
    },
    environment: process.env.NODE_ENV
  };

  // Log at appropriate level
  if (error.isOperational) {
    logger.warn('Operational error', logData);
  } else {
    logger.error('Unexpected error', logData);
    // Alert on unexpected errors in production
    if (isProduction) {
      alertOpsTeam(logData);
    }
  }
}

// Production alerting (integrate with PagerDuty, Slack, etc.)
function alertOpsTeam(errorData) {
  // Example: Send to monitoring service
  console.error('[ALERT] Unexpected error requires attention:', errorData.correlationId);
  // In production: integrate with alerting service
  // await pagerduty.trigger(errorData);
  // await slack.postMessage('#alerts', errorData);
}

// Request correlation middleware
app.use((req, res, next) => {
  req.correlationId = req.headers['x-correlation-id'] || generateCorrelationId();
  res.setHeader('X-Correlation-ID', req.correlationId);
  next();
});

// Example route with proper error handling
app.get('/api/users/:id', async (req, res, next) => {
  try {
    const userId = parseInt(req.params.id, 10);

    if (isNaN(userId) || userId <= 0) {
      throw new AppError(
        'User ID must be a positive integer',
        ErrorTypes.VALIDATION,
        400,
        { field: 'id', received: req.params.id }
      );
    }

    // Simulated database call
    const user = await getUserById(userId);

    if (!user) {
      throw new AppError(
        `User ${userId} not found`,
        ErrorTypes.NOT_FOUND,
        404
      );
    }

    res.json({ success: true, data: user });
  } catch (error) {
    next(error);
  }
});

// Global error handler - MUST be last middleware
app.use((err, req, res, next) => {
  const correlationId = req.correlationId || generateCorrelationId();

  // Log full error details server-side
  logError(err, req, correlationId);

  // Determine status code
  const statusCode = err.statusCode || 500;

  // Send sanitized response to client
  const clientResponse = sanitizeErrorForClient(err, correlationId);

  // Security headers on error responses
  res.set({
    'Content-Type': 'application/json',
    'X-Content-Type-Options': 'nosniff',
    'Cache-Control': 'no-store'
  });

  res.status(statusCode).json(clientResponse);
});

// Catch unhandled rejections
process.on('unhandledRejection', (reason, promise) => {
  logger.error('Unhandled Rejection', { reason: reason, promise: promise });
  if (isProduction) {
    alertOpsTeam({ type: 'unhandledRejection', reason: reason });
  }
});

app.listen(3000, () => {
  logger.info(`Server started in ${process.env.NODE_ENV} mode`);
});
