        const noise = (Math.random() - 0.5) * epsilon;
        return Math.max(0, Math.min(1, p + noise));
    });
}

// Detect extraction patterns
function detectExtractionAttempt(apiKey, input) {
    const key = apiKey || 'anonymous';
    if (!queryLog.has(key)) {
