    userLog.queries.push(crypto.createHash('sha256').update(JSON.stringify(input)).digest('hex'));

    // Check for systematic patterns (many similar queries)
    if (userLog.queries.length > 50) {
        const uniquePatterns = new Set(userLog.queries.slice(-100)).size;
        if (uniquePatterns / userLog.queries.slice(-100).length < 0.3) {
            return true;  // Suspicious pattern detected
        }
    }
