class QueryAnomalyDetector {
    constructor(redis, threshold = 0.7) {
        this.redis = redis;
        this.threshold = threshold;
    }

    async recordAndAnalyze(apiKey, inputFeatures) {
        const key = `queries:${apiKey}`;
        const inputHash = crypto.createHash('sha256')
            .update(JSON.stringify(inputFeatures.slice(0, 100)))
            .digest('hex');

        const queryRecord = JSON.stringify({
            inputHash: inputHash,
            timestamp: Date.now(),
            entropy: this.calculateEntropy(inputFeatures)
        });

        await this.redis.lpush(key, queryRecord);
        await this.redis.ltrim(key, 0, 999);  // Keep last 1000
        await this.redis.expire(key, 86400);   // 24 hour expiry

        return this.analyzePatterns(key);
    }

    calculateEntropy(input) {
        const histogram = {};
        const binSize = 0.1;
        input.forEach(val => {
            const bin = Math.floor(val / binSize);
            histogram[bin] = (histogram[bin] || 0) + 1;
        });

        const total = input.length;
        let entropy = 0;
        Object.values(histogram).forEach(count => {
            const p = count / total;
            entropy -= p * Math.log2(p);
        });
        return entropy;
    }

    async analyzePatterns(key) {
        const records = await this.redis.lrange(key, 0, 99);
        if (records.length < 20) return { suspicious: false };

        const parsed = records.map(r => JSON.parse(r));

        // Check 1: Query rate anomaly
        const timeWindow = 60000;  // 1 minute
        const recentCount = parsed.filter(
            r => Date.now() - r.timestamp < timeWindow
        ).length;

        // Check 2: Low entropy inputs (systematic probing)
        const avgEntropy = parsed.reduce((s, r) => s + r.entropy, 0) / parsed.length;

        // Check 3: Input diversity
        const uniqueHashes = new Set(parsed.map(r => r.inputHash)).size;
        const diversityRatio = uniqueHashes / parsed.length;

        const suspicious = recentCount > 50 || avgEntropy < 2.0 || diversityRatio < 0.3;

        return {
            suspicious,
            riskScore: (recentCount / 100) + (1 / avgEntropy) + (1 - diversityRatio),
            reasons: [
                recentCount > 50 ? 'High query rate' : null,
                avgEntropy < 2.0 ? 'Low input entropy' : null,
                diversityRatio < 0.3 ? 'Low input diversity' : null
            ].filter(Boolean)
        };
    }
}

