Your code has a critical **race condition vulnerability** that allows attackers to drain accounts by exploiting the time gap between checking and updating the balance. This is known as a Time-of-Check to Time-of-Use (TOCTOU) attack.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

// In-memory wallet balances (simulating database)
const wallets = {
  'user123': { balance: 1000 },
  'user456': { balance: 500 }
};

app.post('/api/transfer', async (req, res) => {
  const { fromUserId, toUserId, amount } = req.body;

  // VULNERABLE: Check balance (Time-of-Check)
  const senderWallet = wallets[fromUserId];

  if (!senderWallet) {
    return res.status(404).json({ error: 'Sender wallet not found' });
  }

  if (senderWallet.balance < amount) {
    return res.status(400).json({ error: 'Insufficient funds' });
  }

  // Simulate processing delay (network, external API, etc.)
  await processPayment(fromUserId, toUserId, amount);

  // VULNERABLE: Update balance (Time-of-Use)
  // Race window: balance could have changed!
  wallets[fromUserId].balance -= amount;
  wallets[toUserId].balance += amount;

  res.json({ success: true, newBalance: wallets[fromUserId].balance });
});

async function processPayment(from, to, amount) {
  // Simulates external payment processing delay
  return new Promise(resolve => setTimeout(resolve, 100));
}

app.listen(3000);
```

**Attack Payload**:
```bash
# Attacker sends 10 concurrent requests to transfer $900 each
# when account only has $1000 balance
for i in {1..10}; do
  curl -X POST http://localhost:3000/api/transfer \
    -H "Content-Type: application/json" \
    -d '{"fromUserId":"user123","toUserId":"attacker","amount":900}' &
done
wait
# Result: All 10 requests pass the balance check simultaneously
# Account is drained of $9000 despite only having $1000
```

**Why This Is Dangerous**:
- **TOCTOU Gap**: The balance check and deduction are not atomic; concurrent requests can all pass the check before any deduction occurs
- **No Locking Mechanism**: Multiple requests can read the same balance simultaneously
- **Negative Balance**: Account can go negative, causing financial losses for the platform
- **Non-Deterministic**: Bug is hard to reproduce in testing but exploitable in production

**SECURE VERSION**:

```javascript
const express = require('express');
const { Mutex } = require('async-mutex');
const app = express();

// Per-user mutexes for fine-grained locking
const walletLocks = new Map();

const wallets = {
  'user123': { balance: 1000, version: 0 },
  'user456': { balance: 500, version: 0 }
};

function getWalletLock(userId) {
  if (!walletLocks.has(userId)) {
    walletLocks.set(userId, new Mutex());
  }
  return walletLocks.get(userId);
}

app.post('/api/transfer', async (req, res) => {
  const { fromUserId, toUserId, amount } = req.body;

  // Input validation
  if (!fromUserId || !toUserId || typeof amount !== 'number' || amount <= 0) {
    return res.status(400).json({ error: 'Invalid transfer parameters' });
  }

  // SECURE: Acquire lock on sender's wallet before any operations
  const senderLock = getWalletLock(fromUserId);

  const release = await senderLock.acquire();

  try {
    const senderWallet = wallets[fromUserId];
    const receiverWallet = wallets[toUserId];

    if (!senderWallet || !receiverWallet) {
      return res.status(404).json({ error: 'Wallet not found' });
    }

    // SECURE: Check balance while holding lock
    if (senderWallet.balance < amount) {
      return res.status(400).json({ error: 'Insufficient funds' });
    }

    // SECURE: Atomic update while lock is held
    senderWallet.balance -= amount;
    senderWallet.version += 1;
    receiverWallet.balance += amount;
    receiverWallet.version += 1;

    // Process after state is consistent
    await processPayment(fromUserId, toUserId, amount);

    res.json({ 
      success: true, 
      newBalance: senderWallet.balance,
      transactionVersion: senderWallet.version
    });
  } finally {
    // CRITICAL: Always release lock
    release();
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Mutex Locking**: Ensures only one transfer per user can execute at a time, preventing concurrent balance checks
- **Lock Acquisition Before Check**: Balance is checked only after acquiring exclusive access
- **Optimistic Concurrency Control**: Version field enables detection of concurrent modifications
- **Finally Block Release**: Lock is always released, even if errors occur, preventing deadlocks

Excellent question! In production with PostgreSQL, you need database-level controls because application-level mutexes don't work across multiple server instances. Here's a comprehensive production pattern using database transactions, row-level locking, and optimistic concurrency.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const { Pool } = require('pg');
const { v4: uuidv4 } = require('uuid');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(express.json());

// Production database pool configuration
const pool = new Pool({
  host: process.env.DB_HOST,
  database: process.env.DB_NAME,
  user: process.env.DB_USER,
  password: process.env.DB_PASSWORD,
  max: 20,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 2000,
});

// Rate limiting per user
const transferLimiter = rateLimit({
  windowMs: 60 * 1000, // 1 minute
  max: 10, // 10 transfers per minute
  keyGenerator: (req) => req.body.fromUserId || req.ip,
  message: { error: 'Too many transfer requests' }
});

// Idempotency tracking to prevent duplicate processing
const processedRequests = new Map();

app.post('/api/transfer', transferLimiter, async (req, res) => {
  const { fromUserId, toUserId, amount, idempotencyKey } = req.body;
  const transactionId = uuidv4();
  const startTime = Date.now();

  // Input validation
  if (!fromUserId || !toUserId || typeof amount !== 'number' || amount <= 0) {
    return res.status(400).json({ error: 'Invalid parameters' });
  }

  // Idempotency check - prevent duplicate transactions
  if (idempotencyKey && processedRequests.has(idempotencyKey)) {
    console.log(`[IDEMPOTENT] Duplicate request: ${idempotencyKey}`);
    return res.json(processedRequests.get(idempotencyKey));
  }

  const client = await pool.connect();

  try {
    // SECURE: Begin serializable transaction
    await client.query('BEGIN ISOLATION LEVEL SERIALIZABLE');

    // SECURE: SELECT FOR UPDATE - acquires row-level exclusive lock
    // This prevents other transactions from reading or modifying the row
    const senderResult = await client.query(
      `SELECT id, balance, version 
       FROM wallets 
       WHERE user_id = $1 
       FOR UPDATE NOWAIT`,  // NOWAIT fails immediately if locked
      [fromUserId]
    );

    if (senderResult.rows.length === 0) {
      await client.query('ROLLBACK');
      return res.status(404).json({ error: 'Sender wallet not found' });
    }

    const sender = senderResult.rows[0];

    // SECURE: Balance check with lock held
    if (parseFloat(sender.balance) < amount) {
      await client.query('ROLLBACK');
      console.warn(`[INSUFFICIENT_FUNDS] User: ${fromUserId}, Balance: ${sender.balance}, Requested: ${amount}`);
      return res.status(400).json({ error: 'Insufficient funds' });
    }

    // Lock receiver wallet
    const receiverResult = await client.query(
      `SELECT id, balance, version 
       FROM wallets 
       WHERE user_id = $1 
       FOR UPDATE`,
      [toUserId]
    );

    if (receiverResult.rows.length === 0) {
      await client.query('ROLLBACK');
      return res.status(404).json({ error: 'Receiver wallet not found' });
    }

    // SECURE: Atomic update with optimistic concurrency check
    const updateSender = await client.query(
      `UPDATE wallets 
       SET balance = balance - $1, 
           version = version + 1, 
           updated_at = NOW() 
       WHERE user_id = $2 AND version = $3
       RETURNING balance, version`,
      [amount, fromUserId, sender.version]
    );

    // Version mismatch = concurrent modification detected
    if (updateSender.rowCount === 0) {
      await client.query('ROLLBACK');
      console.error(`[RACE_DETECTED] Concurrent modification on wallet: ${fromUserId}`);
      return res.status(409).json({ error: 'Transaction conflict, please retry' });
    }

    await client.query(
      `UPDATE wallets 
       SET balance = balance + $1, 
           version = version + 1, 
           updated_at = NOW() 
       WHERE user_id = $2`,
      [amount, toUserId]
    );

    // Record transaction for audit trail
    await client.query(
      `INSERT INTO transactions 
       (id, from_user_id, to_user_id, amount, status, created_at, idempotency_key) 
       VALUES ($1, $2, $3, $4, 'completed', NOW(), $5)`,
      [transactionId, fromUserId, toUserId, amount, idempotencyKey]
    );

    // SECURE: Commit transaction atomically
    await client.query('COMMIT');

    const response = {
      success: true,
      transactionId,
      newBalance: updateSender.rows[0].balance,
      version: updateSender.rows[0].version
    };

    // Cache for idempotency
    if (idempotencyKey) {
      processedRequests.set(idempotencyKey, response);
      setTimeout(() => processedRequests.delete(idempotencyKey), 24 * 60 * 60 * 1000);
    }

    // Audit logging
    console.log(JSON.stringify({
      event: 'TRANSFER_SUCCESS',
      transactionId,
      fromUserId,
      toUserId,
      amount,
      duration: Date.now() - startTime,
      timestamp: new Date().toISOString()
    }));

    res.json(response);

  } catch (error) {
    await client.query('ROLLBACK');

    // Handle specific PostgreSQL errors
    if (error.code === '55P03') {
      // NOWAIT lock not available
      console.warn(`[LOCK_CONTENTION] Wallet locked: ${fromUserId}`);
      return res.status(429).json({ 
        error: 'Resource busy, please retry',
        retryAfter: 1
      });
    }

    if (error.code === '40001') {
      // Serialization failure
      console.warn(`[SERIALIZATION_FAILURE] Transaction: ${transactionId}`);
      return res.status(409).json({ 
        error: 'Transaction conflict, please retry' 
      });
    }

    console.error(JSON.stringify({
      event: 'TRANSFER_ERROR',
      transactionId,
      error: error.message,
      code: error.code,
      timestamp: new Date().toISOString()
    }));

    res.status(500).json({ error: 'Transfer failed' });

  } finally {
    client.release();
  }
});

// Health check endpoint for monitoring
app.get('/health', async (req, res) => {
  try {
    await pool.query('SELECT 1');
    res.json({ status: 'healthy', connections: pool.totalCount });
  } catch (error) {
    res.status(503).json({ status: 'unhealthy' });
  }
});

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Database-Level Locking (SELECT FOR UPDATE)**:
```sql
-- Acquires exclusive row lock until transaction ends
SELECT balance FROM wallets WHERE user_id = $1 FOR UPDATE NOWAIT;
-- NOWAIT: Fail immediately if row is locked by another transaction
-- Prevents queue buildup during contention
```

2. **Serializable Transaction Isolation**:
```sql
-- Highest isolation level - transactions appear to execute sequentially
BEGIN ISOLATION LEVEL SERIALIZABLE;
-- PostgreSQL will abort transactions that would cause anomalies
```

3. **Optimistic Concurrency Control (Version Column)**:
```sql
-- Update only succeeds if version hasn't changed
UPDATE wallets 
SET balance = balance - $1, version = version + 1 
WHERE user_id = $2 AND version = $3;
-- rowCount = 0 means concurrent modification detected
```

**Additional Protections**:

- **Idempotency Keys**: Clients send unique key per request; server returns cached result for duplicates, preventing double-charges on network retries
- **Rate Limiting**: Per-user limits prevent automated exploitation attempts
- **NOWAIT Locking**: Fails fast under contention instead of blocking, improving responsiveness
- **Structured Audit Logging**: Every transaction logged with timing metrics for forensic analysis
- **Connection Pooling**: Prevents connection exhaustion under load
- **Retry Guidance**: 409 responses include retry hints for clients to implement exponential backoff
- **Health Endpoint**: Enables load balancers to route around unhealthy instances

