Setting up logging requires careful consideration of retention policies. Many developers make the mistake of implementing basic logging without considering how long logs should be kept or how they should be managed, which can leave you blind during security incidents.

**VULNERABLE CODE**:

```go
package main

import (
	"log"
	"net/http"
	"os"
)

var logFile *os.File

func main() {
	// Simple file logging - overwrites on each restart
	var err error
	logFile, err = os.Create("app.log")
	if err != nil {
		log.Fatal(err)
	}
	defer logFile.Close()

	log.SetOutput(logFile)

	http.HandleFunc("/api/", func(w http.ResponseWriter, r *http.Request) {
		// Basic logging without timestamps or context
		log.Printf("Request: %s %s", r.Method, r.URL.Path)
		w.Write([]byte("OK"))
	})

	http.ListenAndServe(":8080", nil)
}
```

**Why This Is Dangerous**:
- `os.Create()` truncates the log file on each application restart, destroying historical logs
- No log rotation means single file grows unbounded until disk fills
- No retention policy - logs either grow forever or are lost on restart
- Missing critical security fields (source IP, user ID, response codes)
- No backup or archival strategy for forensic requirements
- Violates PCI-DSS (1 year), SOX (7 years), HIPAA (6 years) retention requirements

**SECURE VERSION**:

```go
package main

import (
	"net/http"
	"os"
	"time"

	"go.uber.org/zap"
	"go.uber.org/zap/zapcore"
	"gopkg.in/natefinch/lumberjack.v2"
)

type SecurityLogger struct {
	logger *zap.Logger
}

func NewSecurityLogger() (*SecurityLogger, error) {
	// Configure log rotation with retention
	logRotator := &lumberjack.Logger{
		Filename:   "/var/log/myapp/security.log",
		MaxSize:    100,  // MB before rotation
		MaxBackups: 365,  // Keep 365 rotated files (1 year minimum)
		MaxAge:     365,  // Days to retain old log files
		Compress:   true, // Compress rotated files
	}

	// JSON encoder for structured logging
	encoderConfig := zapcore.EncoderConfig{
		TimeKey:        "timestamp",
		LevelKey:       "level",
		MessageKey:     "message",
		EncodeTime:     zapcore.ISO8601TimeEncoder,
		EncodeLevel:    zapcore.LowercaseLevelEncoder,
		EncodeDuration: zapcore.SecondsDurationEncoder,
	}

	core := zapcore.NewCore(
		zapcore.NewJSONEncoder(encoderConfig),
		zapcore.AddSync(logRotator),
		zap.InfoLevel,
	)

	logger := zap.New(core, zap.AddCaller())
	return &SecurityLogger{logger: logger}, nil
}

func (sl *SecurityLogger) LogRequest(r *http.Request, statusCode int, duration time.Duration) {
	sl.logger.Info("http_request",
		zap.String("method", r.Method),
		zap.String("path", r.URL.Path),
		zap.String("remote_addr", r.RemoteAddr),
		zap.String("user_agent", r.UserAgent()),
		zap.Int("status_code", statusCode),
		zap.Duration("duration", duration),
		zap.String("request_id", r.Header.Get("X-Request-ID")),
	)
}

func main() {
	secLogger, err := NewSecurityLogger()
	if err != nil {
		os.Exit(1)
	}
	defer secLogger.logger.Sync()

	http.HandleFunc("/api/", func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()
		w.Write([]byte("OK"))
		secLogger.LogRequest(r, http.StatusOK, time.Since(start))
	})

	http.ListenAndServe(":8080", nil)
}
```

**Key Security Controls**:
- **Log rotation with retention**: `MaxBackups: 365` and `MaxAge: 365` ensures logs are kept for 1 year minimum, meeting PCI-DSS requirements
- **Compression**: Old logs are compressed to save storage while maintaining availability for forensics
- **Structured JSON logging**: Enables efficient parsing by SIEM systems and supports complex queries during incident investigation
- **Complete audit trail**: Includes timestamp, source IP, request ID for correlation, status codes, and duration

Long-term log retention with tamper-evidence requires a multi-tier approach: hot storage for recent logs, warm storage for medium-term, and cold/immutable storage for archival. Here's a production pattern that meets SOX, HIPAA, and PCI-DSS requirements.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"os"
	"sync"
	"time"

	"cloud.google.com/go/storage"
	"go.uber.org/zap"
	"go.uber.org/zap/zapcore"
	"gopkg.in/natefinch/lumberjack.v2"
)

// RetentionPolicy defines log retention requirements
type RetentionPolicy struct {
	HotRetentionDays   int           // Local fast storage
	WarmRetentionDays  int           // Searchable archive
	ColdRetentionYears int           // Immutable long-term
	ArchiveInterval    time.Duration // How often to archive
}

// CompliancePresets for common regulations
var CompliancePresets = map[string]RetentionPolicy{
	"SOX":     {HotRetentionDays: 90, WarmRetentionDays: 365, ColdRetentionYears: 7, ArchiveInterval: 24 * time.Hour},
	"HIPAA":   {HotRetentionDays: 90, WarmRetentionDays: 365, ColdRetentionYears: 6, ArchiveInterval: 24 * time.Hour},
	"PCI-DSS": {HotRetentionDays: 90, WarmRetentionDays: 365, ColdRetentionYears: 1, ArchiveInterval: 24 * time.Hour},
	"GDPR":    {HotRetentionDays: 30, WarmRetentionDays: 90, ColdRetentionYears: 3, ArchiveInterval: 24 * time.Hour},
}

// TamperEvidentLog provides integrity verification
type TamperEvidentLog struct {
	Timestamp    time.Time              `json:"timestamp"`
	SequenceNum  uint64                 `json:"sequence_num"`
	EventType    string                 `json:"event_type"`
	Data         map[string]interface{} `json:"data"`
	PreviousHash string                 `json:"previous_hash"`
	CurrentHash  string                 `json:"current_hash"`
}

// EnterpriseSecurityLogger handles compliant logging
type EnterpriseSecurityLogger struct {
	logger         *zap.Logger
	archiver       *LogArchiver
	policy         RetentionPolicy
	lastHash       string
	sequenceNum    uint64
	hashMutex      sync.Mutex
	integrityStore *IntegrityStore
}

// IntegrityStore maintains hash chain for verification
type IntegrityStore struct {
	chainFile *os.File
	mu        sync.Mutex
}

func NewIntegrityStore(path string) (*IntegrityStore, error) {
	f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0600)
	if err != nil {
		return nil, fmt.Errorf("failed to open integrity store: %w", err)
	}
	return &IntegrityStore{chainFile: f}, nil
}

func (is *IntegrityStore) RecordHash(seqNum uint64, hash string) error {
	is.mu.Lock()
	defer is.mu.Unlock()
	_, err := fmt.Fprintf(is.chainFile, "%d|%s|%s\n", seqNum, time.Now().UTC().Format(time.RFC3339), hash)
	return err
}

// LogArchiver handles tiered storage
type LogArchiver struct {
	gcsClient  *storage.Client
	bucketName string
	ctx        context.Context
}

func NewLogArchiver(ctx context.Context, bucketName string) (*LogArchiver, error) {
	client, err := storage.NewClient(ctx)
	if err != nil {
		return nil, fmt.Errorf("failed to create GCS client: %w", err)
	}
	return &LogArchiver{
		gcsClient:  client,
		bucketName: bucketName,
		ctx:        ctx,
	}, nil
}

func (la *LogArchiver) ArchiveToImmutableStorage(logPath string, retentionYears int) error {
	// Read local log file
	data, err := os.ReadFile(logPath)
	if err != nil {
		return fmt.Errorf("failed to read log file: %w", err)
	}

	// Generate archive path with timestamp
	archivePath := fmt.Sprintf("security-logs/%s/%s.log.gz",
		time.Now().UTC().Format("2006/01/02"),
		time.Now().UTC().Format("150405"))

	// Upload to immutable bucket with retention lock
	bucket := la.gcsClient.Bucket(la.bucketName)
	obj := bucket.Object(archivePath)

	// Set retention policy (object lock)
	retentionTime := time.Now().AddDate(retentionYears, 0, 0)
	writer := obj.NewWriter(la.ctx)
	writer.Retention = &storage.ObjectRetention{
		Mode:        "Locked",
		RetainUntil: retentionTime,
	}
	writer.ContentType = "application/gzip"

	if _, err := writer.Write(data); err != nil {
		writer.Close()
		return fmt.Errorf("failed to write to GCS: %w", err)
	}

	if err := writer.Close(); err != nil {
		return fmt.Errorf("failed to close GCS writer: %w", err)
	}

	return nil
}

func NewEnterpriseSecurityLogger(complianceType string) (*EnterpriseSecurityLogger, error) {
	policy, exists := CompliancePresets[complianceType]
	if !exists {
		return nil, fmt.Errorf("unknown compliance type: %s", complianceType)
	}

	// Hot storage with rotation
	hotStorage := &lumberjack.Logger{
		Filename:   "/var/log/security/audit.log",
		MaxSize:    100,
		MaxBackups: policy.HotRetentionDays,
		MaxAge:     policy.HotRetentionDays,
		Compress:   true,
	}

	encoderConfig := zapcore.EncoderConfig{
		TimeKey:        "@timestamp",
		LevelKey:       "level",
		MessageKey:     "message",
		EncodeTime:     zapcore.ISO8601TimeEncoder,
		EncodeLevel:    zapcore.LowercaseLevelEncoder,
	}

	core := zapcore.NewCore(
		zapcore.NewJSONEncoder(encoderConfig),
		zapcore.AddSync(hotStorage),
		zap.InfoLevel,
	)

	logger := zap.New(core, zap.AddCaller(), zap.AddStacktrace(zap.ErrorLevel))

	integrityStore, err := NewIntegrityStore("/var/log/security/integrity-chain.dat")
	if err != nil {
		return nil, err
	}

	ctx := context.Background()
	archiver, err := NewLogArchiver(ctx, "company-immutable-logs")
	if err != nil {
		return nil, err
	}

	esl := &EnterpriseSecurityLogger{
		logger:         logger,
		archiver:       archiver,
		policy:         policy,
		lastHash:       "genesis",
		sequenceNum:    0,
		integrityStore: integrityStore,
	}

	// Start archival goroutine
	go esl.archivalRoutine()

	return esl, nil
}

func (esl *EnterpriseSecurityLogger) computeHash(entry TamperEvidentLog) string {
	data, _ := json.Marshal(entry)
	hash := sha256.Sum256(data)
	return hex.EncodeToString(hash[:])
}

func (esl *EnterpriseSecurityLogger) LogSecurityEvent(eventType string, data map[string]interface{}) {
	esl.hashMutex.Lock()
	defer esl.hashMutex.Unlock()

	esl.sequenceNum++

	entry := TamperEvidentLog{
		Timestamp:    time.Now().UTC(),
		SequenceNum:  esl.sequenceNum,
		EventType:    eventType,
		Data:         data,
		PreviousHash: esl.lastHash,
	}

	entry.CurrentHash = esl.computeHash(entry)
	esl.lastHash = entry.CurrentHash

	// Record hash in integrity store
	esl.integrityStore.RecordHash(entry.SequenceNum, entry.CurrentHash)

	// Log the event
	esl.logger.Info(eventType,
		zap.Uint64("sequence_num", entry.SequenceNum),
		zap.String("previous_hash", entry.PreviousHash),
		zap.String("current_hash", entry.CurrentHash),
		zap.Any("data", data),
	)
}

func (esl *EnterpriseSecurityLogger) archivalRoutine() {
	ticker := time.NewTicker(esl.policy.ArchiveInterval)
	for range ticker.C {
		err := esl.archiver.ArchiveToImmutableStorage(
			"/var/log/security/audit.log",
			esl.policy.ColdRetentionYears,
		)
		if err != nil {
			esl.logger.Error("archival_failed", zap.Error(err))
		} else {
			esl.logger.Info("archival_completed",
				zap.Int("retention_years", esl.policy.ColdRetentionYears),
			)
		}
	}
}

func main() {
	// Initialize with SOX compliance (7-year retention)
	secLogger, err := NewEnterpriseSecurityLogger("SOX")
	if err != nil {
		fmt.Printf("Failed to initialize logger: %v\n", err)
		os.Exit(1)
	}

	// Log security events with tamper-evident chain
	secLogger.LogSecurityEvent("authentication", map[string]interface{}{
		"user_id":     "user123",
		"action":      "login_success",
		"source_ip":   "192.168.1.100",
		"user_agent":  "Mozilla/5.0...",
		"mfa_used":    true,
		"session_id":  "sess_abc123",
	})

	secLogger.LogSecurityEvent("data_access", map[string]interface{}{
		"user_id":     "user123",
		"resource":    "financial_reports",
		"action":      "read",
		"record_count": 150,
	})
}
```

**Defense in Depth Layers**:

1. **Hash Chain Integrity**: Each log entry contains the hash of the previous entry, creating a tamper-evident chain. If any entry is modified, the chain breaks:
```go
// Verification function
func VerifyChainIntegrity(logs []TamperEvidentLog) (bool, int) {
    for i := 1; i < len(logs); i++ {
        expectedPrevHash := logs[i-1].CurrentHash
        if logs[i].PreviousHash != expectedPrevHash {
            return false, i // Tampering detected at index i
        }
    }
    return true, -1
}
```

2. **Immutable Cloud Storage**: GCS Object Lock with retention policies prevents deletion even by administrators:
```go
// Bucket-level retention policy (set via Terraform/CLI)
// gsutil retention set 7y gs://company-immutable-logs
// This prevents ANY deletion for 7 years
```

3. **Separate Integrity Store**: Hash chain stored separately from logs, enabling verification even if primary logs are compromised:
```go
// Integrity chain format: sequence|timestamp|hash
// 1|2025-01-09T10:00:00Z|a3f2b1c9...
// 2|2025-01-09T10:00:01Z|b4e3c2d8...
```

**Additional Protections**:

- **Write-Once Storage**: Configure cloud bucket with WORM (Write Once Read Many) compliance mode
- **Geographic Redundancy**: Replicate logs across multiple regions for disaster recovery
- **Encryption at Rest**: All archived logs encrypted with customer-managed keys
- **Access Logging**: Enable access logs on the log bucket itself (meta-logging)
- **Alerting on Gaps**: Monitor for sequence number gaps indicating potential deletion attempts
- **Regular Integrity Audits**: Automated weekly verification of hash chain integrity

**Compliance Mapping**:

| Requirement | Implementation |
|-------------|----------------|
| SOX 7-year retention | `ColdRetentionYears: 7` + GCS Object Lock |
| Tamper-evidence | SHA-256 hash chain with separate integrity store |
| Audit trail | Sequence numbers, timestamps, hash verification |
| Access controls | IAM policies, separate service accounts for read/write |
| Availability | Multi-region replication, 99.999999999% durability |

This is a classic Server-Side Request Forgery (SSRF) scenario - one of the most dangerous vulnerabilities in cloud environments. The Capital One breach in 2019 resulted from exactly this pattern, where attackers accessed the AWS metadata service to steal IAM credentials, exposing 100 million customer records.

**VULNERABLE CODE**:

```java
import java.io.*;
import java.net.*;
import javax.servlet.http.*;
import javax.servlet.annotation.*;

@WebServlet("/api/fetch")
public class UrlFetcherServlet extends HttpServlet {

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String targetUrl = request.getParameter("url");

        // VULNERABLE: No validation of user-supplied URL
        URL url = new URL(targetUrl);
        HttpURLConnection conn = (HttpURLConnection) url.openConnection();
        conn.setRequestMethod("GET");
        conn.setConnectTimeout(5000);

        BufferedReader reader = new BufferedReader(
            new InputStreamReader(conn.getInputStream()));

        StringBuilder content = new StringBuilder();
        String line;
        while ((line = reader.readLine()) != null) {
            content.append(line);
        }
        reader.close();

        response.setContentType("text/plain");
        response.getWriter().write(content.toString());
    }
}
```

**Attack Payload**:
```text
# Access AWS metadata service to steal IAM credentials
http://169.254.169.254/latest/meta-data/iam/security-credentials/

# Access internal Redis server
http://redis.internal:6379/

# Scan internal network
http://192.168.1.1:8080/admin

# Access Kubernetes service account tokens
http://169.254.169.254/latest/meta-data/identity-credentials/ec2/security-credentials/
```

**Why This Is Dangerous**:
- Attacker can access cloud metadata services (AWS, GCP, Azure) to steal credentials
- Internal services not exposed to internet become accessible
- Can bypass firewall rules and access sensitive internal APIs
- Enables network reconnaissance and lateral movement
- May access configuration files, databases, and secrets managers

**SECURE VERSION**:

```java
import java.io.*;
import java.net.*;
import java.util.*;
import java.util.regex.*;
import javax.servlet.http.*;
import javax.servlet.annotation.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@WebServlet("/api/fetch")
public class SecureUrlFetcherServlet extends HttpServlet {

    private static final Logger logger = LoggerFactory.getLogger(SecureUrlFetcherServlet.class);

    // Allowlist of permitted domains
    private static final Set<String> ALLOWED_DOMAINS = Set.of(
        "api.trusted-partner.com",
        "cdn.example.com",
        "images.example.com"
    );

    // Blocked IP ranges (RFC 1918, link-local, cloud metadata)
    private static final List<String> BLOCKED_IP_PATTERNS = List.of(
        "^10\\.",                    // 10.0.0.0/8
        "^172\\.(1[6-9]|2[0-9]|3[01])\\.",  // 172.16.0.0/12
        "^192\\.168\\.",             // 192.168.0.0/16
        "^127\\.",                   // Loopback
        "^169\\.254\\.",             // Link-local (AWS metadata!)
        "^0\\.",                     // Current network
        "^::1$",                     // IPv6 loopback
        "^fc00:",                    // IPv6 unique local
        "^fe80:"                     // IPv6 link-local
    );

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String targetUrl = request.getParameter("url");
        String clientIp = request.getRemoteAddr();

        try {
            // Step 1: Validate URL format
            URL url = validateAndParseUrl(targetUrl);

            // Step 2: Check against domain allowlist
            if (!isAllowedDomain(url.getHost())) {
                logger.warn("SSRF attempt blocked - domain not allowed: {} from {}", 
                           url.getHost(), clientIp);
                response.sendError(403, "Domain not permitted");
                return;
            }

            // Step 3: Resolve DNS and check IP address
            InetAddress resolvedAddress = InetAddress.getByName(url.getHost());
            if (isBlockedIp(resolvedAddress)) {
                logger.warn("SSRF attempt blocked - internal IP: {} from {}", 
                           resolvedAddress.getHostAddress(), clientIp);
                response.sendError(403, "Access denied");
                return;
            }

            // Step 4: Fetch content with security controls
            String content = fetchWithSafetyLimits(url);

            logger.info("URL fetch successful: {} by {}", url.getHost(), clientIp);
            response.setContentType("text/plain");
            response.getWriter().write(content);

        } catch (MalformedURLException e) {
            logger.warn("Invalid URL format: {} from {}", targetUrl, clientIp);
            response.sendError(400, "Invalid URL format");
        } catch (Exception e) {
            logger.error("Fetch error for URL: {}", targetUrl, e);
            response.sendError(500, "Unable to fetch resource");
        }
    }

    private URL validateAndParseUrl(String urlString) throws MalformedURLException {
        if (urlString == null || urlString.isBlank()) {
            throw new MalformedURLException("URL cannot be empty");
        }

        URL url = new URL(urlString);

        // Only allow HTTPS
        if (!"https".equalsIgnoreCase(url.getProtocol())) {
            throw new MalformedURLException("Only HTTPS URLs are permitted");
        }

        return url;
    }

    private boolean isAllowedDomain(String host) {
        return ALLOWED_DOMAINS.stream()
            .anyMatch(allowed -> host.equalsIgnoreCase(allowed) || 
                                 host.endsWith("." + allowed));
    }

    private boolean isBlockedIp(InetAddress address) {
        String ip = address.getHostAddress();
        return BLOCKED_IP_PATTERNS.stream()
            .anyMatch(pattern -> Pattern.matches(pattern, ip));
    }

    private String fetchWithSafetyLimits(URL url) throws IOException {
        HttpURLConnection conn = (HttpURLConnection) url.openConnection();
        conn.setRequestMethod("GET");
        conn.setConnectTimeout(3000);
        conn.setReadTimeout(5000);
        conn.setInstanceFollowRedirects(false);  // Prevent redirect-based SSRF
        conn.setRequestProperty("User-Agent", "InternalFetcher/1.0");

        // Limit response size to prevent DoS
        int maxSize = 1024 * 1024; // 1MB
        ByteArrayOutputStream buffer = new ByteArrayOutputStream();

        try (InputStream is = conn.getInputStream()) {
            byte[] data = new byte[4096];
            int bytesRead;
            int totalRead = 0;

            while ((bytesRead = is.read(data)) != -1) {
                totalRead += bytesRead;
                if (totalRead > maxSize) {
                    throw new IOException("Response exceeds maximum size");
                }
                buffer.write(data, 0, bytesRead);
            }
        }

        return buffer.toString("UTF-8");
    }
}
```

**Key Security Controls**:
- **Domain allowlist**: Only explicitly approved domains can be fetched, blocking all internal addresses by default
- **IP address validation**: Resolves DNS and blocks RFC 1918 private ranges, link-local addresses (169.254.x.x for cloud metadata), and loopback
- **HTTPS enforcement**: Prevents protocol-based attacks and ensures encrypted transport
- **Redirect blocking**: `setInstanceFollowRedirects(false)` prevents attackers from using redirects to bypass domain checks
- **Response size limits**: Prevents denial-of-service via large responses

Excellent security awareness! DNS rebinding is an advanced SSRF bypass technique where attackers control a DNS server that initially returns a valid public IP (passing your validation), then quickly changes to return an internal IP (like 169.254.169.254) before the actual HTTP request is made. This exploits the time-of-check to time-of-use (TOCTOU) gap.

**PRODUCTION PATTERN**:

```java
import java.io.*;
import java.net.*;
import java.util.*;
import java.util.concurrent.*;
import java.util.regex.*;
import javax.net.ssl.*;
import org.apache.http.client.config.*;
import org.apache.http.impl.client.*;
import org.apache.http.impl.conn.*;
import org.apache.http.conn.*;
import org.apache.http.conn.socket.*;
import org.apache.http.protocol.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SsrfProtectedHttpClient {

    private static final Logger logger = LoggerFactory.getLogger(SsrfProtectedHttpClient.class);

    // Allowlisted domains
    private static final Set<String> ALLOWED_DOMAINS = Set.of(
        "api.trusted-partner.com",
        "cdn.example.com"
    );

    // Cache validated IPs to prevent DNS rebinding
    private static final ConcurrentHashMap<String, ValidatedHost> DNS_CACHE = 
        new ConcurrentHashMap<>();
    private static final long DNS_CACHE_TTL_MS = 60000; // 1 minute

    // Blocked IP ranges
    private static final List<IpRange> BLOCKED_RANGES = List.of(
        new IpRange("10.0.0.0", "10.255.255.255"),
        new IpRange("172.16.0.0", "172.31.255.255"),
        new IpRange("192.168.0.0", "192.168.255.255"),
        new IpRange("127.0.0.0", "127.255.255.255"),
        new IpRange("169.254.0.0", "169.254.255.255"),  // Cloud metadata!
        new IpRange("0.0.0.0", "0.255.255.255")
    );

    /**
     * Custom DNS resolver that validates resolved IPs and caches results
     * to prevent DNS rebinding attacks.
     */
    public static class SsrfSafeDnsResolver implements DnsResolver {

        @Override
        public InetAddress[] resolve(String host) throws UnknownHostException {
            // Check cache first to prevent DNS rebinding
            ValidatedHost cached = DNS_CACHE.get(host);
            if (cached != null && !cached.isExpired()) {
                logger.debug("Using cached DNS resolution for: {}", host);
                return cached.addresses;
            }

            // Resolve DNS
            InetAddress[] addresses = InetAddress.getAllByName(host);

            // Validate ALL resolved addresses
            for (InetAddress addr : addresses) {
                if (isBlockedAddress(addr)) {
                    logger.warn("DNS rebinding attempt detected! Host: {} resolved to blocked IP: {}", 
                               host, addr.getHostAddress());
                    throw new UnknownHostException(
                        "DNS resolution returned blocked address: " + addr.getHostAddress());
                }
            }

            // Cache validated result to prevent rebinding
            DNS_CACHE.put(host, new ValidatedHost(addresses));
            logger.debug("DNS resolved and validated: {} -> {}", host, 
                        Arrays.toString(addresses));

            return addresses;
        }
    }

    /**
     * Custom connection socket factory that pins to the validated IP
     * from our DNS resolution - preventing rebinding during connection.
     */
    public static class SsrfSafeConnectionFactory extends PlainConnectionSocketFactory {

        @Override
        public Socket connectSocket(int connectTimeout, Socket socket, 
                HttpHost host, InetSocketAddress remoteAddress, 
                InetSocketAddress localAddress, HttpContext context) throws IOException {

            // Double-check the IP we're actually connecting to
            InetAddress targetIp = remoteAddress.getAddress();
            if (isBlockedAddress(targetIp)) {
                logger.error("Connection blocked to internal IP: {}", 
                           targetIp.getHostAddress());
                throw new IOException("Connection to internal addresses not permitted");
            }

            return super.connectSocket(connectTimeout, socket, host, 
                                       remoteAddress, localAddress, context);
        }
    }

    /**
     * Build a production-ready HTTP client with full SSRF protection.
     */
    public static CloseableHttpClient buildSecureClient() {
        // Custom DNS resolver with validation and caching
        DnsResolver dnsResolver = new SsrfSafeDnsResolver();

        // Custom connection manager with our safe factories
        PoolingHttpClientConnectionManager connManager = 
            new PoolingHttpClientConnectionManager(
                RegistryBuilder.<ConnectionSocketFactory>create()
                    .register("http", new SsrfSafeConnectionFactory())
                    .register("https", SSLConnectionSocketFactory.getSocketFactory())
                    .build(),
                null,  // No connection factory (use registry)
                null,  // No scheme port resolver
                dnsResolver,  // Our safe DNS resolver
                5000,  // Connection time to live
                TimeUnit.MILLISECONDS
            );

        // Request configuration with timeouts
        RequestConfig requestConfig = RequestConfig.custom()
            .setConnectTimeout(3000)
            .setSocketTimeout(5000)
            .setConnectionRequestTimeout(3000)
            .setRedirectsEnabled(false)  // Block redirects
            .setCircularRedirectsAllowed(false)
            .setMaxRedirects(0)
            .build();

        return HttpClients.custom()
            .setConnectionManager(connManager)
            .setDefaultRequestConfig(requestConfig)
            .disableRedirectHandling()  // Explicitly disable redirects
            .setRetryHandler(new DefaultHttpRequestRetryHandler(0, false))  // No retries
            .build();
    }

    /**
     * Validate URL before making request.
     */
    public static void validateUrl(String urlString) throws SecurityException {
        try {
            URL url = new URL(urlString);

            // Protocol check
            if (!"https".equalsIgnoreCase(url.getProtocol())) {
                throw new SecurityException("Only HTTPS URLs are permitted");
            }

            // Port check - only standard ports
            int port = url.getPort();
            if (port != -1 && port != 443) {
                throw new SecurityException("Non-standard ports are not permitted");
            }

            // Domain allowlist check
            String host = url.getHost().toLowerCase();
            boolean allowed = ALLOWED_DOMAINS.stream()
                .anyMatch(domain -> host.equals(domain) || host.endsWith("." + domain));

            if (!allowed) {
                throw new SecurityException("Domain not in allowlist: " + host);
            }

            // Check for IP address in URL (should use domain names only)
            if (isIpAddress(host)) {
                throw new SecurityException("Direct IP addresses are not permitted");
            }

        } catch (MalformedURLException e) {
            throw new SecurityException("Invalid URL format", e);
        }
    }

    private static boolean isBlockedAddress(InetAddress addr) {
        // Check if loopback or site-local
        if (addr.isLoopbackAddress() || addr.isSiteLocalAddress() || 
            addr.isLinkLocalAddress() || addr.isAnyLocalAddress()) {
            return true;
        }

        // Check against explicit blocked ranges
        long ip = ipToLong(addr);
        return BLOCKED_RANGES.stream().anyMatch(range -> range.contains(ip));
    }

    private static boolean isIpAddress(String host) {
        return Pattern.matches(
            "^((25[0-5]|2[0-4][0-9]|[01]?[0-9][0-9]?)\\.){3}(25[0-5]|2[0-4][0-9]|[01]?[0-9][0-9]?)$",
            host);
    }

    private static long ipToLong(InetAddress addr) {
        byte[] octets = addr.getAddress();
        if (octets.length != 4) return -1;  // Not IPv4
        return ((long)(octets[0] & 0xFF) << 24) |
               ((long)(octets[1] & 0xFF) << 16) |
               ((long)(octets[2] & 0xFF) << 8) |
               ((long)(octets[3] & 0xFF));
    }

    // Helper classes
    static class ValidatedHost {
        final InetAddress[] addresses;
        final long expiresAt;

        ValidatedHost(InetAddress[] addresses) {
            this.addresses = addresses;
            this.expiresAt = System.currentTimeMillis() + DNS_CACHE_TTL_MS;
        }

        boolean isExpired() {
            return System.currentTimeMillis() > expiresAt;
        }
    }

    static class IpRange {
        final long start;
        final long end;

        IpRange(String startIp, String endIp) {
            try {
                this.start = ipToLong(InetAddress.getByName(startIp));
                this.end = ipToLong(InetAddress.getByName(endIp));
            } catch (UnknownHostException e) {
                throw new RuntimeException("Invalid IP range", e);
            }
        }

        boolean contains(long ip) {
            return ip >= start && ip <= end;
        }
    }
}
```

**Defense in Depth Layers**:

1. **URL Pre-validation** (before any network activity):
```java
// Block direct IP addresses - force DNS resolution through our resolver
if (isIpAddress(host)) {
    throw new SecurityException("Direct IP addresses are not permitted");
}
```

2. **Custom DNS Resolver with Caching** (prevents rebinding):
```java
// Cache validated DNS results to prevent attacker from changing IP
ValidatedHost cached = DNS_CACHE.get(host);
if (cached != null && !cached.isExpired()) {
    return cached.addresses;  // Use cached, validated IP
}
// Validate all returned IPs BEFORE caching
for (InetAddress addr : addresses) {
    if (isBlockedAddress(addr)) {
        throw new UnknownHostException("Blocked address");
    }
}
DNS_CACHE.put(host, new ValidatedHost(addresses));
```

3. **Connection-time Verification** (final defense):
```java
// Double-check IP at actual connection time
InetAddress targetIp = remoteAddress.getAddress();
if (isBlockedAddress(targetIp)) {
    throw new IOException("Connection blocked");
}
```

**Additional Protections**:

- **Network-level controls**: Configure your cloud VPC/firewall to block outbound traffic to metadata IPs (169.254.169.254) from application servers
- **AWS IMDSv2**: Require token-based access to metadata service, which mitigates SSRF since stolen tokens expire quickly
```java
