  [WORKFLOW_STATES.SHIPPING_ADDED]: [WORKFLOW_STATES.PAYMENT_AUTHORIZED],
  [WORKFLOW_STATES.PAYMENT_AUTHORIZED]: [WORKFLOW_STATES.ORDER_CONFIRMED],
  [WORKFLOW_STATES.ORDER_CONFIRMED]: [] // Terminal state
};

function validateStateTransition(currentState, targetState) {
  const allowedTransitions = VALID_TRANSITIONS[currentState] || [];
  return allowedTransitions.includes(targetState);
}

function generateSecureToken() {
