app.post('/api/checkout/authenticate', (req, res) => {
  try {
    const { sessionId, authToken } = req.body;

    // Verify auth token (integrate with your auth system)
    const userVerified = verifyAuthToken(authToken);
    if (!userVerified) {
      return res.status(401).json({ error: 'Invalid authentication' });
    }

    const session = workflow.transition(
      sessionId,
      'user_authenticated',
      req.clientInfo
    );

    res.json({
      sessionId,
      state: session.state,
      nextSteps: WORKFLOW_CONFIG.transitions[session.state]
    });
  } catch (error) {
    handleWorkflowError(res, error);
  }
});

app.post('/api/checkout/shipping', (req, res) => {
  try {
    const { sessionId, address, method } = req.body;
    const session = workflow.transition(
      sessionId,
