    );

    const orderId = `ORD-${Date.now()}-${crypto.randomBytes(4).toString('hex')}`;

    auditEmitter.emit('workflow_event', {
      event: 'ORDER_CONFIRMED',
      sessionId,
      orderId,
      userId: session.userId,
      totalAmount: session.data.cart.total
    });

    res.json({
      orderId,
      status: 'confirmed',
      workflowHistory: session.stateHistory
    });
  } catch (error) {
    handleWorkflowError(res, error);
  }
});

function handleWorkflowError(res, error) {
  if (error instanceof WorkflowError) {
    const statusCodes = {
      'SESSION_NOT_FOUND': 404,
      'SESSION_EXPIRED': 410,
      'INVALID_TRANSITION': 400
    };
    return res.status(statusCodes[error.code] || 400).json({
      error: error.code,
      message: error.message
    });
  }
  console.error('Unexpected error:', error);
  res.status(500).json({ error: 'Internal server error' });
}

function verifyAuthToken(token) {
