  // Input validation
  if (!username || typeof username !== 'string' || username.length > 100) {
    return res.status(400).json({ error: 'Invalid username' });
  }

  // Create session with JWT (data-only, no code execution possible)
  const token = jwt.sign(
    { username: username.substring(0, 100), role: 'user' },
    JWT_SECRET,
    JWT_OPTIONS
  );

  res.cookie('session', token, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'strict',
    maxAge: 3600000  // 1 hour
  });

  res.json({ success: true });
});

app.listen(3000);
```

**Key Security Controls**:
- **JWT instead of serialization**: JSON Web Tokens only contain data, never executable code
- **Algorithm pinning**: Explicitly specify `HS256` to prevent algorithm confusion attacks
- **Signature verification**: Tokens cannot be tampered with without the secret key
- **Secure cookie flags**: HttpOnly prevents XSS theft, Secure ensures HTTPS-only transmission

When handling complex nested data from external sources, you need a multi-layered defense strategy. The key principle is: **parse data as data, never as code**. Use JSON with strict schema validation, and never use libraries that can execute functions during parsing.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const Ajv = require('ajv');
const addFormats = require('ajv-formats');
const crypto = require('crypto');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();

// Security headers
app.use(helmet());

// Rate limiting
const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,  // 15 minutes
  max: 100,
  message: { error: 'Too many requests' }
});
app.use('/api/', apiLimiter);

// JSON parser with size limits
app.use(express.json({ limit: '100kb' }));

// Schema validator setup
const ajv = new Ajv({
  allErrors: false,       // Don't expose all validation errors
  removeAdditional: true, // Strip unexpected properties
  useDefaults: true,
  coerceTypes: false      // Strict type checking
});
addFormats(ajv);

// Define strict schema for external data
const externalDataSchema = {
  type: 'object',
  required: ['userId', 'payload'],
  properties: {
    userId: {
      type: 'string',
      pattern: '^[a-zA-Z0-9_-]{1,64}$'
    },
    payload: {
      type: 'object',
      properties: {
        items: {
          type: 'array',
          maxItems: 100,
          items: {
            type: 'object',
            properties: {
              id: { type: 'integer', minimum: 0 },
              name: { type: 'string', maxLength: 200 },
              metadata: {
                type: 'object',
                additionalProperties: { type: 'string', maxLength: 500 }
              }
            },
            required: ['id', 'name'],
            additionalProperties: false
          }
        },
        timestamp: { type: 'string', format: 'date-time' }
      },
      additionalProperties: false
    },
    signature: { type: 'string', pattern: '^[a-f0-9]{64}$' }
  },
  additionalProperties: false
};

const validateExternalData = ajv.compile(externalDataSchema);

// Secure data integrity verification
function verifyDataIntegrity(data, signature, secretKey) {
  const expectedSignature = crypto
    .createHmac('sha256', secretKey)
    .update(JSON.stringify(data.payload))
    .digest('hex');

  return crypto.timingSafeEqual(
    Buffer.from(signature),
    Buffer.from(expectedSignature)
  );
}

// Safe JSON parsing with prototype pollution protection
function safeJSONParse(jsonString) {
  const parsed = JSON.parse(jsonString);

  // Recursively sanitize to prevent prototype pollution
  function sanitize(obj) {
    if (obj === null || typeof obj !== 'object') {
      return obj;
    }

    if (Array.isArray(obj)) {
      return obj.map(sanitize);
    }

    const clean = Object.create(null);  // No prototype
    for (const key of Object.keys(obj)) {
      // Block prototype pollution keys
      if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
        continue;
      }
      clean[key] = sanitize(obj[key]);
    }
    return clean;
  }

  return sanitize(parsed);
}

// Audit logging
function auditLog(event, details) {
  const logEntry = {
    timestamp: new Date().toISOString(),
    event: event,
    ...details,
    requestId: crypto.randomUUID()
  };
  console.log(JSON.stringify(logEntry));  // Ship to SIEM in production
}

// API endpoint for external data
app.post('/api/external-data', async (req, res) => {
  const startTime = Date.now();

  try {
    // Layer 1: Safe parsing (already done by express.json, but validate)
    const rawData = safeJSONParse(JSON.stringify(req.body));

    // Layer 2: Schema validation
    const valid = validateExternalData(rawData);
    if (!valid) {
      auditLog('VALIDATION_FAILED', {
        ip: req.ip,
        error: 'Schema validation failed'
      });
      return res.status(400).json({ error: 'Invalid data format' });
    }

    // Layer 3: Integrity verification
    const API_SECRET = process.env.EXTERNAL_API_SECRET;
    if (!verifyDataIntegrity(rawData, rawData.signature, API_SECRET)) {
      auditLog('INTEGRITY_CHECK_FAILED', {
        ip: req.ip,
        userId: rawData.userId
      });
      return res.status(403).json({ error: 'Data integrity check failed' });
    }

    // Layer 4: Process validated data safely
    const result = await processExternalData(rawData);

    auditLog('DATA_PROCESSED', {
      ip: req.ip,
      userId: rawData.userId,
      itemCount: rawData.payload.items?.length || 0,
      processingTime: Date.now() - startTime
    });

    res.json({ success: true, processed: result.count });

  } catch (err) {
    auditLog('PROCESSING_ERROR', {
      ip: req.ip,
      error: err.message
    });

    // Generic error to client, detailed logs for debugging
    res.status(500).json({ error: 'Processing failed' });
  }
});

async function processExternalData(data) {
  // Safe processing - data is now validated and sanitized
  return { count: data.payload.items?.length || 0 };
}

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Safe JSON Parsing with Prototype Pollution Protection**:
```javascript
// Prevent __proto__ and constructor injection
const clean = Object.create(null);  // Object without prototype chain
if (key === '__proto__' || key === 'constructor') continue;
```

2. **Schema Validation with AJV**:
```javascript
// Strict typing, size limits, pattern matching
const schema = {
  additionalProperties: false,  // Reject unexpected fields
  maxItems: 100,                // Prevent DoS via large arrays
  pattern: '^[a-zA-Z0-9_-]+$'   // Whitelist allowed characters
};
```

3. **Cryptographic Integrity Verification**:
```javascript
// HMAC signature with timing-safe comparison
crypto.timingSafeEqual(
  Buffer.from(signature),
  Buffer.from(expectedSignature)
);
```

**Additional Protections**:
- **Size limits**: `express.json({ limit: '100kb' })` prevents memory exhaustion
- **Rate limiting**: Prevents brute force and DoS attacks
- **Audit logging**: Every validation failure logged for incident response
- **Security headers**: Helmet adds CSP, HSTS, X-Frame-Options automatically
- **Timing-safe comparison**: Prevents timing attacks on signature verification
- **No `eval()`, `new Function()`, or `node-serialize`**: Data is never treated as code

