class AdaptiveRateLimiter {
  constructor(redisClient) {
    this.redis = redisClient;
  }

  async checkAndIncrement(key, config) {
    const current = await this.redis.incr(key);
    if (current === 1) {
      await this.redis.pexpire(key, config.windowMs);
    }
    return { current, limit: config.max, remaining: Math.max(0, config.max - current) };
  }

  async isBlocked(key) {
    return await this.redis.get(`blocked:${key}`);
  }

  async block(key, durationMs, reason) {
    await this.redis.setex(`blocked:${key}`, Math.ceil(durationMs / 1000), reason);
  }

  async getDelayMs(failedAttempts) {
    // Progressive delay: 0, 1s, 2s, 4s, 8s, 16s, 30s max
    const delay = Math.min(Math.pow(2, failedAttempts - 1) * 1000, 30000);
    return failedAttempts > 0 ? delay : 0;
  }
}

