    private LoggerInterface $logger;
    private HttpClientInterface $httpClient;
    private string $composerLockPath;
    private array $allowedVulnerabilities = [];

    public function __construct(
        LoggerInterface $logger,
        HttpClientInterface $httpClient,
        string $projectRoot
    ) {
        $this->logger = $logger;
        $this->httpClient = $httpClient;
        $this->composerLockPath = $projectRoot . '/composer.lock';
        $this->loadAllowList($projectRoot . '/security-allowlist.json');
    }

    public function runAudit(): AuditResult {
        $startTime = microtime(true);

        // Run composer audit
        $composerAudit = $this->runComposerAudit();

        // Cross-reference with external vulnerability databases
        $externalVulns = $this->checkExternalDatabases();

        // Merge and deduplicate findings
        $allVulnerabilities = $this->mergeFindings($composerAudit, $externalVulns);

        // Filter out allowed vulnerabilities (with justification)
        $actionableVulns = $this->filterAllowedVulnerabilities($allVulnerabilities);

        // Calculate risk score
        $riskScore = $this->calculateRiskScore($actionableVulns);

        // Log audit results
        $duration = microtime(true) - $startTime;
        $this->logAuditResults($actionableVulns, $riskScore, $duration);

        return new AuditResult(
            vulnerabilities: $actionableVulns,
            riskScore: $riskScore,
            shouldBlock: $riskScore >= self::BLOCK_THRESHOLD,
            duration: $duration
        );
    }

    private function runComposerAudit(): array {
        $output = [];
        $returnCode = 0;

        exec('composer audit --format=json 2>&1', $output, $returnCode);

        $jsonOutput = implode("\n", $output);
        $result = json_decode($jsonOutput, true);

        if (json_last_error() !== JSON_ERROR_NONE) {
            $this->logger->error('Failed to parse composer audit output', [
                'output' => $jsonOutput,
                'error' => json_last_error_msg()
            ]);
            return [];
        }

        return $result['advisories'] ?? [];
    }

    private function checkExternalDatabases(): array {
        $lockContent = json_decode(file_get_contents($this->composerLockPath), true);
        $packages = [];

        foreach ($lockContent['packages'] ?? [] as $package) {
            $packages[] = [
                'name' => $package['name'],
                'version' => $package['version']
            ];
        }

        // Query OSV (Open Source Vulnerabilities) database
        try {
            $response = $this->httpClient->request('POST', 'https://api.osv.dev/v1/querybatch', [
                'json' => [
                    'queries' => array_map(function($pkg) {
                        return [
                            'package' => [
                                'name' => $pkg['name'],
                                'ecosystem' => 'Packagist'
                            ],
                            'version' => $pkg['version']
                        ];
                    }, $packages)
                ]
            ]);

            return json_decode($response->getContent(), true)['results'] ?? [];
        } catch (\Exception $e) {
            $this->logger->warning('External vulnerability check failed', [
                'error' => $e->getMessage()
            ]);
            return [];
        }
    }

    private function calculateRiskScore(array $vulnerabilities): int {
        $maxScore = 0;

        foreach ($vulnerabilities as $vuln) {
            $severity = strtolower($vuln['severity'] ?? 'unknown');
            $score = self::SEVERITY_SCORES[$severity] ?? 0;
            $maxScore = max($maxScore, $score);
        }

        return $maxScore;
    }

    private function filterAllowedVulnerabilities(array $vulns): array {
        return array_filter($vulns, function($vuln) {
            $cve = $vuln['cve'] ?? $vuln['id'] ?? '';

            if (isset($this->allowedVulnerabilities[$cve])) {
                $allowEntry = $this->allowedVulnerabilities[$cve];

                // Check if allowance has expired
                if (strtotime($allowEntry['expires']) < time()) {
                    $this->logger->warning('Vulnerability allowance expired', [
                        'cve' => $cve,
                        'expired' => $allowEntry['expires']
                    ]);
                    return true; // Include in results (allowance expired)
                }

                $this->logger->info('Vulnerability allowed by policy', [
                    'cve' => $cve,
                    'reason' => $allowEntry['reason'],
                    'approved_by' => $allowEntry['approved_by']
                ]);
                return false; // Exclude from results
            }

            return true; // Include in results
        });
    }

    private function logAuditResults(array $vulns, int $riskScore, float $duration): void {
        $this->logger->info('Dependency audit completed', [
            'vulnerability_count' => count($vulns),
            'risk_score' => $riskScore,
            'should_block' => $riskScore >= self::BLOCK_THRESHOLD,
            'duration_seconds' => round($duration, 3),
            'vulnerabilities' => array_map(function($v) {
                return [
                    'package' => $v['package'] ?? 'unknown',
                    'cve' => $v['cve'] ?? $v['id'] ?? 'unknown',
                    'severity' => $v['severity'] ?? 'unknown'
                ];
            }, $vulns)
        ]);
    }

    private function loadAllowList(string $path): void {
        if (file_exists($path)) {
            $content = json_decode(file_get_contents($path), true);
            $this->allowedVulnerabilities = $content['allowed'] ?? [];
        }
    }
}

class AuditResult {
    public function __construct(
        public readonly array $vulnerabilities,
        public readonly int $riskScore,
        public readonly bool $shouldBlock,
        public readonly float $duration
    ) {}

    public function toJson(): string {
        return json_encode([
            'vulnerability_count' => count($this->vulnerabilities),
            'risk_score' => $this->riskScore,
            'should_block' => $this->shouldBlock,
            'duration' => $this->duration,
            'details' => $this->vulnerabilities
        ], JSON_PRETTY_PRINT);
    }
}
```

