const router = express.Router();
const db = require('./database');

// Admin routes - only "hidden" from UI, no server-side checks
router.get('/api/admin/users', async (req, res) => {
  // NO AUTHORIZATION CHECK - Anyone who knows the URL can access
  const users = await db.query('SELECT * FROM users');
  res.json(users);
});

router.delete('/api/admin/users/:id', async (req, res) => {
  // NO AUTHORIZATION CHECK - Any user can delete any account
  await db.query('DELETE FROM users WHERE id = $1', [req.params.id]);
  res.json({ message: 'User deleted' });
});

router.post('/api/admin/config', async (req, res) => {
  // NO AUTHORIZATION CHECK - Anyone can modify system config
  await db.query('UPDATE system_config SET value = $1 WHERE key = $2', 
    [req.body.value, req.body.key]);
  res.json({ message: 'Config updated' });
});

router.get('/api/admin/logs', async (req, res) => {
  // NO AUTHORIZATION CHECK - Exposes sensitive audit logs
  const logs = await db.query('SELECT * FROM audit_logs ORDER BY created_at DESC');
  res.json(logs);
