**Attack Payload**:
```bash
# Attacker discovers admin endpoints through directory fuzzing
curl https://target.com/api/admin/users
# Returns all user data including emails, hashed passwords

# Attacker deletes arbitrary user accounts
curl -X DELETE https://target.com/api/admin/users/1

# Attacker modifies system configuration
curl -X POST https://target.com/api/admin/config \
  -H "Content-Type: application/json" \
  -d '{"key":"password_policy","value":"disabled"}'
```

**Why This Is Dangerous**:
- Any authenticated (or even unauthenticated) user can access admin functions
- Endpoint discovery is trivial via fuzzing tools like ffuf, dirb, or burp
- No audit trail of who performed administrative actions
- Sensitive data exposed without any verification of privilege level

**SECURE VERSION**:

```javascript
const express = require('express');
const router = express.Router();
const db = require('./database');
const jwt = require('jsonwebtoken');

// Authentication middleware - verify JWT token
const authenticate = (req, res, next) => {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = decoded;
    next();
  } catch (err) {
    return res.status(401).json({ error: 'Invalid token' });
  }
};

// Authorization middleware - verify admin role
const requireAdmin = async (req, res, next) => {
  // Always verify role from database, never trust token claims alone
  const result = await db.query(
    'SELECT role FROM users WHERE id = $1 AND is_active = true',
    [req.user.id]
  );

  if (!result.rows[0] || result.rows[0].role !== 'admin') {
    // Log unauthorized access attempt
    console.warn(`Unauthorized admin access attempt by user ${req.user.id} to ${req.path}`);
    return res.status(403).json({ error: 'Admin access required' });
  }

  next();
};

// Apply both middlewares to all admin routes
router.use('/api/admin', authenticate, requireAdmin);

router.get('/api/admin/users', async (req, res) => {
  const users = await db.query('SELECT id, email, role, created_at FROM users');
  res.json(users.rows);
});

router.delete('/api/admin/users/:id', async (req, res) => {
  await db.query('DELETE FROM users WHERE id = $1', [req.params.id]);
  console.info(`Admin ${req.user.id} deleted user ${req.params.id}`);
  res.json({ message: 'User deleted' });
});

module.exports = router;
```

**Key Security Controls**:
- **Authentication middleware**: Verifies user identity via JWT before any route processing
- **Authorization middleware**: Checks admin role from database (not just token) for every admin request
- **Defense in depth**: Multiple layers - authentication, authorization, and audit logging
- **Fail-secure design**: Missing or invalid tokens result in immediate rejection

For granular permissions, you need Role-Based Access Control (RBAC) or Attribute-Based Access Control (ABAC). RBAC assigns permissions to roles, then roles to users. This is essential for principle of least privilege.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const router = express.Router();
const db = require('./database');
const jwt = require('jsonwebtoken');
const rateLimit = require('express-rate-limit');
const { createLogger, transports, format } = require('winston');

// Structured security logging
const securityLogger = createLogger({
  level: 'info',
  format: format.combine(
    format.timestamp(),
    format.json()
  ),
  transports: [
    new transports.File({ filename: 'security-audit.log' }),
    new transports.Console()
  ]
});

// Permission definitions - single source of truth
const PERMISSIONS = {
  USERS_READ: 'users:read',
  USERS_WRITE: 'users:write',
  USERS_DELETE: 'users:delete',
  CONTENT_READ: 'content:read',
  CONTENT_WRITE: 'content:write',
  CONTENT_DELETE: 'content:delete',
  CONFIG_READ: 'config:read',
  CONFIG_WRITE: 'config:write',
  LOGS_READ: 'logs:read'
};

// Role definitions mapping roles to permissions
const ROLES = {
  super_admin: Object.values(PERMISSIONS),
  user_admin: [PERMISSIONS.USERS_READ, PERMISSIONS.USERS_WRITE, PERMISSIONS.USERS_DELETE],
  content_admin: [PERMISSIONS.CONTENT_READ, PERMISSIONS.CONTENT_WRITE, PERMISSIONS.CONTENT_DELETE],
  auditor: [PERMISSIONS.USERS_READ, PERMISSIONS.CONTENT_READ, PERMISSIONS.LOGS_READ],
  viewer: [PERMISSIONS.USERS_READ, PERMISSIONS.CONTENT_READ]
};

// Rate limiter for admin endpoints
const adminLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  message: { error: 'Too many requests, please try again later' },
  standardHeaders: true,
  legacyHeaders: false
});

// Authentication middleware with token validation
const authenticate = async (req, res, next) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  const token = authHeader.split(' ')[1];

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET, {
      algorithms: ['HS256'],
      issuer: process.env.JWT_ISSUER
    });

    // Verify token hasn't been revoked
    const isRevoked = await db.query(
      'SELECT 1 FROM revoked_tokens WHERE token_id = $1',
      [decoded.jti]
    );

    if (isRevoked.rows.length > 0) {
      securityLogger.warn({
        event: 'revoked_token_used',
        tokenId: decoded.jti,
        ip: req.ip
      });
      return res.status(401).json({ error: 'Token has been revoked' });
    }

    req.user = decoded;
    next();
  } catch (err) {
    securityLogger.warn({
      event: 'invalid_token',
      error: err.message,
      ip: req.ip
    });
    return res.status(401).json({ error: 'Invalid or expired token' });
  }
};

// Permission check factory - returns middleware for specific permission
const requirePermission = (...requiredPermissions) => {
  return async (req, res, next) => {
    try {
      // Fetch user's current role from database (not from token)
      const userResult = await db.query(
        'SELECT role, is_active FROM users WHERE id = $1',
        [req.user.id]
      );

      if (!userResult.rows[0] || !userResult.rows[0].is_active) {
        securityLogger.warn({
          event: 'inactive_user_access',
          userId: req.user.id,
          path: req.path,
          ip: req.ip
        });
        return res.status(403).json({ error: 'Account is inactive' });
      }

      const userRole = userResult.rows[0].role;
      const userPermissions = ROLES[userRole] || [];

      // Check if user has ALL required permissions
      const hasPermission = requiredPermissions.every(
        perm => userPermissions.includes(perm)
      );

      if (!hasPermission) {
        securityLogger.warn({
          event: 'unauthorized_access',
          userId: req.user.id,
          userRole: userRole,
          requiredPermissions: requiredPermissions,
          path: req.path,
          method: req.method,
          ip: req.ip
        });
        return res.status(403).json({ error: 'Insufficient permissions' });
      }

      // Attach permissions to request for downstream use
      req.userPermissions = userPermissions;
      req.userRole = userRole;
      next();
    } catch (err) {
      securityLogger.error({
        event: 'permission_check_error',
        error: err.message,
        userId: req.user.id,
        path: req.path
      });
      return res.status(500).json({ error: 'Authorization check failed' });
    }
  };
};

// Apply global middleware to admin routes
router.use('/api/admin', adminLimiter, authenticate);

// User management routes with specific permissions
router.get('/api/admin/users',
  requirePermission(PERMISSIONS.USERS_READ),
  async (req, res) => {
    const users = await db.query(
      'SELECT id, email, role, created_at, last_login FROM users'
    );

    securityLogger.info({
      event: 'users_list_accessed',
      userId: req.user.id,
      userRole: req.userRole,
      ip: req.ip
    });

    res.json(users.rows);
  }
);

router.post('/api/admin/users',
  requirePermission(PERMISSIONS.USERS_WRITE),
  async (req, res) => {
    const { email, role } = req.body;

    // Prevent privilege escalation - can't create user with higher role
    const roleHierarchy = ['viewer', 'content_admin', 'user_admin', 'auditor', 'super_admin'];
    const creatorLevel = roleHierarchy.indexOf(req.userRole);
    const newUserLevel = roleHierarchy.indexOf(role);

    if (newUserLevel >= creatorLevel && req.userRole !== 'super_admin') {
      securityLogger.warn({
        event: 'privilege_escalation_attempt',
        userId: req.user.id,
        attemptedRole: role,
        ip: req.ip
      });
      return res.status(403).json({ error: 'Cannot create user with equal or higher privileges' });
    }

    const result = await db.query(
      'INSERT INTO users (email, role, created_by) VALUES ($1, $2, $3) RETURNING id',
      [email, role, req.user.id]
    );

    securityLogger.info({
      event: 'user_created',
      createdById: req.user.id,
      newUserId: result.rows[0].id,
      newUserRole: role,
      ip: req.ip
    });

    res.status(201).json({ id: result.rows[0].id, message: 'User created' });
  }
);

router.delete('/api/admin/users/:id',
  requirePermission(PERMISSIONS.USERS_DELETE),
  async (req, res) => {
    const targetId = parseInt(req.params.id, 10);

    // Prevent self-deletion
    if (targetId === req.user.id) {
      return res.status(400).json({ error: 'Cannot delete your own account' });
    }

    // Check target user's role to prevent deleting higher-privileged users
    const targetUser = await db.query('SELECT role FROM users WHERE id = $1', [targetId]);
    if (targetUser.rows[0]) {
      const roleHierarchy = ['viewer', 'content_admin', 'user_admin', 'auditor', 'super_admin'];
      if (roleHierarchy.indexOf(targetUser.rows[0].role) >= roleHierarchy.indexOf(req.userRole)) {
        securityLogger.warn({
          event: 'unauthorized_deletion_attempt',
          userId: req.user.id,
          targetId: targetId,
          targetRole: targetUser.rows[0].role,
          ip: req.ip
        });
        return res.status(403).json({ error: 'Cannot delete user with equal or higher privileges' });
      }
    }

    await db.query('DELETE FROM users WHERE id = $1', [targetId]);

    securityLogger.info({
      event: 'user_deleted',
      deletedById: req.user.id,
      deletedUserId: targetId,
      ip: req.ip
    });

    res.json({ message: 'User deleted' });
  }
);

// Audit logs - read only for auditors
router.get('/api/admin/logs',
  requirePermission(PERMISSIONS.LOGS_READ),
  async (req, res) => {
    const logs = await db.query(
      'SELECT * FROM audit_logs ORDER BY created_at DESC LIMIT 1000'
    );
    res.json(logs.rows);
  }
);

module.exports = router;
```

**Defense in Depth Layers**:

1. **Rate Limiting**: Prevents brute force attacks on admin endpoints
```javascript
const adminLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100
});
```

2. **Token Revocation Check**: Prevents use of compromised tokens
```javascript
const isRevoked = await db.query(
  'SELECT 1 FROM revoked_tokens WHERE token_id = $1',
  [decoded.jti]
);
```

3. **Privilege Escalation Prevention**: Users can't grant/affect higher roles
```javascript
if (newUserLevel >= creatorLevel && req.userRole !== 'super_admin') {
  return res.status(403).json({ error: 'Cannot create user with equal or higher privileges' });
}
```

**Additional Protections**:
- **Database-sourced permissions**: Never trust JWT claims alone - always verify current role from database
- **Comprehensive audit logging**: Every admin action logged with user ID, IP, timestamp, and action details
- **Fail-secure error handling**: Permission check failures return 403 without leaking permission details
- **Self-action prevention**: Users cannot delete or demote their own accounts
- **Structured security events**: Use consistent logging format for SIEM integration and alerting

I'll demonstrate XSS vulnerabilities in Spring MVC and secure approaches.

**Vulnerable Code (XSS Risk):**
```java
// Controller
@Controller
public class UserController {

    // DANGEROUS: No sanitization
    @GetMapping("/profile")
    public String showProfile(@RequestParam String name, Model model) {
        model.addAttribute("username", name);  // No escaping
        return "profile";
    }

    // DANGEROUS: Passing raw HTML
    @GetMapping("/comment")
    public String showComment(@RequestParam String comment, Model model) {
        model.addAttribute("commentHtml", comment);  // Raw HTML
        return "comment";
    }
}

// JSP: profile.jsp
// DANGEROUS: Using <%= %> (unescaped output)
<%@ page contentType="text/html;charset=UTF-8" language="java" %>
<html>
<body>
    <h1>Welcome <%= request.getAttribute("username") %></h1>
    <!-- DANGEROUS: Direct output without escaping -->
</body>
</html>

// JSP: comment.jsp
// DANGEROUS: Using c:out with escapeXml="false"
<%@ taglib prefix="c" uri="http://java.sun.com/jsp/jstl/core" %>
<div class="comment">
