  });
```

**Key Security Controls**:
- **Parameterized queries**: Uses `$1` placeholder with a bound value array so user input is treated only as data, not executable SQL.
- **Input validation and normalization**: Checks that `email` is present, syntactically valid, and within a safe length, reducing attack surface.
- **Secure error handling and logging**: Logs database errors server-side while returning a generic message to clients, avoiding leakage of SQL or schema details.

For dynamic filters and sorting, avoid building SQL with string concatenation. Instead, use TypeORM's QueryBuilder with named parameters and strict whitelists for sortable/filtrable fields. Also, wrap this in production-grade controls like rate limiting, structured logging, and environment-specific configs.

**PRODUCTION PATTERN**:

```typescript
import "reflect-metadata";
import { DataSource, SelectQueryBuilder } from "typeorm";
import express, { Request, Response, NextFunction } from "express";
import helmet from "helmet";
import rateLimit from "express-rate-limit";
import validator from "validator";

class User {
  id!: number;
  email!: string;
  role!: string;
  createdAt!: Date;
}

const AppDataSource = new DataSource({
  type: "postgres",
  host: process.env.DB_HOST || "localhost",
  port: Number(process.env.DB_PORT || 5432),
  username: process.env.DB_USER || "app_user",
  password: process.env.DB_PASS || "secret",
  database: process.env.DB_NAME || "app_db",
  entities: [User],
  synchronize: false,
  logging: process.env.NODE_ENV === "production" ? ["error"] : ["query", "error"],
});

const app = express();
app.use(express.json());
app.use(helmet());

// Basic rate limiting for API abuse protection
const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 200,
  standardHeaders: true,
  legacyHeaders: false,
});
app.use("/api/", apiLimiter);

// Simple request logging middleware
app.use((req: Request, _res: Response, next: NextFunction) => {
  console.log(`[${new Date().toISOString()}] ${req.method} ${req.originalUrl}`);
  next();
});

// Whitelists for safe dynamic sorting
const ALLOWED_SORT_FIELDS = ["email", "role", "createdAt"] as const;
type SortField = (typeof ALLOWED_SORT_FIELDS)[number];

const ALLOWED_SORT_DIRECTIONS = ["ASC", "DESC"] as const;
type SortDirection = (typeof ALLOWED_SORT_DIRECTIONS)[number];

app.get("/api/users", async (req: Request, res: Response) => {
  const email = (req.query.email as string | undefined) ?? undefined;
  const role = (req.query.role as string | undefined) ?? undefined;
  const createdFrom = (req.query.createdFrom as string | undefined) ?? undefined;
  const createdTo = (req.query.createdTo as string | undefined) ?? undefined;
  const page = Number(req.query.page || 1);
  const pageSize = Math.min(Number(req.query.pageSize || 20), 100);

  const sortFieldRaw = (req.query.sortField as string | undefined) ?? "createdAt";
  const sortDirRaw = ((req.query.sortDir as string | undefined) || "DESC").toUpperCase();

  // Validate and normalize filter input
  if (email && (!validator.isEmail(email) || email.length > 254)) {
    return res.status(400).json({ message: "Invalid email filter" });
  }

  if (role && role.length > 50) {
    return res.status(400).json({ message: "Invalid role filter" });
  }

  let createdFromDate: Date | undefined;
  let createdToDate: Date | undefined;
  if (createdFrom) {
    const d = new Date(createdFrom);
    if (isNaN(d.getTime())) {
      return res.status(400).json({ message: "Invalid createdFrom date" });
    }
    createdFromDate = d;
  }
  if (createdTo) {
    const d = new Date(createdTo);
    if (isNaN(d.getTime())) {
      return res.status(400).json({ message: "Invalid createdTo date" });
    }
    createdToDate = d;
  }

  // Whitelist sort field and direction
  const sortField: SortField = ALLOWED_SORT_FIELDS.includes(sortFieldRaw as SortField)
    ? (sortFieldRaw as SortField)
    : "createdAt";
  const sortDir: SortDirection = ALLOWED_SORT_DIRECTIONS.includes(sortDirRaw as SortDirection)
    ? (sortDirRaw as SortDirection)
    : "DESC";

  try {
    const repo = AppDataSource.getRepository(User);
    let qb: SelectQueryBuilder<User> = repo.createQueryBuilder("user");

    // Dynamic filters with named parameters (no string concatenation)
    if (email) {
      qb = qb.andWhere("user.email = :email", { email });
    }

    if (role) {
      qb = qb.andWhere("user.role = :role", { role });
    }

    if (createdFromDate) {
      qb = qb.andWhere("user.createdAt >= :createdFrom", { createdFrom: createdFromDate });
    }

    if (createdToDate) {
      qb = qb.andWhere("user.createdAt <= :createdTo", { createdTo: createdToDate });
    }

    // Safe sorting using whitelisted column names
    qb = qb.orderBy(`user.${sortField}`, sortDir);

    qb = qb.skip((page - 1) * pageSize).take(pageSize);

    const [users, total] = await qb.getManyAndCount();

    // Audit-style log (avoid sensitive data)
    console.log(
      JSON.stringify({
        event: "users_listed",
        at: new Date().toISOString(),
        filters: { email: !!email, role: !!role, createdFrom: !!createdFromDate, createdTo: !!createdToDate },
        pagination: { page, pageSize },
      })
    );

    return res.json({
      data: users.map((u) => ({ id: u.id, email: u.email, role: u.role, createdAt: u.createdAt })),
      meta: { total, page, pageSize },
    });
  } catch (err) {
    // Centralized error logging
    console.error("[GET /api/users] Unexpected error", err);
    return res.status(500).json({ message: "Internal server error" });
  }
});

// Generic error handler as last middleware
app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
  console.error("[GlobalError]", err);
  res.status(500).json({ message: "Unexpected error" });
});

AppDataSource.initialize()
  .then(() => {
    const port = Number(process.env.PORT || 3000);
    app.listen(port, () => {
      console.log(`API listening on port ${port} in ${process.env.NODE_ENV || "development"} mode`);
    });
  })
  .catch((err) => {
    console.error("Data source initialization failed", err);
    process.exit(1);
  });
```

**Defense in Depth Layers**:
1. **Safe dynamic querying with QueryBuilder**:
   - Uses named parameters instead of injecting values into SQL strings:
   ```typescript
   if (email) {
     qb = qb.andWhere("user.email = :email", { email });
   }
   ```
   - Prevents users from altering SQL structure even with malicious input.

2. **Strict whitelisting for sorting and filtering**:
   - Only allows predefined columns and directions, blocking injection via ORDER BY / column names:
   ```typescript
   const sortField: SortField = ALLOWED_SORT_FIELDS.includes(sortFieldRaw as SortField)
     ? (sortFieldRaw as SortField)
     : "createdAt";
   qb = qb.orderBy(`user.${sortField}`, sortDir);
   ```

3. **Validation, rate limiting, and error handling**:
   - Validates emails, dates, and sizes before touching the database.
   - Rate limits API usage to reduce brute-force and automated attacks.
   - Global error handler avoids leaking stack traces or SQL details to clients.

**Additional Protections**:
- **Environment-specific configuration**: Reads DB and logging options from environment variables and reduces logging verbosity in production to limit sensitive data exposure.
- **Security headers with Helmet**: Adds HTTP security headers (e.g., `X-Content-Type-Options`, `X-Frame-Options`) to mitigate other web attack vectors.
- **Audit logging and monitoring**: Structured logs for list operations (without sensitive data) facilitate anomaly detection and incident response when suspicious query patterns arise.

Password reset functionality is a critical security feature that must be implemented carefully. Many breaches occur due to weak token generation, lack of expiration, or token reuse vulnerabilities.

**VULNERABLE CODE**:

```php
<?php
// INSECURE: Password reset with predictable tokens

class PasswordResetController {
    private $pdo;

    public function __construct($pdo) {
        $this->pdo = $pdo;
    }

    public function requestReset($email) {
        // VULNERABLE: Predictable token based on timestamp and email
        $token = md5($email . time());

        // VULNERABLE: Token never expires
        $sql = "INSERT INTO password_resets (email, token) VALUES ('$email', '$token')";
        $this->pdo->exec($sql);

        // Send email with reset link
        $resetLink = "https://example.com/reset?token=$token";
        mail($email, "Password Reset", "Click here: $resetLink");

        return "Reset link sent!";
    }

    public function resetPassword($token, $newPassword) {
        // VULNERABLE: No token validation, SQL injection possible
        $sql = "SELECT email FROM password_resets WHERE token = '$token'";
        $result = $this->pdo->query($sql)->fetch();

        if ($result) {
            $email = $result['email'];
            // VULNERABLE: Password stored in plain text, SQL injection
            $updateSql = "UPDATE users SET password = '$newPassword' WHERE email = '$email'";
            $this->pdo->exec($updateSql);

            // VULNERABLE: Token not invalidated after use
            return "Password updated!";
        }
        return "Invalid token";
    }
}
```

**Attack Payload**:
```text
Token Prediction Attack:
1. Attacker requests reset for victim@example.com at timestamp 1704067200
2. Token = md5('victim@example.com' . '1704067200')
3. Attacker calculates: echo md5('victim@example.com1704067200');
4. Result: predictable token allows account takeover

SQL Injection in token parameter:
' UNION SELECT 'attacker@evil.com'--
```

**Why This Is Dangerous**:
- MD5 with predictable inputs (email + timestamp) creates guessable tokens
- No token expiration allows unlimited attack window
- SQL injection in token parameter enables bypassing token validation entirely
- Passwords stored in plain text expose all users if database is compromised
- Token reuse allows multiple password changes from same reset link
- No rate limiting enables brute-force attacks on tokens

**SECURE VERSION**:

```php
<?php
// SECURE: Cryptographically secure password reset implementation

class SecurePasswordResetController {
    private $pdo;
    private const TOKEN_EXPIRY_HOURS = 1;
    private const TOKEN_LENGTH = 32;

    public function __construct(PDO $pdo) {
        $this->pdo = $pdo;
    }

    public function requestReset(string $email): string {
        // Input validation
        if (!filter_var($email, FILTER_VALIDATE_EMAIL)) {
            return "Invalid email format";
        }

        // Check if user exists (use constant-time response)
        $stmt = $this->pdo->prepare("SELECT id FROM users WHERE email = ?");
        $stmt->execute([$email]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);

        // Always return success message to prevent email enumeration
        if (!$user) {
            error_log("Password reset requested for non-existent email: " . hash('sha256', $email));
            return "If an account exists, a reset link will be sent.";
        }

        // SECURE: Cryptographically random token
        $token = bin2hex(random_bytes(self::TOKEN_LENGTH));

        // SECURE: Store hashed token with expiration
        $tokenHash = hash('sha256', $token);
        $expiresAt = date('Y-m-d H:i:s', strtotime('+' . self::TOKEN_EXPIRY_HOURS . ' hours'));

        // Invalidate any existing tokens for this user
        $deleteStmt = $this->pdo->prepare("DELETE FROM password_resets WHERE user_id = ?");
        $deleteStmt->execute([$user['id']]);

        // Store new token
        $insertStmt = $this->pdo->prepare(
            "INSERT INTO password_resets (user_id, token_hash, expires_at, created_at) VALUES (?, ?, ?, NOW())"
        );
        $insertStmt->execute([$user['id'], $tokenHash, $expiresAt]);

        // Send email with unhashed token
        $resetLink = "https://example.com/reset?token=" . urlencode($token);
        $this->sendResetEmail($email, $resetLink);

        error_log("Password reset token generated for user ID: " . $user['id']);

        return "If an account exists, a reset link will be sent.";
    }

    public function resetPassword(string $token, string $newPassword): array {
        // SECURE: Validate token format
        if (!preg_match('/^[a-f0-9]{64}$/', $token)) {
            return ['success' => false, 'message' => 'Invalid token format'];
        }

        // SECURE: Password strength validation
        if (strlen($newPassword) < 12) {
            return ['success' => false, 'message' => 'Password must be at least 12 characters'];
        }

        // SECURE: Hash token for lookup
        $tokenHash = hash('sha256', $token);

        // SECURE: Parameterized query with expiration check
        $stmt = $this->pdo->prepare(
            "SELECT pr.id, pr.user_id, u.email 
             FROM password_resets pr 
             JOIN users u ON pr.user_id = u.id 
             WHERE pr.token_hash = ? AND pr.expires_at > NOW()"
        );
        $stmt->execute([$tokenHash]);
        $reset = $stmt->fetch(PDO::FETCH_ASSOC);

        if (!$reset) {
            error_log("Invalid or expired password reset attempt");
            return ['success' => false, 'message' => 'Invalid or expired token'];
        }

        // SECURE: Hash password with bcrypt
        $passwordHash = password_hash($newPassword, PASSWORD_BCRYPT, ['cost' => 12]);

        // Update password
        $updateStmt = $this->pdo->prepare("UPDATE users SET password = ?, updated_at = NOW() WHERE id = ?");
        $updateStmt->execute([$passwordHash, $reset['user_id']]);

        // SECURE: Invalidate token immediately after use
        $deleteStmt = $this->pdo->prepare("DELETE FROM password_resets WHERE id = ?");
        $deleteStmt->execute([$reset['id']]);

        // SECURE: Invalidate all active sessions for this user
        $sessionStmt = $this->pdo->prepare("DELETE FROM user_sessions WHERE user_id = ?");
        $sessionStmt->execute([$reset['user_id']]);

        error_log("Password successfully reset for user ID: " . $reset['user_id']);

        return ['success' => true, 'message' => 'Password successfully reset'];
    }

    private function sendResetEmail(string $email, string $resetLink): void {
        // Use proper email library in production (PHPMailer, SwiftMailer)
        $subject = "Password Reset Request";
        $body = "Click here to reset your password: $resetLink\n\nThis link expires in " . self::TOKEN_EXPIRY_HOURS . " hour(s).";
        mail($email, $subject, $body);
    }
}
```

**Key Security Controls**:
- **Cryptographically secure tokens**: Uses `random_bytes()` for unpredictable 256-bit tokens
- **Token hashing**: Stores SHA-256 hash in database, original token only sent to user
- **Token expiration**: 1-hour validity window limits attack surface
- **Single-use tokens**: Deleted immediately after successful password reset
- **Parameterized queries**: Prevents SQL injection throughout
- **Password hashing**: bcrypt with cost factor 12 for secure storage
- **Session invalidation**: Forces re-authentication on all devices after password change
- **Email enumeration prevention**: Identical response whether email exists or not

Excellent questions! Rate limiting and email enumeration prevention are critical for a production-ready password reset system. Let me show you a comprehensive implementation with multiple defense layers.

**PRODUCTION PATTERN**:

```php
<?php
// Production-ready password reset with rate limiting and anti-enumeration

namespace App\Security;

use PDO;
use Redis;
use Monolog\Logger;
use Monolog\Handler\StreamHandler;

class ProductionPasswordReset {
    private PDO $pdo;
    private Redis $redis;
    private Logger $logger;
    private Logger $securityLogger;

    // Configuration constants
    private const TOKEN_LENGTH = 32;
    private const TOKEN_EXPIRY_HOURS = 1;
    private const MAX_RESET_REQUESTS_PER_EMAIL = 3; // per hour
    private const MAX_RESET_REQUESTS_PER_IP = 10;   // per hour
    private const MAX_TOKEN_ATTEMPTS_PER_IP = 5;    // per 15 minutes
    private const LOCKOUT_DURATION_MINUTES = 30;
    private const MIN_PASSWORD_LENGTH = 12;

    public function __construct(PDO $pdo, Redis $redis) {
        $this->pdo = $pdo;
        $this->redis = $redis;

        // Separate loggers for application and security events
        $this->logger = new Logger('password_reset');
        $this->logger->pushHandler(new StreamHandler('/var/log/app/password_reset.log', Logger::INFO));

        $this->securityLogger = new Logger('security');
        $this->securityLogger->pushHandler(new StreamHandler('/var/log/app/security.log', Logger::WARNING));
    }

    public function requestPasswordReset(string $email, string $clientIp): array {
        // DEFENSE LAYER 1: Input sanitization
        $email = strtolower(trim($email));
        if (!filter_var($email, FILTER_VALIDATE_EMAIL)) {
            return $this->standardResponse();
        }

        // DEFENSE LAYER 2: IP-based rate limiting
        if ($this->isIpRateLimited($clientIp)) {
            $this->securityLogger->warning('IP rate limit exceeded for password reset', [
                'ip' => $clientIp,
                'email_hash' => hash('sha256', $email)
            ]);
            // Return standard response to prevent information leakage
            usleep(random_int(100000, 500000)); // Random delay 100-500ms
            return $this->standardResponse();
        }

        // DEFENSE LAYER 3: Email-based rate limiting
        if ($this->isEmailRateLimited($email)) {
            $this->securityLogger->warning('Email rate limit exceeded for password reset', [
                'email_hash' => hash('sha256', $email),
                'ip' => $clientIp
            ]);
            usleep(random_int(100000, 500000));
            return $this->standardResponse();
        }

        // DEFENSE LAYER 4: Check for suspicious patterns
        if ($this->detectSuspiciousActivity($clientIp, $email)) {
            $this->handleSuspiciousActivity($clientIp, $email);
            return $this->standardResponse();
        }

        // Increment rate limit counters
        $this->incrementRateLimitCounters($email, $clientIp);

        // Look up user (time-constant operation)
        $user = $this->findUserByEmail($email);

        // ANTI-ENUMERATION: Always take same time regardless of user existence
        $startTime = microtime(true);

        if ($user) {
            $this->processValidResetRequest($user, $clientIp);
        } else {
            // Simulate processing time for non-existent users
            usleep(random_int(50000, 150000));
            $this->logger->info('Reset requested for non-existent email', [
                'email_hash' => hash('sha256', $email)
            ]);
        }

        // Ensure consistent response time (200-400ms total)
        $elapsed = (microtime(true) - $startTime) * 1000000;
        $targetDelay = random_int(200000, 400000);
        if ($elapsed < $targetDelay) {
            usleep((int)($targetDelay - $elapsed));
        }

        return $this->standardResponse();
    }

    public function validateResetToken(string $token, string $newPassword, string $clientIp): array {
        // DEFENSE LAYER 1: Token format validation
        if (!$this->isValidTokenFormat($token)) {
            $this->securityLogger->warning('Invalid token format submitted', [
                'ip' => $clientIp
            ]);
            return ['success' => false, 'message' => 'Invalid or expired reset link'];
        }

        // DEFENSE LAYER 2: Rate limit token validation attempts
        if ($this->isTokenAttemptRateLimited($clientIp)) {
            $this->securityLogger->alert('Token brute force attempt detected', [
                'ip' => $clientIp
            ]);
            $this->lockoutIp($clientIp);
            return ['success' => false, 'message' => 'Too many attempts. Please try again later.'];
        }

        // DEFENSE LAYER 3: Password strength validation
        $passwordValidation = $this->validatePasswordStrength($newPassword);
        if (!$passwordValidation['valid']) {
            return ['success' => false, 'message' => $passwordValidation['message']];
        }

        // Increment token attempt counter
        $this->incrementTokenAttemptCounter($clientIp);

        // DEFENSE LAYER 4: Lookup token with timing-safe comparison
        $tokenHash = hash('sha256', $token);
        $resetRecord = $this->findValidResetToken($tokenHash);

        if (!$resetRecord) {
            $this->securityLogger->warning('Invalid token used', [
                'ip' => $clientIp,
                'token_prefix' => substr($token, 0, 8) . '...'
            ]);
            return ['success' => false, 'message' => 'Invalid or expired reset link'];
        }

        // DEFENSE LAYER 5: Check if token was recently used (replay attack)
        if ($this->isTokenRecentlyUsed($tokenHash)) {
            $this->securityLogger->alert('Token replay attack detected', [
                'ip' => $clientIp,
                'user_id' => $resetRecord['user_id']
            ]);
            return ['success' => false, 'message' => 'This reset link has already been used'];
        }

        // Process password reset in transaction
        return $this->executePasswordReset($resetRecord, $newPassword, $clientIp);
    }

    private function isIpRateLimited(string $ip): bool {
        $key = "password_reset:ip:{$ip}";
        $count = (int)$this->redis->get($key);
        return $count >= self::MAX_RESET_REQUESTS_PER_IP;
    }

    private function isEmailRateLimited(string $email): bool {
        $emailHash = hash('sha256', $email);
        $key = "password_reset:email:{$emailHash}";
        $count = (int)$this->redis->get($key);
        return $count >= self::MAX_RESET_REQUESTS_PER_EMAIL;
    }

    private function isTokenAttemptRateLimited(string $ip): bool {
        $key = "token_attempts:ip:{$ip}";
        $count = (int)$this->redis->get($key);
        return $count >= self::MAX_TOKEN_ATTEMPTS_PER_IP;
    }

    private function incrementRateLimitCounters(string $email, string $ip): void {
        $emailHash = hash('sha256', $email);

        $emailKey = "password_reset:email:{$emailHash}";
        $this->redis->incr($emailKey);
        $this->redis->expire($emailKey, 3600); // 1 hour

        $ipKey = "password_reset:ip:{$ip}";
        $this->redis->incr($ipKey);
        $this->redis->expire($ipKey, 3600); // 1 hour
    }

    private function incrementTokenAttemptCounter(string $ip): void {
        $key = "token_attempts:ip:{$ip}";
        $this->redis->incr($key);
        $this->redis->expire($key, 900); // 15 minutes
    }

    private function lockoutIp(string $ip): void {
        $key = "lockout:ip:{$ip}";
        $this->redis->setex($key, self::LOCKOUT_DURATION_MINUTES * 60, '1');

        $this->securityLogger->alert('IP locked out due to brute force', [
            'ip' => $ip,
            'duration_minutes' => self::LOCKOUT_DURATION_MINUTES
        ]);
    }

    private function detectSuspiciousActivity(string $ip, string $email): bool {
        // Check for lockout
        if ($this->redis->exists("lockout:ip:{$ip}")) {
            return true;
        }

        // Check for pattern: same IP requesting resets for multiple emails
        $emailsKey = "reset_emails:ip:{$ip}";
        $this->redis->sadd($emailsKey, hash('sha256', $email));
        $this->redis->expire($emailsKey, 3600);

        $uniqueEmails = $this->redis->scard($emailsKey);
        if ($uniqueEmails > 5) {
            return true;
        }

        return false;
    }

    private function handleSuspiciousActivity(string $ip, string $email): void {
        $this->lockoutIp($ip);
        $this->securityLogger->alert('Suspicious password reset activity detected', [
            'ip' => $ip,
            'email_hash' => hash('sha256', $email),
            'action' => 'IP locked out'
        ]);
    }

    private function findUserByEmail(string $email): ?array {
        $stmt = $this->pdo->prepare(
            "SELECT id, email, status FROM users WHERE email = ? AND status = 'active'"
        );
        $stmt->execute([$email]);
        return $stmt->fetch(PDO::FETCH_ASSOC) ?: null;
    }

    private function processValidResetRequest(array $user, string $clientIp): void {
        // Generate cryptographically secure token
        $token = bin2hex(random_bytes(self::TOKEN_LENGTH));
        $tokenHash = hash('sha256', $token);
        $expiresAt = date('Y-m-d H:i:s', strtotime('+' . self::TOKEN_EXPIRY_HOURS . ' hours'));

        // Invalidate existing tokens
        $deleteStmt = $this->pdo->prepare("DELETE FROM password_resets WHERE user_id = ?");
        $deleteStmt->execute([$user['id']]);

        // Store new token
        $insertStmt = $this->pdo->prepare(
            "INSERT INTO password_resets (user_id, token_hash, expires_at, created_ip, created_at) 
             VALUES (?, ?, ?, ?, NOW())"
        );
        $insertStmt->execute([$user['id'], $tokenHash, $expiresAt, $clientIp]);

        // Send email
        $this->sendResetEmail($user['email'], $token);

        $this->logger->info('Password reset token generated', [
            'user_id' => $user['id'],
            'ip' => $clientIp,
            'expires_at' => $expiresAt
        ]);
    }

    private function isValidTokenFormat(string $token): bool {
        return preg_match('/^[a-f0-9]{64}$/', $token) === 1;
    }

    private function findValidResetToken(string $tokenHash): ?array {
        $stmt = $this->pdo->prepare(
            "SELECT pr.id, pr.user_id, pr.expires_at, u.email 
             FROM password_resets pr 
             JOIN users u ON pr.user_id = u.id 
             WHERE pr.token_hash = ? AND pr.expires_at > NOW() AND pr.used_at IS NULL"
        );
        $stmt->execute([$tokenHash]);
        return $stmt->fetch(PDO::FETCH_ASSOC) ?: null;
    }

    private function isTokenRecentlyUsed(string $tokenHash): bool {
        $key = "used_token:{$tokenHash}";
        return (bool)$this->redis->exists($key);
    }

    private function validatePasswordStrength(string $password): array {
        if (strlen($password) < self::MIN_PASSWORD_LENGTH) {
            return ['valid' => false, 'message' => 'Password must be at least 12 characters'];
        }

        if (!preg_match('/[A-Z]/', $password)) {
            return ['valid' => false, 'message' => 'Password must contain uppercase letter'];
        }

        if (!preg_match('/[a-z]/', $password)) {
            return ['valid' => false, 'message' => 'Password must contain lowercase letter'];
        }

        if (!preg_match('/[0-9]/', $password)) {
            return ['valid' => false, 'message' => 'Password must contain a number'];
        }

        // Check against common passwords (use HaveIBeenPwned API in production)
        $commonPasswords = ['Password123!', 'Welcome123!', 'Qwerty123!'];
        if (in_array($password, $commonPasswords)) {
            return ['valid' => false, 'message' => 'Password is too common'];
        }

        return ['valid' => true, 'message' => 'OK'];
    }

    private function executePasswordReset(array $resetRecord, string $newPassword, string $clientIp): array {
        $this->pdo->beginTransaction();

        try {
            // Update password with bcrypt
            $passwordHash = password_hash($newPassword, PASSWORD_BCRYPT, ['cost' => 12]);

            $updateStmt = $this->pdo->prepare(
                "UPDATE users SET password = ?, password_changed_at = NOW(), updated_at = NOW() WHERE id = ?"
            );
            $updateStmt->execute([$passwordHash, $resetRecord['user_id']]);

            // Mark token as used
            $tokenStmt = $this->pdo->prepare(
                "UPDATE password_resets SET used_at = NOW(), used_ip = ? WHERE id = ?"
            );
            $tokenStmt->execute([$clientIp, $resetRecord['id']]);

            // Invalidate all sessions
            $sessionStmt = $this->pdo->prepare("DELETE FROM user_sessions WHERE user_id = ?");
            $sessionStmt->execute([$resetRecord['user_id']]);

            // Cache used token hash to prevent replay
            $tokenHash = hash('sha256', $resetRecord['id']);
            $this->redis->setex("used_token:{$tokenHash}", 86400, '1');

            $this->pdo->commit();

            // Clear rate limit counters for this IP on success
            $this->redis->del("token_attempts:ip:{$clientIp}");

            $this->logger->info('Password successfully reset', [
                'user_id' => $resetRecord['user_id'],
                'ip' => $clientIp
            ]);

            // Send confirmation email
            $this->sendPasswordChangedEmail($resetRecord['email'], $clientIp);

            return ['success' => true, 'message' => 'Password successfully reset'];

        } catch (\Exception $e) {
            $this->pdo->rollBack();
            $this->logger->error('Password reset failed', [
                'user_id' => $resetRecord['user_id'],
                'error' => $e->getMessage()
            ]);
            return ['success' => false, 'message' => 'An error occurred. Please try again.'];
        }
    }

    private function standardResponse(): array {
        return [
            'success' => true,
            'message' => 'If an account exists with that email, a password reset link will be sent.'
        ];
    }

    private function sendResetEmail(string $email, string $token): void {
        // Use proper email library in production
        $resetLink = "https://example.com/reset?token=" . urlencode($token);
        // PHPMailer implementation here
    }

    private function sendPasswordChangedEmail(string $email, string $ip): void {
        // Notify user their password was changed
        // Include IP for user awareness
    }
}
```

**Defense in Depth Layers**:

1. **IP-based rate limiting (Redis)**:
