**Why This Is Dangerous**:
- Base64 is encoding, NOT encryption - credentials are transmitted in plaintext equivalent
- Any attacker on the network can sniff and decode credentials in seconds
- No protection against replay attacks - captured credentials work indefinitely
- Hardcoded passwords in source code expose credentials in version control
- Debug mode enabled leaks stack traces and enables code execution

**SECURE VERSION**:

```python
from flask import Flask, request, Response, abort
from werkzeug.security import check_password_hash, generate_password_hash
import os
import logging
from functools import wraps

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY')

# Configure secure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Passwords stored as secure hashes (loaded from secure config)
USERS = {
    "admin": generate_password_hash(os.environ.get('ADMIN_PASSWORD', '')),
    "user": generate_password_hash(os.environ.get('USER_PASSWORD', ''))
}

def check_auth(username, password):
    """Verify credentials using constant-time comparison"""
    if username not in USERS:
        # Prevent timing attacks by still checking a hash
        check_password_hash(generate_password_hash('dummy'), password)
        return False
    return check_password_hash(USERS[username], password)

def requires_auth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        auth = request.authorization
        client_ip = request.environ.get('HTTP_X_FORWARDED_FOR', request.remote_addr)

        if not auth:
            logger.warning(f"Missing auth header from {client_ip}")
            return Response(
                'Authentication required', 401,
                {'WWW-Authenticate': 'Basic realm="Secure API"'}
            )

        if not check_auth(auth.username, auth.password):
            logger.warning(f"Failed login for user '{auth.username}' from {client_ip}")
            return Response('Invalid credentials', 401)

        logger.info(f"Successful auth for '{auth.username}' from {client_ip}")
        return f(*args, **kwargs)
    return decorated

@app.route('/api/data')
@requires_auth
def get_data():
    return {"message": "Hello", "data": "sensitive info"}

if __name__ == '__main__':
    # MUST be deployed behind TLS-terminating reverse proxy
    # or use ssl_context for direct HTTPS
    ssl_context = (
        os.environ.get('SSL_CERT_PATH', 'cert.pem'),
        os.environ.get('SSL_KEY_PATH', 'key.pem')
    )
    app.run(host='0.0.0.0', port=5000, ssl_context=ssl_context, debug=False)
```

**Key Security Controls**:
- **HTTPS/TLS**: Encrypts all traffic including credentials in transit
- **Password hashing**: Uses werkzeug's secure password hashing with salt
- **Constant-time comparison**: Prevents timing attacks on authentication
- **Environment variables**: Credentials never stored in source code
- **Audit logging**: All authentication attempts logged with IP addresses

User registration has a subtle but critical vulnerability: race conditions. When two requests arrive simultaneously trying to register the same username, both might pass the uniqueness check before either completes insertion, creating duplicate accounts.

**VULNERABLE CODE**:

```php
<?php
class UserRegistration {
    private $pdo;

    public function __construct(PDO $pdo) {
        $this->pdo = $pdo;
    }

    public function register(string $username, string $email, string $password): array {
        // VULNERABLE: Check-then-act pattern creates race window
        $stmt = $this->pdo->prepare("SELECT COUNT(*) FROM users WHERE username = ?");
        $stmt->execute([$username]);

        if ($stmt->fetchColumn() > 0) {
            return ['success' => false, 'error' => 'Username already exists'];
        }

        // VULNERABLE: Time gap between check above and insert below
        // Another request could insert the same username here!

        $hashedPassword = password_hash($password, PASSWORD_DEFAULT);

        $insertStmt = $this->pdo->prepare(
            "INSERT INTO users (username, email, password_hash, created_at) VALUES (?, ?, ?, NOW())"
        );

        try {
            $insertStmt->execute([$username, $email, $hashedPassword]);
            return ['success' => true, 'user_id' => $this->pdo->lastInsertId()];
        } catch (PDOException $e) {
            return ['success' => false, 'error' => 'Registration failed'];
        }
    }
}
```

**Attack Payload**:
```bash
# Race condition exploit - send simultaneous requests
for i in {1..10}; do
    curl -X POST http://target.com/register \
        -d "username=victimuser&email=attacker$i@evil.com&password=pass123" &
done
wait
# Result: Multiple accounts created with same username
```

**Why This Is Dangerous**:
- Time-of-check-to-time-of-use (TOCTOU) vulnerability between SELECT and INSERT
- Concurrent requests can both pass the uniqueness check simultaneously
- Database may end up with duplicate usernames if no UNIQUE constraint exists
- Attacker can claim usernames before legitimate users complete registration
- Even with UNIQUE constraint, race creates inconsistent user experience

**SECURE VERSION**:

```php
<?php
class SecureUserRegistration {
    private $pdo;

    public function __construct(PDO $pdo) {
        $this->pdo = $pdo;
        $this->pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
    }

    public function register(string $username, string $email, string $password): array {
        // Input validation first
        if (!$this->validateUsername($username)) {
            return ['success' => false, 'error' => 'Invalid username format'];
        }

        if (!filter_var($email, FILTER_VALIDATE_EMAIL)) {
            return ['success' => false, 'error' => 'Invalid email format'];
        }

        $hashedPassword = password_hash($password, PASSWORD_BCRYPT, ['cost' => 12]);

        // SECURE: Use database UNIQUE constraint as primary defense
        // Attempt INSERT directly - let database enforce uniqueness atomically
        try {
            $stmt = $this->pdo->prepare(
                "INSERT INTO users (username, email, password_hash, created_at) 
                 VALUES (LOWER(?), LOWER(?), ?, NOW())"
            );
            $stmt->execute([$username, $email, $hashedPassword]);

            return [
                'success' => true, 
                'user_id' => $this->pdo->lastInsertId()
            ];

        } catch (PDOException $e) {
            // SECURE: Handle duplicate key violation specifically
            if ($e->getCode() == '23000') { // Integrity constraint violation
                // Determine which field caused the duplicate
                if (strpos($e->getMessage(), 'username') !== false) {
                    return ['success' => false, 'error' => 'Username already exists'];
                }
                if (strpos($e->getMessage(), 'email') !== false) {
                    return ['success' => false, 'error' => 'Email already registered'];
                }
                return ['success' => false, 'error' => 'Account already exists'];
            }

            error_log("Registration error: " . $e->getMessage());
            return ['success' => false, 'error' => 'Registration failed'];
        }
    }

    private function validateUsername(string $username): bool {
        // 3-30 chars, alphanumeric and underscores only
        return preg_match('/^[a-zA-Z0-9_]{3,30}$/', $username) === 1;
    }
}

// Database schema MUST have UNIQUE constraints:
// CREATE UNIQUE INDEX idx_users_username ON users(LOWER(username));
// CREATE UNIQUE INDEX idx_users_email ON users(LOWER(email));
```

**Key Security Controls**:
- **Atomic database constraint**: UNIQUE index enforces uniqueness at database level, eliminating race window
- **INSERT-first pattern**: Attempt insert directly instead of check-then-act
- **Case-insensitive uniqueness**: LOWER() prevents 'Admin' vs 'admin' duplicates
- **Specific error handling**: Catch constraint violations and provide appropriate feedback

Great question! When you need pre-registration validation (invite codes, banned lists), you must use database transactions with proper locking to prevent race conditions while maintaining atomicity.

**PRODUCTION PATTERN**:

```php
<?php
declare(strict_types=1);

class ProductionUserRegistration {
    private PDO $pdo;
    private RateLimiter $rateLimiter;
    private AuditLogger $auditLogger;

    private const MAX_REGISTRATION_ATTEMPTS = 5;
    private const LOCKOUT_DURATION = 900; // 15 minutes

    public function __construct(PDO $pdo, RateLimiter $rateLimiter, AuditLogger $auditLogger) {
        $this->pdo = $pdo;
        $this->pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
        $this->rateLimiter = $rateLimiter;
        $this->auditLogger = $auditLogger;
    }

    public function register(
        string $username, 
        string $email, 
        string $password,
        ?string $inviteCode = null,
        string $clientIp = ''
    ): RegistrationResult {

        // Layer 1: Rate limiting before any database operations
        if (!$this->rateLimiter->checkLimit($clientIp, 'registration', self::MAX_REGISTRATION_ATTEMPTS, self::LOCKOUT_DURATION)) {
            $this->auditLogger->log('registration_rate_limited', [
                'ip' => $clientIp,
                'username_attempted' => $username
            ]);
            return new RegistrationResult(false, 'Too many registration attempts. Please try again later.');
        }

        // Layer 2: Input validation (non-database checks first)
        $validationResult = $this->validateInput($username, $email, $password);
        if (!$validationResult->isValid()) {
            return new RegistrationResult(false, $validationResult->getError());
        }

        // Layer 3: Transaction with advisory lock for complex registration logic
        try {
            $this->pdo->beginTransaction();

            // SECURE: Advisory lock prevents concurrent registration attempts for same username
            // This lock is released when transaction commits/rolls back
            $lockKey = crc32('user_registration_' . strtolower($username));
            $lockStmt = $this->pdo->prepare("SELECT GET_LOCK(?, 5) as lock_acquired");
            $lockStmt->execute([$lockKey]);
            $lockResult = $lockStmt->fetch(PDO::FETCH_ASSOC);

            if ($lockResult['lock_acquired'] !== 1) {
                $this->pdo->rollBack();
                return new RegistrationResult(false, 'Registration temporarily unavailable. Please retry.');
            }

            try {
                // Layer 4: Check banned usernames (within lock)
                if ($this->isUsernameBanned($username)) {
                    $this->releaseLock($lockKey);
                    $this->pdo->rollBack();
                    $this->auditLogger->log('banned_username_attempt', [
                        'username' => $username,
                        'ip' => $clientIp
                    ]);
                    return new RegistrationResult(false, 'This username is not available');
                }

                // Layer 5: Validate and consume invite code atomically
                if ($inviteCode !== null) {
                    $inviteResult = $this->consumeInviteCode($inviteCode, $email);
                    if (!$inviteResult->isValid()) {
                        $this->releaseLock($lockKey);
                        $this->pdo->rollBack();
                        return new RegistrationResult(false, $inviteResult->getError());
                    }
                }

                // Layer 6: Create user with atomic uniqueness enforcement
                $hashedPassword = password_hash($password, PASSWORD_ARGON2ID, [
                    'memory_cost' => 65536,
                    'time_cost' => 4,
                    'threads' => 3
                ]);

                $userId = $this->createUser($username, $email, $hashedPassword, $inviteCode);

                // Layer 7: Create verification token
                $verificationToken = $this->createEmailVerificationToken($userId);

                $this->releaseLock($lockKey);
                $this->pdo->commit();

                // Layer 8: Audit successful registration
                $this->auditLogger->log('user_registered', [
                    'user_id' => $userId,
                    'username' => $username,
                    'ip' => $clientIp,
                    'invite_code_used' => $inviteCode !== null
                ]);

                return new RegistrationResult(true, 'Registration successful', [
                    'user_id' => $userId,
                    'verification_token' => $verificationToken
                ]);

            } catch (PDOException $e) {
                $this->releaseLock($lockKey);
                throw $e;
            }

        } catch (PDOException $e) {
            if ($this->pdo->inTransaction()) {
                $this->pdo->rollBack();
            }

            // Handle duplicate key violations
            if ($e->getCode() == '23000') {
                $errorField = $this->parseConstraintViolation($e->getMessage());
                $this->auditLogger->log('duplicate_registration_attempt', [
                    'field' => $errorField,
                    'ip' => $clientIp
                ]);
                return new RegistrationResult(false, "This {$errorField} is already registered");
            }

            // Log unexpected errors without exposing details
            $this->auditLogger->log('registration_error', [
                'error' => $e->getMessage(),
                'ip' => $clientIp
            ]);

            return new RegistrationResult(false, 'Registration failed. Please try again.');
        }
    }

    private function consumeInviteCode(string $code, string $email): ValidationResult {
        // SECURE: FOR UPDATE locks the row, preventing concurrent use
        $stmt = $this->pdo->prepare(
            "SELECT id, max_uses, current_uses, expires_at, allowed_domain 
             FROM invite_codes 
             WHERE code = ? AND is_active = 1
             FOR UPDATE"
        );
        $stmt->execute([$code]);
        $invite = $stmt->fetch(PDO::FETCH_ASSOC);

        if (!$invite) {
            return new ValidationResult(false, 'Invalid invite code');
        }

        if ($invite['expires_at'] && strtotime($invite['expires_at']) < time()) {
            return new ValidationResult(false, 'Invite code has expired');
        }

        if ($invite['max_uses'] !== null && $invite['current_uses'] >= $invite['max_uses']) {
            return new ValidationResult(false, 'Invite code has reached maximum uses');
        }

        // Check domain restriction
        if ($invite['allowed_domain']) {
            $emailDomain = substr($email, strpos($email, '@') + 1);
            if (strtolower($emailDomain) !== strtolower($invite['allowed_domain'])) {
                return new ValidationResult(false, 'Invite code is restricted to specific email domain');
            }
        }

        // Atomically increment usage counter
        $updateStmt = $this->pdo->prepare(
            "UPDATE invite_codes SET current_uses = current_uses + 1 WHERE id = ?"
        );
        $updateStmt->execute([$invite['id']]);

        return new ValidationResult(true);
    }

    private function isUsernameBanned(string $username): bool {
        $normalizedUsername = strtolower(preg_replace('/[^a-z0-9]/i', '', $username));

        $stmt = $this->pdo->prepare(
            "SELECT 1 FROM banned_usernames WHERE LOWER(pattern) = ? OR ? LIKE pattern LIMIT 1"
        );
        $stmt->execute([$normalizedUsername, $normalizedUsername]);

        return $stmt->fetch() !== false;
    }

    private function createUser(string $username, string $email, string $hashedPassword, ?string $inviteCode): int {
        $stmt = $this->pdo->prepare(
            "INSERT INTO users (username, email, password_hash, invite_code_used, status, created_at) 
             VALUES (LOWER(?), LOWER(?), ?, ?, 'pending_verification', NOW())"
        );
        $stmt->execute([$username, $email, $hashedPassword, $inviteCode]);

        return (int) $this->pdo->lastInsertId();
    }

    private function createEmailVerificationToken(int $userId): string {
        $token = bin2hex(random_bytes(32));
        $hashedToken = hash('sha256', $token);
        $expiresAt = date('Y-m-d H:i:s', strtotime('+24 hours'));

        $stmt = $this->pdo->prepare(
            "INSERT INTO email_verifications (user_id, token_hash, expires_at, created_at)
             VALUES (?, ?, ?, NOW())"
        );
        $stmt->execute([$userId, $hashedToken, $expiresAt]);

        return $token;
    }

    private function validateInput(string $username, string $email, string $password): ValidationResult {
        if (!preg_match('/^[a-zA-Z0-9_]{3,30}$/', $username)) {
            return new ValidationResult(false, 'Username must be 3-30 characters, alphanumeric and underscores only');
        }

        if (!filter_var($email, FILTER_VALIDATE_EMAIL) || strlen($email) > 255) {
            return new ValidationResult(false, 'Invalid email address');
        }

        if (strlen($password) < 12 || strlen($password) > 128) {
            return new ValidationResult(false, 'Password must be 12-128 characters');
        }

        // Check password complexity
        if (!preg_match('/[A-Z]/', $password) || 
            !preg_match('/[a-z]/', $password) || 
            !preg_match('/[0-9]/', $password)) {
            return new ValidationResult(false, 'Password must contain uppercase, lowercase, and numbers');
        }

        return new ValidationResult(true);
    }

    private function releaseLock(int $lockKey): void {
        $this->pdo->prepare("SELECT RELEASE_LOCK(?)")->execute([$lockKey]);
    }

    private function parseConstraintViolation(string $message): string {
        if (stripos($message, 'username') !== false) return 'username';
        if (stripos($message, 'email') !== false) return 'email';
        return 'account';
    }
}

// Supporting classes
class RegistrationResult {
    private bool $success;
    private string $message;
    private array $data;

    public function __construct(bool $success, string $message, array $data = []) {
        $this->success = $success;
        $this->message = $message;
        $this->data = $data;
    }

    public function isSuccess(): bool { return $this->success; }
    public function getMessage(): string { return $this->message; }
    public function getData(): array { return $this->data; }
}

class ValidationResult {
    private bool $valid;
    private string $error;

    public function __construct(bool $valid, string $error = '') {
        $this->valid = $valid;
        $this->error = $error;
    }

    public function isValid(): bool { return $this->valid; }
    public function getError(): string { return $this->error; }
}
