**Additional Protections**:
- **ARGON2ID hashing**: Memory-hard algorithm resistant to GPU attacks
- **Comprehensive audit logging**: Track all registration attempts for security monitoring
- **Constant-time username availability check**: Prevents timing-based username enumeration
- **Email verification**: Pending status until email confirmed prevents account squatting
- **Transaction isolation**: All critical operations within single transaction
- **Graceful error handling**: User-friendly messages without leaking system details

Role-based access control (RBAC) is critical for protecting administrative functions. A common mistake is relying on client-side checks or easily manipulated session data without server-side verification.

**VULNERABLE CODE**:

```php
<?php
// Vulnerable admin controller - trusts user input for role
class AdminController {
    private $pdo;

    public function __construct($pdo) {
        $this->pdo = $pdo;
    }

    // DANGEROUS: Role checked from session without verification
    public function updateUserRole() {
        session_start();

        // Vulnerable: trusts session role without database verification
        if ($_SESSION['role'] !== 'admin') {
            header('Location: /unauthorized.php');
            exit;
        }

        $userId = $_POST['user_id'];
        $newRole = $_POST['role']; // User-controlled input!

        // CRITICAL FLAW: No validation on role value
        $sql = "UPDATE users SET role = ? WHERE id = ?";
        $stmt = $this->pdo->prepare($sql);
        $stmt->execute([$newRole, $userId]);

        echo json_encode(['success' => true]);
    }

    // DANGEROUS: Allows users to update their own profile including role
    public function updateProfile() {
        session_start();
        $userId = $_SESSION['user_id'];

        // Mass assignment vulnerability - accepts any field from POST
        $fields = [];
        $values = [];
        foreach ($_POST as $key => $value) {
            $fields[] = "$key = ?";
            $values[] = $value;
        }
        $values[] = $userId;

        $sql = "UPDATE users SET " . implode(', ', $fields) . " WHERE id = ?";
        $stmt = $this->pdo->prepare($sql);
        $stmt->execute($values);
    }
}
?>
```

**Attack Payload**:
```bash
# Privilege escalation via profile update
curl -X POST https://target.com/profile/update \
  -H "Cookie: PHPSESSID=user_session_here" \
  -d "name=John&email=john@example.com&role=admin"

# Direct role manipulation
curl -X POST https://target.com/admin/updateRole \
  -H "Cookie: PHPSESSID=compromised_admin_session" \
  -d "user_id=attacker_id&role=superadmin"
```

**Why This Is Dangerous**:
- Session role can be manipulated if session fixation or hijacking occurs
- Mass assignment allows users to set their own role field
- No whitelist validation on which roles can be assigned
- No verification that the current user has permission to assign specific roles
- Missing audit logging of privilege changes

**SECURE VERSION**:

```php
<?php
class SecureAdminController {
    private $pdo;
    private const VALID_ROLES = ['user', 'moderator', 'admin'];
    private const ROLE_HIERARCHY = [
        'user' => 0,
        'moderator' => 1,
        'admin' => 2,
        'superadmin' => 3
    ];

    public function __construct($pdo) {
        $this->pdo = $pdo;
    }

    // Verify role from database, not session alone
    private function verifyUserRole(int $userId): ?string {
        $stmt = $this->pdo->prepare(
            "SELECT role FROM users WHERE id = ? AND active = 1"
        );
        $stmt->execute([$userId]);
        $result = $stmt->fetch(PDO::FETCH_ASSOC);
        return $result ? $result['role'] : null;
    }

    // Check if current user can assign target role
    private function canAssignRole(string $currentRole, string $targetRole): bool {
        $currentLevel = self::ROLE_HIERARCHY[$currentRole] ?? 0;
        $targetLevel = self::ROLE_HIERARCHY[$targetRole] ?? PHP_INT_MAX;

        // Users can only assign roles below their own level
        return $currentLevel > $targetLevel;
    }

    public function updateUserRole(): void {
        session_start();

        // CSRF protection
        if (!$this->validateCsrfToken($_POST['csrf_token'] ?? '')) {
            http_response_code(403);
            echo json_encode(['error' => 'Invalid CSRF token']);
            exit;
        }

        $currentUserId = filter_var($_SESSION['user_id'], FILTER_VALIDATE_INT);
        if (!$currentUserId) {
            http_response_code(401);
            exit;
        }

        // CRITICAL: Verify role from database, not session
        $currentUserRole = $this->verifyUserRole($currentUserId);
        if (!$currentUserRole || $currentUserRole !== 'admin') {
            $this->logSecurityEvent('privilege_escalation_attempt', [
                'user_id' => $currentUserId,
                'session_role' => $_SESSION['role'] ?? 'unknown',
                'db_role' => $currentUserRole,
                'ip' => $_SERVER['REMOTE_ADDR']
            ]);
            http_response_code(403);
            echo json_encode(['error' => 'Insufficient privileges']);
            exit;
        }

        // Validate input
        $targetUserId = filter_var($_POST['user_id'], FILTER_VALIDATE_INT);
        $newRole = $_POST['role'] ?? '';

        if (!$targetUserId || !in_array($newRole, self::VALID_ROLES, true)) {
            http_response_code(400);
            echo json_encode(['error' => 'Invalid parameters']);
            exit;
        }

        // Prevent assigning roles equal to or above own level
        if (!$this->canAssignRole($currentUserRole, $newRole)) {
            $this->logSecurityEvent('role_assignment_denied', [
                'admin_id' => $currentUserId,
                'target_user' => $targetUserId,
                'attempted_role' => $newRole
            ]);
            http_response_code(403);
            echo json_encode(['error' => 'Cannot assign this role level']);
            exit;
        }

        // Perform update with audit trail
        $this->pdo->beginTransaction();
        try {
            // Log the change before making it
            $this->logRoleChange($currentUserId, $targetUserId, $newRole);

            $stmt = $this->pdo->prepare(
                "UPDATE users SET role = ?, updated_at = NOW(), updated_by = ? WHERE id = ?"
            );
            $stmt->execute([$newRole, $currentUserId, $targetUserId]);

            $this->pdo->commit();
            echo json_encode(['success' => true]);
        } catch (Exception $e) {
            $this->pdo->rollBack();
            error_log("Role update failed: " . $e->getMessage());
            http_response_code(500);
            echo json_encode(['error' => 'Update failed']);
        }
    }

    // Safe profile update with whitelist
    public function updateProfile(): void {
        session_start();

        // WHITELIST of allowed fields - role is NOT included
        $allowedFields = ['name', 'email', 'phone', 'timezone'];

        $userId = filter_var($_SESSION['user_id'], FILTER_VALIDATE_INT);
        if (!$userId) {
            http_response_code(401);
            exit;
        }

        $fields = [];
        $values = [];

        foreach ($_POST as $key => $value) {
            // Only process whitelisted fields
            if (in_array($key, $allowedFields, true)) {
                $fields[] = "$key = ?";
                $values[] = htmlspecialchars($value, ENT_QUOTES, 'UTF-8');
            }
        }

        if (empty($fields)) {
            http_response_code(400);
            echo json_encode(['error' => 'No valid fields to update']);
            exit;
        }

        $values[] = $userId;
        $sql = "UPDATE users SET " . implode(', ', $fields) . ", updated_at = NOW() WHERE id = ?";
        $stmt = $this->pdo->prepare($sql);
        $stmt->execute($values);

        echo json_encode(['success' => true]);
    }

    private function validateCsrfToken(string $token): bool {
        return hash_equals($_SESSION['csrf_token'] ?? '', $token);
    }

    private function logSecurityEvent(string $event, array $data): void {
        error_log(json_encode([
            'event' => $event,
            'timestamp' => date('c'),
            'data' => $data
        ]));
    }

    private function logRoleChange(int $adminId, int $targetId, string $newRole): void {
        $stmt = $this->pdo->prepare(
            "INSERT INTO role_audit_log (admin_id, target_user_id, new_role, changed_at, ip_address) 
             VALUES (?, ?, ?, NOW(), ?)"
        );
        $stmt->execute([$adminId, $targetId, $newRole, $_SERVER['REMOTE_ADDR']]);
    }
}
?>
```

**Key Security Controls**:
- **Database role verification**: Always verify roles from the database, never trust session data alone for critical operations
- **Field whitelist**: Explicitly whitelist allowed fields for mass updates, preventing role injection
- **Role hierarchy enforcement**: Users can only assign roles below their own privilege level
- **CSRF protection**: Prevents attackers from tricking admins into making unauthorized role changes
- **Comprehensive audit logging**: All privilege changes are logged with who, what, when, and from where

API protection requires a centralized authorization layer that works consistently across all authentication methods. The key is to never scatter authorization checks throughout your codebase - use middleware that enforces permissions at every entry point.

**PRODUCTION PATTERN**:

```php
<?php
// config/authorization.php - Centralized permission definitions
return [
    'permissions' => [
        'users.view' => ['user', 'moderator', 'admin'],
        'users.create' => ['moderator', 'admin'],
        'users.update' => ['moderator', 'admin'],
        'users.delete' => ['admin'],
        'users.update_role' => ['admin'],
        'settings.view' => ['admin'],
        'settings.modify' => ['admin'],
        'reports.view' => ['moderator', 'admin'],
        'reports.export' => ['admin'],
    ],
    'role_hierarchy' => [
        'user' => 1,
        'moderator' => 2,
        'admin' => 3,
        'superadmin' => 4,
    ],
];
?>
```

```php
<?php
// middleware/AuthorizationMiddleware.php
namespace App\Middleware;

use App\Services\AuthService;
use App\Services\AuditLogger;
use App\Exceptions\UnauthorizedException;
use App\Exceptions\ForbiddenException;

class AuthorizationMiddleware {
    private $authService;
    private $auditLogger;
    private $config;
    private $pdo;

    public function __construct(
        AuthService $authService,
        AuditLogger $auditLogger,
        array $config,
        \PDO $pdo
    ) {
        $this->authService = $authService;
        $this->auditLogger = $auditLogger;
        $this->config = $config;
        $this->pdo = $pdo;
    }

    public function handle(array $request, string $requiredPermission, callable $next) {
        // Step 1: Extract and validate authentication
        $authResult = $this->authenticate($request);

        if (!$authResult['authenticated']) {
            $this->auditLogger->logSecurityEvent('auth_failure', [
                'reason' => $authResult['reason'],
                'ip' => $request['ip'] ?? 'unknown',
                'user_agent' => $request['headers']['User-Agent'] ?? 'unknown',
                'endpoint' => $request['uri'] ?? 'unknown'
            ]);
            throw new UnauthorizedException('Authentication required');
        }

        $userId = $authResult['user_id'];
        $authMethod = $authResult['method']; // 'session', 'jwt', 'api_key'

        // Step 2: CRITICAL - Verify role from database regardless of auth method
        $userRole = $this->getVerifiedRole($userId);

        if (!$userRole) {
            $this->auditLogger->logSecurityEvent('role_verification_failed', [
                'user_id' => $userId,
                'auth_method' => $authMethod
            ]);
            throw new UnauthorizedException('Account not found or inactive');
        }

        // Step 3: Check if role has required permission
        if (!$this->hasPermission($userRole, $requiredPermission)) {
            $this->auditLogger->logSecurityEvent('privilege_escalation_attempt', [
                'user_id' => $userId,
                'role' => $userRole,
                'required_permission' => $requiredPermission,
                'auth_method' => $authMethod,
                'ip' => $request['ip'],
                'endpoint' => $request['uri'],
                'request_body' => $this->sanitizeForLog($request['body'] ?? [])
            ]);
            throw new ForbiddenException('Insufficient privileges');
        }

        // Step 4: Add verified context to request
        $request['auth_context'] = [
            'user_id' => $userId,
            'role' => $userRole,
            'auth_method' => $authMethod,
            'permissions' => $this->getRolePermissions($userRole),
            'verified_at' => time()
        ];

        // Step 5: Log successful authorization for audit trail
        $this->auditLogger->logAccess([
            'user_id' => $userId,
            'permission' => $requiredPermission,
            'endpoint' => $request['uri'],
            'method' => $request['method']
        ]);

        return $next($request);
    }

    private function authenticate(array $request): array {
        // Try JWT first (API clients)
        $authHeader = $request['headers']['Authorization'] ?? '';

        if (preg_match('/^Bearer\s+(.+)$/i', $authHeader, $matches)) {
            $token = $matches[1];
            $result = $this->authService->validateJwt($token);

            if ($result['valid']) {
                // CRITICAL: Don't trust role from JWT, we'll verify from DB
                return [
                    'authenticated' => true,
                    'user_id' => $result['user_id'],
                    'method' => 'jwt'
                ];
            }
            return ['authenticated' => false, 'reason' => 'invalid_jwt'];
        }

        // Try API key (service accounts)
        $apiKey = $request['headers']['X-API-Key'] ?? '';
        if ($apiKey) {
            $result = $this->authService->validateApiKey($apiKey);
            if ($result['valid']) {
                return [
                    'authenticated' => true,
                    'user_id' => $result['service_account_id'],
                    'method' => 'api_key'
                ];
            }
            return ['authenticated' => false, 'reason' => 'invalid_api_key'];
        }

        // Try session (web clients)
        if (session_status() === PHP_SESSION_NONE) {
            session_start();
        }

        if (isset($_SESSION['user_id']) && isset($_SESSION['auth_fingerprint'])) {
            // Verify session fingerprint to prevent session hijacking
            $expectedFingerprint = $this->generateSessionFingerprint($request);
            if (hash_equals($_SESSION['auth_fingerprint'], $expectedFingerprint)) {
                return [
                    'authenticated' => true,
                    'user_id' => $_SESSION['user_id'],
                    'method' => 'session'
                ];
            }
            return ['authenticated' => false, 'reason' => 'session_fingerprint_mismatch'];
        }

        return ['authenticated' => false, 'reason' => 'no_credentials'];
    }

    // CRITICAL: Always verify role from authoritative source
    private function getVerifiedRole(int $userId): ?string {
        $stmt = $this->pdo->prepare(
            "SELECT role FROM users 
             WHERE id = ? 
             AND active = 1 
             AND (locked_until IS NULL OR locked_until < NOW())
             AND deleted_at IS NULL"
        );
        $stmt->execute([$userId]);
        $result = $stmt->fetch(\PDO::FETCH_ASSOC);

        return $result ? $result['role'] : null;
    }

    private function hasPermission(string $role, string $permission): bool {
        $allowedRoles = $this->config['permissions'][$permission] ?? [];
        return in_array($role, $allowedRoles, true);
    }

    private function getRolePermissions(string $role): array {
        $permissions = [];
        foreach ($this->config['permissions'] as $perm => $roles) {
            if (in_array($role, $roles, true)) {
                $permissions[] = $perm;
            }
        }
        return $permissions;
    }

    private function generateSessionFingerprint(array $request): string {
        return hash('sha256', 
            ($request['ip'] ?? '') . 
            ($request['headers']['User-Agent'] ?? '')
        );
    }

    private function sanitizeForLog(array $data): array {
        $sensitive = ['password', 'token', 'secret', 'api_key', 'credit_card'];
        foreach ($data as $key => $value) {
            if (in_array(strtolower($key), $sensitive, true)) {
                $data[$key] = '[REDACTED]';
            }
        }
        return $data;
    }
}
?>
