<?php
// controllers/ApiController.php - Using the middleware
namespace App\Controllers;

use App\Middleware\AuthorizationMiddleware;

class UserApiController {
    private $authMiddleware;
    private $pdo;

    public function __construct(AuthorizationMiddleware $authMiddleware, \PDO $pdo) {
        $this->authMiddleware = $authMiddleware;
        $this->pdo = $pdo;
    }

    public function updateUserRole(array $request): array {
        // Middleware enforces permission check BEFORE any logic runs
        return $this->authMiddleware->handle(
            $request,
            'users.update_role',  // Required permission
            function($request) {
                return $this->performRoleUpdate($request);
            }
        );
    }

    private function performRoleUpdate(array $request): array {
        $authContext = $request['auth_context'];
        $currentUserId = $authContext['user_id'];
        $currentRole = $authContext['role'];

        // Additional business logic validation
        $targetUserId = filter_var(
            $request['body']['user_id'] ?? null,
            FILTER_VALIDATE_INT
        );
        $newRole = $request['body']['role'] ?? '';

        // Validate target role is in allowed list
        $allowedRoles = ['user', 'moderator', 'admin'];
        if (!in_array($newRole, $allowedRoles, true)) {
            return ['error' => 'Invalid role', 'code' => 400];
        }

        // Prevent assigning roles at or above own level
        $roleHierarchy = ['user' => 1, 'moderator' => 2, 'admin' => 3, 'superadmin' => 4];
        if (($roleHierarchy[$newRole] ?? 0) >= ($roleHierarchy[$currentRole] ?? 0)) {
            return ['error' => 'Cannot assign role at or above your level', 'code' => 403];
        }

        // Prevent self-modification of role
        if ($targetUserId === $currentUserId) {
            return ['error' => 'Cannot modify own role', 'code' => 403];
        }

        // Perform update
        $stmt = $this->pdo->prepare(
            "UPDATE users SET role = ?, updated_by = ?, updated_at = NOW() WHERE id = ?"
        );
        $stmt->execute([$newRole, $currentUserId, $targetUserId]);

        return ['success' => true, 'message' => 'Role updated'];
    }
}
