// Behavioral analysis configuration
const DETECTION_CONFIG = {
  // Immediate alerts
  immediate: {
    failedLoginsPerUser: 5,
    failedLoginsPerIP: 15,
    timeWindowSeconds: 300
  },
  // Slow attack detection (credential stuffing)
