class SecurityAlertSystem {
  constructor() {
    this.alertChannels = {
      slack: process.env.SLACK_SECURITY_CHANNEL,
      pagerduty: process.env.PAGERDUTY_ROUTING_KEY,
      webhook: process.env.SIEM_WEBHOOK_URL
    };
