  async trackLoginAttempt(event) {
    const { username, ip, success, userAgent, timestamp } = event;

    // Store detailed event for analysis
    const eventId = crypto.randomUUID();
    const eventData = JSON.stringify({
      eventId,
      username: this.hashUsername(username),
      ip,
      success,
      userAgentHash: this.hashUserAgent(userAgent),
      timestamp,
      hour: new Date(timestamp).getHours()
    });

    // Add to time-series for analysis
    await redis.zadd('login:events', Date.now(), eventData);
    await redis.expire('login:events', 86400); // 24 hour retention

    if (!success) {
      await this.analyzeFailedAttempt(event);
    } else {
      await this.checkSuccessfulLoginAnomalies(event);
    }
  }

  async analyzeFailedAttempt(event) {
    const { username, ip, userAgent, timestamp } = event;
    const alerts = [];

    // 1. Immediate threshold checks
    const userFailures = await this.incrementCounter(`failed:user:${username}`, 
      DETECTION_CONFIG.immediate.timeWindowSeconds);
    const ipFailures = await this.incrementCounter(`failed:ip:${ip}`, 
      DETECTION_CONFIG.immediate.timeWindowSeconds);

    if (userFailures >= DETECTION_CONFIG.immediate.failedLoginsPerUser) {
      alerts.push({
        type: 'BRUTE_FORCE_USER',
        severity: 'HIGH',
        details: { username, attempts: userFailures, ip }
      });
    }

    if (ipFailures >= DETECTION_CONFIG.immediate.failedLoginsPerIP) {
      alerts.push({
        type: 'BRUTE_FORCE_IP',
        severity: 'HIGH',
        details: { ip, attempts: ipFailures }
      });
    }

    // 2. Credential stuffing detection (many users from one IP)
    await redis.sadd(`ip:users:${ip}`, username);
    await redis.expire(`ip:users:${ip}`, DETECTION_CONFIG.slowAttack.timeWindowHours * 3600);
    const uniqueUsers = await redis.scard(`ip:users:${ip}`);

    if (uniqueUsers >= DETECTION_CONFIG.slowAttack.uniqueUsersFromIP) {
      alerts.push({
        type: 'CREDENTIAL_STUFFING',
        severity: 'CRITICAL',
        details: { ip, uniqueUsers, timeWindow: '1 hour' }
      });
    }

    // 3. Distributed attack detection (many IPs targeting one user)
    await redis.sadd(`user:ips:${username}`, ip);
    await redis.expire(`user:ips:${username}`, 3600);
    const uniqueIPs = await redis.scard(`user:ips:${username}`);

