    const lastLogin = await redis.hgetall(`user:lastlogin:${username}`);

    if (lastLogin.ip && lastLogin.ip !== ip) {
      // Check for impossible travel
      const lastGeo = await this.getGeoLocation(lastLogin.ip);
      const currentGeo = await this.getGeoLocation(ip);

      if (lastGeo && currentGeo) {
        const distance = this.calculateDistance(lastGeo, currentGeo);
        const timeDiff = (Date.now() - parseInt(lastLogin.timestamp)) / 3600000; // hours
