    } catch (error) {
      logger.error('Failed to send Slack alert', { error: error.message });
    }
  }

  async sendToSIEM(alert) {
    try {
      await axios.post(this.alertChannels.webhook, {
        timestamp: new Date().toISOString(),
        source: 'auth-service',
        ...alert
      }, {
        timeout: 5000,
        headers: { 'Authorization': `Bearer ${process.env.SIEM_API_KEY}` }
      });
    } catch (error) {
      logger.error('Failed to send SIEM alert', { error: error.message });
    }
  }

  async triggerPagerDuty(alert) {
    try {
      await axios.post('https://events.pagerduty.com/v2/enqueue', {
        routing_key: this.alertChannels.pagerduty,
        event_action: 'trigger',
        payload: {
          summary: `${alert.type}: ${JSON.stringify(alert.details)}`,
          severity: alert.severity.toLowerCase(),
          source: 'auth-service',
          custom_details: alert.details
        }
      });
    } catch (error) {
      logger.error('Failed to trigger PagerDuty', { error: error.message });
    }
  }

  async incrementCounter(key, ttl) {
    const count = await redis.incr(key);
    await redis.expire(key, ttl);
    return count;
  }

  hashUsername(username) {
    return crypto.createHash('sha256').update(username).digest('hex').substring(0, 16);
  }

  hashUserAgent(userAgent) {
    return crypto.createHash('sha256').update(userAgent || '').digest('hex').substring(0, 8);
  }

  async getGeoLocation(ip) {
    // Use IP geolocation service
    try {
      const response = await axios.get(`https://ipapi.co/${ip}/json/`, { timeout: 2000 });
      return { lat: response.data.latitude, lon: response.data.longitude };
    } catch {
      return null;
    }
  }

  calculateDistance(geo1, geo2) {
    // Haversine formula
    const R = 6371; // Earth's radius in km
    const dLat = (geo2.lat - geo1.lat) * Math.PI / 180;
    const dLon = (geo2.lon - geo1.lon) * Math.PI / 180;
    const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
              Math.cos(geo1.lat * Math.PI / 180) * Math.cos(geo2.lat * Math.PI / 180) *
              Math.sin(dLon/2) * Math.sin(dLon/2);
    return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  }
}

