**PRODUCTION PATTERN**:

```javascript
const { app, autoUpdater, dialog } = require('electron');
const crypto = require('crypto');
const fs = require('fs');
const path = require('path');
const https = require('https');
const { createLogger, transports, format } = require('winston');

// Security-focused logger
const securityLogger = createLogger({
  level: 'info',
  format: format.combine(
    format.timestamp(),
    format.json()
  ),
  transports: [
    new transports.File({ filename: 'security-audit.log' }),
    new transports.Console()
  ]
});

class SecureElectronUpdater {
  constructor() {
    // PUBLIC KEY embedded at build time - NEVER include private key
    this.UPDATE_PUBLIC_KEY = process.env.UPDATE_PUBLIC_KEY || `-----BEGIN PUBLIC KEY-----
MIIBIjANBgkqhkiG9w0BAQEFAAOCAQ8AMIIBCgKCAQEA...
-----END PUBLIC KEY-----`;

    // Pinned certificate fingerprints (rotate quarterly)
    this.PINNED_CERTS = [
      'sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=',
      'sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=' // Backup
    ];

    this.UPDATE_SERVER = 'https://updates.myapp.com';
    this.ALLOWED_SIGNERS = ['release-signing-key-2024'];
    this.updateInProgress = false;
  }

  async initialize() {
    // Verify app integrity on startup
    await this.verifySelfIntegrity();

    // Configure electron-updater with security settings
    if (process.platform === 'darwin') {
      autoUpdater.setFeedURL({
        url: `${this.UPDATE_SERVER}/darwin`,
        serverType: 'json'
      });
    } else {
      autoUpdater.setFeedURL({
        url: `${this.UPDATE_SERVER}/win32`,
        serverType: 'default'
      });
    }

    this.setupEventHandlers();
  }

  async verifySelfIntegrity() {
    // Verify the running application hasn't been tampered with
    const appPath = app.getAppPath();
    const integrityFile = path.join(appPath, '.integrity');

    if (!fs.existsSync(integrityFile)) {
      securityLogger.warn('Integrity file missing - first run or tampering', {
        event: 'INTEGRITY_CHECK_SKIP',
        appPath
      });
      return;
    }

    try {
      const integrityData = JSON.parse(fs.readFileSync(integrityFile, 'utf8'));
      const criticalFiles = ['main.js', 'preload.js', 'renderer.js'];

      for (const file of criticalFiles) {
        const filePath = path.join(appPath, file);
        if (fs.existsSync(filePath)) {
          const content = fs.readFileSync(filePath);
          const hash = crypto.createHash('sha256').update(content).digest('hex');

          if (integrityData.files[file] !== hash) {
            securityLogger.error('File integrity check failed', {
              event: 'INTEGRITY_FAILURE',
              file,
              expected: integrityData.files[file],
              actual: hash
            });
            throw new Error(`Integrity check failed for ${file}`);
          }
        }
      }

      securityLogger.info('Application integrity verified', {
        event: 'INTEGRITY_VERIFIED'
      });
    } catch (error) {
      securityLogger.error('Integrity verification error', {
        event: 'INTEGRITY_ERROR',
        error: error.message
      });
      // In production, you might want to exit or alert the user
      dialog.showErrorBox('Security Alert', 'Application integrity check failed');
    }
  }

  verifyUpdateSignature(updateManifest, signature) {
    try {
      // Verify signature using embedded public key
      const verify = crypto.createVerify('RSA-SHA512');
      verify.update(JSON.stringify(updateManifest));
      verify.end();

      const isValid = verify.verify(this.UPDATE_PUBLIC_KEY, signature, 'base64');

      securityLogger.info('Update signature verification', {
        event: 'SIGNATURE_VERIFICATION',
        result: isValid ? 'VALID' : 'INVALID',
        version: updateManifest.version
      });

      return isValid;
    } catch (error) {
      securityLogger.error('Signature verification error', {
        event: 'SIGNATURE_ERROR',
        error: error.message
      });
      return false;
    }
  }

  async fetchUpdateManifest() {
    return new Promise((resolve, reject) => {
      const options = {
        hostname: new URL(this.UPDATE_SERVER).hostname,
        port: 443,
        path: '/latest.json',
        method: 'GET',
        timeout: 30000,
        headers: {
          'User-Agent': `${app.getName()}/${app.getVersion()}`,
          'X-Request-ID': crypto.randomUUID()
        },
        // TLS configuration
        minVersion: 'TLSv1.2',
        // Certificate pinning callback
        checkServerIdentity: (hostname, cert) => {
          const certFingerprint = `sha256/${crypto
            .createHash('sha256')
            .update(cert.raw)
            .digest('base64')}`;

          if (!this.PINNED_CERTS.includes(certFingerprint)) {
            securityLogger.error('Certificate pinning failure', {
              event: 'CERT_PIN_FAILURE',
              hostname,
              fingerprint: certFingerprint
            });
            return new Error('Certificate fingerprint mismatch');
          }
          return undefined;
        }
      };

      const req = https.request(options, (res) => {
        if (res.statusCode !== 200) {
          reject(new Error(`HTTP ${res.statusCode}`));
          return;
        }

        let data = '';
        res.on('data', chunk => data += chunk);
        res.on('end', () => {
          try {
            const parsed = JSON.parse(data);
            resolve(parsed);
          } catch (e) {
            reject(new Error('Invalid JSON response'));
          }
        });
      });

      req.on('error', reject);
      req.on('timeout', () => {
        req.destroy();
        reject(new Error('Request timeout'));
      });

      req.end();
    });
  }

  async checkForSecureUpdate() {
    if (this.updateInProgress) {
      securityLogger.warn('Update already in progress');
      return null;
    }

    this.updateInProgress = true;

    try {
      const manifest = await this.fetchUpdateManifest();

      // Verify manifest signature
      if (!this.verifyUpdateSignature(manifest.data, manifest.signature)) {
        throw new Error('Invalid update signature');
      }

      // Verify signer is in allowed list
      if (!this.ALLOWED_SIGNERS.includes(manifest.data.signer)) {
        securityLogger.error('Unknown signer', {
          event: 'UNKNOWN_SIGNER',
          signer: manifest.data.signer
        });
        throw new Error('Update signed by unknown key');
      }

      // Verify version is newer (prevent downgrade attacks)
      const currentVersion = app.getVersion();
      if (!this.isNewerVersion(manifest.data.version, currentVersion)) {
        securityLogger.warn('Downgrade attempt detected', {
          event: 'DOWNGRADE_ATTEMPT',
          current: currentVersion,
          offered: manifest.data.version
        });
        throw new Error('Downgrade attack detected');
      }

      // Verify release timestamp is reasonable
      const releaseTime = new Date(manifest.data.releaseDate);
      const now = new Date();
      const maxAge = 30 * 24 * 60 * 60 * 1000; // 30 days

      if (now - releaseTime > maxAge) {
        securityLogger.warn('Stale update detected', {
          event: 'STALE_UPDATE',
          releaseDate: manifest.data.releaseDate
        });
        // Don't fail, but log for monitoring
      }

      securityLogger.info('Secure update available', {
        event: 'UPDATE_AVAILABLE',
        version: manifest.data.version,
        sha256: manifest.data.sha256
      });

      return manifest.data;
    } catch (error) {
      securityLogger.error('Update check failed', {
        event: 'UPDATE_CHECK_FAILED',
        error: error.message
      });
      throw error;
    } finally {
      this.updateInProgress = false;
    }
  }

  isNewerVersion(newVersion, currentVersion) {
    const parseVersion = (v) => v.split('.').map(Number);
    const newParts = parseVersion(newVersion);
    const currentParts = parseVersion(currentVersion);

    for (let i = 0; i < Math.max(newParts.length, currentParts.length); i++) {
      const newPart = newParts[i] || 0;
      const currentPart = currentParts[i] || 0;
      if (newPart > currentPart) return true;
      if (newPart < currentPart) return false;
    }
    return false;
  }

  setupEventHandlers() {
    autoUpdater.on('update-downloaded', async (event, releaseNotes, releaseName, releaseDate, updateURL) => {
      securityLogger.info('Update downloaded', {
        event: 'UPDATE_DOWNLOADED',
        releaseName,
        releaseDate
      });

      // Show user confirmation before installing
      const { response } = await dialog.showMessageBox({
        type: 'info',
        buttons: ['Restart Now', 'Later'],
        title: 'Application Update',
        message: `Version ${releaseName} is ready to install.`,
        detail: 'The application will restart to apply the update.'
      });

      if (response === 0) {
        autoUpdater.quitAndInstall();
      }
    });

    autoUpdater.on('error', (error) => {
      securityLogger.error('Auto-updater error', {
        event: 'UPDATER_ERROR',
        error: error.message
      });
    });
  }
}

// Build pipeline: Sign release manifest
// This runs in your CI/CD pipeline, NOT in the application
class ReleaseSigningService {
  static signRelease(manifestData, privateKeyPath) {
    // Private key should be in HSM or secure key management
    const privateKey = fs.readFileSync(privateKeyPath, 'utf8');
    const sign = crypto.createSign('RSA-SHA512');
    sign.update(JSON.stringify(manifestData));
    sign.end();
    return sign.sign(privateKey, 'base64');
  }

  static generateReleaseManifest(version, filePath, signerKeyId) {
    const fileContent = fs.readFileSync(filePath);
    const sha256 = crypto.createHash('sha256').update(fileContent).digest('hex');
    const sha512 = crypto.createHash('sha512').update(fileContent).digest('hex');

    return {
      version,
      releaseDate: new Date().toISOString(),
      signer: signerKeyId,
      sha256,
      sha512,
      size: fileContent.length,
      platform: process.platform,
      arch: process.arch
    };
  }
}

module.exports = { SecureElectronUpdater, ReleaseSigningService };
