@WebServlet("/api/v1/internal/*")
public class SecureInternalApiServlet extends HttpServlet {

    private static final Logger AUDIT_LOG = Logger.getLogger("API_SECURITY_AUDIT");
    private static final Logger METRICS_LOG = Logger.getLogger("API_METRICS");

    // Rate limiting: 100 requests per minute per API key
    private final ConcurrentHashMap<String, RateLimiter> rateLimiters = new ConcurrentHashMap<>();
    private final ApiKeyValidator apiKeyValidator;
    private final ServiceAuthenticator serviceAuth;
    private final Set<String> allowedNetworks;

    public SecureInternalApiServlet() {
        this.apiKeyValidator = new ApiKeyValidator();
        this.serviceAuth = new ServiceAuthenticator();
        this.allowedNetworks = loadAllowedNetworks();
    }

    @Override
    protected void service(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        long startTime = System.currentTimeMillis();
        String requestId = UUID.randomUUID().toString();
        String clientIp = getClientIp(request);

        try {
            // LAYER 1: Network-level restriction (defense in depth)
            if (!isAllowedNetwork(clientIp)) {
                AUDIT_LOG.severe(String.format(
                    "[%s] Blocked request from unauthorized network: %s",
                    requestId, clientIp));
                response.sendError(HttpServletResponse.SC_FORBIDDEN);
                return;
            }

            // LAYER 2: API Key validation with HMAC verification
            String apiKey = extractApiKey(request);
            if (apiKey == null || !apiKeyValidator.isValid(apiKey)) {
                AUDIT_LOG.warning(String.format(
                    "[%s] Invalid or missing API key from IP: %s",
                    requestId, clientIp));
                response.sendError(HttpServletResponse.SC_UNAUTHORIZED);
                return;
            }

            // LAYER 3: Request signature verification (prevents replay attacks)
            if (!verifyRequestSignature(request, apiKey)) {
                AUDIT_LOG.severe(String.format(
                    "[%s] Invalid request signature for key: %s from IP: %s",
                    requestId, maskApiKey(apiKey), clientIp));
                response.sendError(HttpServletResponse.SC_UNAUTHORIZED);
                return;
            }

            // LAYER 4: Rate limiting per API key
            RateLimiter limiter = rateLimiters.computeIfAbsent(
                apiKey, k -> new RateLimiter(100, Duration.ofMinutes(1)));
            if (!limiter.tryAcquire()) {
                AUDIT_LOG.warning(String.format(
                    "[%s] Rate limit exceeded for key: %s",
                    requestId, maskApiKey(apiKey)));
                response.setHeader("Retry-After", "60");
                response.sendError(429, "Rate limit exceeded");
                return;
            }

            // LAYER 5: Service-to-service mutual TLS verification
            if (!serviceAuth.verifyMtls(request)) {
                AUDIT_LOG.severe(String.format(
                    "[%s] mTLS verification failed from IP: %s",
                    requestId, clientIp));
                response.sendError(HttpServletResponse.SC_UNAUTHORIZED);
                return;
            }

            // All checks passed - process request
            AUDIT_LOG.info(String.format(
                "[%s] Authorized API request: method=%s, path=%s, key=%s, ip=%s",
                requestId, request.getMethod(), request.getPathInfo(),
                maskApiKey(apiKey), clientIp));

            super.service(request, response);

        } finally {
            // Log request metrics for monitoring
            long duration = System.currentTimeMillis() - startTime;
            METRICS_LOG.info(String.format(
                "request_id=%s duration_ms=%d status=%d",
                requestId, duration, response.getStatus()));
        }
    }

    private String extractApiKey(HttpServletRequest request) {
        // Check Authorization header first (preferred)
        String authHeader = request.getHeader("Authorization");
        if (authHeader != null && authHeader.startsWith("Bearer ")) {
            return authHeader.substring(7);
        }
        // Fallback to X-API-Key header
        return request.getHeader("X-API-Key");
    }

    private boolean verifyRequestSignature(HttpServletRequest request, String apiKey) {
        String timestamp = request.getHeader("X-Timestamp");
        String signature = request.getHeader("X-Signature");

        if (timestamp == null || signature == null) {
            return false;
        }

        // Prevent replay attacks: reject requests older than 5 minutes
        long requestTime = Long.parseLong(timestamp);
        long currentTime = System.currentTimeMillis();
        if (Math.abs(currentTime - requestTime) > 300000) {
            return false;
        }

        // Verify HMAC-SHA256 signature
        String payload = request.getMethod() + request.getRequestURI() + timestamp;
        String expectedSignature = computeHmacSignature(payload, getSecretForKey(apiKey));

        return MessageDigest.isEqual(
            signature.getBytes(), expectedSignature.getBytes());
    }

    private String computeHmacSignature(String payload, String secret) {
        try {
            Mac hmac = Mac.getInstance("HmacSHA256");
            SecretKeySpec keySpec = new SecretKeySpec(
                secret.getBytes(), "HmacSHA256");
            hmac.init(keySpec);
            byte[] hash = hmac.doFinal(payload.getBytes());
            return Base64.getEncoder().encodeToString(hash);
        } catch (Exception e) {
            throw new SecurityException("Failed to compute HMAC", e);
        }
    }

    private String getSecretForKey(String apiKey) {
        // Retrieve from secure vault (HashiCorp Vault, AWS Secrets Manager, etc.)
        return SecretVaultClient.getSecret("api-key-secrets", apiKey);
    }

    private boolean isAllowedNetwork(String clientIp) {
        return allowedNetworks.stream()
            .anyMatch(network -> ipMatchesCidr(clientIp, network));
    }

    private Set<String> loadAllowedNetworks() {
        // Load from environment or secure configuration
        return Set.of(
            "10.0.0.0/8",      // Internal VPC
            "172.16.0.0/12",   // Kubernetes pod network
            "192.168.0.0/16"   // Private network
        );
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    private String maskApiKey(String apiKey) {
        if (apiKey == null || apiKey.length() < 8) {
            return "***";
        }
        return apiKey.substring(0, 4) + "..." + 
               apiKey.substring(apiKey.length() - 4);
    }

    private boolean ipMatchesCidr(String ip, String cidr) {
        // Implementation of CIDR matching
        return true; // Simplified for example
    }
}
```

**Defense in Depth Layers**:

1. **Network Segmentation**:
```java
// Kubernetes NetworkPolicy example (deploy alongside)
// Only allow traffic from specific namespaces
private Set<String> loadAllowedNetworks() {
    String networks = System.getenv("ALLOWED_NETWORKS");
    if (networks == null) {
        // Fail secure: deny all if not configured
        throw new SecurityException("ALLOWED_NETWORKS not configured");
    }
    return Arrays.stream(networks.split(","))
        .map(String::trim)
        .collect(Collectors.toSet());
}
```

2. **Cryptographic API Key Validation**:
```java
public class ApiKeyValidator {
    private final SecretVaultClient vault;

    public boolean isValid(String apiKey) {
        // Keys are hashed in storage - never stored plaintext
        String keyHash = sha256(apiKey);
        ApiKeyRecord record = vault.getApiKeyRecord(keyHash);

        if (record == null) return false;
        if (record.isRevoked()) return false;
        if (record.getExpiresAt().isBefore(Instant.now())) return false;

        return true;
    }

    private String sha256(String input) {
        MessageDigest digest = MessageDigest.getInstance("SHA-256");
        byte[] hash = digest.digest(input.getBytes());
        return Base64.getEncoder().encodeToString(hash);
    }
}
```

3. **Mutual TLS for Service-to-Service**:
```java
public class ServiceAuthenticator {
    public boolean verifyMtls(HttpServletRequest request) {
        X509Certificate[] certs = (X509Certificate[]) 
            request.getAttribute("javax.servlet.request.X509Certificate");

        if (certs == null || certs.length == 0) {
            return false;
        }

        X509Certificate clientCert = certs[0];

        // Verify certificate is from trusted CA
        if (!isTrustedCa(clientCert.getIssuerDN())) {
            return false;
        }

        // Verify certificate is not revoked (check CRL or OCSP)
        if (isCertificateRevoked(clientCert)) {
            return false;
        }

        // Verify service identity from certificate CN/SAN
        String serviceIdentity = extractServiceIdentity(clientCert);
        return isAuthorizedService(serviceIdentity);
    }
}
```

**Additional Protections**:
- **API Key Rotation**: Automatically rotate keys every 90 days with zero-downtime deployment
- **Anomaly Detection**: Monitor for unusual request patterns (geographic anomalies, time-based anomalies)
- **Circuit Breaker**: Automatically block API keys that generate too many errors
- **Request Tracing**: Correlate requests across services with distributed tracing (Jaeger, Zipkin)
- **Secrets Management**: Store API secrets in HashiCorp Vault or AWS Secrets Manager, never in code or config files
- **Key Scoping**: Each API key should have minimal permissions (principle of least privilege)
- **Incident Response**: Automated alerting when suspicious patterns detected, with runbook for key revocation

Mass assignment vulnerabilities occur when you directly assign user-supplied data to database objects without filtering which fields can be modified. This was exploited in CVE-2024-4985 affecting GitHub Enterprise Server, where attackers could escalate to admin privileges.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const mongoose = require('mongoose');
const app = express();

app.use(express.json());

// User schema with sensitive fields
const userSchema = new mongoose.Schema({
  username: String,
  email: String,
  password: String,
  isAdmin: { type: Boolean, default: false },
  role: { type: String, default: 'user' },
  accountBalance: { type: Number, default: 0 },
  verified: { type: Boolean, default: false }
});

const User = mongoose.model('User', userSchema);

// VULNERABLE: Direct object spread from request body
app.post('/api/register', async (req, res) => {
  const newUser = new User(req.body);  // Mass assignment!
  await newUser.save();
  res.json({ message: 'User created', user: newUser });
});

// VULNERABLE: Direct update with request body
app.put('/api/users/:id', async (req, res) => {
  const user = await User.findByIdAndUpdate(
    req.params.id,
    req.body,  // Mass assignment!
    { new: true }
  );
  res.json(user);
});
```

**Attack Payload**:
```json
{
  "username": "attacker",
  "email": "attacker@evil.com",
  "password": "password123",
  "isAdmin": true,
  "role": "superadmin",
  "accountBalance": 999999,
  "verified": true
}
```

**Why This Is Dangerous**:
- Attackers can set `isAdmin: true` to gain administrative privileges
- `role` field can be manipulated to bypass role-based access controls
- `accountBalance` can be inflated for financial fraud
- `verified` can be set to bypass email verification

**SECURE VERSION**:

```javascript
const express = require('express');
const mongoose = require('mongoose');
const { body, validationResult } = require('express-validator');
const app = express();

app.use(express.json());

const User = mongoose.model('User', userSchema);

// Define allowed fields for each operation
const ALLOWED_REGISTRATION_FIELDS = ['username', 'email', 'password'];
const ALLOWED_UPDATE_FIELDS = ['username', 'email'];

// Helper function to pick only allowed fields
function pickAllowedFields(source, allowedFields) {
  const result = {};
  for (const field of allowedFields) {
    if (source.hasOwnProperty(field)) {
      result[field] = source[field];
    }
  }
  return result;
}

// SECURE: Explicit field allowlist for registration
app.post('/api/register', [
  body('username').isLength({ min: 3, max: 30 }).trim().escape(),
  body('email').isEmail().normalizeEmail(),
  body('password').isLength({ min: 8 })
], async (req, res) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ errors: errors.array() });
  }

  // Only pick allowed fields - ignores isAdmin, role, etc.
  const userData = pickAllowedFields(req.body, ALLOWED_REGISTRATION_FIELDS);

  const newUser = new User(userData);
  await newUser.save();

  // Don't return sensitive fields
  const { password, ...safeUser } = newUser.toObject();
  res.json({ message: 'User created', user: safeUser });
});

// SECURE: Explicit field allowlist for updates
app.put('/api/users/:id', async (req, res) => {
  const updateData = pickAllowedFields(req.body, ALLOWED_UPDATE_FIELDS);

  const user = await User.findByIdAndUpdate(
    req.params.id,
    { $set: updateData },  // Only update allowed fields
    { new: true, runValidators: true }
  ).select('-password');

  res.json(user);
});
```

**Key Security Controls**:
- **Field allowlisting**: Only explicitly allowed fields can be assigned to models
- **Input validation**: All inputs validated before processing using express-validator
- **Sensitive field exclusion**: Password and other sensitive fields excluded from responses

Role-based field access control is a common production requirement. You need to define field permissions per role and enforce them consistently across your application.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const mongoose = require('mongoose');
const { body, validationResult } = require('express-validator');
const winston = require('winston');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(express.json());

// Configure audit logger
const auditLogger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'audit.log' })
  ]
});

// Role-based field permissions
const FIELD_PERMISSIONS = {
  user: {
    create: ['username', 'email', 'password'],
    update: ['username', 'email', 'avatar', 'bio'],
    read: ['id', 'username', 'email', 'avatar', 'bio', 'createdAt']
  },
  moderator: {
    create: ['username', 'email', 'password'],
    update: ['username', 'email', 'avatar', 'bio', 'verified'],
    read: ['id', 'username', 'email', 'avatar', 'bio', 'verified', 'createdAt', 'lastLogin']
  },
  admin: {
    create: ['username', 'email', 'password', 'role', 'verified'],
    update: ['username', 'email', 'avatar', 'bio', 'role', 'verified', 'isActive', 'permissions'],
    read: ['id', 'username', 'email', 'avatar', 'bio', 'role', 'verified', 'isActive', 'permissions', 'createdAt', 'lastLogin', 'loginAttempts']
  }
};

// Sensitive fields that can NEVER be mass assigned
const PROTECTED_FIELDS = ['_id', 'id', 'isAdmin', 'passwordHash', 'resetToken', 'accountBalance', 'apiKey'];

class FieldAccessControl {
  static getAllowedFields(userRole, operation) {
    const rolePerms = FIELD_PERMISSIONS[userRole] || FIELD_PERMISSIONS.user;
    return rolePerms[operation] || [];
  }

  static filterFields(data, userRole, operation) {
    const allowedFields = this.getAllowedFields(userRole, operation);
    const filtered = {};
    const blocked = [];

    for (const [key, value] of Object.entries(data)) {
      if (PROTECTED_FIELDS.includes(key)) {
        blocked.push({ field: key, reason: 'protected' });
        continue;
      }
      if (allowedFields.includes(key)) {
        filtered[key] = value;
      } else {
        blocked.push({ field: key, reason: 'not_permitted_for_role' });
      }
    }

    return { filtered, blocked };
  }

  static canUpdateField(userRole, field) {
    if (PROTECTED_FIELDS.includes(field)) return false;
    const allowedFields = this.getAllowedFields(userRole, 'update');
    return allowedFields.includes(field);
  }
}

// Middleware: Authenticate and attach user role
const authenticate = async (req, res, next) => {
  try {
    const token = req.headers.authorization?.split(' ')[1];
    if (!token) {
      return res.status(401).json({ error: 'Authentication required' });
    }
    // Verify JWT and get user (simplified)
    const decoded = await verifyToken(token);
    req.user = await User.findById(decoded.userId).select('-password');
    if (!req.user) {
      return res.status(401).json({ error: 'User not found' });
    }
    next();
  } catch (error) {
    res.status(401).json({ error: 'Invalid token' });
  }
};

// Middleware: Filter request body based on role permissions
const filterBodyByRole = (operation) => {
  return (req, res, next) => {
    const userRole = req.user?.role || 'user';
    const { filtered, blocked } = FieldAccessControl.filterFields(
      req.body,
      userRole,
      operation
    );

    // Log blocked field attempts (potential attack indicator)
    if (blocked.length > 0) {
      auditLogger.warn('Mass assignment attempt blocked', {
        userId: req.user?.id,
        userRole,
        operation,
        blockedFields: blocked,
        ip: req.ip,
        userAgent: req.get('user-agent'),
        timestamp: new Date().toISOString()
      });
    }

    req.filteredBody = filtered;
    req.blockedFields = blocked;
    next();
  };
};

// Rate limiting for profile updates
const updateLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 10,
  message: { error: 'Too many update requests, please try again later' }
});

// SECURE: Role-based user update
app.put('/api/users/:id',
  authenticate,
  updateLimiter,
  filterBodyByRole('update'),
  [
    body('username').optional().isLength({ min: 3, max: 30 }).trim(),
    body('email').optional().isEmail().normalizeEmail(),
    body('role').optional().isIn(['user', 'moderator', 'admin'])
  ],
  async (req, res) => {
    try {
      const errors = validationResult(req);
      if (!errors.isEmpty()) {
        return res.status(400).json({ errors: errors.array() });
      }

      const targetUserId = req.params.id;
      const requesterId = req.user.id;
      const requesterRole = req.user.role;

      // Authorization check: users can only update themselves, admins can update anyone
      if (requesterId !== targetUserId && requesterRole !== 'admin') {
        auditLogger.warn('Unauthorized update attempt', {
          requesterId,
          targetUserId,
          requesterRole,
          ip: req.ip
        });
        return res.status(403).json({ error: 'Not authorized to update this user' });
      }

      // Check for privilege escalation attempt
      if (req.filteredBody.role && requesterRole !== 'admin') {
        auditLogger.warn('Privilege escalation attempt', {
          requesterId,
          attemptedRole: req.body.role,
          ip: req.ip
        });
        delete req.filteredBody.role;
      }

      // Prevent admins from removing their own admin role
      if (targetUserId === requesterId && req.filteredBody.role && req.filteredBody.role !== 'admin') {
        return res.status(400).json({ error: 'Cannot demote yourself' });
      }

      const updatedUser = await User.findByIdAndUpdate(
        targetUserId,
        { $set: req.filteredBody },
        { new: true, runValidators: true }
      ).select(FieldAccessControl.getAllowedFields(requesterRole, 'read').join(' '));

      if (!updatedUser) {
        return res.status(404).json({ error: 'User not found' });
      }

      // Audit log successful update
      auditLogger.info('User updated successfully', {
        requesterId,
        targetUserId,
        updatedFields: Object.keys(req.filteredBody),
        timestamp: new Date().toISOString()
      });

      res.json({
        message: 'User updated',
        user: updatedUser,
        ...(req.blockedFields.length > 0 && {
          warning: 'Some fields were not updated due to permissions'
        })
      });
    } catch (error) {
      auditLogger.error('User update error', { error: error.message });
      res.status(500).json({ error: 'Internal server error' });
    }
  }
);

// Admin-only endpoint to update sensitive fields
app.put('/api/admin/users/:id',
  authenticate,
  (req, res, next) => {
    if (req.user.role !== 'admin') {
      auditLogger.warn('Non-admin admin endpoint access', {
        userId: req.user.id,
        role: req.user.role,
        ip: req.ip
      });
      return res.status(403).json({ error: 'Admin access required' });
    }
    next();
  },
  filterBodyByRole('update'),
  async (req, res) => {
    // Admin-specific update logic with full audit trail
    // ...
  }
);
```

**Defense in Depth Layers**:

1. **Field Allowlisting by Role**:
```javascript
// Each role has explicit field permissions
const permissions = FIELD_PERMISSIONS[userRole][operation];
// Unknown roles default to most restrictive
const rolePerms = FIELD_PERMISSIONS[userRole] || FIELD_PERMISSIONS.user;
```

2. **Protected Fields (Global Blocklist)**:
```javascript
// These fields can NEVER be mass-assigned regardless of role
const PROTECTED_FIELDS = ['_id', 'id', 'isAdmin', 'passwordHash', 'resetToken'];
if (PROTECTED_FIELDS.includes(key)) {
  blocked.push({ field: key, reason: 'protected' });
  continue; // Skip field entirely
}
```

3. **Audit Logging for Attack Detection**:
```javascript
// Log every blocked field attempt for security monitoring
if (blocked.length > 0) {
  auditLogger.warn('Mass assignment attempt blocked', {
    userId: req.user?.id,
    blockedFields: blocked,
    ip: req.ip,
    timestamp: new Date().toISOString()
  });
}
```

**Additional Protections**:
- **Rate limiting**: Prevents automated mass assignment probing
- **Input validation**: Validates allowed fields meet format requirements
- **Authorization checks**: Verifies user can only update their own profile (unless admin)
- **Privilege escalation prevention**: Special handling for role changes
- **Response filtering**: Only returns fields the user is permitted to see
- **Schema-level protection**: Use Mongoose schema options like `select: false` for sensitive fields

Simply bolting on a basic SMS code can still leave you vulnerable to MFA bypass, replay, and brute-force if you handle it incorrectly.

**VULNERABLE CODE**:

```csharp
using System;
using System.Collections.Concurrent;
using Microsoft.AspNetCore.Mvc;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/auth")]    
    public class AuthController : ControllerBase
    {
        // In-memory store for demo (vulnerable design)
        private static readonly ConcurrentDictionary<string, string> PendingOtps = new();

        [HttpPost("login")]        
        public IActionResult Login([FromForm] string username, [FromForm] string password)
        {
            if (username == "admin" && password == "P@ssw0rd")
            {
                // Generate predictable 6-digit code with no expiry
                var otp = new Random().Next(0, 999999).ToString("D6");
                PendingOtps[username] = otp;

                // Fake SMS send (logs to console)
                Console.WriteLine($"Sending OTP {otp} to user {username}");

                return Ok("OTP sent");
            }

            return Unauthorized("Invalid credentials");
        }

        [HttpPost("verify-otp")]        
        public IActionResult VerifyOtp([FromForm] string username, [FromForm] string otp)
        {
            if (PendingOtps.TryGetValue(username, out var storedOtp) && storedOtp == otp)
            {
                // OTP never cleared, no attempt limit
                return Ok("Logged in with 2FA");
            }

            return Unauthorized("Invalid OTP");
        }
    }
}
```

**Attack Payload** (brute-forcing the OTP):
```bash
# Example brute-force loop using curl
for code in $(seq -w 000000 999999); do
  curl -X POST "https://victim.com/api/auth/verify-otp" \
    -d "username=admin" -d "otp=${code}";
done
```

**Why This Is Dangerous**:
- Uses a predictable, fast `Random()` generator and static 6-digit codes with no expiry, so brute-force is trivial.
- Stores OTPs in a global dictionary without per-user rate limiting, device binding, or invalidation after use.
- No audit logging or alerting on repeated failures, so attacks like MFA brute-force or fatigue are invisible.

**SECURE VERSION**:

```csharp
using System;
using System.Collections.Concurrent;
using System.Security.Cryptography;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;

namespace MyApp.Controllers
{
    public class OtpEntry
    {
        public string Code { get; set; } = string.Empty;
        public DateTimeOffset ExpiresAt { get; set; }
        public int FailedAttempts { get; set; }
        public bool Used { get; set; }
        public string DeviceId { get; set; } = string.Empty;
    }

    [ApiController]
    [Route("api/auth")]    
    public class SecureAuthController : ControllerBase
    {
        private static readonly ConcurrentDictionary<string, OtpEntry> PendingOtps = new();
        private const int MaxOtpAttempts = 5;
        private static readonly TimeSpan OtpLifetime = TimeSpan.FromMinutes(5);
        private readonly ILogger<SecureAuthController> _logger;

        public SecureAuthController(ILogger<SecureAuthController> logger)
        {
            _logger = logger;
        }

        [HttpPost("login")]        
        public IActionResult Login([FromForm] string username, [FromForm] string password, [FromForm] string deviceId)
        {
            // TODO: replace with proper password hash verification
            if (username == "admin" && password == "P@ssw0rd")
            {
                var otp = GenerateSecureOtp();
                var entry = new OtpEntry
                {
                    Code = otp,
                    ExpiresAt = DateTimeOffset.UtcNow.Add(OtpLifetime),
                    FailedAttempts = 0,
                    Used = false,
                    DeviceId = deviceId
                };

                PendingOtps[username] = entry;

                // In production, send via secure SMS/Email/Authenticator push
                _logger.LogInformation("Sending OTP to user {User} for device {Device}", username, deviceId);

                return Ok("OTP sent to your registered device");
            }

            _logger.LogWarning("Failed primary credential login for user {User}", username);
            return Unauthorized("Invalid credentials");
        }

        [HttpPost("verify-otp")]        
        public IActionResult VerifyOtp([FromForm] string username, [FromForm] string otp, [FromForm] string deviceId)
        {
            if (!PendingOtps.TryGetValue(username, out var entry))
            {
                _logger.LogWarning("OTP verification attempted for user {User} with no pending OTP", username);
                return Unauthorized("Invalid or expired OTP");
            }

            if (entry.Used || DateTimeOffset.UtcNow > entry.ExpiresAt)
            {
                PendingOtps.TryRemove(username, out _);
                _logger.LogWarning("Expired or used OTP for user {User}", username);
                return Unauthorized("Invalid or expired OTP");
            }

            if (!string.Equals(entry.DeviceId, deviceId, StringComparison.Ordinal))
            {
                _logger.LogWarning("OTP device mismatch for user {User}", username);
                return Unauthorized("Invalid OTP");
            }

            if (!TimeConstantCompare(entry.Code, otp))
            {
                entry.FailedAttempts++;
                _logger.LogWarning("Invalid OTP for user {User}, attempt {Attempt}", username, entry.FailedAttempts);

                if (entry.FailedAttempts >= MaxOtpAttempts)
                {
                    PendingOtps.TryRemove(username, out _);
                    _logger.LogError("User {User} exceeded max OTP attempts, OTP invalidated", username);
                }

                return Unauthorized("Invalid OTP");
            }

            entry.Used = true;
            PendingOtps.TryRemove(username, out _);
            _logger.LogInformation("User {User} successfully completed MFA", username);

            // Issue secure session / JWT token here
            return Ok("Logged in with strong MFA");
        }

        private static string GenerateSecureOtp()
        {
            // 6-digit OTP from cryptographically secure RNG
            using var rng = RandomNumberGenerator.Create();
            var bytes = new byte[4];
            rng.GetBytes(bytes);
            var value = BitConverter.ToUInt32(bytes, 0) % 1_000_000;
            return value.ToString("D6");
        }

        private static bool TimeConstantCompare(string a, string b)
        {
            if (a.Length != b.Length)
            {
                return false;
            }

            var result = 0;
            for (var i = 0; i < a.Length; i++)
            {
                result |= a[i] ^ b[i];
            }

            return result == 0;
        }
    }
}
```

**Key Security Controls**:
- Uses a cryptographically secure random generator and short OTP lifetime to prevent prediction and limit replay windows.
- Enforces per-user attempt limits, device binding, and single-use semantics to make brute-force and token sharing far harder.
- Adds structured logging on failures and successes so suspicious MFA activity (brute-force, abuse) can be detected and investigated.

For production, you typically want a time-based one-time password (TOTP) using authenticator apps, strong session management, rate limiting, and layered monitoring.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.IdentityModel.Tokens.Jwt;
using System.Security.Claims;
using System.Text;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using Microsoft.IdentityModel.Tokens;

namespace MyApp.Controllers
{
    public interface ITotpService
    {
        bool VerifyCode(string secret, string code, int allowedDriftSteps = 1);
    }

    [ApiController]
    [Route("api/auth")]    
    public class ProdAuthController : ControllerBase
    {
        private readonly ILogger<ProdAuthController> _logger;
        private readonly IConfiguration _config;
        private readonly ITotpService _totpService;

        public ProdAuthController(
            ILogger<ProdAuthController> logger,
            IConfiguration config,
            ITotpService totpService)
        {
            _logger = logger;
            _config = config;
            _totpService = totpService;
        }

        [HttpPost("login")]
        [AllowAnonymous]
        public IActionResult Login([FromForm] string username, [FromForm] string password)
        {
            // 1. Primary authentication (hash + salt in production)
            if (!ValidateUserPassword(username, password))
            {
                _logger.LogWarning("Invalid primary login for {User} from {IP}", username, HttpContext.Connection.RemoteIpAddress);
                return Unauthorized("Invalid credentials");
            }

            // 2. Check if MFA is enrolled
            var mfaSecret = GetUserTotpSecret(username);
            if (string.IsNullOrEmpty(mfaSecret))
            {
                _logger.LogWarning("User {User} without MFA attempted login", username);
                return StatusCode(StatusCodes.Status403Forbidden, "MFA required. Please enroll.");
            }

            // 3. Issue short-lived MFA challenge token (no full session yet)
            var mfaToken = IssueMfaChallengeToken(username);

            _logger.LogInformation("MFA challenge issued for {User} from {IP}", username, HttpContext.Connection.RemoteIpAddress);
            return Ok(new { mfa_token = mfaToken, message = "Enter your authenticator app code." });
        }

        [HttpPost("verify-mfa")]
        [AllowAnonymous]
        public IActionResult VerifyMfa([FromForm] string mfaToken, [FromForm] string code)
        {
            var principal = ValidateMfaChallengeToken(mfaToken);
            if (principal == null)
            {
                _logger.LogWarning("Invalid or expired MFA token from {IP}", HttpContext.Connection.RemoteIpAddress);
                return Unauthorized("Invalid or expired MFA session");
            }

            var username = principal.FindFirst(ClaimTypes.Name)?.Value;
            if (string.IsNullOrEmpty(username))
            {
                _logger.LogError("MFA token missing username claim");
                return Unauthorized("Invalid MFA token");
            }

            // Rate limiting should also be enforced at the API gateway or middleware layer

            var mfaSecret = GetUserTotpSecret(username);
            if (string.IsNullOrEmpty(mfaSecret))
            {
                _logger.LogError("MFA verification for user {User} without secret", username);
                return Unauthorized("MFA not configured");
            }

            if (!_totpService.VerifyCode(mfaSecret, code))
            {
                _logger.LogWarning("Invalid TOTP for {User} from {IP}", username, HttpContext.Connection.RemoteIpAddress);
                return Unauthorized("Invalid code");
            }

            // 4. Successful MFA – issue full session / JWT
            var accessToken = IssueAccessToken(username);

            _logger.LogInformation("User {User} successfully completed MFA from {IP}", username, HttpContext.Connection.RemoteIpAddress);
            return Ok(new { access_token = accessToken });
        }

        private bool ValidateUserPassword(string username, string password)
        {
            // Placeholder; integrate with your identity store
            return username == "admin" && password == "P@ssw0rd";
        }

        private string GetUserTotpSecret(string username)
        {
            // In production, retrieve encrypted TOTP secret from DB
            if (username == "admin")
            {
                return "BASE32ENCODEDSECRET"; // placeholder
            }

            return string.Empty;
        }

        private string IssueMfaChallengeToken(string username)
        {
            var key = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(_config["Jwt:MfaKey"]!));
            var creds = new SigningCredentials(key, SecurityAlgorithms.HmacSha256);

            var token = new JwtSecurityToken(
                issuer: _config["Jwt:Issuer"],
                audience: _config["Jwt:Audience"],
                claims: new[] { new Claim(ClaimTypes.Name, username) },
                expires: DateTime.UtcNow.AddMinutes(5),
                signingCredentials: creds);

            return new JwtSecurityTokenHandler().WriteToken(token);
        }

        private ClaimsPrincipal? ValidateMfaChallengeToken(string token)
        {
            try
            {
                var handler = new JwtSecurityTokenHandler();
                var principal = handler.ValidateToken(token, new TokenValidationParameters
                {
                    ValidateIssuer = true,
                    ValidateAudience = true,
                    ValidateIssuerSigningKey = true,
                    ValidIssuer = _config["Jwt:Issuer"],
                    ValidAudience = _config["Jwt:Audience"],
                    IssuerSigningKey = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(_config["Jwt:MfaKey"]!)),
                    ClockSkew = TimeSpan.FromSeconds(30)
                }, out _);

                return principal;
            }
            catch (Exception ex)
            {
                _logger.LogWarning(ex, "Failed to validate MFA token");
                return null;
            }
        }

        private string IssueAccessToken(string username)
        {
            var key = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(_config["Jwt:AccessKey"]!));
            var creds = new SigningCredentials(key, SecurityAlgorithms.HmacSha256);

            var claims = new[]
            {
                new Claim(ClaimTypes.Name, username),
                new Claim("mfa", "true")
            };

            var token = new JwtSecurityToken(
                issuer: _config["Jwt:Issuer"],
                audience: _config["Jwt:Audience"],
                claims: claims,
                expires: DateTime.UtcNow.AddMinutes(_config.GetValue<int>("Jwt:AccessTokenMinutes")),
                signingCredentials: creds);

            return new JwtSecurityTokenHandler().WriteToken(token);
        }
    }
}
```

**Defense in Depth Layers**:
1. **Environment-specific hardening**
   - Configure secrets and strict cookie/JWT settings only in production:
   ```csharp
   // In Program.cs / Startup.cs
   if (builder.Environment.IsProduction())
   {
       builder.Services.ConfigureApplicationCookie(options =>
       {
           options.Cookie.HttpOnly = true;
           options.Cookie.SecurePolicy = CookieSecurePolicy.Always;
           options.Cookie.SameSite = SameSiteMode.Strict;
       });
   }
   ```
2. **Rate limiting and lockout policies**
   - Use middleware or an API gateway to throttle login and MFA endpoints:
   ```csharp
   // Pseudocode for per-IP + per-user rate limit
   // Apply strict limits on /api/auth/login and /api/auth/verify-mfa
   app.UseMiddleware<RateLimitingMiddleware>();
   ```
3. **Monitoring and anomaly detection**
   - Log detailed events for security analytics:
   ```csharp
   _logger.LogWarning("Multiple failed MFA attempts for {User} from {IP}", user, ip);
   // Feed logs into SIEM to alert on spikes, impossible travel, or MFA fatigue patterns.
   ```

**Additional Protections**:
- Enroll MFA using secure flows (e.g., QR codes with TOTP secret, confirmed by password + second factor) and store secrets encrypted with a KMS.
- Use security headers such as `Strict-Transport-Security`, `X-Content-Type-Options`, and `Content-Security-Policy` to protect the web front-end that drives the MFA UX.
- Implement robust fallback and recovery: require strong identity proofing for MFA reset, notify users on new device enrollment, and log & alert on any MFA method changes.

I'll demonstrate both vulnerable and secure command execution in Go.

**Vulnerable Code (Command Injection Risk):**
```go
package main

import (
    "fmt"
    "os/exec"
)

// DANGEROUS: Using sh -c with string concatenation
func pingHostVulnerable(hostname string) (string, error) {
    // This spawns a shell, allowing injection
    cmd := exec.Command("sh", "-c", fmt.Sprintf("ping -c 4 %s", hostname))

    output, err := cmd.CombinedOutput()
    if err != nil {
        return "", err
    }

    return string(output), nil
}
```

**Why This Is Dangerous:**
Using `sh -c` spawns a shell interpreter. If user provides `8.8.8.8; rm -rf /`, the command becomes:
```bash
sh -c "ping -c 4 8.8.8.8; rm -rf /"
# Pings, then attempts to delete everything
```

**Secure Implementation:**
```go
package main

import (
    "context"
    "errors"
    "fmt"
    "net"
    "os/exec"
    "regexp"
    "time"
)

var (
    hostnameRegex = regexp.MustCompile(`^[a-zA-Z0-9]([a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(\.[a-zA-Z0-9]([a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$`)
)

// Validate hostname or IP address
func isValidHost(host string) error {
    if host == "" {
        return errors.New("empty host")
    }

    // Try parsing as IP address
    if ip := net.ParseIP(host); ip != nil {
        return nil
    }

    // Validate as hostname
    if !hostnameRegex.MatchString(host) || len(host) > 253 {
        return errors.New("invalid hostname format")
    }

    return nil
}

// SECURE: Direct command execution without shell
func pingHostSafe(ctx context.Context, hostname string) (string, error) {
    // Validate input
    if err := isValidHost(hostname); err != nil {
        return "", fmt.Errorf("invalid host: %w", err)
    }

    // Create context with timeout
    ctx, cancel := context.WithTimeout(ctx, 10*time.Second)
    defer cancel()

    // exec.Command with separate arguments - NO SHELL
    cmd := exec.CommandContext(ctx, "ping", "-c", "4", hostname)

    // Execute and capture output
    output, err := cmd.CombinedOutput()

    if ctx.Err() == context.DeadlineExceeded {
        return "", errors.New("command timeout")
    }

    if err != nil {
        return "", fmt.Errorf("ping failed: %w", err)
    }

    return string(output), nil
}

// Usage
func main() {
    ctx := context.Background()

    result, err := pingHostSafe(ctx, "8.8.8.8")
    if err != nil {
        fmt.Printf("Error: %v\n", err)
        return
    }

    fmt.Println(result)
}
```

**Key Security Controls:**
1. **exec.Command** with separate args - No shell invocation
2. **Context with timeout** - Prevents hung processes
3. **Input validation** - Regex and net.ParseIP validation
4. **No string concatenation** - Arguments passed separately
5. **Error handling** - Timeout and execution errors handled properly

For dynamic commands, use a builder pattern with strict allowlists:

```go
package main

import (
    "context"
    "errors"
    "fmt"
    "os/exec"
    "regexp"
    "time"
)

// Allowlist of permitted programs
var allowedPrograms = map[string]bool{
    "ping":       true,
    "nslookup":   true,
    "dig":        true,
    "traceroute": true,
}

// Allowlist of options per program
var allowedOptions = map[string]map[string]*regexp.Regexp{
    "ping": {
        "-c": regexp.MustCompile(`^\d{1,2}$`),  // Count
        "-W": regexp.MustCompile(`^\d{1,2}$`),  // Timeout
    },
    "dig": {
        "+short": nil,  // Boolean flag
        "+trace": nil,
    },
}

type CommandBuilder struct {
    program string
    args    []string
}

func NewCommandBuilder(program string) (*CommandBuilder, error) {
    if !allowedPrograms[program] {
        return nil, fmt.Errorf("program not allowed: %s", program)
    }

    return &CommandBuilder{
        program: program,
        args:    []string{},
    }, nil
}

func (cb *CommandBuilder) AddOption(option, value string) (*CommandBuilder, error) {
    opts, ok := allowedOptions[cb.program]
    if !ok {
        return nil, fmt.Errorf("no options defined for program: %s", cb.program)
    }

    pattern, exists := opts[option]
    if !exists {
        return nil, fmt.Errorf("option not allowed: %s", option)
    }

    // Boolean flag (nil pattern)
    if pattern == nil {
        cb.args = append(cb.args, option)
        return cb, nil
    }

    // Validate value
    if !pattern.MatchString(value) {
        return nil, fmt.Errorf("invalid value for %s: %s", option, value)
    }

    cb.args = append(cb.args, option, value)
    return cb, nil
}

func (cb *CommandBuilder) AddTarget(target string) (*CommandBuilder, error) {
    // Validate target
    if err := isValidHost(target); err != nil {
        return nil, fmt.Errorf("invalid target: %w", err)
    }

    cb.args = append(cb.args, target)
    return cb, nil
}

func (cb *CommandBuilder) Execute(ctx context.Context) ([]byte, error) {
    // Add timeout to context
    ctx, cancel := context.WithTimeout(ctx, 30*time.Second)
    defer cancel()

    // Build command
    cmd := exec.CommandContext(ctx, cb.program, cb.args...)

    // Execute
    output, err := cmd.CombinedOutput()

    if ctx.Err() == context.DeadlineExceeded {
        return nil, errors.New("command timeout")
    }

    if err != nil {
        return nil, fmt.Errorf("command failed: %w", err)
    }

    return output, nil
}

// Alternative: Lower-level safe execution
type CommandExecutor struct {
    timeout time.Duration
}

func NewCommandExecutor(timeout time.Duration) *CommandExecutor {
    return &CommandExecutor{
        timeout: timeout,
    }
}

func (ce *CommandExecutor) ExecuteSafe(ctx context.Context, program string, args []string) ([]byte, error) {
    // Validate program
    if !allowedPrograms[program] {
        return nil, fmt.Errorf("program not allowed: %s", program)
    }

    // Validate all arguments are safe strings
    for _, arg := range args {
        if containsShellMetachar(arg) {
            return nil, fmt.Errorf("argument contains shell metacharacters: %s", arg)
        }
    }

    // Create context with timeout
    ctx, cancel := context.WithTimeout(ctx, ce.timeout)
    defer cancel()

    // Execute command
    cmd := exec.CommandContext(ctx, program, args...)

    // Clear environment to prevent injection
    cmd.Env = []string{}

    output, err := cmd.CombinedOutput()

    if ctx.Err() == context.DeadlineExceeded {
        return nil, errors.New("command timeout")
    }

    return output, err
}

func containsShellMetachar(s string) bool {
    // Check for shell metacharacters
    dangerousChars := []byte{'&', '|', ';', '$', '`', '\n', '(', ')', '<', '>'}
    for _, char := range dangerousChars {
        for i := 0; i < len(s); i++ {
            if s[i] == char {
                return true
            }
        }
    }
    return false
}

// Usage examples
func main() {
    ctx := context.Background()

    // Using builder
    builder, err := NewCommandBuilder("ping")
    if err != nil {
        fmt.Printf("Error: %v\n", err)
        return
    }

    output, err := builder.
        AddOption("-c", "4").
        AddTarget("8.8.8.8").
        Execute(ctx)

    if err != nil {
        fmt.Printf("Error: %v\n", err)
        return
    }

    fmt.Printf("Output:\n%s\n", output)

    // Using executor
    executor := NewCommandExecutor(10 * time.Second)
    output2, err := executor.ExecuteSafe(ctx, "dig", []string{"+short", "google.com"})
    if err != nil {
        fmt.Printf("Error: %v\n", err)
        return
    }

    fmt.Printf("Output:\n%s\n", output2)
}
```

**Security Pattern:**
- **exec.Command with args** - Never use shell
- **Context with timeout** - All commands have time limits
- **Allowlist validation** - Programs, options, and patterns
- **Empty environment** - `cmd.Env = []string{}` prevents injection
- **Shell metacharacter detection** - Additional safety check
- **Builder pattern** - Type-safe command construction

**Critical Go Rules:**
1. Never use `exec.Command("sh", "-c", ...)` with user input
2. Always pass arguments separately, not in command string
3. Always use `CommandContext` with timeout
4. Clear environment with `cmd.Env = []string{}`
5. Validate all inputs against allowlists
6. Check for shell metacharacters as additional safety

