const crypto = require('crypto');
const nodemailer = require('nodemailer');
const mysql = require('mysql2/promise');

const app = express();
app.use(express.json());

const db = mysql.createPool({
  host: 'localhost',
  user: 'app',
  password: 'password',
  database: 'users_db'
});

// VULNERABLE: Predictable token generation
app.post('/api/forgot-password', async (req, res) => {
  const { email } = req.body;

  // VULNERABLE: Token based on timestamp - predictable!
  const resetToken = Date.now().toString(36);

  // VULNERABLE: Token never expires
  await db.query(
    'UPDATE users SET reset_token = ? WHERE email = ?',
    [resetToken, email]
  );

  // VULNERABLE: Reveals if email exists in system
  const [users] = await db.query('SELECT * FROM users WHERE email = ?', [email]);
  if (users.length === 0) {
    return res.status(404).json({ error: 'Email not found' });
  }

  // Send email with reset link
  const resetLink = `http://example.com/reset?token=${resetToken}`;
  await sendEmail(email, resetLink);

  res.json({ message: 'Reset link sent', token: resetToken }); // VULNERABLE: Leaks token!
});

// VULNERABLE: No token validation or expiry
app.post('/api/reset-password', async (req, res) => {
  const { token, newPassword } = req.body;

  // VULNERABLE: No password strength validation
  // VULNERABLE: Token not invalidated after use
  await db.query(
