**Attack Payload**:
```javascript
// Token prediction attack - tokens are based on timestamp
const baseTime = Date.now();
for (let i = -10000; i <= 10000; i++) {
  const predictedToken = (baseTime + i).toString(36);
  // Try each predicted token against the reset endpoint
  fetch('/api/reset-password', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ token: predictedToken, newPassword: 'hacked123' })
  });
}
```

**Why This Is Dangerous**:
- Predictable tokens based on timestamp can be brute-forced within seconds
- Token never expires, allowing indefinite attack window
- Email enumeration reveals which emails are registered
- No rate limiting enables automated attacks
- Password stored in plaintext
- Token not invalidated after successful reset (token reuse attacks)
- Reset link exposed in API response

**SECURE VERSION**:

```javascript
const express = require('express');
const crypto = require('crypto');
const bcrypt = require('bcrypt');
const nodemailer = require('nodemailer');
const mysql = require('mysql2/promise');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(express.json());

const db = mysql.createPool({
  host: process.env.DB_HOST,
  user: process.env.DB_USER,
  password: process.env.DB_PASSWORD,
  database: process.env.DB_NAME
});

const SALT_ROUNDS = 12;
const TOKEN_EXPIRY_MINUTES = 15;

// Rate limiting for password reset
const resetLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 3, // 3 requests per window per IP
  message: { error: 'Too many reset attempts, please try again later' }
});

app.post('/api/forgot-password', resetLimiter, async (req, res) => {
  const { email } = req.body;

  // SECURE: Generate cryptographically random token
  const resetToken = crypto.randomBytes(32).toString('hex');
  const tokenHash = crypto.createHash('sha256').update(resetToken).digest('hex');
  const expiresAt = new Date(Date.now() + TOKEN_EXPIRY_MINUTES * 60 * 1000);

  // Check if user exists (but don't reveal this)
  const [users] = await db.query('SELECT id FROM users WHERE email = ?', [email]);

  if (users.length > 0) {
    // Invalidate any existing tokens first
    await db.query('DELETE FROM password_reset_tokens WHERE user_id = ?', [users[0].id]);

    // Store hashed token with expiry
    await db.query(
      'INSERT INTO password_reset_tokens (user_id, token_hash, expires_at) VALUES (?, ?, ?)',
      [users[0].id, tokenHash, expiresAt]
    );

    // Send email with unhashed token
    const resetLink = `https://example.com/reset?token=${resetToken}`;
    await sendSecureEmail(email, resetLink);
  }

  // SECURE: Always return same response to prevent enumeration
  res.json({ message: 'If an account exists, a reset link will be sent' });
});

app.post('/api/reset-password', resetLimiter, async (req, res) => {
  const { token, newPassword } = req.body;

  // SECURE: Validate password strength
  if (!isStrongPassword(newPassword)) {
    return res.status(400).json({ error: 'Password does not meet requirements' });
  }

  // Hash the provided token to compare with stored hash
  const tokenHash = crypto.createHash('sha256').update(token).digest('hex');

  // Find valid, non-expired token
  const [tokens] = await db.query(
    'SELECT user_id FROM password_reset_tokens WHERE token_hash = ? AND expires_at > NOW()',
    [tokenHash]
  );

  if (tokens.length === 0) {
    return res.status(400).json({ error: 'Invalid or expired reset token' });
  }

  const userId = tokens[0].user_id;

  // SECURE: Hash the new password
  const hashedPassword = await bcrypt.hash(newPassword, SALT_ROUNDS);

  // Update password and invalidate token atomically
  const connection = await db.getConnection();
  try {
    await connection.beginTransaction();

    await connection.query('UPDATE users SET password = ? WHERE id = ?', [hashedPassword, userId]);
    await connection.query('DELETE FROM password_reset_tokens WHERE user_id = ?', [userId]);

    await connection.commit();
  } catch (error) {
    await connection.rollback();
    throw error;
  } finally {
    connection.release();
  }

  res.json({ message: 'Password successfully updated' });
});

function isStrongPassword(password) {
  return password.length >= 12 &&
    /[A-Z]/.test(password) &&
    /[a-z]/.test(password) &&
    /[0-9]/.test(password) &&
    /[^A-Za-z0-9]/.test(password);
}
```

**Key Security Controls**:
- **Cryptographically secure tokens**: Uses `crypto.randomBytes(32)` generating 256 bits of entropy, making brute-force infeasible
- **Token hashing**: Only hashed tokens stored in database; if database is compromised, tokens can't be used
- **Time-limited validity**: 15-minute expiry window minimizes attack opportunity
- **Rate limiting**: Prevents enumeration and brute-force attacks
- **Constant-time responses**: Same response regardless of email existence prevents account enumeration
- **Single-use tokens**: Token deleted immediately after successful reset
- **Password hashing**: bcrypt with salt prevents plaintext password exposure

Great questions! Production password reset systems need to handle multiple reset requests gracefully, support alternative verification methods securely, and include comprehensive monitoring. Security questions are generally discouraged due to their weak security profile, but if required, they must be implemented with proper safeguards.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const crypto = require('crypto');
const bcrypt = require('bcrypt');
const nodemailer = require('nodemailer');
const mysql = require('mysql2/promise');
const rateLimit = require('express-rate-limit');
const winston = require('winston');
const helmet = require('helmet');
const { body, validationResult } = require('express-validator');

const app = express();
app.use(helmet());
app.use(express.json());

// Production-grade logging
const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  defaultMeta: { service: 'password-reset' },
  transports: [
    new winston.transports.File({ filename: 'security-audit.log', level: 'info' }),
    new winston.transports.File({ filename: 'error.log', level: 'error' })
  ]
});

const CONFIG = {
  TOKEN_EXPIRY_MINUTES: parseInt(process.env.TOKEN_EXPIRY_MINUTES) || 15,
  MAX_ACTIVE_TOKENS: 1,
  SALT_ROUNDS: 12,
  MAX_RESET_ATTEMPTS_PER_HOUR: 3,
  MAX_SECURITY_QUESTION_ATTEMPTS: 3,
  LOCKOUT_DURATION_MINUTES: 30,
  MIN_PASSWORD_LENGTH: 12,
  REQUIRE_MFA_FOR_RESET: process.env.REQUIRE_MFA === 'true'
};

class PasswordResetService {
  constructor(db, emailService, logger) {
    this.db = db;
    this.emailService = emailService;
    this.logger = logger;
  }

  // Generate cryptographically secure token
  generateSecureToken() {
    const token = crypto.randomBytes(32).toString('hex');
    const tokenHash = crypto.createHash('sha256').update(token).digest('hex');
    return { token, tokenHash };
  }

  // Check if user is locked out from reset attempts
  async isUserLockedOut(userId) {
    const [lockouts] = await this.db.query(
      `SELECT COUNT(*) as count FROM password_reset_attempts 
       WHERE user_id = ? AND created_at > DATE_SUB(NOW(), INTERVAL ? MINUTE) AND success = false`,
      [userId, CONFIG.LOCKOUT_DURATION_MINUTES]
    );
    return lockouts[0].count >= CONFIG.MAX_RESET_ATTEMPTS_PER_HOUR;
  }

  // Record reset attempt for monitoring
  async recordResetAttempt(userId, success, method, ipAddress, userAgent) {
    await this.db.query(
      `INSERT INTO password_reset_attempts 
       (user_id, success, method, ip_address, user_agent, created_at) 
       VALUES (?, ?, ?, ?, ?, NOW())`,
      [userId, success, method, ipAddress, userAgent]
    );

    this.logger.info('Password reset attempt', {
      userId,
      success,
      method,
      ipAddress,
      timestamp: new Date().toISOString()
    });
  }

  // Initiate password reset via email
  async initiateEmailReset(email, ipAddress, userAgent) {
    const [users] = await this.db.query(
      'SELECT id, email, mfa_enabled FROM users WHERE email = ? AND account_status = "active"',
      [email]
    );

    // Always return same response timing to prevent timing attacks
    const startTime = Date.now();
    const MIN_RESPONSE_TIME = 500; // Minimum 500ms response

    if (users.length > 0) {
      const user = users[0];

      if (await this.isUserLockedOut(user.id)) {
        this.logger.warn('Locked out user attempted reset', { userId: user.id, email });
        // Don't reveal lockout to prevent enumeration
      } else {
        // Check for existing active tokens
        const [existingTokens] = await this.db.query(
          'SELECT COUNT(*) as count FROM password_reset_tokens WHERE user_id = ? AND expires_at > NOW()',
          [user.id]
        );

        if (existingTokens[0].count >= CONFIG.MAX_ACTIVE_TOKENS) {
          // Invalidate old tokens before creating new one
          await this.db.query('DELETE FROM password_reset_tokens WHERE user_id = ?', [user.id]);
        }

        const { token, tokenHash } = this.generateSecureToken();
        const expiresAt = new Date(Date.now() + CONFIG.TOKEN_EXPIRY_MINUTES * 60 * 1000);

        await this.db.query(
          `INSERT INTO password_reset_tokens 
           (user_id, token_hash, expires_at, ip_address, created_at) 
           VALUES (?, ?, ?, ?, NOW())`,
          [user.id, tokenHash, expiresAt, ipAddress]
        );

        // If MFA is enabled and required, include in reset flow
        const resetUrl = CONFIG.REQUIRE_MFA_FOR_RESET && user.mfa_enabled
          ? `https://${process.env.DOMAIN}/reset?token=${token}&mfa=required`
          : `https://${process.env.DOMAIN}/reset?token=${token}`;

        await this.emailService.sendPasswordResetEmail(email, resetUrl, expiresAt);

        await this.recordResetAttempt(user.id, true, 'email_initiated', ipAddress, userAgent);
      }
    }

    // Ensure consistent response timing
    const elapsed = Date.now() - startTime;
    if (elapsed < MIN_RESPONSE_TIME) {
      await new Promise(resolve => setTimeout(resolve, MIN_RESPONSE_TIME - elapsed));
    }

    return { message: 'If an account exists with that email, a reset link will be sent' };
  }

  // Verify security questions (if required as additional factor)
  async verifySecurityQuestions(userId, answers, ipAddress) {
    const [storedAnswers] = await this.db.query(
      'SELECT question_id, answer_hash FROM security_answers WHERE user_id = ?',
      [userId]
    );

    if (storedAnswers.length === 0) {
      return { valid: false, error: 'Security questions not configured' };
    }

    // Verify all answers using constant-time comparison
    let allCorrect = true;
    for (const stored of storedAnswers) {
      const providedAnswer = answers.find(a => a.questionId === stored.question_id);
      if (!providedAnswer) {
        allCorrect = false;
        continue;
      }

      // Normalize answer: lowercase, trim whitespace
      const normalizedAnswer = providedAnswer.answer.toLowerCase().trim();
      const isMatch = await bcrypt.compare(normalizedAnswer, stored.answer_hash);
      if (!isMatch) {
        allCorrect = false;
      }
    }

    await this.recordResetAttempt(userId, allCorrect, 'security_questions', ipAddress, null);

    return { valid: allCorrect };
  }

  // Complete password reset
  async completeReset(token, newPassword, mfaCode, ipAddress, userAgent) {
    const tokenHash = crypto.createHash('sha256').update(token).digest('hex');

    const [tokens] = await this.db.query(
      `SELECT prt.user_id, prt.id as token_id, u.mfa_enabled, u.mfa_secret 
       FROM password_reset_tokens prt 
       JOIN users u ON prt.user_id = u.id 
       WHERE prt.token_hash = ? AND prt.expires_at > NOW() AND prt.used = false`,
      [tokenHash]
    );

    if (tokens.length === 0) {
      this.logger.warn('Invalid or expired reset token used', { ipAddress });
      return { success: false, error: 'Invalid or expired reset token' };
    }

    const { user_id: userId, token_id: tokenId, mfa_enabled: mfaEnabled, mfa_secret: mfaSecret } = tokens[0];

    // Verify MFA if enabled and required
    if (CONFIG.REQUIRE_MFA_FOR_RESET && mfaEnabled) {
      if (!mfaCode) {
        return { success: false, error: 'MFA code required', requireMfa: true };
      }

      const isMfaValid = this.verifyTOTP(mfaSecret, mfaCode);
      if (!isMfaValid) {
        await this.recordResetAttempt(userId, false, 'mfa_failed', ipAddress, userAgent);
        return { success: false, error: 'Invalid MFA code' };
      }
    }

    // Validate password strength
    const passwordValidation = this.validatePassword(newPassword);
    if (!passwordValidation.valid) {
      return { success: false, error: passwordValidation.error };
    }

    // Check password hasn't been used recently
    const [recentPasswords] = await this.db.query(
      'SELECT password_hash FROM password_history WHERE user_id = ? ORDER BY created_at DESC LIMIT 5',
      [userId]
    );

    for (const recent of recentPasswords) {
      if (await bcrypt.compare(newPassword, recent.password_hash)) {
        return { success: false, error: 'Cannot reuse recent passwords' };
      }
    }

    const hashedPassword = await bcrypt.hash(newPassword, CONFIG.SALT_ROUNDS);

    // Atomic transaction: update password, invalidate token, log to history
    const connection = await this.db.getConnection();
    try {
      await connection.beginTransaction();

      // Update password
      await connection.query(
        'UPDATE users SET password = ?, password_changed_at = NOW() WHERE id = ?',
        [hashedPassword, userId]
      );

      // Mark token as used (instead of deleting, for audit trail)
      await connection.query(
        'UPDATE password_reset_tokens SET used = true, used_at = NOW() WHERE id = ?',
        [tokenId]
      );

      // Add to password history
      await connection.query(
        'INSERT INTO password_history (user_id, password_hash, created_at) VALUES (?, ?, NOW())',
        [userId, hashedPassword]
      );

      // Invalidate all user sessions for security
      await connection.query(
        'DELETE FROM user_sessions WHERE user_id = ?',
        [userId]
      );

      await connection.commit();

      await this.recordResetAttempt(userId, true, 'password_changed', ipAddress, userAgent);

      // Send confirmation email
      const [user] = await this.db.query('SELECT email FROM users WHERE id = ?', [userId]);
      await this.emailService.sendPasswordChangedNotification(user[0].email, ipAddress);

      this.logger.info('Password successfully reset', { userId, ipAddress });

      return { success: true, message: 'Password successfully updated' };

    } catch (error) {
      await connection.rollback();
      this.logger.error('Password reset transaction failed', { error: error.message, userId });
      throw error;
    } finally {
      connection.release();
    }
  }

  validatePassword(password) {
    if (password.length < CONFIG.MIN_PASSWORD_LENGTH) {
      return { valid: false, error: `Password must be at least ${CONFIG.MIN_PASSWORD_LENGTH} characters` };
    }
    if (!/[A-Z]/.test(password)) {
      return { valid: false, error: 'Password must contain uppercase letter' };
    }
    if (!/[a-z]/.test(password)) {
      return { valid: false, error: 'Password must contain lowercase letter' };
    }
    if (!/[0-9]/.test(password)) {
      return { valid: false, error: 'Password must contain a number' };
    }
    if (!/[^A-Za-z0-9]/.test(password)) {
      return { valid: false, error: 'Password must contain a special character' };
    }
    return { valid: true };
  }

  verifyTOTP(secret, code) {
    // Implementation would use speakeasy or similar library
    const speakeasy = require('speakeasy');
    return speakeasy.totp.verify({
      secret: secret,
      encoding: 'base32',
      token: code,
      window: 1
    });
  }
}

// Rate limiters
