namespace App\Http\Controllers;

use PHPMailer\PHPMailer\PHPMailer;
use PHPMailer\PHPMailer\Exception;
use Illuminate\Http\Request;
use Illuminate\Support\Facades\Log;
use Illuminate\Support\Facades\Validator;

class SecureContactController extends Controller
{
    public function sendEmail(Request $request)
    {
        // Validate and sanitize all inputs
        $validated = Validator::make($request->all(), [
            'email' => 'required|email:rfc,dns|max:255',
            'name' => 'required|string|max:100|regex:/^[a-zA-Z\s]+$/',
            'subject' => 'required|string|max:200',
            'message' => 'required|string|max:5000'
        ])->validate();

        try {
            $mail = new PHPMailer(true);

            // Use SMTP instead of mail() to avoid injection
            $mail->isSMTP();
            $mail->Host = config('mail.mailers.smtp.host');
            $mail->SMTPAuth = true;
            $mail->Username = config('mail.mailers.smtp.username');
            $mail->Password = config('mail.mailers.smtp.password');
            $mail->SMTPSecure = PHPMailer::ENCRYPTION_STARTTLS;
            $mail->Port = config('mail.mailers.smtp.port');

            // Safe: Using validated, sanitized inputs
            $mail->setFrom(config('mail.from.address'), config('mail.from.name'));
            $mail->addReplyTo($validated['email'], $validated['name']);
            $mail->addAddress('contact@company.com');
            $mail->Subject = htmlspecialchars($validated['subject'], ENT_QUOTES, 'UTF-8');
            $mail->Body = htmlspecialchars($validated['message'], ENT_QUOTES, 'UTF-8');

            $mail->send();

            Log::info('Contact email sent', [
                'from' => $validated['email'],
                'ip' => $request->ip()
            ]);

            return response()->json(['status' => 'sent']);

        } catch (Exception $e) {
            Log::error('Email send failed', [
                'error' => $e->getMessage(),
                'ip' => $request->ip()
            ]);
            return response()->json(['status' => 'error'], 500);
        }
    }
}
```

**Key Security Controls**:
- **Semantic versioning with caret (^)**: Allows automatic minor/patch updates including security fixes
- **roave/security-advisories**: Blocks installation of packages with known vulnerabilities
- **Input validation**: Strict validation before any processing
- **SMTP transport**: Avoids mail() function injection vectors entirely

