<?php
// app/Console/Commands/AnalyzeSecurityAudit.php

namespace App\Console\Commands;

use Illuminate\Console\Command;
use Illuminate\Support\Facades\Http;
use Illuminate\Support\Facades\Log;
use Illuminate\Support\Facades\Cache;

class AnalyzeSecurityAudit extends Command
{
    protected $signature = 'security:analyze-audit {file}';
    protected $description = 'Analyze composer audit results and enforce security policy';

    private array $severityWeights = [
        'critical' => 10,
        'high' => 7,
        'medium' => 4,
        'low' => 1
    ];

    public function handle(): int
    {
        $auditFile = $this->argument('file');

        if (!file_exists($auditFile)) {
            $this->error('Audit file not found');
            return Command::FAILURE;
        }

        $auditData = json_decode(file_get_contents($auditFile), true);
        $config = config('dependency-security');
        $vulnerabilities = $this->categorizeVulnerabilities($auditData);

        // Log all findings
        $this->logVulnerabilities($vulnerabilities);

        // Check against policy
        $policyViolations = $this->checkPolicy($vulnerabilities, $config);

        if (!empty($policyViolations)) {
            $this->alertSecurityTeam($policyViolations);
            $this->displayViolations($policyViolations);
            return Command::FAILURE;
        }

        $this->info('Security audit passed - no policy violations');
        return Command::SUCCESS;
    }

    private function categorizeVulnerabilities(array $auditData): array
    {
        $categorized = [
            'critical' => [],
            'high' => [],
            'medium' => [],
            'low' => []
        ];

        foreach ($auditData['advisories'] ?? [] as $package => $advisories) {
            foreach ($advisories as $advisory) {
                $severity = strtolower($advisory['severity'] ?? 'medium');
                $categorized[$severity][] = [
                    'package' => $package,
                    'advisory_id' => $advisory['advisoryId'] ?? 'unknown',
                    'title' => $advisory['title'] ?? 'No description',
                    'cve' => $advisory['cve'] ?? null,
                    'affected_versions' => $advisory['affectedVersions'] ?? 'unknown',
                    'patched_versions' => $advisory['patchedVersions'] ?? 'none',
                    'is_transitive' => $this->isTransitiveDependency($package)
                ];
            }
        }

        return $categorized;
    }

    private function isTransitiveDependency(string $package): bool
    {
        $composerJson = json_decode(
            file_get_contents(base_path('composer.json')), 
            true
        );

        $directDeps = array_merge(
            array_keys($composerJson['require'] ?? []),
            array_keys($composerJson['require-dev'] ?? [])
        );

        return !in_array($package, $directDeps);
    }

    private function checkPolicy(array $vulnerabilities, array $config): array
    {
        $violations = [];
        $allowed = $config['scanning']['allowed_advisories'] ?? [];

        if ($config['scanning']['fail_on_critical']) {
            foreach ($vulnerabilities['critical'] as $vuln) {
                if (!isset($allowed[$vuln['advisory_id']])) {
                    $violations[] = $vuln;
                }
            }
        }

        if ($config['scanning']['fail_on_high']) {
            foreach ($vulnerabilities['high'] as $vuln) {
                if (!isset($allowed[$vuln['advisory_id']])) {
                    $violations[] = $vuln;
                }
            }
        }

        return $violations;
    }

    private function alertSecurityTeam(array $violations): void
    {
        $webhook = config('dependency-security.scanning.slack_webhook');

        if (!$webhook) {
            return;
        }

        $message = $this->formatSlackMessage($violations);

        Http::post($webhook, [
            'text' => ':rotating_light: Security Policy Violation',
            'blocks' => $message
        ]);

        Log::channel('security')->critical('Dependency vulnerability detected', [
            'violations' => $violations,
            'environment' => app()->environment(),
            'timestamp' => now()->toIso8601String()
        ]);
    }

    private function formatSlackMessage(array $violations): array
    {
        $blocks = [];

        foreach ($violations as $vuln) {
            $blocks[] = [
                'type' => 'section',
                'text' => [
                    'type' => 'mrkdwn',
                    'text' => sprintf(
                        "*%s* in `%s`\nCVE: %s\nTransitive: %s\nFix: Update to %s",
                        $vuln['title'],
                        $vuln['package'],
                        $vuln['cve'] ?? 'N/A',
                        $vuln['is_transitive'] ? 'Yes' : 'No',
                        $vuln['patched_versions']
                    )
                ]
            ];
        }

        return $blocks;
    }

    private function logVulnerabilities(array $vulnerabilities): void
    {
        $total = array_sum(array_map('count', $vulnerabilities));

        Log::channel('security')->info('Dependency audit completed', [
            'total_vulnerabilities' => $total,
            'critical' => count($vulnerabilities['critical']),
            'high' => count($vulnerabilities['high']),
            'medium' => count($vulnerabilities['medium']),
            'low' => count($vulnerabilities['low'])
        ]);
    }

    private function displayViolations(array $violations): void
    {
        $this->error('Security policy violations detected:');

        foreach ($violations as $vuln) {
            $this->line('');
            $this->error("Package: {$vuln['package']}");
            $this->warn("  Title: {$vuln['title']}");
            $this->warn("  CVE: " . ($vuln['cve'] ?? 'N/A'));
            $this->warn("  Transitive: " . ($vuln['is_transitive'] ? 'Yes' : 'No'));
            $this->info("  Fix: Update to {$vuln['patched_versions']}");
        }
    }
}
