    public class AzureKeyVaultKeyService : IKeyManagementService
    {
        private readonly KeyClient _keyClient;
        private readonly IMemoryCache _cache;
        private readonly ILogger<AzureKeyVaultKeyService> _logger;
        private readonly string _keyName;
        private readonly TimeSpan _cacheDuration = TimeSpan.FromMinutes(5);

        public AzureKeyVaultKeyService(
            string keyVaultUrl,
            string keyName,
            IMemoryCache cache,
            ILogger<AzureKeyVaultKeyService> logger)
        {
            _keyClient = new KeyClient(
                new Uri(keyVaultUrl),
                new DefaultAzureCredential());
            _keyName = keyName;
            _cache = cache;
            _logger = logger;
        }

        public async Task<byte[]> GetCurrentKeyAsync()
        {
            string cacheKey = $"encryption_key_{_keyName}_current";

            if (!_cache.TryGetValue(cacheKey, out byte[] key))
            {
                _logger.LogInformation("Fetching current encryption key from Key Vault");

                KeyVaultKey kvKey = await _keyClient.GetKeyAsync(_keyName);
                key = kvKey.Key.K; // For symmetric keys

                _cache.Set(cacheKey, key, _cacheDuration);
                _logger.LogInformation("Encryption key cached. Version: {Version}", kvKey.Properties.Version);
            }

            return key;
        }

        public async Task<byte[]> GetKeyByVersionAsync(string version)
        {
            string cacheKey = $"encryption_key_{_keyName}_{version}";

            if (!_cache.TryGetValue(cacheKey, out byte[] key))
            {
                _logger.LogInformation("Fetching encryption key version {Version} from Key Vault", version);

                KeyVaultKey kvKey = await _keyClient.GetKeyAsync(_keyName, version);
                key = kvKey.Key.K;

                // Cache historical keys longer since they don't change
                _cache.Set(cacheKey, key, TimeSpan.FromHours(1));
            }

            return key;
        }

        public async Task<string> GetCurrentKeyVersionAsync()
        {
            KeyVaultKey kvKey = await _keyClient.GetKeyAsync(_keyName);
            return kvKey.Properties.Version;
        }
    }

    public class ProductionEncryptionService
    {
        private readonly IKeyManagementService _keyService;
        private readonly ILogger<ProductionEncryptionService> _logger;
        private const int KeyVersionLength = 32; // GUID without hyphens

        public ProductionEncryptionService(
            IKeyManagementService keyService,
            ILogger<ProductionEncryptionService> logger)
        {
            _keyService = keyService;
            _logger = logger;
        }

        public async Task<string> EncryptAsync(string plainText, string context = null)
        {
            if (string.IsNullOrEmpty(plainText))
                throw new ArgumentException("Plain text cannot be empty", nameof(plainText));

            byte[] key = await _keyService.GetCurrentKeyAsync();
            string keyVersion = await _keyService.GetCurrentKeyVersionAsync();

            using (Aes aes = Aes.Create())
            {
                aes.Key = key;
                aes.GenerateIV();

                // Include authenticated data if context provided
                byte[] associatedData = string.IsNullOrEmpty(context) 
                    ? Array.Empty<byte>() 
                    : Encoding.UTF8.GetBytes(context);

                using (MemoryStream ms = new MemoryStream())
                {
                    // Format: [KeyVersion(32 bytes)][IV(16 bytes)][Tag(16 bytes)][Ciphertext]
                    byte[] versionBytes = Encoding.ASCII.GetBytes(keyVersion.Replace("-", "").Substring(0, KeyVersionLength));
                    ms.Write(versionBytes, 0, KeyVersionLength);
                    ms.Write(aes.IV, 0, aes.IV.Length);

                    // Use AES-GCM for authenticated encryption
                    byte[] plainBytes = Encoding.UTF8.GetBytes(plainText);
                    byte[] cipherBytes = new byte[plainBytes.Length];
                    byte[] tag = new byte[16];

                    using (AesGcm aesGcm = new AesGcm(key))
                    {
                        aesGcm.Encrypt(aes.IV, plainBytes, cipherBytes, tag, associatedData);
                    }

                    ms.Write(tag, 0, tag.Length);
                    ms.Write(cipherBytes, 0, cipherBytes.Length);

                    _logger.LogDebug("Data encrypted with key version {KeyVersion}", keyVersion);
                    return Convert.ToBase64String(ms.ToArray());
                }
            }
        }

        public async Task<string> DecryptAsync(string cipherText, string context = null)
        {
            if (string.IsNullOrEmpty(cipherText))
                throw new ArgumentException("Cipher text cannot be empty", nameof(cipherText));

            byte[] fullCipher = Convert.FromBase64String(cipherText);

            // Extract key version
            string keyVersion = Encoding.ASCII.GetString(fullCipher, 0, KeyVersionLength);

            // Get the specific key version used for encryption
            byte[] key = await _keyService.GetKeyByVersionAsync(keyVersion);

            // Extract IV
            byte[] iv = new byte[16];
            Array.Copy(fullCipher, KeyVersionLength, iv, 0, 16);

            // Extract tag
            byte[] tag = new byte[16];
            Array.Copy(fullCipher, KeyVersionLength + 16, tag, 0, 16);

            // Extract ciphertext
            int cipherOffset = KeyVersionLength + 32;
            byte[] cipherBytes = new byte[fullCipher.Length - cipherOffset];
            Array.Copy(fullCipher, cipherOffset, cipherBytes, 0, cipherBytes.Length);

            byte[] associatedData = string.IsNullOrEmpty(context)
                ? Array.Empty<byte>()
                : Encoding.UTF8.GetBytes(context);

            byte[] plainBytes = new byte[cipherBytes.Length];

            using (AesGcm aesGcm = new AesGcm(key))
            {
                aesGcm.Decrypt(iv, cipherBytes, tag, plainBytes, associatedData);
            }

            _logger.LogDebug("Data decrypted using key version {KeyVersion}", keyVersion);
            return Encoding.UTF8.GetString(plainBytes);
        }

        public async Task<int> ReEncryptWithCurrentKeyAsync(
            IEnumerable<EncryptedRecord> records,
            Func<EncryptedRecord, Task> updateCallback)
        {
            string currentVersion = await _keyService.GetCurrentKeyVersionAsync();
            int reEncryptedCount = 0;

            foreach (var record in records)
            {
                string recordKeyVersion = GetKeyVersionFromCiphertext(record.EncryptedValue);

                if (recordKeyVersion != currentVersion)
                {
                    string plainText = await DecryptAsync(record.EncryptedValue, record.Context);
                    record.EncryptedValue = await EncryptAsync(plainText, record.Context);

                    await updateCallback(record);
                    reEncryptedCount++;

                    _logger.LogInformation(
                        "Re-encrypted record {RecordId} from key version {OldVersion} to {NewVersion}",
                        record.Id, recordKeyVersion, currentVersion);
                }
            }

            return reEncryptedCount;
        }

        private string GetKeyVersionFromCiphertext(string cipherText)
        {
            byte[] data = Convert.FromBase64String(cipherText);
            return Encoding.ASCII.GetString(data, 0, KeyVersionLength);
        }
    }

    public class EncryptedRecord
    {
        public string Id { get; set; }
        public string EncryptedValue { get; set; }
        public string Context { get; set; }
    }
}
