**SECURE VERSION**:

```java
import javax.servlet.http.*;
import java.io.*;
import java.nio.file.*;
import java.util.logging.Logger;
import java.util.regex.Pattern;

public class SecureFileDownloadServlet extends HttpServlet {
    private static final Logger logger = Logger.getLogger(SecureFileDownloadServlet.class.getName());
    private static final Path BASE_DIR = Paths.get("/var/app/uploads/").toAbsolutePath().normalize();
    private static final Pattern SAFE_FILENAME = Pattern.compile("^[a-zA-Z0-9][a-zA-Z0-9._-]{0,254}$");

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String filename = request.getParameter("file");
        String clientIP = request.getRemoteAddr();

        // DEFENSE 1: Input validation - whitelist allowed characters
        if (filename == null || !SAFE_FILENAME.matcher(filename).matches()) {
            logger.warning("Invalid filename attempt from " + clientIP + ": " + filename);
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid filename");
            return;
        }

        // DEFENSE 2: Resolve and normalize the path
        Path requestedPath = BASE_DIR.resolve(filename).normalize();

        // DEFENSE 3: Canonical path check - verify file is within allowed directory
        if (!requestedPath.startsWith(BASE_DIR)) {
            logger.severe("Path traversal attempt from " + clientIP + ": " + filename);
            response.sendError(HttpServletResponse.SC_FORBIDDEN, "Access denied");
            return;
        }

        // DEFENSE 4: Verify file exists and is a regular file (not symlink to outside)
        if (!Files.exists(requestedPath) || !Files.isRegularFile(requestedPath)) {
            response.sendError(HttpServletResponse.SC_NOT_FOUND);
            return;
        }

        // DEFENSE 5: Check real path to prevent symlink attacks
        Path realPath = requestedPath.toRealPath();
        if (!realPath.startsWith(BASE_DIR.toRealPath())) {
            logger.severe("Symlink escape attempt from " + clientIP);
            response.sendError(HttpServletResponse.SC_FORBIDDEN);
            return;
        }

        logger.info("File download: " + filename + " by " + clientIP);
        serveFile(requestedPath, response);
    }

    private void serveFile(Path filePath, HttpServletResponse response) throws IOException {
        response.setContentType("application/octet-stream");
        response.setHeader("Content-Disposition", 
            "attachment; filename=\"" + filePath.getFileName() + "\"");
        response.setContentLengthLong(Files.size(filePath));

        Files.copy(filePath, response.getOutputStream());
    }
}
```

**Key Security Controls**:
- **Whitelist validation**: Only allows alphanumeric filenames with limited special characters, rejecting any path components
- **Path normalization**: `normalize()` resolves `..` sequences before comparison
- **Directory containment check**: `startsWith(BASE_DIR)` ensures resolved path stays within allowed directory
- **Symlink protection**: `toRealPath()` resolves symbolic links to prevent escape via symlinks
- **Security logging**: All suspicious attempts are logged with client IP for incident response

Supporting subdirectories adds complexity but can be done securely with proper authorization checks and path validation. Here's a production-ready pattern that handles user-specific directories:

**PRODUCTION PATTERN**:

```java
import javax.servlet.http.*;
import java.io.*;
import java.nio.file.*;
import java.security.Principal;
import java.util.logging.Logger;
import java.util.regex.Pattern;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;

public class SecureUserFileServlet extends HttpServlet {
    private static final Logger logger = Logger.getLogger(SecureUserFileServlet.class.getName());
    private static final Logger auditLogger = Logger.getLogger("AUDIT.FileAccess");

    private static final Path BASE_UPLOAD_DIR = Paths.get("/var/app/uploads/").toAbsolutePath().normalize();

    // Whitelist patterns - no path separators allowed in individual components
    private static final Pattern SAFE_PATH_COMPONENT = Pattern.compile("^[a-zA-Z0-9][a-zA-Z0-9._-]{0,63}$");
    private static final int MAX_PATH_DEPTH = 5;
    private static final long MAX_FILE_SIZE = 100 * 1024 * 1024; // 100MB

    // Rate limiting per user
    private static final ConcurrentHashMap<String, AtomicInteger> downloadCounts = new ConcurrentHashMap<>();
    private static final int MAX_DOWNLOADS_PER_MINUTE = 30;

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String clientIP = request.getRemoteAddr();
        Principal userPrincipal = request.getUserPrincipal();

        // DEFENSE 1: Authentication required
        if (userPrincipal == null) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED);
            return;
        }

        String authenticatedUserId = userPrincipal.getName();

        // DEFENSE 2: Rate limiting per user
        if (!checkRateLimit(authenticatedUserId)) {
            logger.warning("Rate limit exceeded for user: " + authenticatedUserId);
            response.setHeader("Retry-After", "60");
            response.sendError(429, "Too many requests");
            return;
        }

        // Get path parameter: /files/user123/documents/file.pdf
        String pathInfo = request.getPathInfo();
        if (pathInfo == null || pathInfo.length() < 2) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST);
            return;
        }

        // DEFENSE 3: Parse and validate each path component individually
        String[] pathComponents = pathInfo.substring(1).split("/");

        if (pathComponents.length < 2 || pathComponents.length > MAX_PATH_DEPTH) {
            logger.warning("Invalid path depth from " + clientIP + ": " + pathInfo);
            response.sendError(HttpServletResponse.SC_BAD_REQUEST);
            return;
        }

        // Validate each component against whitelist
        for (String component : pathComponents) {
            if (!SAFE_PATH_COMPONENT.matcher(component).matches()) {
                logger.warning("Invalid path component from " + clientIP + ": " + component);
                response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid path");
                return;
            }
        }

        String requestedUserId = pathComponents[0];

        // DEFENSE 4: Authorization - user can only access their own files
        // (or admin can access all)
        if (!authorizeAccess(authenticatedUserId, requestedUserId, request)) {
            auditLogger.warning(String.format(
                "UNAUTHORIZED_ACCESS_ATTEMPT user=%s target_user=%s path=%s ip=%s",
                authenticatedUserId, requestedUserId, pathInfo, clientIP));
            response.sendError(HttpServletResponse.SC_FORBIDDEN);
            return;
        }

        // DEFENSE 5: Build path safely using Path.resolve() for each component
        Path targetPath = BASE_UPLOAD_DIR;
        for (String component : pathComponents) {
            targetPath = targetPath.resolve(component);
        }
        targetPath = targetPath.normalize();

        // DEFENSE 6: Final containment check
        if (!targetPath.startsWith(BASE_UPLOAD_DIR)) {
            auditLogger.severe(String.format(
                "PATH_TRAVERSAL_BLOCKED user=%s path=%s resolved=%s ip=%s",
                authenticatedUserId, pathInfo, targetPath, clientIP));
            response.sendError(HttpServletResponse.SC_FORBIDDEN);
            return;
        }

        // DEFENSE 7: Verify it's a regular file (not directory, symlink escape, etc.)
        if (!Files.exists(targetPath) || !Files.isRegularFile(targetPath)) {
            response.sendError(HttpServletResponse.SC_NOT_FOUND);
            return;
        }

        // DEFENSE 8: Resolve real path to catch symlink attacks
        Path realPath = targetPath.toRealPath();
        Path realBaseDir = BASE_UPLOAD_DIR.toRealPath();
        if (!realPath.startsWith(realBaseDir)) {
            auditLogger.severe(String.format(
                "SYMLINK_ESCAPE_BLOCKED user=%s target=%s real=%s ip=%s",
                authenticatedUserId, targetPath, realPath, clientIP));
            response.sendError(HttpServletResponse.SC_FORBIDDEN);
            return;
        }

        // DEFENSE 9: File size check to prevent DoS
        long fileSize = Files.size(realPath);
        if (fileSize > MAX_FILE_SIZE) {
            response.sendError(HttpServletResponse.SC_REQUEST_ENTITY_TOO_LARGE);
            return;
        }

        // Audit log successful access
        auditLogger.info(String.format(
            "FILE_DOWNLOAD user=%s file=%s size=%d ip=%s",
            authenticatedUserId, realPath.getFileName(), fileSize, clientIP));

        serveFileSecurely(realPath, response);
    }

    private boolean authorizeAccess(String authenticatedUser, String targetUser, 
                                    HttpServletRequest request) {
        // User can access their own files
        if (authenticatedUser.equals(targetUser)) {
            return true;
        }

        // Admin role can access all files
        if (request.isUserInRole("ADMIN") || request.isUserInRole("FILE_AUDITOR")) {
            return true;
        }

        // Check for explicit sharing permissions (from database)
        return checkSharingPermission(authenticatedUser, targetUser);
    }

    private boolean checkSharingPermission(String requestor, String owner) {
        // In production: query database for sharing permissions
        // SELECT 1 FROM file_shares WHERE owner_id = ? AND shared_with = ? AND expires_at > NOW()
        return false;
    }

    private boolean checkRateLimit(String userId) {
        AtomicInteger count = downloadCounts.computeIfAbsent(userId, k -> new AtomicInteger(0));
        return count.incrementAndGet() <= MAX_DOWNLOADS_PER_MINUTE;
    }

    private void serveFileSecurely(Path filePath, HttpServletResponse response) throws IOException {
        String contentType = Files.probeContentType(filePath);
        if (contentType == null) {
            contentType = "application/octet-stream";
        }

        // DEFENSE 10: Security headers
        response.setContentType(contentType);
        response.setHeader("Content-Disposition", 
            "attachment; filename=\"" + sanitizeFilename(filePath.getFileName().toString()) + "\"");
        response.setContentLengthLong(Files.size(filePath));
        response.setHeader("X-Content-Type-Options", "nosniff");
        response.setHeader("Cache-Control", "private, no-cache, no-store");
        response.setHeader("Content-Security-Policy", "default-src 'none'");

        Files.copy(filePath, response.getOutputStream());
    }

    private String sanitizeFilename(String filename) {
        // Remove any characters that could cause header injection
        return filename.replaceAll("[^a-zA-Z0-9._-]", "_");
    }

    // Reset rate limits every minute (call from scheduled task)
    public static void resetRateLimits() {
        downloadCounts.clear();
    }
}
```

**Defense in Depth Layers**:

1. **Authentication Gate**:
```java
if (userPrincipal == null) {
    response.sendError(HttpServletResponse.SC_UNAUTHORIZED);
    return;
}
